-- Poems batch 400
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-372','秋霁','吴潜','宋','宋词','song-ci','秋霁','[]','阶砌吟蛩，正竹外萧萧，雨骤风驶。',129,'宋词/ci.song.15000.json','["阶砌吟蛩，正竹外萧萧，雨骤风驶。", "凉浸桃笙，暑消葵扇，借伊一些秋意。", "枕边茉莉。", "满尘奁、贮香能腻。", "也不用，玉骨冰肌，人伴佳眠尔。", "谁信此境，渐入华胥，旷然不知，庄蝶谁是。", "笑邯郸、羁魂客梦，贪他荣贵暂时里。", "飞鼠扑灯还自坠。", "展转惊寤，才听禁鼓三敲，夜声寥阒，又般滋味。"]'),
('song-ci-373','洞仙歌','吴潜','宋','宋词','song-ci','洞仙歌','[]','□□□□，□□□□瘦。',101,'宋词/ci.song.15000.json','["□□□□，□□□□瘦。", "□□□□□□酒。", "□□深，碎蕊残萼都收，归簟枕，谁道栀橐敢就。", "月边偏爱惜，冰玉肌肤，应对垣娥共搔首。", "疑怪得中原，讹道天花，胡尘后、可堪怀旧。", "且海国、浮沈醉花心，喜近日烽烟，渐消亭候。"]'),
('song-ci-374','洞仙歌','吴潜','宋','宋词','song-ci','洞仙歌','[]','冠儿遍簇，那时人消瘦。',101,'宋词/ci.song.15000.json','["冠儿遍簇，那时人消瘦。", "玉斝琼卮劝君酒。", "是清凉境界，露湿烟凝，香更重，非是沈檀合就。", "四窗花满砌，争似家山，橙蟹将肥重回首。", "花亦为君怜，草木禽鱼，相思处、莫如乡旧。", "更西风、溪莼与香鲈，想别墅樵渔，费他侦候。"]'),
('song-ci-375','小重山','吴潜','宋','宋词','song-ci','小重山','[]','碧霄如水月如钲。',70,'宋词/ci.song.15000.json','["碧霄如水月如钲。", "今宵知为我，特分明。", "冰壶玉界两三星。", "清露下，渐觉湿衣轻。", "高树点流萤。", "秋声还又动，客心惊。", "吾家水月寄昭亭。", "归去也，天岂太无情。"]'),
('song-ci-376','醉桃源・阮郎归','吴潜','宋','宋词','song-ci','醉桃源・阮郎归','[]','东风阑槛两三亭。',56,'宋词/ci.song.15000.json','["东风阑槛两三亭。", "游人步晚晴。", "蜂回蝶转得能轻。", "忽然春意生。", "花未老，酒须倾。", "劝君休独醒。", "古来我辈最锺情。", "举头百舌声。"]'),
('song-ci-377','青玉案','吴潜','宋','宋词','song-ci','青玉案','[]','流芳只怕春无几。',82,'宋词/ci.song.15000.json','["流芳只怕春无几。", "拼夜饮、更才二。", "不用追他欢乐事。", "绮窗朱户，燕帷莺馆，多少人憔悴。", "踏歌梦想江南市。", "管春尽、扁舟放行李。", "寒食休倾游子泪。", "归去来兮，不如归去，铁定知今是。"]'),
('song-ci-378','点绛唇','吴潜','宋','宋词','song-ci','点绛唇','[]','岸舣扁舟，江南有个人归老。',50,'宋词/ci.song.15000.json','["岸舣扁舟，江南有个人归老。", "簇新亭沼。", "分付还他了。", "凝伫晴空，一抹天边鸟。", "嗟潦倒。", "去多来少。", "莫问钟昏晓。"]'),
('song-ci-379','清平乐','吴潜','宋','宋词','song-ci','清平乐','[]','轻轻却暑。',53,'宋词/ci.song.15000.json','["轻轻却暑。", "只是些儿雨。", "喜看新抽麻与苎。", "他家烟水墅。", "晚山放出青青。", "是谁簸弄阴晴。", "老子何时去也，祗应露湿金茎。"]'),
('song-ci-380','渔家傲','吴潜','宋','宋词','song-ci','渔家傲','[]','每日困慵当午昼。',72,'宋词/ci.song.15000.json','["每日困慵当午昼。", "出来便解双眉皱。", "一带朦胧烟雨岫。", "山翁瘦。", "林泉纵好他园囿。", "一见此君如话旧。", "玉版老师呼唤候。", "万立琅玕争劝酒。", "踌躇久。", "清风收拾归怀袖。"]'),
('song-ci-381','渔家傲','吴潜','宋','宋词','song-ci','渔家傲','[]','遍阅芳园闲半昼。',72,'宋词/ci.song.15000.json','["遍阅芳园闲半昼。", "残花尚有榴裙皱。", "倦鸟投林云返岫。", "人影瘦。", "可怜身世为他囿。", "燕子飞来还忆旧。", "回头又是梅黄候。", "且尽一杯昌歜酒。", "凝睇久。", "晚风细雨沾衫袖。"]'),
('song-ci-382','柳梢青','吴潜','宋','宋词','song-ci','柳梢青','[]','绿野平泉，古来人事，空里飞花。',61,'宋词/ci.song.15000.json','["绿野平泉，古来人事，空里飞花。", "月榭风亭，荷漪藓石，说郑公家。", "老梅傍水茶牙。", "人那得、光阴似他。", "万种思量，百年倒断，付与残霞。"]'),
('song-ci-383','柳梢青','吴潜','宋','宋词','song-ci','柳梢青','[]','好把元宵。',61,'宋词/ci.song.15000.json','["好把元宵。", "良辰美景，暮暮朝朝。", "万盏华灯，一轮明月，燕管秦箫。", "何人帕坠鲛绡。", "有玉凰、金鸾绣雕。", "目下欢娱，眼前烦恼，只在今宵。"]'),
('song-ci-384','贺圣朝','吴潜','宋','宋词','song-ci','贺圣朝','[]','捷书夜半甘泉去。',60,'宋词/ci.song.15000.json','["捷书夜半甘泉去。", "报天骄膏斧。", "摩空铜垒，闸流瞿滟，扫清云雾。", "楼兰飞馘，焉耆授首，谩夸称前古。", "须知开庆，太平千载，方从今数。"]'),
('song-ci-385','浪淘沙','吴潜','宋','宋词','song-ci','浪淘沙','[]','望月眼穿东。',64,'宋词/ci.song.15000.json','["望月眼穿东。", "云幕千重。", "有时推出赖他风。", "恰似玉环犹未窦，得恁玲珑。", "谁在华山峰。", "一半天中。", "君逾五十我成翁。", "未必明年如此夜，笑口难逢。"]'),
('song-ci-386','贺新郎','吴潜','宋','宋词','song-ci','贺新郎','[]','汲水驱炎热。',142,'宋词/ci.song.15000.json','["汲水驱炎热。", "晚些儿、披衣露坐，待他凉月。", "俄顷银盘从海际，推上璇霄璧阙。", "尽散作、满怀冰雪。", "万里河潢收卷去，掩长庚、弧矢光都灭。", "一大片，琉璃揭。", "玉□擣药何时歇。", "几千年、阴晴隐现，团圆亏缺。", "月缺还圆人但老，重换朱颜无诀。", "想旧日、嫦娥心别。", "且吸琼浆斟北斗，尽今来、古往俱休说。", "香茉莉，正清绝。"]'),
('song-ci-387','贺新郎','吴潜','宋','宋词','song-ci','贺新郎','[]','月绽浮云里。',142,'宋词/ci.song.15000.json','["月绽浮云里。", "未须臾、长风扫荡，碧空如水。", "谁在冰壶玉界上，眇视征蛮战蚁。", "便弃掷、尘寰脱屣。", "絺葛清冷紧袖冷，露华浓、暗袭人肌理。", "和酷暑，争些气。", "谯楼漏转三更二。", "夜沈沈、经星纬宿，换垣移市。", "万籁渐生秋意思，时节那堪屈指。", "奈投老、未酬归计。", "矫首高天天不应，忽林梢、睡鹊惊飞起。", "同一梦，我与尔。"]'),
('song-ci-388','鹊桥仙','吴潜','宋','宋词','song-ci','鹊桥仙','[]','银河半隐，玉蟾高挂，已觉炎光向后。',68,'宋词/ci.song.15000.json','["银河半隐，玉蟾高挂，已觉炎光向后。", "穿针楼上未眠人，应自把、荷花挼揉。", "双星缥缈，霎时聚散，肯向鹊桥回首。", "原来一岁一番期，却捱得、天长地久。"]'),
('song-ci-389','鹊桥仙','吴潜','宋','宋词','song-ci','鹊桥仙','[]','馨香饼饵，新鲜瓜果，乞巧千门万户。',68,'宋词/ci.song.15000.json','["馨香饼饵，新鲜瓜果，乞巧千门万户。", "到头人事控抟难，与拙底、无多来去。", "痴儿忘想，夜看银汉，要待云车飞度。", "谁知牛女已尊年，又那得、欢娱意绪。"]'),
('song-ci-390','秋夜雨','吴潜','宋','宋词','song-ci','秋夜雨','[]','不嫌天上云遮月。',63,'宋词/ci.song.15000.json','["不嫌天上云遮月。", "雨来正是双绝。", "雷公驱电母，尽收卷、十分袢热。", "三更又报初秋了，少待他、西风凄冽。", "灵悟话头莫说。", "且唱饮、刘郎一阕。"]'),
('song-ci-391','秋夜雨','吴潜','宋','宋词','song-ci','秋夜雨','[]','云头电掣如金索。',62,'宋词/ci.song.15000.json','["云头电掣如金索。", "须臾天尽帏幕。", "一凉恩到骨，正骤雨、盆倾檐角。", "桃笙今夜难禁也，赖醉乡、情分非薄。", "清梦何处托。", "又只是、故园篱落。"]'),
('song-ci-392','秋夜雨','吴潜','宋','宋词','song-ci','秋夜雨','[]','单于系颈须长索。',62,'宋词/ci.song.15000.json','["单于系颈须长索。", "捷书新上油幕。", "尽沈边柝也，更底问、悲笳哀角。", "衰翁七十迎头了，先自来、声利都薄。", "归计犹未托。", "又一叶、西风吹落。"]'),
('song-ci-393','秋夜雨','吴潜','宋','宋词','song-ci','秋夜雨','[]','吴翁里第还巾角。',63,'宋词/ci.song.15000.json','["吴翁里第还巾角。", "不妨天地席幕。", "家僮归报道，快酿酒、休教醨薄。", "相逢聚散应搔首，且趁时、一笑为乐。", "人世大都护落。", "更莫问、是非今昨。"]'),
('song-ci-394','秋夜雨','吴潜','宋','宋词','song-ci','秋夜雨','[]','西风半入孤城角。',62,'宋词/ci.song.15000.json','["西风半入孤城角。", "人生归燕巢幕。", "倦翁衰甚也，又不是、官卑禄薄。", "收绳卷索今番稳，尽一丘一壑足乐。", "还是远空雁落。", "报宛句、溪光犹昨。"]'),
('song-ci-395','秋夜雨','吴潜','宋','宋词','song-ci','秋夜雨','[]','晚来小雨鸣檐角。',63,'宋词/ci.song.15000.json','["晚来小雨鸣檐角。", "又还烟障云幕。", "四明窗透荡，渐夜永、綀衫轻薄。", "候虫但要吟教老，不管人、老欠欢乐。", "闲看烛花尽落。", "浮世事、转头成昨。"]'),
('song-ci-396','生查子','吴潜','宋','宋词','song-ci','生查子','[]','坐临芳沼边，荷气侵衣湿。',48,'宋词/ci.song.15000.json','["坐临芳沼边，荷气侵衣湿。", "唧唧暗蛩鸣，点点流萤入。", "人生歧路中，底用杨朱泣。", "一笑倚阑干，颓玉当风立。"]'),
('song-ci-397','生查子','吴潜','宋','宋词','song-ci','生查子','[]','夜夜云气浮，带得香烟湿。',48,'宋词/ci.song.15000.json','["夜夜云气浮，带得香烟湿。", "万籁本无情，一一秋声入。", "须臾离合间，应笑儿曹泣。", "新雨涨鄞江，明日桅樯立。"]'),
('song-ci-398','西河','吴潜','宋','宋词','song-ci','西河','[]','都会地。',126,'宋词/ci.song.15000.json','["都会地。", "东南盛府堪记。", "蓬莱缥缈十洲中，雉城拥起。", "凭高一盼大江横，遥连沧海无际。", "壁同众山翠倚。", "赤龙、白鹞争系。", "风帆指顾便青齐，势雄万垒。", "越栖吴沼古难凭，兴亡都付流水。", "画堂绮屋锦绣市。", "是洛阳、耆旧州里。", "富贵荣华当世。", "问昔年、贺老疏狂，何事轻寄平生、烟波里。"]'),
('song-ci-399','桂枝香','吴潜','宋','宋词','song-ci','桂枝香','[]','三年海国。',124,'宋词/ci.song.15000.json','["三年海国。", "又荏苒素秋，天净如沐。", "凄砌寒蛩暗语，杵声相续。", "梧桐一叶西风里，对斜阳、好个团簇。", "老香堂畔，苍然古桧，无限心曲。", "叹石室、棋方半局。", "便时换人非，光景能蹙。", "千古鸱夷，尚恐欠些归宿。", "倚空笑把轮云事，付坤牛、乾马征逐。", "且巴重九，昭亭句溪，杖藜巾幅。"]'),
('song-ci-400','南乡子','吴潜','宋','宋词','song-ci','南乡子','[]','野思浩难收。',66,'宋词/ci.song.15000.json','["野思浩难收。", "坐看鱼舟度远洲。", "芦苇已雕荷已败，风飕。", "桂子飘香八月头。", "归计这回酬。", "犹及家山一半秋。", "虽则家山元是客，浮休。", "有底欢娱有底愁。"]'),
('song-ci-401','南乡子','吴潜','宋','宋词','song-ci','南乡子','[]','野景有谁收。',66,'宋词/ci.song.15000.json','["野景有谁收。", "只在苍鸥白鹭洲。", "风树飘摇云树暗，衣飕。", "目断青天天际头。", "壮志世难酬。", "丹桂红蕖又晚秋。", "多少心情多少事，都休。", "载取江湖一片愁。"]'),
('song-ci-402','行香子','吴潜','宋','宋词','song-ci','行香子','[]','世事尘轻。',84,'宋词/ci.song.15000.json','["世事尘轻。", "宠辱何惊。", "□不须、更问君平。", "一帆客棹，几曲渔汀。", "正年华晚，露华澹，月华明。", "休论烟阁，莫说云屏。", "算惟堪、瓜种东陵。", "驹阴短景，蜗角浮名。", "但岁难留，身难健，鬓难青。"]'),
('song-ci-403','秋夜雨','吴潜','宋','宋词','song-ci','秋夜雨','[]','腰棚傀儡曾悬索。',62,'宋词/ci.song.15000.json','["腰棚傀儡曾悬索。", "粗瞒凭一层幕。", "施呈精妙处，解幻出、蛟龙头角。", "谁知鲍老从旁笑，更郭郎、摇手消薄。", "歧路难准托。", "田稻熟、只宜村落。"]'),
('song-ci-404','糖多令・唐多令','吴潜','宋','宋词','song-ci','糖多令・唐多令','[]','鸥鹭水中洲。',74,'宋词/ci.song.15000.json','["鸥鹭水中洲。", "夕阳天际流。", "倚西风、底处危楼。", "若使中秋无好月，虚过了、一年秋。", "举眼望云头。", "蟾光一线不。", "想孀娥、自古多愁。", "安得仙师呼鹤驾，将我去、广寒游。"]'),
('song-ci-405','南乡子','吴潜','宋','宋词','song-ci','南乡子','[]','黄耳讯初收。',66,'宋词/ci.song.15000.json','["黄耳讯初收。", "为说鸥汀与鹭洲。", "争问主人归近远，飕飕。", "定是登高九月头。", "有酒且相酬。", "莫管西风满鬓秋。", "今日是今明日古，休休。", "转首鄞江总别愁。"]'),
('song-ci-406','诉衷情','吴潜','宋','宋词','song-ci','诉衷情','[]','今宵分破鹘沦秋。',54,'宋词/ci.song.15000.json','["今宵分破鹘沦秋。", "孤客兴何悠。", "要向云中邀月，真个是呆头。", "风阵紧，电光流。", "雨声飕。", "嫦娥应道，未卜明年，是乐还愁。"]'),
('song-ci-407','水调歌头','吴潜','宋','宋词','song-ci','水调歌头','[]','今岁月和桂，不肯作中秋。',114,'宋词/ci.song.15000.json','["今岁月和桂，不肯作中秋。", "一年惟此佳节，底事白教休。", "我已侵寻七秩，况复轮囷万感，合恨更分愁。", "先自无聊赖，雨意得能稠。", "天柱峰，知何处，老难游。", "痴云如妒，不知弦管可吹不。", "安得风姨扫荡，推出团圆月姊，便遣桂香浮。", "世事十常九，不使展眉头。"]'),
('song-ci-408','水调歌头','吴潜','宋','宋词','song-ci','水调歌头','[]','已是三堪乐，更是百无忧。',113,'宋词/ci.song.15000.json','["已是三堪乐，更是百无忧。", "山朋溪友呼酒，互劝复争酬。", "钓水肥鲜鳊鳜，采树甘鲜梨栗，䆉稏一齐收", "树底飞轻盖，溪上放轻舟。", "笑鸱夷，名已谢，利还谋。", "蜗蝇些小头角，何事被渠钩。", "春际鹭翻蝶舞，秋际猿啼鹤唳，物我共悠悠。", "倚棹明当发，归梦落三洲。"]'),
('song-ci-409','水调歌头','吴潜','宋','宋词','song-ci','水调歌头','[]','老子百般足，无事可闲忧。',114,'宋词/ci.song.15000.json','["老子百般足，无事可闲忧。", "几年思返林壑，今日愿方酬。", "潦倒戏衫舞袖，郎讲门槌拍板，端的这回收。", "日月两浮毂，身世一虚舟。", "想鹪鹩，与鸿鹄，不相谋。", "惊鳞万里深逝，谁肯更吞钩。", "醉则北窗高卧，醒则南园行乐，莫莫更悠悠。", "云在山中谷，月在水中洲。"]'),
('song-ci-410','水调歌头','吴潜','宋','宋词','song-ci','水调歌头','[]','若说故园景，何止可消忧。',114,'宋词/ci.song.15000.json','["若说故园景，何止可消忧。", "买邻谁欲来住，须把万金酬。", "屋外泓澄是水，水外阴森是竹，风月尽兜收。", "柳径荷漪畔，灯火系渔舟。", "且东皋，田二顷，稻粱谋。", "竹篱茅舍，窗户不用玉为钩。", "新擘黄鸡肉嫩，新斫紫螯膏美，一醉自悠悠。", "巴得春来到，芦笋长沙洲。"]'),
('song-ci-411','水调歌头','吴潜','宋','宋词','song-ci','水调歌头','[]','且尽一杯酒，莫问百年忧。',114,'宋词/ci.song.15000.json','["且尽一杯酒，莫问百年忧。", "胸中多少磊块，老去已难酬。", "见说旄头星落，半夜天矫陨坠，玉垒阵云收。", "世运回如此，稳泛辋川舟。", "鸥鹭侣，猿鹤伴，为吾谋。", "主人归也，正是重九月如钩。", "便把三程为两，更趱两程为一，尚恐是悠悠。", "旁有渔翁道，肯负白苹洲。"]'),
('song-ci-412','水调歌头','吴潜','宋','宋词','song-ci','水调歌头','[]','处处羊肠路，归路是安便。',114,'宋词/ci.song.15000.json','["处处羊肠路，归路是安便。", "从头点检身世，今日岂非天。", "未论分封邦国，未论分符乡国，晚节且圆全。", "但觉君恩重，老泪忽潸然。", "谢东山，裴绿野，李平泉。", "从今许我，攀附诸老与齐肩。", "更得十年安乐，便了百年光景，不是谩归田。", "谨勿伤离别，聊共醉觥船。"]'),
('song-ci-413','浣溪沙','吴潜','宋','宋词','song-ci','浣溪沙','[]','半饷西风暖换凉。',48,'宋词/ci.song.15000.json','["半饷西风暖换凉。", "岩花月魄衬云裳。", "一杯旋擘翠橙香。", "旧酝不妨排日醉，新篘尚可去时尝。", "无何乡里是吾乡。"]'),
('song-ci-414','谒金门','吴潜','宋','宋词','song-ci','谒金门','[]','秋已老。',53,'宋词/ci.song.15000.json','["秋已老。", "又是败荷衰草。", "客子安排归棹了。", "回头烟树渺。", "檀板休教歌杳。", "金兽且教香绕。", "一醉秋堂秋夜悄。", "从他霜漏晓。"]'),
('song-ci-415','谒金门','吴潜','宋','宋词','song-ci','谒金门','[]','汤怕老。',53,'宋词/ci.song.15000.json','["汤怕老。", "缓煮龙芽凤草。", "七碗徐徐撑腹了。", "庐家诗兴渺。", "君岂荆溪路杳。", "我已泾川梦绕。", "酒兴茶酣人语悄。", "莫教鸡聒晓。"]'),
('song-ci-416','谒金门','吴潜','宋','宋词','song-ci','谒金门','[]','休怨老。',53,'宋词/ci.song.15000.json','["休怨老。", "更替北邙荒草。", "勘破人生都已了。", "江湖归兴渺。", "盘谷深深杳杳。", "曲水弯弯绕绕。", "啼鸟空山山更悄。", "钟昏钟又晓。"]'),
('song-ci-417','水调歌头','吴潜','宋','宋词','song-ci','水调歌头','[]','倚舵秋江浒，明日片帆轻。',114,'宋词/ci.song.15000.json','["倚舵秋江浒，明日片帆轻。", "从头点检身世，百事已圆成。", "及第曾攀龙首，仕宦曾居鸱阁，衣锦更光荣。", "若又不知止，天道恐亏盈。", "借称呼，遮俗眼，便归耕。", "但馀心愿，朝暮香火告神明。", "一愿君王万寿，次愿干戈永息，三愿岁丰登。", "四愿老安乐，疾病免相荣。"]'),
('song-ci-418','水调歌头','吴潜','宋','宋词','song-ci','水调歌头','[]','便作阳关别，烟雨暗孤汀。',114,'宋词/ci.song.15000.json','["便作阳关别，烟雨暗孤汀。", "浮屠三宿桑下，犹自不忘情。", "何况情锺我辈，聚散葱葱草草，真个是云萍。", "上下四方客，后会渺难凭。", "愿诸公，皆衮衮，喜通津。", "老夫从此归隐，耕钓了馀生。", "若见江南苍鴚，更遇江东黄耳，莫惜寄音声。", "强阁儿女泪，有酒且频倾。"]'),
('song-ci-419','贺新郎','吴潜','宋','宋词','song-ci','贺新郎','[]','晚打西江渡。',142,'宋词/ci.song.15000.json','["晚打西江渡。", "便抬头、严城鼓角，乱烟深处。", "无限珠玑双手接，颇觉奚囊暴富。", "强载月、空舟回去。", "劝子不须忧百草，四周维、自著灵鳌柱。", "互今古，只如许。", "杭州直北还乡路。", "想山中、猿呼鹿啸，鹭翔鸥舞。", "尽道翁归真个也，只怕颜容非故。", "愿从此、耕云钓雨。", "盘谷幽深空谷杳，但书来、时寄相思句。", "千里外，镇延伫。"]'),
('song-ci-420','风流子','方君遇','宋','宋词','song-ci','风流子','[]','春被雨禁持。',133,'宋词/ci.song.15000.json','["春被雨禁持。", "伤心事、仿佛去年时。", "记芳径暮归，褪妆微醉，暗帏先寝，闻笑佯痴。", "回首别离容易过，杨柳又依依。", "红烛怨歌，鬓花零落，青绫牵梦，屏影参差。", "桃源今何在，刘郎去，应念瘦损香肌。", "误约夜阑，从前怪我都疑。", "但怕收残泪，对人徐语，指弹新恨，推户潜窥。", "还是恹恹病也，无计怜伊。"]'),
('song-ci-421','贺新郎','平江妓','宋','宋词','song-ci','贺新郎','[]','春色元无主。',144,'宋词/ci.song.15000.json','["春色元无主。", "荷东君、著意看承，等闲分付。", "多少无情风与浪，又那更、蜂欺蝶妒。", "算燕雀、眼前无数。", "纵使帘栊能爱护，到如今、已是成迟暮。", "芳草碧，遮归路。", "看看做到难言处。", "怕宣郎、旌旗轻转，易歌襦裤。", "月满西楼弦索静，云蔽崑城阆府。", "便恁地、一帆轻举。", "独倚阑干愁拍碎，惨玉容、泪眼如红雨。", "去与住，两难诉。"]'),
('song-ci-422','满江红','陈垲','宋','宋词','song-ci','满江红','["\u957f\u6c5f"]','万里长江，天与限、东南吴楚。',68,'宋词/ci.song.15000.json','["万里长江，天与限、东南吴楚。", "何人者，提英□□，指鞭欲渡。", "孟德舳舻烟赤壁，佛狸心胆寒瓜步。", "问波涛、说尽几英雄，今犹古。", "中原地，纷（下缺）。"]'),
('song-ci-423','减字木兰花','淮上女','宋','宋词','song-ci','减字木兰花','[]','淮山隐隐。',52,'宋词/ci.song.15000.json','["淮山隐隐。", "千里云峰千里恨。", "淮水悠悠。", "万顷烟波万顷愁。", "山长水远。", "遮住行人东望眼。", "恨旧愁新。", "有泪无言对晚春。"]'),
('song-ci-424','行香子','黄孝迈','宋','宋词','song-ci','行香子','[]','一春花下，幽恨重重。',22,'宋词/ci.song.15000.json','["一春花下，幽恨重重。", "又愁晴，又愁雨，又愁风。"]'),
('song-ci-425','水龙吟','黄孝迈','宋','宋词','song-ci','水龙吟','[]','自侧金卮，临风一笑，酒容吹尽。',64,'宋词/ci.song.15000.json','["自侧金卮，临风一笑，酒容吹尽。", "恨东风、忙去熏桃染柳，不念淡妆人冷。", "惊鸿去后，轻抛素袜，杳无音信。", "细看来，只怕蕊仙不肯，让梅花俊。"]'),
('song-ci-426','湘春夜月','黄孝迈','宋','宋词','song-ci','湘春夜月','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','近清明。',125,'宋词/ci.song.15000.json','["近清明。", "翠禽枝上消魂。", "可惜一片清歌，都付与黄昏。", "欲共柳花低诉，怕柳花轻薄，不解伤春。", "念楚乡旅宿，柔情别绪，谁与温存。", "空樽夜泣，青山不语，残月当门。", "翠玉楼前，惟是有、一波湘水，摇荡湘云。", "天长梦短，问甚时、重见桃根。", "这次第，算人间没个并刀，翦断心上愁痕。"]'),
('song-ci-427','水龙吟','黄孝迈','宋','宋词','song-ci','水龙吟','[]','闲情小院沈吟，草深柳密帘空翠。',126,'宋词/ci.song.15000.json','["闲情小院沈吟，草深柳密帘空翠。", "风檐夜响，残灯慵剔，寒轻怯睡。", "店舍无烟，关山有月，梨花满地。", "二十年好梦，不曾圆合，而今老、都休矣。", "谁共题诗秉烛，两厌厌、天涯别袂。", "柔肠一寸，七分是恨，三分是泪。", "芳信不来，玉箫尘染，粉衣香退。", "待问春，怎把千红换得，一池绿水。"]'),
('song-ci-428','水调歌头','吴千能','宋','宋词','song-ci','水调歌头','[]','澹氏人安在，缥缈九霄间。',114,'宋词/ci.song.15000.json','["澹氏人安在，缥缈九霄间。", "我来唯有石屋，周览百寻宽。", "一曲中分夷险，两牖空光平布，满洞贮清寒。", "高歌自堪仰，何必论金丹。", "周贤士，知此意，薄秦官。", "一床一枕，依然犹伴白云间。", "门外俗尘如海，门里道心如水，谈笑足回澜。", "此事无今古，不信叩嵛山。"]'),
('song-ci-429','望海潮','史隽之','宋','宋词','song-ci','望海潮','[]','危岑孤秀，飞轩爽豁，空江泱漭黄流。',129,'宋词/ci.song.15000.json','["危岑孤秀，飞轩爽豁，空江泱漭黄流。", "吴札故邱，春申旧国，西风吹换清秋。", "沧海浪初收。", "共登高临眺，尊俎绸缪。", "凤集高罔，驹留空谷接英游。", "八窗尽控琼钩。", "送帆樯杳杳，潮汐悠悠。", "千古兴怀，关河极目，愁边灭没轻鸥。", "淮岸隔重洲。", "认澹霞天末，一缕青浮。", "未许英雄老去，西北是神州。"]'),
('song-ci-430','水调歌・水调','张友仁','宋','宋词','song-ci','水调歌・水调','[]','石屋势平旷，峭壁几巉岩。',114,'宋词/ci.song.15000.json','["石屋势平旷，峭壁几巉岩。", "妙哉天造地设，谁复谓神剜。", "畴昔涪翁题品，曾说人寰稀有，岂特冠湘南。", "趁取脚轻健，相与上高寒。", "避秦者，君莫问，意其间。", "祖龙文密，至今草木尚愁颜。", "赢得功成丹鼎，久矣乘风而去，跨鹤与骖鸾。", "犹有白云在，镇日绕禅关。"]'),
('song-ci-431','酹江月・念奴娇','王柏','宋','宋词','song-ci','酹江月・念奴娇','[]','今岁腊前，苦无多寒色、梅花先白。',120,'宋词/ci.song.15000.json','["今岁腊前，苦无多寒色、梅花先白。", "可惜横斜清浅处，谁妨孤山仙客。", "玉勒寻芳，金尊护冷，定与心期隔。", "夜阑人悄，可无一段春月。", "怕它香已飘零，罗浮梦断，不与东君接。", "买得鹅湖千幅绢，留取天然标格。", "树老梢癯，蕊圆须健，不放风骚歇。", "花光何处，儿孙声价方彻。"]'),
('song-ci-432','贺新郎','刘震孙','宋','宋词','song-ci','贺新郎','[]','怕绿野堂边，刘郎去后，谁伴老裴度。',17,'宋词/ci.song.15000.json','["怕绿野堂边，刘郎去后，谁伴老裴度。"]'),
('song-ci-433','点绛唇','周晋','宋','宋词','song-ci','点绛唇','[]','午梦初回，卷帘尽放春愁去。',50,'宋词/ci.song.15000.json','["午梦初回，卷帘尽放春愁去。", "昼长无侣。", "自对黄鹂语。", "絮影苹香，春在无人处。", "移舟去。", "未成新句。", "一砚梨花雨。"]'),
('song-ci-434','清平乐','周晋','宋','宋词','song-ci','清平乐','[]','图书一室。',54,'宋词/ci.song.15000.json','["图书一室。", "香暖垂帘密。", "花满翠壶熏研席。", "睡觉满窗晴日。", "手寒不了残棋。", "篝香细勘唐碑。", "无酒无诗情绪，欲梅欲雪天时。"]'),
('song-ci-435','柳梢青','周晋','宋','宋词','song-ci','柳梢青','["\u897f\u6e56"]','似雾中花，似风前雪，似雨馀云。',61,'宋词/ci.song.15000.json','["似雾中花，似风前雪，似雨馀云。", "本自无情，点萍成绿，却又多情。", "西湖南陌东城。", "甚管定、年年送春。", "薄幸东风，薄情游子，薄命佳人。"]'),
('song-ci-436','菩萨蛮','曾原一','宋','宋词','song-ci','菩萨蛮','[]','淡黄斜日留汀草。',52,'宋词/ci.song.15000.json','["淡黄斜日留汀草。", "檐低半露遥岑小。", "病眼不禁愁。", "阑干无数秋。", "雁声何处落。", "旧梦还惊觉。", "风重葛衣单。", "深山吹笛寒。"]'),
('song-ci-437','小重山','曾原一','宋','宋词','song-ci','小重山','[]','薄雪初消银月单。',70,'宋词/ci.song.15000.json','["薄雪初消银月单。", "疏疏浮竹影、矮红阑。", "梅花梦事落孤山。", "禁人处，霜重鼓声寒。", "留取晓来看。", "斑帘低小阁、烛花残。", "一帆明月去沧湾。", "空相忆，雪浪月痕翻。"]'),
('song-ci-438','谒金门','曾原一','宋','宋词','song-ci','谒金门','[]','梅粉褪。',53,'宋词/ci.song.15000.json','["梅粉褪。", "点点雨声春恨。", "半吐桃花芳意嫩。", "草痕青寸寸。", "把酒花边低问。", "莫解寒深红损。", "等待春风晴得稳。", "琵琶重整顿。"]'),
('song-ci-439','临江仙','赵希囿','宋','宋词','song-ci','临江仙','[]','天宇泬寥山气肃，云寒树立无声。',70,'宋词/ci.song.15000.json','["天宇泬寥山气肃，云寒树立无声。", "读书岩下石纵横。", "红尘飞不到，溪水自澄清。", "疏影暗香沙路古，何妨曳杖闲行。", "巢林冻雀不曾惊。", "晚钟穿翠霭，来共话平生。"]'),
('song-ci-440','水调歌头','江万里','宋','宋词','song-ci','水调歌头','[]','生日重重见，馀闰有新春。',114,'宋词/ci.song.15000.json','["生日重重见，馀闰有新春。", "为吾母寿，富贵外物总休论。", "且说家怀旧话，教学也曾菽水，亲意尽欣欣。", "只此是真乐，乐岂在邦君。", "吾二老，常说与，要廉勤。", "庐陵几千万户，休戚属儿身。", "三瑞堂中绿醑，酿就满城和气，端又属人伦。", "吾亦老吾老，谁不敬其亲。"]'),
('song-ci-441','西江月','萧廷之','宋','宋词','song-ci','西江月','[]','两手劈开混沌，坦然直露丹宗。',58,'宋词/ci.song.15000.json','["两手劈开混沌，坦然直露丹宗。", "日魂月魄自西东。", "牢捉莫轻放纵。", "外道邪魔缩项，相将结宝中宫。", "九还七返片时功。", "皆赖黄婆相送。"]'),
('song-ci-442','西江月','萧廷之','宋','宋词','song-ci','西江月','[]','默运乾坤否泰，抽添妙在屯蒙。',58,'宋词/ci.song.15000.json','["默运乾坤否泰，抽添妙在屯蒙。", "起於复卦剥于终。", "温养两般作用。", "沐浴要防危险，吹嘘全藉离风。", "工夫还返入坤宫。", "火足不宜轻弄。"]'),
('song-ci-443','西江月','萧廷之','宋','宋词','song-ci','西江月','[]','要识真铅真汞，都来只一根源。',58,'宋词/ci.song.15000.json','["要识真铅真汞，都来只一根源。", "烹煎火候妙中玄。", "不是知音难辨。", "采取莫差时日，仍分弦后弦前。", "玉炉一霎火烧天。", "无位真人出现。"]'),
('song-ci-444','西江月','萧廷之','宋','宋词','song-ci','西江月','[]','莫问九三二八，无过阴偶阳奇。',58,'宋词/ci.song.15000.json','["莫问九三二八，无过阴偶阳奇。", "大都离坎结夫妻。", "要识屯蒙既未。", "若遇一阳起复，便堪进火无迟。", "只应差失在毫厘。", "野战更宜仔细。"]'),
('song-ci-445','西江月','萧廷之','宋','宋词','song-ci','西江月','[]','鼎器法天象地，坎离运用无差。',58,'宋词/ci.song.15000.json','["鼎器法天象地，坎离运用无差。", "夫妻相会入黄家。", "共说无生妙话。", "雨意云情了当，领头驾动河车。", "搬归顶上结三花。", "牢闭玉关金锁。"]'),
('song-ci-446','西江月','萧廷之','宋','宋词','song-ci','西江月','[]','拨动顶门关捩，自然虎啸龙吟。',58,'宋词/ci.song.15000.json','["拨动顶门关捩，自然虎啸龙吟。", "九还七返义幽深。", "出入不离玄牝。", "运用玉炉火候，鼎中练就真金。", "强兵战胜便收心。", "妙在无伤无损。"]'),
('song-ci-447','西江月','萧廷之','宋','宋词','song-ci','西江月','[]','一二复临养火，兔鸡沐浴潜藏。',58,'宋词/ci.song.15000.json','["一二复临养火，兔鸡沐浴潜藏。", "分明变化在中央。", "结就玄珠片饷。", "还返归根托体，守城抱一提防。", "黄庭来往是寻常。", "恍惚之中纵放。"]'),
('song-ci-448','西江月','萧廷之','宋','宋词','song-ci','西江月','[]','夹脊双关透顶，此为大道玄门。',58,'宋词/ci.song.15000.json','["夹脊双关透顶，此为大道玄门。", "金丹只是此宗根。", "大要知时搬运。", "温养守城野战，华池玉液频吞。", "玉炉常使火温温。", "采药审他老嫩。"]'),
('song-ci-449','西江月','萧廷之','宋','宋词','song-ci','西江月','[]','调燮火工非小，差殊只在毫厘。',58,'宋词/ci.song.15000.json','["调燮火工非小，差殊只在毫厘。", "鼎炉汞走黑铅飞。", "从此恐君丧志。", "须共真师细论，无令妄动轻为。", "幽微玄妙最深机。", "言语仍须避忌。"]'),
('song-ci-450','西江月','萧廷之','宋','宋词','song-ci','西江月','[]','九曲江头逆浪，霎时冲过天心。',58,'宋词/ci.song.15000.json','["九曲江头逆浪，霎时冲过天心。", "昆仑顶上水澄澄。", "酝就琼浆自饮。", "便向此时采取，河车搬运无停。", "阴阳一气自浮沈。", "锁闭玉关牢稳。"]'),
('song-ci-451','西江月','萧廷之','宋','宋词','song-ci','西江月','[]','药产西南坤地，金丹只此根宗。',58,'宋词/ci.song.15000.json','["药产西南坤地，金丹只此根宗。", "学人著意细推穷。", "妙绝无过真种。", "了一万般皆毕，休分南北西东。", "执文泥象岂能通。", "恰似哑人谈梦。"]'),
('song-ci-452','西江月','萧廷之','宋','宋词','song-ci','西江月','[]','金液还丹大道，古人万劫一传。',58,'宋词/ci.song.15000.json','["金液还丹大道，古人万劫一传。", "倾心剖腹露诸篇。", "接引直超道岸。", "莫怪天机泄尽，此玄玄外无玄。", "留传后代与名贤。", "有目分明觑见。"]'),
('song-ci-453','南乡子','萧廷之','宋','宋词','song-ci','南乡子','[]','真汞与真铅。',66,'宋词/ci.song.15000.json','["真汞与真铅。", "产在先天与后天。", "大开知时勤采取，玄玄。", "得穴何愁不作仙。", "进火要精专。", "审究前弦与后弦。", "屯卦抽添蒙卦止，难传。", "毫发差殊不结丹。"]'),
('song-ci-454','南乡子','萧廷之','宋','宋词','song-ci','南乡子','[]','两手擘鸿濛。',66,'宋词/ci.song.15000.json','["两手擘鸿濛。", "慧剑飞来第一峰。", "外道修罗惊缩项，神通。", "造化元来在掌中。", "锻炼玉炉红。", "橐龠吹嘘藉巽风。", "十月托胎吞入腹，坤宫。", "立见三清太上翁。"]'),
('song-ci-455','南乡子','萧廷之','宋','宋词','song-ci','南乡子','[]','温养象周天。',66,'宋词/ci.song.15000.json','["温养象周天。", "须要微微火力全。", "爱护婴儿惟藉母，三年。", "运用抽添象缺圆。", "牛斗会河边。", "拾取玄珠种玉田。", "定意如如行火候，精专。", "剖腹分明说与贤。"]'),
('song-ci-456','南乡子','萧廷之','宋','宋词','song-ci','南乡子','[]','生甲更生庚。',66,'宋词/ci.song.15000.json','["生甲更生庚。", "此是丹头切要明。", "药嫩采来归土釜，煎烹。", "文武刚柔次第行。", "片饷结丹成。", "沐浴防危更守城。", "到此不须行火候，持盈。", "火若加临必定倾。"]'),
('song-ci-457','南乡子','萧廷之','宋','宋词','song-ci','南乡子','[]','木兔与金鸡。',66,'宋词/ci.song.15000.json','["木兔与金鸡。", "刑德临门有偶奇。", "炉内丹砂宜沐浴，防危。", "神水溶溶满玉池。", "年月日并时。", "刻里工夫一例推。", "著意研穷丹造次，毫厘。", "十月殷勤自保持。"]'),
('song-ci-458','南乡子','萧廷之','宋','宋词','song-ci','南乡子','[]','鼎器法乾坤。',66,'宋词/ci.song.15000.json','["鼎器法乾坤。", "上是天元下地元。", "若也更能颠倒运，交番。", "阖劈循环在八门。", "搬运上昆仑。", "龟与蛇儿自吐吞。", "百尺竿头牢把线，掀援。", "从此元神命永存。"]'),
('song-ci-459','南乡子','萧廷之','宋','宋词','song-ci','南乡子','[]','关锁自周天。',66,'宋词/ci.song.15000.json','["关锁自周天。", "升降循环三寸田。", "不在嘘呵并数息，天然。", "九转无亏火力全。", "胎息漫流传。", "要在阴阳不可偏。", "呼吸吹嘘皆赖巽，绵绵。", "妙在前弦与后弦。"]'),
('song-ci-460','南乡子','萧廷之','宋','宋词','song-ci','南乡子','[]','复卦起潜龙。',66,'宋词/ci.song.15000.json','["复卦起潜龙。", "戊己微调未可攻。", "九二见龙临卦主，神通。", "从此炉中次第红。", "泰卦恰相逢。", "猛火烧乾藉巽风。", "炼就黄芽并白雪，奇功。", "还返归坤道始穷。"]'),
('song-ci-461','南乡子','萧廷之','宋','宋词','song-ci','南乡子','[]','识得水中金。',66,'宋词/ci.song.15000.json','["识得水中金。", "煅炼烹煎理更深。", "进退抽添须九转，浮沈。", "温养潜龙复与临。", "妙运自天心。", "托仗黄婆配丙壬。", "酝就醍醐山顶降，频斟。", "慢拨无弦一曲琴。"]'),
('song-ci-462','南乡子','萧廷之','宋','宋词','song-ci','南乡子','[]','长子到西方。',66,'宋词/ci.song.15000.json','["长子到西方。", "少女归乾变六阳。", "便好下功修二八，提防。", "至九方知道自昌。", "牛斗共商量。", "巧夺天功妙莫量。", "离坎夫妻交媾后，难忘。", "始觉壶中日月长。"]'),
('song-ci-463','南乡子','萧廷之','宋','宋词','song-ci','南乡子','[]','白雪与黄芽。',66,'宋词/ci.song.15000.json','["白雪与黄芽。", "两味精华共一家。", "采择辨时衰与旺，堪夸。", "火候毫厘不可差。", "顶上结三花。", "驾动羊车与鹿车。", "乌兔往来南北面，交加。", "从此天河稳泛槎。"]'),
('song-ci-464','南乡子','萧廷之','宋','宋词','song-ci','南乡子','[]','尽净露天机。',66,'宋词/ci.song.15000.json','["尽净露天机。", "只恐时人自执迷。", "颔下藏珠当猛取，休迟。", "道在身中更问谁。", "尘纲忽抛离。", "百岁年华七十稀。", "莫待老来铅汞少，堪悲。", "业报前途难自欺。"]'),
('song-ci-465','百岁令','朱涣','宋','宋词','song-ci','百岁令','[]','瑞芳楼下，有花中君子，群然相聚。',118,'宋词/ci.song.15000.json','["瑞芳楼下，有花中君子，群然相聚。", "笑把筒露浥，来庆黄堂初度。", "净植无尘，清香近远，人与花名伍。", "六郎那得，这般潇洒襟宇。", "运了多少兵筹，依红泛绿，向俭池容与。", "歌裤方腾持节去，未许制衣湘楚。", "紫禁荷囊，玉堂莲炬，遍历清华处。", "归寻太乙，轻舟一叶江渚。"]'),
('song-ci-466','二郎神','周弼','宋','宋词','song-ci','二郎神','[]','浪花皱石，毡叶月、欲移还定。',129,'宋词/ci.song.15000.json','["浪花皱石，毡叶月、欲移还定。", "想白伫烘晴，黄蕉摊雨，人整斜巾照领。", "翦断鲛绡何人续，黯梦想、秋江风冷。", "空露渍藻铺，云根苔甃，指痕环影。", "重省。", "五湖万里，谁问烟艇。", "料宝像尘侵，玉瓢珠锁，羞对菱花故镜。", "领略鸦黄，破除螺黛，都付渚苹汀荇。", "春醉醒，暮雨朝云何处，柳蹊花迳。"]'),
('song-ci-467','浣溪沙','周弼','宋','宋词','song-ci','浣溪沙','[]','朴朴精神的的香。',48,'宋词/ci.song.15000.json','["朴朴精神的的香。", "荼縻一朵晓来妆。", "雏莺叶底学宫商。", "著意劝人须尽醉，扶头中酒又何妨。", "绿窗花影日偏长。"]'),
('song-ci-468','浣溪沙','黄时龙','宋','宋词','song-ci','浣溪沙','[]','雨歇花梢月正明。',48,'宋词/ci.song.15000.json','["雨歇花梢月正明。", "映帘人静绣灯昏。", "鸳鸯成字便停针。", "笑启玉奁明酒晕，缓寻金叶熨香心。", "一春情绪此时深。"]'),
('song-ci-469','夜行船','黄时龙','宋','宋词','song-ci','夜行船','[]','十四弦声犹未断。',66,'宋词/ci.song.15000.json','["十四弦声犹未断。", "星月上、西墙一半。", "却手休弹，含情微妒，报道春宵短。", "银烛纱笼须早办。", "不住地、金蕉催劝。", "别院人归，小窗灯静，自把花枝看。"]'),
('song-ci-470','虞美人','黄时龙','宋','宋词','song-ci','虞美人','[]','卷帘人出身如燕。',68,'宋词/ci.song.15000.json','["卷帘人出身如燕。", "烛底粉妆明艳。", "羯鼓初催按六么。", "无限春娇都上、舞裙腰。", "画堂深窈亲曾见。", "宛转楚波如怨。", "小立花心曲未终。", "一把柳丝无力、倚东风。"]'),
('song-ci-471','玉楼春','陈云','宋','宋词','song-ci','玉楼春','[]','琼奴家与章台并。',64,'宋词/ci.song.15000.json','["琼奴家与章台并。", "路远可怜归梦近。", "波头浪语脸红潮，镜面频思眉翠晕。", "年年花月年年病。", "花月无情人有恨。", "欲将此恨寄湘流，又恐湘流流不尽。"]'),
('song-ci-472','谒金门','陈云','宋','宋词','song-ci','谒金门','[]','春昼永。',53,'宋词/ci.song.15000.json','["春昼永。", "接叶鸣禽相应。", "风定落红香一径。", "疏疏窗竹影。", "寂寞年时酒病。", "远笛悠悠吹醒。", "闲上层楼天又暝。", "云山青不尽。"]'),
('song-ci-473','谒金门','陈东甫','宋','宋词','song-ci','谒金门','[]','西风竹。',53,'宋词/ci.song.15000.json','["西风竹。", "风入翠烟□矗。", "红小阑干知几曲。", "声声敲碧玉。", "窗下凤台银烛。", "断梦已惊难续。", "曾伴去年庭下菊。", "夜阑听雨宿。"]'),
('song-ci-474','长相思','陈东甫','宋','宋词','song-ci','长相思','[]','花深深。',44,'宋词/ci.song.15000.json','["花深深。", "柳阴阴。", "度柳穿花觅信音。", "君心负妾心。", "怨鸣琴。", "恨孤衾。", "钿誓钗盟何处寻。", "当初谁料今。"]'),
('song-ci-475','望江南・忆江南','陈东甫','宋','宋词','song-ci','望江南・忆江南','[]','芳思远，南苑惜春时。',32,'宋词/ci.song.15000.json','["芳思远，南苑惜春时。", "翠柳枝柔金笛怨，碧桃花老玉笙悲。", "风日正迟迟。"]'),
('song-ci-476','瑞鹤仙','黄中','宋','宋词','song-ci','瑞鹤仙','[]','睡馀抛倦枕。',127,'宋词/ci.song.15000.json','["睡馀抛倦枕。", "忆篆鼎香销，起来慵整。", "晴光破清冷。", "正柳黄梅淡，染金匀粉。", "茶瓯隽永。", "试经行、桐花旧井。", "记前回、未绿鸥波，近日燕芹青尽。", "因省。", "春风如旧，人面何归，对时伤景。", "楼高望回。", "潮有信，雁无准。", "任相如多病，沈郎全瘦，都没音尘寄问。", "便做无、阿鹊频频，可能睡稳。"]'),
('song-ci-477','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','[]','西风吹上牛头，天涯慰此人情耳。',127,'宋词/ci.song.15000.json','["西风吹上牛头，天涯慰此人情耳。", "斜阳任晚，青山全似，故人知己。", "迤逦归来，须臾懒去，桂华犹未。", "待冰轮推上，梧桐树了，更儿是、点儿几。", "满眼碧天如洗。", "便分明、水晶宫里。", "区区玩事，一觞一咏，一灯而已。", "欲待无眠，争如且恁，有无穷意。", "怕嫦娥，隔窗偷看，须下却、帐儿睡。"]'),
('song-ci-478','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','[]','几年野渡孤舟，萧然袖此经纶手。',127,'宋词/ci.song.15000.json','["几年野渡孤舟，萧然袖此经纶手。", "归来廊庙，从容进退，祖风犹有。", "小队环花，轻艘漕玉，暂临金斗。", "把持书帷幄，期年坐啸，尘不动、依依柳。", "好是公堂称寿。", "正元戎、阃垣开后。", "旌旗才举，胡雏马上，闻风西走。", "一点阳春，无边德泽，淮山长久。", "待官军，定了长安，貂蝉侍、未央酒。"]'),
('song-ci-479','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','[]','明堂一柱擎天，眼看黄阁空诸老。',127,'宋词/ci.song.15000.json','["明堂一柱擎天，眼看黄阁空诸老。", "平生方寸、班班四字，诚心公道。", "玉帐云旗，金城露布，尚勤征讨。", "向淮头蜀口，一时做就，安石传、孔明表。", "谈笑妖氛如扫。", "看整齐、乾坤都了。", "衮衣赤舄，归来廊庙，雍容师保。", "三相一门，双亲千岁，人间蓬岛。", "举黄封，细唱调羹，官梅上、正春早。"]'),
('song-ci-480','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','[]','东南一气当春，便从黄钺登台斗。',127,'宋词/ci.song.15000.json','["东南一气当春，便从黄钺登台斗。", "紫皇举此，亨屯济泰，属之公手。", "淮浦烽销，未央觞献，捷传清昼。", "庆太平朝野，骎骎重见，昔淳化、今嘉祐。", "史观年编新就。", "看勋庸、光前垂后。", "三槐鼎盛，双椿盘固，古今希有。", "宴侍龙颜，欢承鹤发，相期长久。", "问前朝，相业谁同，八九十、迈文富。"]'),
('song-ci-481','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','[]','岷峨寿佛东来，手移斗柄春寰宇。',126,'宋词/ci.song.15000.json','["岷峨寿佛东来，手移斗柄春寰宇。", "经纶事业，诗书流出，时为膏雨。", "载采三阶，炳丹一念，雍容枢辅。", "望岩廊风范，扬休山立，真汉相、殆天与。", "国步时当如许。", "赖明堂、倚空一柱。", "苍生引领，整齐中夏，奠安西土。", "多士相期，直须无愧，范韩文富。", "且梅边一笑，春风祝公，寿介东鲁。"]'),
('song-ci-482','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','[]','举杯长揖常娥，高情怜我霜髯白。',126,'宋词/ci.song.15000.json','["举杯长揖常娥，高情怜我霜髯白。", "婆娑树底，老蟾何物，千秋一色。", "一镜高悬，肺肝洞烛，了无尘隔。", "任亿千万里，同然玉界，都不管、天南北。", "老子萍蓬纵迹。", "对西风、几番行役。", "平生玩事，从头细数，山川历历。", "明月明年，知他何处，能如今夕。", "惜无人共我，登楼酹古，一笑横笛。"]'),
('song-ci-483','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','[]','少年管领良宵，直须醉待东方白。',126,'宋词/ci.song.15000.json','["少年管领良宵，直须醉待东方白。", "而今老去，何忧何乐，不空不色。", "桐影横斜，桂香摇落，仙凡奚隔。", "怅银桥梦断，玉啸声杳，人如往、楚天北。", "冷眼乾坤阵迹。", "笑英雄、等为行役。", "庾楼袁舫，浩歌长啸，壮游曾历。", "万里瑶台，乘风归去，不知何夕。", "对冰轮孤负，欠千锺酒，与三弄笛。"]'),
('song-ci-484','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','[]','归来袖手江湖，不妨左右持螯白。',126,'宋词/ci.song.15000.json','["归来袖手江湖，不妨左右持螯白。", "凉宵幸对，一轮端正，娟娟秋色。", "万宇冰清，千林霜缟，更无云隔。", "对金茎露冷，铜壶漏静，梧阴转、画桥北。", "堪叹平生辙迹。", "算纷纷、为谁驱役。", "兔蟾应笑，蝇蜗累我，中年虚历。", "抖擞吟情，徘徊舞影，可怜佳夕。", "怅力微心在，梦中一曲，似黄楼笛。"]'),
('song-ci-485','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','["\u897f\u6e56"]','归来三见梅花，年年借此花为寿。',127,'宋词/ci.song.15000.json','["归来三见梅花，年年借此花为寿。", "八窗轩槛，月边竹畔，数枝开又。", "姑射肌肤，广平风度，对人依旧。", "把离骚读遍，椒兰荃蕙，奚敢及、众芳首。", "幸与岁寒为友。", "任天公、雪僝霜僽。", "香名一点，西湖东阁，逊浦曾有。", "金鼎家毡，玉堂椽笔，傥来斯受。", "且巡檐、管领先春，林外事、付卮酒。"]'),
('song-ci-486','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','["\u897f\u6e56"]','几番南极星边，樽前常借南枝寿。',126,'宋词/ci.song.15000.json','["几番南极星边，樽前常借南枝寿。", "今年好处，冰清汉节，与梅为友。", "老桧苍榕，婆娑环拱，影横香瘦。", "把草庭生意，蛮烟尽洗，都付与、风霜手。", "岭首小春时候。", "看明宵、桂轮圆又。", "此人此地，此花此月，宜诗宜酒。", "把绣归来，调羹金鼎，西湖春后。", "愿玉奴、岁与素娥不老，共人长久。"]'),
('song-ci-487','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','["\u897f\u6e56"]','小窗香雾笼葱，砚寒金井频呵冻。',126,'宋词/ci.song.15000.json','["小窗香雾笼葱，砚寒金井频呵冻。", "老坡仙去，新声犹寄，绿毛么凤。", "瘦脸盈盈，不禁僝僽，雪浓霜重。", "赖墨池佳致，草成玄白，聊以此、当清供。", "长记月明曾共。", "拈虬髯、几番孤耸。", "春风一点，著公翠袖，撩人清梦。", "逋尔何如，西湖惯见，影斜芗动。", "要岁寒得友，岂容无竹，倩谁添种。"]'),
('song-ci-488','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','[]','元英燕罢瑶台，玉妃满地花钿委。',126,'宋词/ci.song.15000.json','["元英燕罢瑶台，玉妃满地花钿委。", "山川幻出，剡溪梁苑，齐宫郢里。", "半点瑕无，一团和就，珠圆琼碎。", "任谢家儿女，庭前争诧，临空撤、絮风起。", "夜入蔡州城里。", "问官军、果谁堪比。", "饮羔烹凤，众宾一笑，直聊尔耳。", "寒耸玉楼，冻呵金井，属公诗史。", "更须待大白，浩歌黄竹，为丰年喜。"]'),
('song-ci-489','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','["\u957f\u6c5f"]','玉龙飞下残鳞，千岩万壑皆填委。',126,'宋词/ci.song.15000.json','["玉龙飞下残鳞，千岩万壑皆填委。", "乾坤一色，不知身隔，蓬莱几里。", "疑是瑶英，盛开元圃，被风敲碎。", "倚危楼极目，长江渺处，浑错认、沙鸥起。", "依约青帘遥指。", "记山家、酒香无比。", "访梅江路，何时归唤，小苍长耳。", "孙案袁门，不妨高卧，足娱书史。", "且摩挲霜鬓，嘲吟冰著，共荆人喜。"]'),
('song-ci-490','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','[]','琅琅环佩三千，一楼玉立中端委。',126,'宋词/ci.song.15000.json','["琅琅环佩三千，一楼玉立中端委。", "瑶琚碾就，襄王故国，屈平遗里。", "多少铅华，飞琼涂抹，一时挼碎。", "记少年驰逐，银杯缟带，几番被、鸡呼起。", "冷入重貂如水。", "鬓丝丝、叹非前比。", "羔儿满泛，狮儿低唱，飘风过耳。", "冰释边忧，春生民乐，欢形佐史。", "倩何人蜚奏，五云天上，助吾君喜。"]'),
('song-ci-491','醉蓬莱','李曾伯','宋','宋词','song-ci','醉蓬莱','[]','倚栏干一笑，旧日琵琶，何处寻觅。',120,'宋词/ci.song.15000.json','["倚栏干一笑，旧日琵琶，何处寻觅。", "独立东风，吹未醒狂客。", "沙外青归，柳边黄浅，依旧自春色。", "极目长淮，晴烟一抹，不堪重忆。", "老子平生，萍流蓬转，昔去今来，鸥鹭都识。", "拍拍轻舟，烟浪暗天北。", "自有乾坤，江山如此，多少等陈迹。", "世事从来，付之杯酒，青衫休湿。"]'),
('song-ci-492','醉蓬莱','李曾伯','宋','宋词','song-ci','醉蓬莱','[]','是人生好处，仕宦归来，享清闲福。',120,'宋词/ci.song.15000.json','["是人生好处，仕宦归来，享清闲福。", "屈指吾翁，恰八年荆蜀。", "星火丛中，风涛局上，转青天刍粟。", "轺传欣还，里闾相庆，双鬓犹绿。", "为报中朝，如今老子，肯把貂蝉，换取松菊。", "西舍东邻，正新篘初熟。", "屋仅一椽，田姑二顷，剩种花莳竹。", "缓引金钗，细斟琼斝，唱长生曲。"]'),
('song-ci-493','醉蓬莱','李曾伯','宋','宋词','song-ci','醉蓬莱','["\u897f\u6e56"]','把东南温厚，天遣西来，试薰风手。',120,'宋词/ci.song.15000.json','["把东南温厚，天遣西来，试薰风手。", "一佛人间，与峨眉长久。", "玉帐旌旗，金城鼓吹，笑乌奴歌酒。", "狐兔烟清，貔貅月淡，凯音新奏。", "元祐明时，中朝司马，记得边人，岁问安否。", "勋业如今，□□□□□。", "公衮沙堤，归来无恙，有西湖花柳。", "更借当年，一龟一鹤，伴千秋寿。"]'),
('song-ci-494','醉蓬莱','李曾伯','宋','宋词','song-ci','醉蓬莱','[]','有擎天一柱，殿角西头，手扶宗祐。',120,'宋词/ci.song.15000.json','["有擎天一柱，殿角西头，手扶宗祐。", "万里鱼凫，倚金城山立。", "亭障惊沙，毡裘卷地，倏度黄龙碛。", "玉帐从容，招摇才指，顿清边色。", "见说中天，翠华南渡，一捷金平，胆寒西贼。", "帝锡公侯，更高逾前绩。", "箕尾辉腾，昴街芒敛，看清平天日。", "周衮归来，凤池麟阁，双鬓犹黑。"]'),
('song-ci-495','醉蓬莱','李曾伯','宋','宋词','song-ci','醉蓬莱','[]','记石湖佳句，为海棠花，合来西蜀。',120,'宋词/ci.song.15000.json','["记石湖佳句，为海棠花，合来西蜀。", "不道东州，更香霏情淑。", "汉竹光中，召棠阴里，想清欢未足。", "少驻旌麾，姑留樽俎，待春风曲。", "见说吾家，丹溪老子，万籍名堂，孙枝犹馥。", "南极星边，正魁星明烛。", "五马归来，一龟无恙，访旧松新菊。", "从今长伴，西山一佛，镇岷江绿。"]'),
('song-ci-496','醉蓬莱','李曾伯','宋','宋词','song-ci','醉蓬莱','[]','问江东父老，十数年来，谁为安石。',120,'宋词/ci.song.15000.json','["问江东父老，十数年来，谁为安石。", "万里鲸波，一柱独山立。", "汉橐班高，郢斤名重，喜动旌旗色。", "虎踞龙盘，有人於此，千载犹昔。", "好是元戎，护寒旧手，到处人传，争道公别。", "办取风樯，指顾定南北。", "只恐为霖，玉麟堂小，留不住台席。", "一片仁心，寿身寿国，与同箕翼。"]'),
('song-ci-497','醉蓬莱','李曾伯','宋','宋词','song-ci','醉蓬莱','[]','自陇头垂谱，调鼎传家，典刑犹有。',120,'宋词/ci.song.15000.json','["自陇头垂谱，调鼎传家，典刑犹有。", "岁岁芳期，报小春时候。", "仙骨非凡，生香不断，标格蕙兰右。", "江路孤山，水边雪际，为渠诗瘦。", "白玉堂前，青毡席上，孰谓无人，有如此酒。", "得意春风，且占万花首。", "会看常娥，移栽月殿，肯向桂华后。", "应笑家林，枯松厌蹇，岁寒堪友。"]'),
('song-ci-498','醉蓬莱','李曾伯','宋','宋词','song-ci','醉蓬莱','[]','正阳生一脉，绣日添长，台云书瑞。',120,'宋词/ci.song.15000.json','["正阳生一脉，绣日添长，台云书瑞。", "劲节昂霄，仁意雪霜里。", "粟庾红陈，草扉绿茂，襦裤蔼千里。", "马熟车轻，铃斋曾到，从容游戏。", "好是邦人，能言世美，犹爱其棠，而况其子。", "洞里桃花，岁月任渠记。", "一点梅梢，为传消息，有东皇知己。", "倚看明年，相逢贡袜，曳星辰履。"]'),
('song-ci-499','六州歌头','李曾伯','宋','宋词','song-ci','六州歌头','[]','桂香深处，倾盖岭之西。',181,'宋词/ci.song.15000.json','["桂香深处，倾盖岭之西。", "云南外，曾指点，是挛鞮。", "酌玻璃。", "篸带江山里，挥银笔，摛绮句，湖海气，羞篷弱，吐虹霓。", "回首烟尘碌碌，公家事、自笑痴儿。", "盍田园归去，耕钓侣黔黎。", "月夕花时。", "恣吟题。", "怅荆州路，同北望，剡溪兴，又东驰。", "雄边上，夸前躅，壮新基。", "灿宸奎。", "客问西陲事，公莫惜，语教知。", "秋城梦，笳却骑，舞闻鸡。", "休作中年离恨，聊拼取、一醉如泥。", "梅边佳致，逸兴与逋齐。", "人在苏堤。"]'),
('song-ci-500','摸鱼儿','李曾伯','宋','宋词','song-ci','摸鱼儿','[]','对楼头、欠招欢伯，和风吹老芳讯。',140,'宋词/ci.song.15000.json','["对楼头、欠招欢伯，和风吹老芳讯。", "凭阑面面蒲萄绿，依约碧岑才寸。", "无尽兴。", "纵燃竹烹泉，亦自清肠吻。", "凭谁与问。", "旧城郭何如，英雄安在，何说解孤愤。", "铜鞮路，极目长安甚近。", "当时宾主相信。", "翩翩公子登高赋，局面还思著紧。", "乘暇整。", "谩课柳评花，援镜搔蓬鬓。", "江平浪稳。", "怅我有兰舟，何人共楫，毋作孔明恨。"]'),
('song-ci-501','八声甘州','李曾伯','宋','宋词','song-ci','八声甘州','[]','拟龙山、把酒酹西风，西风苦无情。',119,'宋词/ci.song.15000.json','["拟龙山、把酒酹西风，西风苦无情。", "似秋容不受，骚人登眺，特地悭晴。", "依稀两三过雁，何处是方城。", "目断危楼外，山远烟轻。", "且对黄花一笑，叹浮生易老，乐事难并。", "唤遏云低唱，檐溜任霏铃。", "问何如、乌纱折角，把芳名、盖取晋参军。", "东篱下，阴晴不管，输与渊明。"]'),
('song-ci-502','八声甘州','李曾伯','宋','宋词','song-ci','八声甘州','[]','有庞眉、扶杖岘山来，举觞寿南山。',119,'宋词/ci.song.15000.json','["有庞眉、扶杖岘山来，举觞寿南山。", "道天怜赤子，相逢钧播，久望毡还。", "幸际君王神武，上宰是甘盘。", "少运风霆手，整顿何难。", "好个霜天时候，听雁门新雁，眺远凭阑。", "想经纶心上，一点炳如丹。", "抚舆图、真儒事了，把勋庸、留在鼎彝看。", "八千岁，四明洞府，一佛人间。"]'),
('song-ci-503','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','形胜风流，乐事良辰，一时四并。',139,'宋词/ci.song.15000.json','["形胜风流，乐事良辰，一时四并。", "正榆更新火，觞浮曲水，那堪上巳，又是清明。", "赤壁功名，东坡文字，俯仰人间无古今。", "诗书帅，对烽烟静昼，俎豆添春。", "水边天气催人。", "便须认杨花雪样生。", "慨英风满席，思旌绵上，清谈束阁，肯记兰亭。", "安得长绳，高悬碧落，系住画檐红日阴。", "柔桑外，听鸣鸠唤雨，全胜流莺。"]'),
('song-ci-504','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','鸿禧主人，一闲半年，未尝厌闲。',140,'宋词/ci.song.15000.json','["鸿禧主人，一闲半年，未尝厌闲。", "谓有溪可钓，有田可秣，有兰堪佩，有菊堪餐。", "羽檄秋风，胡笳夜月，多少勋名留汉关。", "如今且，效樽罍北海，歌舞东山。", "门前。", "咫尺长安。", "但只恐纶音催禁班。", "把鹭鬓数茎，更因民白，鸥心一片，犹为君丹。", "蓝绶儿痴，彩衣家庆，倦羽伶俜江汉还。", "春光小，看庭苇岁岁，一笑梅间。"]'),
('song-ci-505','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','轩冕傥来，功名杯水，行藏依楼。',140,'宋词/ci.song.15000.json','["轩冕傥来，功名杯水，行藏依楼。", "把方略评梅，工夫课柳，精神伴鹤，谈笑盟鸥。", "草檄寻樵，移文问钓，任江上东南风未休。", "君知否，问如今绿野，胜似青油。", "从伊万户封留。", "算得似团栾歌笑不。", "怕魏阙兴思，高车驷马，江湖难著，缓带轻裘。", "雪意何如，新醪熟未，乐事良辰聊献酬。", "从今去，更八千椿算，才一春秋。"]'),
('song-ci-506','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','今代清流，北斗以南，文昌一星。',139,'宋词/ci.song.15000.json','["今代清流，北斗以南，文昌一星。", "对露门进读，銮坡演翰，琐闱批敕，宝牒成文。", "笔下权衡，胸中律度，礼乐人才俱讨论。", "鸳行里，羡才高片玉，辉映条冰。", "几年简在吾君。", "便须把诗书开太平。", "笑诸公炙手，昔成何事，一贤冷眼，今独修名。", "花底退朝，槐边听制，一武商岩霖雨新。", "金罍举，对春风九十，岁岁平分。"]'),
('song-ci-507','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','天下中庸，千载一灯，传之自公。',139,'宋词/ci.song.15000.json','["天下中庸，千载一灯，传之自公。", "有涵洪雅量，陂澄千顷，坚凝定力，壁立孤峰。", "佐鼎调梅，参帷借箸，略试斯文经济功。", "听淮鹤，暂素丝揽辔，玉帐分弓。", "朝来鼓角声雄。", "庆元帅新除初度逢。", "任西风局面，人皆澒洞，福星堂上，我独从容。", "草檄传燕，开门释蔡，了却中原公衮东。", "归廊庙，把格天勋业，与宋无穷。"]'),
('song-ci-508','沁园春','李曾伯','宋','宋词','song-ci','沁园春','["\u6d1e\u5ead\u6e56"]','画舸呼风，长剑倚天，壮哉此行。',139,'宋词/ci.song.15000.json','["画舸呼风，长剑倚天，壮哉此行。", "指洞庭彭蠡，遍观吴楚，瞿塘滟澦，直上峨岷。", "帝语春温，军声秋肃，手济时屯开泰平。", "天应是，念蚕丛父老，公为更生。", "眼看四海无人。", "今天下英雄惟使君。", "想驰情忠武，将兴王业，抚膺司马，忍咎吾民。", "净洗甲兵，归来鼎辅，定使八荒同一云。", "经营事，比京河形势，更近函秦。"]'),
('song-ci-509','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','漫浪江头，三听秋砧，一登故台。',137,'宋词/ci.song.15000.json','["漫浪江头，三听秋砧，一登故台。", "望烟芜莽苍，令人目断，风樯掀舞，何日眉开。", "把酒新亭，围棋别墅，老气当时何壮哉。", "江东事，百年无恙，全是时才。", "纷然竞付轻埃。", "还水绕赏心东向淮。", "叹阿奴侪悲，因人碌碌，乃翁材略，馀地恢恢。", "凤阙天高，鹭洲潮落，约取白鸥归去来。", "阑干外，英雄陈迹，一醁琼杯。"]'),
('song-ci-510','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','绮阁香销，玉砌梦残，凄凉旧台。',137,'宋词/ci.song.15000.json','["绮阁香销，玉砌梦残，凄凉旧台。", "对御沟红叶，一番木落，宫墙黄菊，几度花开。", "水溯岷源，山联吴会，目送征鸿安往哉。", "都休问，六朝人物，谁拙谁才。", "平生衮衮烟尘。", "记匹马当年荆蜀淮。", "叹雕零殆尽，词源已竭，消磨未去，酒量犹恢。", "八跪蟹肥，四腮鲈美，客有可人招不来。", "油幢暇，凭栏一笑，相与传杯。"]'),
('song-ci-511','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','目断长空，手拍危栏，高兴酒浓。',139,'宋词/ci.song.15000.json','["目断长空，手拍危栏，高兴酒浓。", "拟招呼短艇，追陪飞盖，一餐湘菊，共赋芙蓉。", "雁字沈秋，鸦林噪晚，几阵萧萧雨更风。", "空凝伫，不如一鹤，随意西东。", "堪嗟乐事难逢。", "愧元伯、巨卿千里从。", "望文星聚彩，交辉吴分，天飙吹翅，独隔崑蓬。", "野墅荒烟，败荷衰草，人在可怜憔悴中。", "还相念，愿持觥薄罚，别许从容。"]'),
('song-ci-512','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','雨抹晴妆，修眉镜清，寸碧翠浓。',139,'宋词/ci.song.15000.json','["雨抹晴妆，修眉镜清，寸碧翠浓。", "对蒹葭尽处，丛丛烟树，池塘侧畔，面面芙蓉。", "千百栖乌，两三过雁，时有婆娑一笛风。", "斜阳里，更青帘半卷，在小桥东。", "佳人何日重逢。", "问还肯扁舟载酒从。", "笑平生劲概，寸心如铁，中年老态，两鬓成蓬。", "荷锸栽蔬，腰镰刈稻，且寄西郊图画中。", "空回首，望五湖鸥鹭，心事容容。"]'),
('song-ci-513','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','秋岂悲人，人不悲秋，比春更浓。',139,'宋词/ci.song.15000.json','["秋岂悲人，人不悲秋，比春更浓。", "有蕙兰风度，尚存芳菊，牡丹之献，犹在芙蓉。", "举蟹持醪，得鲈作鲙，晋宋间人有此风。", "休轻笑，彼柴桑傲吏，龌龊篱东。", "携壶与客还逢。", "愿时许先生杖履从。", "叹尘踪如寄，鸥凫江海，性真聊适，蜩鷃蒿蓬。", "刮眼青天，惊心黄叶，立尽梧桐月正中。", "凄然久，看物情终竟，不似春容。"]'),
('song-ci-514','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','大江之西，康庐之阴，壮哉此州。',139,'宋词/ci.song.15000.json','["大江之西，康庐之阴，壮哉此州。", "有舳橹千里，旌旗百万，襟喉上国，屏翰中流。", "弹压鲸波，指麾虎渡，著此商川万斛舟。", "青毡旧，看崇诗说礼，缓带轻裘。", "十年泉石优游。", "久高卧元龙百尺楼。", "正九重侧席，相期岩弼，一贤砥柱，聊试边筹。", "了却分弓，归来调鼎，得见茂洪何复忧。", "谈兵暇，问琵琶歌曲，无恙还不。"]'),
('song-ci-515','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','北固台端，南渡后来，无此伟人。',140,'宋词/ci.song.15000.json','["北固台端，南渡后来，无此伟人。", "自从容佐鼎，光华揽辔，几年中外，属目经纶。", "万灶炊烟，千艘漕雪，手整江淮如掌平。", "诗书效，看马腾士饱，酒好兵精。", "平生。", "馀事功名。", "岂管葛诸人能拟伦。", "暂牙筹游戏，小淹惟月，金瓯注想，便合为霖。", "沆瀣一襟，风流八咏，秋入诗坛如许清。", "为公寿，有黄花不老，长伴香名。"]'),
('song-ci-516','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','揽秀岷峨，著鞭江淮，诸公所奇。',139,'宋词/ci.song.15000.json','["揽秀岷峨，著鞭江淮，诸公所奇。", "对塞垣烟淡，相随弓剑，城楼月落，几共灯棋。", "驿柳摇黄，溪桃涨绿，稳趁春风度玉墀。", "亨衢去，看紫薇红药，太乙青藜。", "孤山若放梅时。", "莫忘却扬州曾有诗。", "怅英游难驻，堪怜只影，中年易感，祗付双眉。", "珍重交情，勉旃时用，回首岫云从此归。", "能相忆，有好音遗我，在水之湄。"]'),
('song-ci-517','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','水北洛南，未尝无人，不同者时。',140,'宋词/ci.song.15000.json','["水北洛南，未尝无人，不同者时。", "赖交情兰臭，绸缪相好，宦情云薄，得失何知。", "夜观论兵，春原吊古，慷慨事功千载期。", "萧如也，料行囊如水，只有新诗。", "归兮。", "归去来兮。", "我亦办征帆非晚归。", "正姑苏台畔，米廉酒好，吴松江上，莼嫩鱼肥。", "我住孤村，相连一水，载月不妨时过之。", "长亭路，又何须回首，折柳依依。"]'),
('song-ci-518','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','天下奇观，江浮两山，地雄一州。',140,'宋词/ci.song.15000.json','["天下奇观，江浮两山，地雄一州。", "对晴烟抹翠，怒涛翻雪，离离塞草，拍拍风舟。", "春去春来，潮生潮落，几度斜阳人倚楼。", "堪怜处，怅英雄白发，空敝貂裘。", "淮头。", "虏尚虔刘。", "谁为把中原一战收。", "问只今人物，岂无安石，且容老子，还访浮丘。", "鸥鹭眠沙，渔樵唱晚，不管人间半点愁。", "危栏外，渺沧波无极，去去归休。"]'),
('song-ci-519','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','紫金山前，铁骑围中，惟公尚知。',139,'宋词/ci.song.15000.json','["紫金山前，铁骑围中，惟公尚知。", "怅当时卯角，鱼犹同队，如今缟鬓，鸥已忘机。", "故垒荒榛，群贤拱木，畴记官军夜战时。", "不图见，独岁寒不改，老气犹奇。", "嗟哉月驶舟移。", "四十载光阴昨梦非。", "叹荷薪弗克，祗惭弓冶，扃柴却扫，绝望簪圭。", "菌短椿长，鷃微鹏巨，天分当然何足疑。", "闻公里，有磻溪堪钓，盍亦云归。"]'),
('song-ci-520','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','大疏归来，小阮适闲，喜同此时。',139,'宋词/ci.song.15000.json','["大疏归来，小阮适闲，喜同此时。", "问垂弧历载，几番遥祝，举觞华旦，相会良希。", "颂以松椿，酌之椒柏，预卜明年百事宜。", "春犹浅，趁雪晴梅放，且和新诗。", "公虽厌直兰闱。", "如正色朝端当宁知。", "看大廷诸老，争推前席，吾家五祖，自有传衣。", "暖律初回，要津立上，卿相时来皆可为。", "祈公寿，与东君不老，南极齐辉。"]'),
('song-ci-521','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','弧矢四方，江汉一萍，少年壮游。',139,'宋词/ci.song.15000.json','["弧矢四方，江汉一萍，少年壮游。", "叹而今老矣，祗宜野服，欲何为者，还著轻裘。", "匹马萧萧，孤鸾杳杳，城郭重来空白头。", "西风里，对一番新月，又荻花秋。", "依然千古荆州。", "问刘表诸人还在不。", "向亭前举酒，不堪北顾，船头击楫，忍负中流。", "远水长天，淡烟衰草，还是当时王粲楼。", "何如且，倩吴歌楚舞，一洗新愁。"]'),
('song-ci-522','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','嗟矍铄翁，对婵娟月，怀汗漫游。',139,'宋词/ci.song.15000.json','["嗟矍铄翁，对婵娟月，怀汗漫游。", "怅江湖幸有，季鹰鲈脍，田园忍负，晏子弧裘。", "丹桂开时，青苹渺处，家在三吴天尽头。", "庭皋静，又一番叶落，天下皆秋。", "少年弓剑边州。", "惊转首黄粱还梦不。", "叹悠悠千载，关山无恙，滔滔一水，岁月俱流。", "镜老菱花，笳悲庐叶，新雁数行人倚楼。", "君知否，把眉峰蹙破，岂为身愁。"]'),
('song-ci-523','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','唤麴生来，与常娥约，从太守游。',139,'宋词/ci.song.15000.json','["唤麴生来，与常娥约，从太守游。", "把玉箫声寄，萧关短笛，霓裳曲换，清塞重裘。", "桂影飘摇，桐阴立尽，多少征人霜满头。", "油幢暇，不掀髯一笑，辜负中秋。", "斗杓矗处中州。", "还有解闻鸡起舞不。", "看鸣弦中鹄，穿杨电激，飞球戏马，策垂星流。", "绣帽归军，玳簪环客，薄晚同登庾亮楼。", "浮生事，是几番玩月，何苦多愁。"]'),
('song-ci-524','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','麴生来言，素娥寄声，偶阆苑游。',140,'宋词/ci.song.15000.json','["麴生来言，素娥寄声，偶阆苑游。", "问去年今夕，逢余桂岭，前年今夕，见子菟裘。", "何事尘劳，启人厌倦，痴兔老蟾因缩头。", "宜珍重，要相期后会，直待来秋。", "休休。", "莫舞凉州。", "岂巫女风姨相妒不。", "枉停歌准拟，冰轮东上，持杯顾恋，银汉西流。", "一笑天悭，四并时少，应负珠帘十二楼。", "呼蕉叶，且与生酹古，排遣牢愁。"]'),
('song-ci-525','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','百尺楼头，奇哉此翁，元龙后身。',139,'宋词/ci.song.15000.json','["百尺楼头，奇哉此翁，元龙后身。", "当壮年襟度，百川鲸吸，平生出处，一片鸥轻。", "冷淡逋梅，淋漓旭草，但见风雷笔下生。", "荆州幕，觉坐间小异，乃有斯人。", "牙樯喜色津津。", "正江影涵秋无点尘。", "对白苹黄苇，且供诗卷，紫薇红药，却演丝纶。", "举酒延蟾，倚栏闻雁，应念征人归尚春。", "君王问，尽不妨细说，万里戎情。"]'),
('song-ci-526','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','一段太清境，谁幻出阶坳。',114,'宋词/ci.song.15000.json','["一段太清境，谁幻出阶坳。", "不知身住何处，爽气逼霜袍。", "但见人间一样，似夜又还非夜，栖鸟不安巢。", "认得在尘世，禁鼓二更敲。", "最忺看，来竹底，上梅梢。", "几家朱户，不如儿女醉蓬茅。", "谁把琴声三弄，不管骚人幽趣，似向曲中嘲。", "长啸赋赤壁，有酒更无肴。"]'),
('song-ci-527','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','夜永厌银烛，移步下堂坳。',114,'宋词/ci.song.15000.json','["夜永厌银烛，移步下堂坳。", "秋风昨梦少年，高兴鹄成袍。", "世上痴儿睡去，历历江山细数，孤鹘啸危巢。", "地静未容去，门掩不妨敲。", "转巍阑，低画桶，落寒梢。", "南楼老子争似，短笛一椽茅。", "无色界间长啸，不夜城中高卧，随意弄诗嘲。", "洗斝要更酌，为我问佳肴。"]'),
('song-ci-528','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','["\u897f\u6e56"]','千一载英杰，百二国山河。',114,'宋词/ci.song.15000.json','["千一载英杰，百二国山河。", "提封几半宇宙，万里仗天戈。", "十乘晋军旗鼓，三岁秦关扃锁，地利属人和。", "位次功第一，未数酂侯何。", "建青油，持柴荷，听黄麻。", "乾坤整顿都了，玉殿侍羲娥。", "且醉东湖花柳，却泛西湖舟楫，留不住岷峨。", "谁为语儒馆，浓墨被诗歌。"]'),
('song-ci-529','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','三蜀最佳处，昌是海棠州。',114,'宋词/ci.song.15000.json','["三蜀最佳处，昌是海棠州。", "清香燕寝闲暇，人与地风流。", "十万人家寿域，六七十翁儿状，眉寿祝公侯。", "谁为语廊庙，且许寇恂留。", "过书云，才几日，纪千秋。", "祖孙卮酒相贺，庆事袭箕裘。", "自有诗书万卷，安用田园千顷，松菊足优游。", "持以寿公者，梅萼伴清修。"]'),
('song-ci-530','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','["\u957f\u6c5f"]','老子世北客，家本住吴头。',114,'宋词/ci.song.15000.json','["老子世北客，家本住吴头。", "登临聊复尔耳，佳节懒为酬。", "刚被西风断送，又为黄花牵帅，草创作斯游。", "目力眇无际，更上一层楼。", "对长江，流不尽，古今愁。", "凭兰正拟一笑，襟袍怯於秋。", "高处令人心悸，放旷舒怀何暇，好趁醒时休。", "留取江湖量，归去醉中州。"]'),
('song-ci-531','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','行客送行客，况又值新秋。',114,'宋词/ci.song.15000.json','["行客送行客，况又值新秋。", "莼乡此去万里，先我上扁舟。", "三载乌奴聚首，异县乡情对语，乘月几登楼。", "去去远蜀口，日日望吴头。", "丹青手，描不就，此离愁。", "半生萍梗江汉，别恨最绸缪。", "远水长空一色，风顺波平如掌，雁序际天游。", "故旧有相问，犹滞剑南州。"]'),
('song-ci-532','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','骤雨送行色，把剑渡长淮。',114,'宋词/ci.song.15000.json','["骤雨送行色，把剑渡长淮。", "西风咄咄怪事，吹不散烟霾。", "才是橙黄时候，早似梅边天气，寒意已相催。", "老子尚顽耐，仆马苦虺隤。", "叹平生，身客路，半天涯。", "飞鸢跕跕曾见，底事又重来。", "回首白云何处，目送孤鸿千里，去影为徘徊。", "篱菊渐秋色，杜瓮有新醅。"]'),
('song-ci-533','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','万里长淮北，青是汉时山。',114,'宋词/ci.song.15000.json','["万里长淮北，青是汉时山。", "几年壁垒相望，高枕度春闲。", "不道草庐豪杰，手袖伊吾长剑，驰志在楼兰。", "锺鼓令秋肃，毡罽胆冰寒。", "诗书帅，金横带，玉为鞍。", "天生如结数辈，虏岂易江南。", "京索成皋此际，东郭韩庐俱困，故老正争看。", "琳檄未能草，冯铗直空弹。"]'),
('song-ci-534','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','岘山羊叔子，江左管夷吾。',114,'宋词/ci.song.15000.json','["岘山羊叔子，江左管夷吾。", "勋名掀揭宇宙，金匮侈丹书。", "两载风寒卧护，一柱狂澜屹立，形势壮陪都。", "功业笑儿辈，别有大规模。", "看东归，游凤沼，转鸿枢。", "不应廊庙人物，犹佩玉麟符。", "好是茅峰仙客，更与锺山佛子，同日庆垂弧。", "一饮共千岁，永永辅皇图。"]'),
('song-ci-535','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','["\u957f\u6c5f"]','簪履盛元幕，领袖属英游。',114,'宋词/ci.song.15000.json','["簪履盛元幕，领袖属英游。", "登车揽辔馀事，何止客诸候。", "看尽巫云岷雪，却妨庐峰湓浦，砥柱赞中流。", "百叠青山路，一片白苹洲。", "今日事，风涛上，一虚舟。", "长江万顷寒碧，犹谓马能浮。", "况是眼前局面，心腹忧如边角，胜著赖帷筹。", "谈笑济时了，勋业迈前修。"]'),
('song-ci-536','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','风卷江湖浪，举足是羊肠。',114,'宋词/ci.song.15000.json','["风卷江湖浪，举足是羊肠。", "峡山知在何处，榛莽更凄凉。", "不为渊明五斗，直为班超万里，雅志未能忘。", "耿耿富襟抱，行计有诗囊。", "溯吴头，逾楚尾，界瞿塘。", "从他昵昵燕语，留不住征樯。", "芳草天涯弥望，着我飞凫来去，在在可徜徉。", "持此见刘表，抵掌与谈王。"]'),
('song-ci-537','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','幻出广寒境，罗袜净无尘。',114,'宋词/ci.song.15000.json','["幻出广寒境，罗袜净无尘。", "素娥风格分明，玉骨水为神。", "手揽清光盈掬，眼看山河一色，阅尽古今人。", "对影且长啸，一酌瓮头春。", "千万顷，琉璃色，楚天清。", "庾楼袁舫何事，汩汩主和宾。", "但见老蟾无恙，不管镜圆钩阙，寒暑任相更。", "此夕幸无雨，何惜放颜醺。"]'),
('song-ci-538','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','碾就一轮玉，扫尽四边尘。',114,'宋词/ci.song.15000.json','["碾就一轮玉，扫尽四边尘。", "白乎不涅不磷，千古此丰神。", "领略常娥体态，寂寞谪仙材调，四海岂无人。", "安得金丹诀，长驻玉颜春。", "镜圆明，冰样洁，水来清。", "良宵难值如许，何惜且留宾。", "拟唤桓伊三弄，影转画檐西畔，钟鼓趣残更。", "肺腑尽霜雪，麴糵不能醺。"]'),
('song-ci-539','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','久欲乘槎去，间阔几仙尘。',114,'宋词/ci.song.15000.json','["久欲乘槎去，间阔几仙尘。", "乾坤炯炯不夜，造化抑何神。", "谁道二分无赖，到处一轮都满，天未始私人。", "今夕果何夕，非夏亦非春。", "风露下，明作哲，圣之清。", "纷纷浮世代谢，燕客与鸿宾。", "欢恨离愁尽扫，谢赋鲍诗高束，一枕听严更。", "尔自屋梁落，吾已醉醺醺。"]'),
('song-ci-540','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','薄酒长亭别，饱饭故园归。',114,'宋词/ci.song.15000.json','["薄酒长亭别，饱饭故园归。", "两年婉婉席上，甘苦每同之。", "騄骥群中独步，糜鹿兴前不瞬，孰可与争驰。", "力挽不能寸，健翮遽斜飞。", "经营事，艰难状，老天知。", "区区塞马得失，一笑付观棋。", "用则风云万里，不用烟霞一壑，两鬓未应丝。", "回首乌樯外，鸥鸟自忘机。"]'),
('song-ci-541','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','壁垒壮西塞，形势古州来。',114,'宋词/ci.song.15000.json','["壁垒壮西塞，形势古州来。", "九重庙算经远，边隙肯轻开。", "整顿金城千仞，遮护风寒数处，蛇豕敢当哉。", "惆怅倚长剑，扫未尽烟埃。", "骑连营，桥列栅，木成排。", "老酋鱼釜视我，孰与障吾淮。", "横槊冲围四出，北府牢之何勇，新进喜多才。", "老子何归矣，击壤乐春台。"]'),
('song-ci-542','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','枣颊上秋色，朔漠寇南来。',114,'宋词/ci.song.15000.json','["枣颊上秋色，朔漠寇南来。", "斧螗蜂猬棼集，腥雾扫难开。", "细看眼前局面，惊落人间匕箸，砥柱者谁哉。", "熊虎贾馀勇，弧兔等轻埃。", "炮雷轰，戈日耀，阵云排。", "不图风定波息，谈笑静长淮。", "休诧穿杨妙手，乘早闹蓝抽脚，谁拙又谁才。", "束起楼兰剑，归钓子陵台。"]'),
('song-ci-543','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','壮志小鹏背，万里欲乘风。',114,'宋词/ci.song.15000.json','["壮志小鹏背，万里欲乘风。", "马瘏裘敝，老来无复旧游重。", "楚尾吴头蜀口，三十载间陈迹，衮衮水之东。", "休说射雕手，且学钓渔翁。", "奚为者，聊尔耳，此山中。", "壶觞自引，不妨换羽与移宫。", "蓬矢桑弧何事，朝菌大椿皆分，识破色俱空。", "掬润弄明月，长啸倚青松。"]'),
('song-ci-544','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','鸿雁未应到，可怪此番风。',114,'宋词/ci.song.15000.json','["鸿雁未应到，可怪此番风。", "木犀天气，何事爽逼夹衣重。", "长记呼韩塞下，每向飞廉声里，占见马蹄东。", "今日闭门睡，都不管山翁。", "李北平，班定远，魏云中。", "纷纷成败，任取勋业纪南宫。", "幸得明朝无雨，定是中宵有月，莫放酒尊空。", "起舞弄庭叶，清影伴岩松。"]'),
('song-ci-545','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','一番蓼花雨，几阵桂枝风。',114,'宋词/ci.song.15000.json','["一番蓼花雨，几阵桂枝风。", "杖藜多暇，准拟同醉小山重。", "底事阮郎清致，苦托休文瘦损，咫尺阻西东。", "秋色浩如许，岂可欠诗翁。", "门前事，都莫问，付杯中。", "纷纷蛮触等耳，富贵大槐宫。", "何惜振衣而起，相与凭栏一笑，抵掌共谈空。", "佳客傥不至，推枕卧云松。"]'),
('song-ci-546','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','缔好恨不早，觌面雅相志。',114,'宋词/ci.song.15000.json','["缔好恨不早，觌面雅相志。", "璇星楼上，一见天产此英奇。", "功在淮梁砥柱，政蔼汉扶襦裤，仅借寇恂期。", "懊恼剑花冷，手欲鲙鲸鲵。", "濡须坞，咽喉地，腹心谁。", "公其揽辔凭轼，勋业笑谈为。", "贯索旄头息焰，斗极泰阶动色，归佐太平基。", "客有问仆者，只说在渔矶。"]'),
('song-ci-547','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','之子问行役，火伞正当天。',114,'宋词/ci.song.15000.json','["之子问行役，火伞正当天。", "酷哉几可炙手，流汗满襟沾。", "仆仆长亭古道，人在竹舆何似，甑釜受蒸煎。", "帝悯苍生热，敕下九龙渊。", "命丰隆，驱屏翳，起蜚廉。", "神工一炊黍顷，爽气遍垓埏。", "洗涤山河尘土，转作清凉境界，物类举醒然。", "稽首谢天赐，伸脚快宵眠。"]'),
('song-ci-548','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','君莫厌行役，易尔此非难。',114,'宋词/ci.song.15000.json','["君莫厌行役，易尔此非难。", "人情无已，久阴忧潦霁忧乾。", "借得庭轩一榻，忘却征涂炎暑，小驻瀹龙团。", "世路任渠险，襟抱五湖宽。", "叹平生，环辙迹，已苍颜。", "梅花雪片万里，奚又絷南冠。", "应是江山好处，犹待推排老眼，天未许休官。", "莫忆故园竹，日日报平安。"]'),
('song-ci-549','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','乔木老盘谷，仙李盛峨岷。',114,'宋词/ci.song.15000.json','["乔木老盘谷，仙李盛峨岷。", "参横井转，月边犹赖有长庚。", "传得丹溪正派，更是平庵宅相，夷路早蜚英。", "十载星沙幕，一片玉壶冰。", "题舆了，千万里，尽云津。", "渚宫小驻，不妨谈笑对秋城。", "西去凭熊驾驷，东下握兰持橐，衮衮看峥嵘。", "愿借鹫峰桂，岁以寿金觥。"]'),
('song-ci-550','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','万里净无翳，一镜独当天。',114,'宋词/ci.song.15000.json','["万里净无翳，一镜独当天。", "老蟾痴兔顽甚，阅世几何年。", "任尔炎凉千变，不改山河一色，爽气逼人寒。", "何必乘槎去，直到斗牛间。", "叹常娥，元不嫁，只孤眠。", "古今遗恨，不能长似此宵圆。", "我有竹溪茅舍，办取金风玉露，一笑四并全。", "细和坡仙句，低唱教婵娟。"]'),
('song-ci-551','满江红','李曾伯','宋','宋词','song-ci','满江红','[]','镇日山行，人倦也、马还无力。',115,'宋词/ci.song.15000.json','["镇日山行，人倦也、马还无力。", "游历处，总堪图画，足供吟笔。", "涧水绿中声漱玉，岭云白外光浮碧。", "信野花、啼鸟一般春，今方识。", "真可羡，林泉客。", "真可叹，尘埃役。", "想希夷冷笑，我曹踪迹。", "七十二峰神物境，几千万壑仙人室。", "待身名、办了却归来，相寻觅。"]'),
('song-ci-552','满江红','李曾伯','宋','宋词','song-ci','满江红','[]','衮衮青春，都只恁、堂堂过了。',115,'宋词/ci.song.15000.json','["衮衮青春，都只恁、堂堂过了。", "才解得，一分春思，一分春恼。", "儿态尚眠庭院柳，梦魂已入池塘草。", "问不知、春意到花梢，深多少。", "花正似，人人小。", "人应似，年年好。", "奈吴帆望断，秦关声杳。", "不恨碧云遮雁绝，只愁红雨催莺老。", "最苦是、茅店月明时，鸡声晓。"]'),
('song-ci-553','满江红','李曾伯','宋','宋词','song-ci','满江红','["\u897f\u6e56"]','天顾坤维，烦紫气、来从南斗。',115,'宋词/ci.song.15000.json','["天顾坤维，烦紫气、来从南斗。", "鞭才定，匆匆塞上，咏薇吟柳。", "少借日边霖雨望，教知天下风云手。", "听吾民、争说近年无，前朝有。", "平安夜，舒长昼。", "笳鼓静，笙歌奏。", "记西湖五月，藕花时候。", "待把雁门冠带了，归来麟阁丹青旧。", "放蜀山、万点入樽罍，为君寿。"]'),
('song-ci-554','满江红','李曾伯','宋','宋词','song-ci','满江红','[]','姑射山人，仙去后、唯存标格。',115,'宋词/ci.song.15000.json','["姑射山人，仙去后、唯存标格。", "犹赖有、墨池老手，草玄能白。", "留得岁寒风骨在，岂烦造化栽培力。", "有世间、肉眼莫教看，非渠识。", "元不夜，枝何月。", "元未腊，花何雪。", "最孤高不受，多情轻折。", "只有暗香天靳予，黄金作指难为术。", "更若将、解语付真真，空成色。"]'),
('song-ci-555','满江红','李曾伯','宋','宋词','song-ci','满江红','[]','老去生涯，都付与、一丘一壑。',115,'宋词/ci.song.15000.json','["老去生涯，都付与、一丘一壑。", "功名事，惭非好手，几逢危著。", "走马斗鸡年少趣，椎牛酾酒军中乐。", "到而今、浑似梦中看，休休莫。", "江湖路，西风恶。", "霄汉志，秋云薄。", "更那堪州铁，铸成重错。", "当贵买臣毋足羡，知非伯玉真能觉。", "问心期、应有海翁鸥，山人鹤。"]'),
('song-ci-556','满江红','李曾伯','宋','宋词','song-ci','满江红','["\u897f\u6e56"]','竹马同游，平生志、相期霄壑。',115,'宋词/ci.song.15000.json','["竹马同游，平生志、相期霄壑。", "今老矣，儒冠宁误，戎妆徒著。", "卷起鲸鲵江海事，放教禽鸟山林乐。", "问尚堪、舞剑渡河无，公应莫。", "粟可饭，衣从恶。", "秫可酒，茶胜薄。", "但此身长健，老天不错。", "竹院昼闲参内景，蒲团夜坐披圆觉。", "愿此生、无愧北山猿，西湖鹤。"]'),
('song-ci-557','满江红','李曾伯','宋','宋词','song-ci','满江红','[]','小小池亭，仿佛似、洛川岩壑。',115,'宋词/ci.song.15000.json','["小小池亭，仿佛似、洛川岩壑。", "天付与、老身游戏，馀生吃著。", "剩喜酒能消思虑，翻疑书解妨人乐。", "听雨翁、白雪寄新词，愁言莫。", "毋自叹，蒿莱恶。", "甘自味，齑盐薄。", "对乱花丛竹，翠红交错。", "元亮悦闻亲友话，羲之常恐儿曹觉。", "望碧云、休忆女乘鸾，人骑鹤。"]'),
('song-ci-558','满江红','李曾伯','宋','宋词','song-ci','满江红','[]','既作闲人，便应付、此身沟壑。',115,'宋词/ci.song.15000.json','["既作闲人，便应付、此身沟壑。", "不应更，将愁半点，寸心中著。", "责子渊明徒自苦，忧君范老何时乐。", "纵一嘲、一咏欲奚为，何如莫。", "不自鄙，葵蔬恶。", "还肯荐，茅柴薄。", "任侯门海陆，杂陈珍错。", "有暇盍联车骑过，相忘勿遣诗情觉。", "怕家僮、无处买莼鲈，烹琴鹤。"]'),
('song-ci-559','贺新郎','李曾伯','宋','宋词','song-ci','贺新郎','[]','万里归朝去。',142,'宋词/ci.song.15000.json','["万里归朝去。", "倚江亭、绿波碧色，一川晴絮。", "赢得威名留草木，玉垒雪山高处。", "未应减、平淮裴度。", "见说金瓯书字久，待公来、便作商岩雨。", "休望却，蜀都赋。", "旌旗回首春城暮。", "听樯头、飞燕似把，人情低诉。", "两两三三鸥鹭里，拍拍船儿一羽。", "算惟有、清芬载取。", "百万人家儿样恋，恨柳风、不为留连住。", "离梦绕，沙堤路。"]'),
('song-ci-560','贺新郎','李曾伯','宋','宋词','song-ci','贺新郎','[]','满酌荆州酒。',142,'宋词/ci.song.15000.json','["满酌荆州酒。", "望莱庭、斑衣拜祝，俾吾亲寿。", "玉水雪楼游宦地，近访甘棠依旧。", "逢父老、颂声盈口。", "争道蜀边劳数载，也真宜、略畔云横岫。", "小儿辈，任成否。", "东皋十月梅开后。", "想亲朋、团栾一笑，从容觞豆。", "塞上弓刀成底事，不过腰金如斗。", "算不直、渊明株柳。", "只恐鲸鲵无计取，更须烦、绿野持竿手。", "看勋业，国长久。"]'),
('song-ci-561','贺新郎','李曾伯','宋','宋词','song-ci','贺新郎','[]','将谓霏微雨。',142,'宋词/ci.song.15000.json','["将谓霏微雨。", "恍朝来、虚檐生白，寒侵冒絮。", "拟和盐花凌谢韫，巧思翻成金注。", "谁寄我、雪车冰柱。", "酿熟羊羔炉拥兽，羡画楼、金帐调宫羽。", "人应共，回风舞。", "围场校猎淮云暮。", "记当时、银杯缟带，网禽罝兔。", "老去不禁鞍马力，独对愁吟似甫。", "问一棹、剡溪何处。", "愿与铁衣春解戍，把梁园、旧话供儿语。", "孤梅外，梦魂度。"]'),
('song-ci-562','贺新郎','李曾伯','宋','宋词','song-ci','贺新郎','[]','才过黄花雨。',142,'宋词/ci.song.15000.json','["才过黄花雨。", "问长堤、依依万柳，未春何絮。", "一目河山银幻出，惊诧夜光流注。", "巍观矗、玉为云柱。", "风卷寒庐迷过雁，渺沧波、莫认沙鸥羽。", "千万蝶，空中舞。", "霸桥寂寞前溪暮。", "耸诗肩、霜裘拥貉，月毫挥兔。", "记得梅奴曾索笑，解珮如逢交甫。", "今孤垒、寒烟深处。", "休说鹅池平蔡事，庆新年、一稔欢相语。", "持大白，勿虚度。"]'),
('song-ci-563','贺新郎','李曾伯','宋','宋词','song-ci','贺新郎','[]','幸得闲中趣。',142,'宋词/ci.song.15000.json','["幸得闲中趣。", "问何为、倏逾桂岭，重来荆渚。", "唤醒门前弧矢梦，钩月相辉初度。", "谩羞听、军中鼙鼓。", "马上弓刀成底事，仅平明、旆入襄州去。", "能不愧，古羊杜。", "此身何以酬明主。", "怅新来、鬓毛添白，衰容如许。", "三万貔貅齐贾勇，好为一清狐兔。", "看柳色、大堤如故。", "世事付之杯酒外，那棋边、得失都休语。", "来共看，雁儿舞。"]'),
('song-ci-564','念奴娇','李曾伯','宋','宋词','song-ci','念奴娇','[]','黄梅过雨，望隔林、一缕长烟浮碧。',120,'宋词/ci.song.15000.json','["黄梅过雨，望隔林、一缕长烟浮碧。", "亟拥征鞍寻午梦，卧看青山排闼。", "扫户风清，拂檐云淡，爽气生萧发。", "黄粱惊觉，子规枝上啼彻。", "堪羡麦熟蚕成，酒香鸡嫩，风味农家别。", "幸有住山供活计，何苦江湖南北。", "菊老陶园，瓜荒邵圃，空负干时策。", "洛阳三顷，胜如金印六国。"]'),
('song-ci-565','念奴娇','李曾伯','宋','宋词','song-ci','念奴娇','[]','平生宦海，是几番风雨，几番霜雪。',120,'宋词/ci.song.15000.json','["平生宦海，是几番风雨，几番霜雪。", "绿野来归身强健，镜里微添华发。", "剑束床头，书寻架上，富贵轻於叶。", "南坡石竹，年来尤更清绝。", "好是梅坞松关，对湘溪一曲，翠屏千叠。", "柱杖篮舆诗卷里，尚小东山勋业。", "只恐鸥盟，难望鹤怨，未是闲时节。", "片云收却，照人依旧明月。"]'),
('song-ci-566','念奴娇','李曾伯','宋','宋词','song-ci','念奴娇','[]','云胡不喜。',120,'宋词/ci.song.15000.json','["云胡不喜。", "得抽脚篮中，安身局外。", "世路风涛都历遍，几度眉攒心碎。", "八尺藤床，二升粟饭，方寸恢馀地。", "翻云覆雨，从伊造物儿戏。", "不见刻木牵丝，鸡皮鹤发，弄罢寂无事。", "随分风光堪领略，聊放疏狂些子。", "刘项雌雄，跖颜修短，无彼亦无此。", "茅檐高卧，不知春到花底。"]'),
('song-ci-567','念奴娇','李曾伯','宋','宋词','song-ci','念奴娇','[]','浮生如寄，叹征尘驱我，担簦西去。',120,'宋词/ci.song.15000.json','["浮生如寄，叹征尘驱我，担簦西去。", "烟障云屏相迎送，几幅鹅溪缣素。", "挥汗流金，饮冰漱玉，桃叶呼前渡。", "若将有意，道傍一鹭延伫。", "细读壁上龙蛇，太丘笔在，更著茶玻句。", "樽酒十年今白发，不改江流东注。", "胜概难逢，旅怀易动，信美非吾土。", "恨无六翮，长风万里高举。"]'),
('song-ci-568','满庭芳','李曾伯','宋','宋词','song-ci','满庭芳','[]','浪拍金鳌，春浮铁瓮，气清天朗如秋。',118,'宋词/ci.song.15000.json','["浪拍金鳌，春浮铁瓮，气清天朗如秋。", "江皋无事，飞盖强追游。", "万顷蒲萄光里，风樯共、塔影悠悠。", "人间事，年华似掷，一水与俱流。", "绸缪。", "千古恨，纷纷离合，晋宋曹刘。", "望长安何处，落照西头。", "往事苍苔陈迹，夷吾在、吾属何愁。", "清樽畔，谁能为我，一曲舞梁州。"]'),
('song-ci-569','满庭芳','李曾伯','宋','宋词','song-ci','满庭芳','[]','山接平芜，烟横远墅，修眉淡抹晴妆。',118,'宋词/ci.song.15000.json','["山接平芜，烟横远墅，修眉淡抹晴妆。", "菊梅交际，天未十分霜。", "几许无穷秋思，空凝伫、衰柳斜阳。", "溪头路，黄芦一片，凫雁两三行。", "平章。", "风景似，画图一幅，著我徜徉。", "山中无事，聊尔适吾狂。", "不用登临感慨，青帘外、新酒堪尝。", "何为者，东家宋玉，千古叹凄凉。"]'),
('song-ci-570','瑞鹤仙','李曾伯','宋','宋词','song-ci','瑞鹤仙','[]','百年过半也。',126,'宋词/ci.song.15000.json','["百年过半也。", "怅壮心零落，鬓星星也。", "风儿渐凉也。", "近中秋月儿，又初生也。", "田园暇也。", "矍铄哉、是翁也。", "记当时，弧矢垂门，孤负四方志也。", "休也。", "牙签插架，玉帐持麾，总成非也。", "浮生梦也。", "皇皇欲、奚为也。", "趁身闲、随分粗衣淡饭，一笑又何妨也。", "问神仙，底处蓬莱，醉乡是也。"]'),
('song-ci-571','喜迁莺','李曾伯','宋','宋词','song-ci','喜迁莺','["\u897f\u6e56"]','轻云暮卷，望澄空如水，千里一碧。',126,'宋词/ci.song.15000.json','["轻云暮卷，望澄空如水，千里一碧。", "菱镜冰悬，桂轮玉碾，喜见中原秋色。", "老蟾炯炯无翳，阅尽尘寰今夕。", "堪恨处，度霓裳曾到，长生宫阙。", "坐客。", "休叹息。", "看此清光，天岂限南北。", "便好乘风，为持玉斧，修取山河如一。", "西湖旧时花草，会遣孀娥重识。", "从今去，举太平玩事，长如今夕。"]'),
('song-ci-572','声声慢','李曾伯','宋','宋词','song-ci','声声慢','[]','红绡剪就，绛蜡熔成，天然一种仙姿。',119,'宋词/ci.song.15000.json','["红绡剪就，绛蜡熔成，天然一种仙姿。", "竹外家风，凄凉俭薄为宜。", "东君苦怜消瘦，强教伊、傅粉匀脂。", "较量尽，胜夭桃轻俗，繁杏粗肥。", "好是新妆雅态，对疏蟾淡淡，薄雾霏霏。", "迥出红尘，轻盈玉骨冰肌。", "犹嫌污人颜色，谁云似、虢国娥眉。", "香韵别，怕满园、蜂蝶未知。"]'),
('song-ci-573','声声慢','李曾伯','宋','宋词','song-ci','声声慢','[]','修洁孤高，凌霜傲雪，潇然尘外丰姿。',119,'宋词/ci.song.15000.json','["修洁孤高，凌霜傲雪，潇然尘外丰姿。", "一白无瑕，玉堂茅舍俱宜。", "飘飘羽衣缟袂，都不染、富贵膏脂。", "调羹事，看水边清瘦，雨后红肥。", "偏爱春工尚浅，向南枝信透，东阁香霏。", "翠袖犹寒，不禁弱质柔肌。", "浑如故人邂逅，聊相与、一笑开眉。", "归去晚，任帘栊、深闭未知。"]'),
('song-ci-574','青玉案','李曾伯','宋','宋词','song-ci','青玉案','[]','栖鸦啼破烟林暝。',81,'宋词/ci.song.15000.json','["栖鸦啼破烟林暝。", "把旅梦、俄惊醒。", "猛拍征鞍登小岭。", "峰回路转，月明人静，幻出清凉境。", "马蹄踏碎琼瑶影。", "任露压巾纱未忺整。", "贪看前山云隐隐。", "翠微深处，有人家否，试击柴扃问。"]'),
('song-ci-575','青玉案','李曾伯','宋','宋词','song-ci','青玉案','[]','去年曾借梅为寿。',80,'宋词/ci.song.15000.json','["去年曾借梅为寿。", "转眼垂弧小春又。", "一笑巡檐清影瘦。", "雪边聊且，收香藏白，少俟融和透。", "新来东阁高吟就。", "金鼎家声自依旧。", "唤取玉妃重举酒。", "百花头上，一枝芳信，终属东君手。"]'),
('song-ci-576','好事近','李曾伯','宋','宋词','song-ci','好事近','[]','春在粉墙西，墙里不知春色。',53,'宋词/ci.song.15000.json','["春在粉墙西，墙里不知春色。", "惟有桃花一树，似故园曾识。", "晚来携客上南楼，山外又山隔。", "准拟清明何处，问东风知得。"]'),
('song-ci-577','柳梢青','李曾伯','宋','宋词','song-ci','柳梢青','[]','万里青天，西来后我，先我东归。',61,'宋词/ci.song.15000.json','["万里青天，西来后我，先我东归。", "夜月鞭筹，春风幕府，鹗荐争推。", "杯行到手休辞。", "道秋菊、春兰有时。", "若到松江，莫惊鸥鹭，记取坡词。"]'),
('song-ci-578','虞美人','李曾伯','宋','宋词','song-ci','虞美人','[]','韶华只隔窗儿外。',66,'宋词/ci.song.15000.json','["韶华只隔窗儿外。", "病起昏於醉。", "花开花落总相忘。", "惟有梦随胡蝶、趁春忙。", "故园芳草应如旧。", "只恨人消瘦。", "拟凭飞燕语归期。", "拼却牡丹开了、有酴縻。"]'),
('song-ci-579','减字木兰花','李曾伯','宋','宋词','song-ci','减字木兰花','[]','无可不可。',52,'宋词/ci.song.15000.json','["无可不可。", "还你天公还我我。", "味触声香。", "尽付庄周蝶满床。", "谩天不过。", "留取心机休用破。", "净几明窗。", "乐取闲中日月长。"]'),
('song-ci-580','减字木兰花','李曾伯','宋','宋词','song-ci','减字木兰花','[]','如何则可。',52,'宋词/ci.song.15000.json','["如何则可。", "我亦不知其谓我。", "隐几焚香。", "对酒一壶书一床。", "知仁观过。", "浑沌翻怜谁凿破。", "寄傲南窗。", "堪羡渊明滋味长。"]'),
('song-ci-581','西江月','李曾伯','宋','宋词','song-ci','西江月','[]','不暖不寒天气，无思无虑山人。',58,'宋词/ci.song.15000.json','["不暖不寒天气，无思无虑山人。", "竹窗时听野禽鸣。", "更有松风成韵。", "竟日蒲团打坐，有时藜杖闲行。", "呼童开酒荐杯羹。", "欲睡携书就枕。"]'),
('song-ci-582','西江月','李曾伯','宋','宋词','song-ci','西江月','[]','排遣新寒有酒，追寻旧隐无人。',58,'宋词/ci.song.15000.json','["排遣新寒有酒，追寻旧隐无人。", "四山朔吹又冬鸣。", "吹送午锺馀韵。", "过眼霜高木落，寄心月驶云行。", "归欤闭户饱藜羹。", "世事华胥一枕。"]'),
('song-ci-583','糖多令・唐多令','李曾伯','宋','宋词','song-ci','糖多令・唐多令','["\u957f\u6c5f"]','枫荻响飕飕。',74,'宋词/ci.song.15000.json','["枫荻响飕飕。", "长江六月秋。", "二十年、重到沙头。", "城郭人民那似旧，曾识面、两三鸥。", "落日且登楼。", "英雄休涕流。", "望黄旗、王气东浮。", "借问烟芜苍莽处，还莫是、古襄州。"]'),
('song-ci-584','点绛唇','李曾伯','宋','宋词','song-ci','点绛唇','[]','懒上巍楼，楚江一望天无际。',50,'宋词/ci.song.15000.json','["懒上巍楼，楚江一望天无际。", "漫游萍寄。", "莫挽东流水。", "一片秋光，直到山阴里。", "人还记。", "戍边归未。", "更忆鲈鱼美。"]'),
('song-ci-585','摸鱼儿','李曾伯','宋','宋词','song-ci','摸鱼儿','[]','趁西风、且登黄鹤，挥豪先奏秋赋。',140,'宋词/ci.song.15000.json','["趁西风、且登黄鹤，挥豪先奏秋赋。", "燕山桂种清分在，人物翩翩如许。", "堪羡处。", "长安近、蟾宫相继金闺步。", "佳哉盛举。", "看精淬龙泉，厚培鹏背，自此要津去。", "荆州事，多幸乡情相予。", "几番灯柝棋墅。", "转头江阔轻帆速，梦入吴松鸥鹭。", "君记取。", "旧王粲、曾言信美非吾土。", "故人相语。", "为细数艰难，满头雪白，无奈戌边苦。"]'),
('song-ci-586','摸鱼儿','李曾伯','宋','宋词','song-ci','摸鱼儿','[]','对垂弧、引觞一笑，凄凉薄分天气。',140,'宋词/ci.song.15000.json','["对垂弧、引觞一笑，凄凉薄分天气。", "丁年驰骛弓刀后，报国孤忠自许。", "堪叹处。", "今老矣，强颜犹踵邯郸步。", "安能远举。", "谩目送征鸿，梦劳胡蝶，无计便归去。", "清闲禄，旧说天公靳予。", "何时松菊村墅。", "生非燕颔鸢肩相，岂是觚棱鹓鹭。", "收拾取。", "休直似、文渊定远空怀土。", "阿戎可语。", "待乞得身还，屏伊世累，甘受作诗苦。"]'),
('song-ci-587','朝中措','李曾伯','宋','宋词','song-ci','朝中措','[]','少年随分赋鹦洲。',57,'宋词/ci.song.15000.json','["少年随分赋鹦洲。", "得意桂花秋。", "今日送君行色，梦和月到南楼。", "材名仲父，辞华季子，香满南州。", "勉力中流击楫，直须连钓鳌头。"]'),
('song-ci-588','齐天乐','李曾伯','宋','宋词','song-ci','齐天乐','[]','少年塞上秋来早，昴街尚馀芒曜。',123,'宋词/ci.song.15000.json','["少年塞上秋来早，昴街尚馀芒曜。", "举目关河，惊心弧矢，顾我岂堪戎纛。", "几番凤诰。", "愧保障何功，恩隆旒藻。", "笑指呼鹰，露花烟草忆刘表。", "头颅如许相与，岁寒犹赖有，白发公道。", "对月怀人，临风访古，往事凄凉难考。", "何时是了。", "莫驰志伊吾，贪名清庙。", "松菊归来，稽山招此老。"]'),
('song-ci-589','八声甘州','李曾伯','宋','宋词','song-ci','八声甘州','[]','正莼鲈佳梦绕吴乡，牙樯忍轻离。',118,'宋词/ci.song.15000.json','["正莼鲈佳梦绕吴乡，牙樯忍轻离。", "向仲宣楼上，凭高举酒，几共灯棋。", "曾记少陵留咏，出幕合持麾。", "飞盖长安去，华贯平跻。", "好是倚门迎笑，恰野堂云壑，菊后梅时。", "庆凤雏新长，携手奉莱衣。", "抚孤松、绝胜细柳，念征人、徒老玉关西。", "归来也，幅巾藜杖，办取追随。"]'),
('song-ci-590','八声甘州','李曾伯','宋','宋词','song-ci','八声甘州','[]','领青油车骑出郊坰，来游晋龙山。',118,'宋词/ci.song.15000.json','["领青油车骑出郊坰，来游晋龙山。", "喜水天澄霁，稻畦镰净，榆塞戈闲。", "登高谩酬佳节，一笑破苍颜。", "剩泛茱萸菊，杯莫留残。", "休说参军往事，意当时凝眺，不到长安。", "赖座间小异，豪气眇尘寰。", "到如今、祗成佳话，记封姨、曾荐众宾欢。", "吾曹事，有如此酒，要共弹冠。"]'),
('song-ci-591','八声甘州','李曾伯','宋','宋词','song-ci','八声甘州','[]','怅浮生、俯仰迹成空，依然此江山。',119,'宋词/ci.song.15000.json','["怅浮生、俯仰迹成空，依然此江山。", "对秋容如画，天长雁度，水阔鸥闲。", "追游未甘老态，凭酒借红颜。", "归骑斜阳外，柳老荷残。", "幸对黄花时节，喜宾朋晤语，烽火平安。", "仅风巾一笑，名尚满人寰。", "要流芳、相期千载，肯区区、徒恋片时欢。", "姑聊尔，招呼楚调，慰藉南冠。"]'),
('song-ci-592','满庭芳','李曾伯','宋','宋词','song-ci','满庭芳','[]','八足横戈，一身衷甲，将军致尔来前。',118,'宋词/ci.song.15000.json','["八足横戈，一身衷甲，将军致尔来前。", "呼僮解缚，亟荐泽虞鲜。", "族类横行草地，今骈首、鼎镬连连。", "荆江上，不图霜后，风味似吴天。", "晴川。", "千里外，分甘遗远，多谢勤拳。", "对香枨新酒，一洗腥膻。", "慰我吟情归思，都忘却、张孟鲈鳊。", "持螯了，老饕作赋，佳话楚乡传。"]'),
('song-ci-593','哨遍','李曾伯','宋','宋词','song-ci','哨遍','[]','大块赋形，皇览揆予，俾尔昌而寿。',248,'宋词/ci.song.15000.json','["大块赋形，皇览揆予，俾尔昌而寿。", "嗟壮游。", "岁月老征裘。", "向秋来、顿如蒲柳。", "桂开又。", "鲈莼蟹橙正美，故人应忆传杯手。", "想薜荔岩峦，梧桐庭院，当时风景依旧。", "对斜阳、极目倚危楼。", "问一舸、何时过吴头。", "乘下泽车，戴华阳巾，锦衣游昼。", "犹。", "客有名流。", "交情金石襟期厚。", "双湖烟艇里，剑锋紫气冲斗。", "剩妙墨淋漓，清歌发越，未应独步诗千首。", "待挂了衣冠，来寻杖履，陪君此乐须有。", "到如今、不愿酒泉侯。", "愿生入、玉门早归休。", "任远人、从问安否。", "梁园宾客虽富。", "谁出相如右。", "相逢身健，时平无事，是处溪山明秀。", "与君举斝若为酬。", "有年年、人月长久。"]'),
('song-ci-594','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','[]','黄旗吉语飞来，胡儿已落将军手。',126,'宋词/ci.song.15000.json','["黄旗吉语飞来，胡儿已落将军手。", "吾皇神武，一新城郭，断谟天授。", "铁骑才临，雕戈竞逐，击蛇先首。", "快风驱雨洗，江空谷静，淮淝上、似之否。", "此事老臣何有。", "想捷传、延英方昼。", "玉颜应笑，金瓯堪保，贺声交口。", "吾责免夫，吾归可矣，萧然一叟。", "把功名，分付诸公，聊自尝酒盈斗。"]'),
('song-ci-595','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','[]','荆州咫尺神州，几番得失孙刘手。',126,'宋词/ci.song.15000.json','["荆州咫尺神州，几番得失孙刘手。", "山河天险，东南牖户，钺何轻授。", "泪落碑存，鹤归城是，不堪回首。", "喜大堤草色，镇长春在，羊与陆、孰能否。", "风景依然吾有。", "柳营深、铁衣闲画。", "摩云胜气，追戎马足，走蜚狐口。", "往事纷纷，付之蛮触，相忘庄叟。", "有人焉，中夜闻鸡，剑光正烛牛斗。"]'),
('song-ci-596','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','[]','吾皇神武中兴，直须整顿舆图旧。',126,'宋词/ci.song.15000.json','["吾皇神武中兴，直须整顿舆图旧。", "岂惟天顾，岷峨一角，但西其首。", "遮护咽喉，扶持气派，宁无医手。", "有庙谟先定，傍观何待，留侯蹑、魏侯肘。", "天眷我家仁厚。", "盛英才、载量车斗。", "中流孤艇，千钧一发，老夫何有。", "休对秋风，移宫换羽，吟无绝口。", "看福星，太乙临梁，此虏自不能久。"]'),
('song-ci-597','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','[]','梅边连辔偕来，柳边先我观光去。',126,'宋词/ci.song.15000.json','["梅边连辔偕来，柳边先我观光去。", "一门椿桂，尊君孙盛，小儿文举。", "黄鹤联登，横翔雕鹗，健凌鹦鹉。", "趁霜晴春小，南宫问讯，又同奏、明光赋。", "从此青云阔步。", "看龙门、锦标双取。", "荆州时事，不妨大对，细陈当宁。", "久要论交，中年语别，不堪离绪。", "约杏园，得意归时，吾已在浙江浒。"]'),
('song-ci-598','满江红','李曾伯','宋','宋词','song-ci','满江红','[]','千古襄阳，天岂肯、付之荆棘。',115,'宋词/ci.song.15000.json','["千古襄阳，天岂肯、付之荆棘。", "宸算定、图回三载，一新坚壁。", "狼吻不甘春哨衄，马蹄又踏寒滩入。", "向下洲、一鼓扫群胡，三军力。", "连帅是，并州绩。", "宾佐有，雍丘逖。", "赖阴人成事，同心却敌。", "见说陈尸三十里，投鞍委甲如山积。", "待老臣、为作岘樊铭，劖诸石。"]'),
('song-ci-599','满江红','李曾伯','宋','宋词','song-ci','满江红','[]','推枕闻鸡，正怪得、乾坤都白。',115,'宋词/ci.song.15000.json','["推枕闻鸡，正怪得、乾坤都白。", "元是有、福星临照，至和薰出。", "缘饰夜城疑不夜，弥漫色界成无色。", "更摛词、巧欲夺天葩，尤殊特。", "貂帽拥，寒何力。", "羔酿举，情何极。", "欠开樽细挹，梅花标格。", "十万铁衣冰到骨，祈天只愿王师息。", "想家童、日办剡中舟，溪头立。"]'),
('song-ci-600','满江红','李曾伯','宋','宋词','song-ci','满江红','[]','荡节将行，原显尽、花毡铺白。',115,'宋词/ci.song.15000.json','["荡节将行，原显尽、花毡铺白。", "人羡道、青丝辔整，红蕖幕出。", "宇宙中间无点医，水天上下俱同色。", "向个中、著此玉为人，真英特。", "元自得，融和力。", "浑不管，凝寒极。", "看福星临照，政敷民格。", "且访桃源仙世界，伫传梅驿春消息。", "定明年、拜表贺端闱，螭坳立。"]'),
('song-ci-601','八声甘州','李曾伯','宋','宋词','song-ci','八声甘州','[]','自当年、种柳向西门，古今号名州。',119,'宋词/ci.song.15000.json','["自当年、种柳向西门，古今号名州。", "对风声策策，浪涛衮衮，又是新秋。", "暂为江山弹压，谁得似贤侯。", "夜观灯棋里，几共边筹。", "休效季鹰高兴，为莼羹鲈脍，遽念吴头。", "且安排维楫，相与济中流。", "看邦人、尽歌襦裤，愿紫皇、乞与福星留。", "令人忆，数行过雁，月在南楼。"]'),
('song-ci-602','八声甘州','李曾伯','宋','宋词','song-ci','八声甘州','[]','续仲宣、一赋小呼鹰，声名满荆州。',119,'宋词/ci.song.15000.json','["续仲宣、一赋小呼鹰，声名满荆州。", "向宾筵游戏，豪端月露，皮里阳秋。", "遍历文书刁斗，何患不封侯。", "横槊风烟表，独占诗筹。", "见说眉攒心事，在岷峨乡国，落日西头。", "怅英豪遗恨，都付大江流。", "伟平生、经纶雅志，把重弓、聊为汉关留。", "中秋近，何如载酒，一笑登楼。"]'),
('song-ci-603','八声甘州','李曾伯','宋','宋词','song-ci','八声甘州','[]','自六朝、用武诧荆州，襟喉重疆陲。',119,'宋词/ci.song.15000.json','["自六朝、用武诧荆州，襟喉重疆陲。", "更西风似箭，峡江如线，事势夔夔。", "须仗中流砥柱，天付治平谁。", "甚矣吾衰矣，将老东篱。", "休说纷纷往梦，任阴平邓艾，骆谷姜维。", "向棋边聊且，官事了痴儿。", "雨未阴、毋忘户牖，挂长绳、系不住铜仪。", "空遐想，桃源春媚，安得追随。"]'),
('song-ci-604','八声甘州','李曾伯','宋','宋词','song-ci','八声甘州','[]','对西风、先自念莼鲈，又还月生西。',119,'宋词/ci.song.15000.json','["对西风、先自念莼鲈，又还月生西。", "叹平生霜露，而今都在，两鬓丝丝。", "当年门垂蓬矢，壮岁竟奚为。", "磊落中心事，只有天知。", "多谢君恩深厚，费丁宁温诏，犹置驱驰。", "看弓刀何事，终是愧毛锥。", "愿今年、四郊无警，向酒边、多作数篇诗。", "山林下，相将见一，舍我其谁。"]'),
('song-ci-605','八声甘州','李曾伯','宋','宋词','song-ci','八声甘州','[]','问秋光、乞得一宵闲，满引玉东西。',118,'宋词/ci.song.15000.json','["问秋光、乞得一宵闲，满引玉东西。", "喜亲朋咸集，宴酣真乐，非竹非丝。", "坎止流行付分，岂尽是人为。", "试向君平卜，还可前知。", "自笑头颅如此，奈乌轮难系，驹隙如驰。", "慨壮图已矣，指地不须锥。", "任从渠、翻云覆雨，愿老於耕钓乐于诗。", "三军事，天家自有，大将为谁。"]'),
('song-ci-606','八声甘州','李曾伯','宋','宋词','song-ci','八声甘州','[]','仿离骚、览揆度新讴，空云霭乌丝。',119,'宋词/ci.song.15000.json','["仿离骚、览揆度新讴，空云霭乌丝。", "把长庚才调，小施筹笔，犹处囊锥。", "鸾枳鸂滩发轫，指日问朝衣。", "雪片梅花外，已露南枝。", "休羡汉疏晋阮，记当年楚产，同是家儿。", "怅岁华如许，同官复同时。", "引宫商、细赓郢唱，向樽前、谁为一歌之。", "蓬壶侣，长春不老，有美人兮。"]'),
('song-ci-607','八声甘州','李曾伯','宋','宋词','song-ci','八声甘州','[]','记当年、虏压顺昌城，直欲付靴尖。',119,'宋词/ci.song.15000.json','["记当年、虏压顺昌城，直欲付靴尖。", "赖君家乃祖，笑麾白羽，净洗腥膻。", "荆州甘棠蔼蔼，浓墨宇犹鲜。", "少出拿云手，整顿青毡。", "好个嫩凉天气，想闻鸡听雁，意气犹忺。", "看相将喜事，眉色已黄占。", "祝君龄、有如此酒，举金罍、须放十分添。", "还知否，封侯事业，正在华颠。"]'),
('song-ci-608','八声甘州','李曾伯','宋','宋词','song-ci','八声甘州','[]','问孀娥、僝僽厌看人，唯复厌人看。',119,'宋词/ci.song.15000.json','["问孀娥、僝僽厌看人，唯复厌人看。", "正凉宵准拟，招延素魄，慰藉苍颜。", "廉纤梧桐细雨，吹彻玉箫寒。", "仿佛山河影，只在云端。", "又似去年今夕，枉教人愁怅，立尽阑干。", "想菱花尘匣，憔悴女乘鸾。", "恨无从、一登天柱，约宾朋、随分荐清欢。", "持杯祝，老蟾无恙，留待明年。"]'),
('song-ci-609','朝中措','李曾伯','宋','宋词','song-ci','朝中措','[]','灯棋三载客边头。',57,'宋词/ci.song.15000.json','["灯棋三载客边头。", "江汉等萍浮。", "一片白云关念，对床夜雨难留。", "堂堂事会，相期烝楫，供济泾舟。", "今岁雁来应早，着鞭莫待深秋。"]'),
('song-ci-610','朝中措','李曾伯','宋','宋词','song-ci','朝中措','[]','南风吹棹过吴头。',57,'宋词/ci.song.15000.json','["南风吹棹过吴头。", "聚散付云浮。", "且共一杯怀楚，须期万户封留。", "藕花时候，五湖烟雨，西子扁舟。", "转首梦回残角，征人塞上新秋。"]'),
('song-ci-611','朝中措','李曾伯','宋','宋词','song-ci','朝中措','[]','夜来南极十分明。',57,'宋词/ci.song.15000.json','["夜来南极十分明。", "申月应生申。", "小范龙图老子，大苏玉局仙人。", "擎天健手，家传方略，功在峨岷。", "看取芝封夜下，归来尽展经纶。"]'),
('song-ci-612','贺新凉・贺新郎','李曾伯','宋','宋词','song-ci','贺新凉・贺新郎','[]','可恨经年别。',142,'宋词/ci.song.15000.json','["可恨经年别。", "正安排、剖瓜植竹，拟酬佳节。", "应为犁锄机杼懒，天遣阿香磨折。", "翻一饷、廉纤凄切。", "寂寞金针红线女，枉玉箫、吹断秦楼月。", "清漏静，楚天阔。", "东皋且愿三农悦。", "任从渠、鹊桥蛛网，一番虚设。", "挽取天河聊为我，尽洗西风残热。", "休懊恼、云生巫峡。", "底用乞灵求太巧，看世人、弄巧多成拙。", "姑止酒，命茶啜。"]'),
('song-ci-613','贺新凉・贺新郎','李曾伯','宋','宋词','song-ci','贺新凉・贺新郎','[]','晓听平安报。',141,'宋词/ci.song.15000.json','["晓听平安报。", "信荆州、古今形胜，金汤天造。", "落日岘山陈迹在，依旧大堤芳草。", "叹紫塞、黄尘未扫。", "水合水生来又去，赖胡雏、犹畏熊当道。", "薇柳戌，甚时了。", "乞身屡上盏天表。", "感恩深、丁宁帝语，许同芳召。", "自愧黔驴无伎俩，桑土绸缪盍早。", "空手袖、剑锋懊恼。", "要脍鲸鲵封京观，愿汉庭用壮臣年老。", "毋更取，仲华笑。"]'),
('song-ci-614','贺新凉・贺新郎','李曾伯','宋','宋词','song-ci','贺新凉・贺新郎','[]','梦觉闻鸡报。',141,'宋词/ci.song.15000.json','["梦觉闻鸡报。", "问岘边、晋家城郭，旧邦新造。", "谁遣平明旌旆入，人说当年草草。", "犹幸把、腥埃俱扫。", "对越老苍方寸在，任酉渠、远度龙堆道。", "还又过，一春了。", "少年意气轻三表。", "到如今、名惭小范，功卑前召。", "赖有把茅归去是，乘此抽身须早。", "何苦受、天来烦恼。", "报国丹忠虽未泯，奈长卿已病文渊老。", "聊把酒，仰天笑。"]'),
('song-ci-615','醉蓬莱','李曾伯','宋','宋词','song-ci','醉蓬莱','[]','问金城方略，数十年来，谁堪称许。',120,'宋词/ci.song.15000.json','["问金城方略，数十年来，谁堪称许。", "万福威名，草木识淮浦。", "西顾天长，中流地重，著此巨鳌柱。", "见说棋边，风声鹤唳，胆落胡虏。", "老子家声，六韬亲授，渭水归来，非熊非虎。", "江汉滔滔，建大将旗鼓。", "弧矢开祥，节旄迎渥，勋业纪盟府。", "好对芳天，莺花未老，金樽频举。"]'),
('song-ci-616','醉蓬莱','李曾伯','宋','宋词','song-ci','醉蓬莱','[]','自鹫峰曾见，金粟如来，犹有英烈。',120,'宋词/ci.song.15000.json','["自鹫峰曾见，金粟如来，犹有英烈。", "碧玉琅玕，点缀碎琼屑。", "不御纷华，独餐沆瀣，比众芳殊别。", "好向凉宵，无风无雨，宜露宜月。", "身在山中，名香天下，全似幽人，一种修洁。", "解使多愁，对此亦纾悦。", "缘绮窗前，乌云鬓侧，休为玉人折。", "剩赋新词，满倾佳醑，为成三绝。"]'),
('song-ci-617','醉蓬莱','李曾伯','宋','宋词','song-ci','醉蓬莱','[]','问前身应在，香醉山中，今存风烈。',120,'宋词/ci.song.15000.json','["问前身应在，香醉山中，今存风烈。", "佳夕招延，清论度飞屑。", "玉斝盈盈，金英点点，标格侬家别。", "好个凉天，更无滴雨，只欠些月。", "菊客兰兄，纷纷侪辈，纵尔芬芳，输我高洁。", "鼻观先知，羞取俗颜悦。", "解后成欢，从容挹爽，何羡广寒折。", "我有高吟，为君纪此，一段奇绝。"]'),
('song-ci-618','醉蓬莱','李曾伯','宋','宋词','song-ci','醉蓬莱','[]','大不逾粟许，飘散人间，直恁清烈。',120,'宋词/ci.song.15000.json','["大不逾粟许，飘散人间，直恁清烈。", "管领芳樽，底事不渠屑。", "中夜庭前，小山丛畔，韵度从来别。", "那更今年，留连秋色，将傍菊月。", "堪羡纱窗，胆瓶斜浸，浅酌低讴，人花双洁。", "恼杀多情，一见一回悦。", "生怕朝来，梧桐过雨，把花神摧折。", "倩取骚人，黄香作传，笔未宜绝。"]'),
('song-ci-619','醉蓬莱','李曾伯','宋','宋词','song-ci','醉蓬莱','[]','指梅花雪片，问讯八窗，南枝开未。',120,'宋词/ci.song.15000.json','["指梅花雪片，问讯八窗，南枝开未。", "一点春风，消息岭头寄。", "太白精神，广平韵度，是岂众芳拟。", "东阁吟边，水清月淡，不妨游戏。", "犹记双湖，几番初度，持酒相期，已花为比。", "鼎味家传，须向玉堂里。", "吏隐南昌，未应高兴，香在岁寒际。", "倩取瑶姬，花前一唱，寿吾仙李。"]'),
('song-ci-620','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','天顾坤维，持橐秉旄，屈公此行。',140,'宋词/ci.song.15000.json','["天顾坤维，持橐秉旄，屈公此行。", "正地雷观象，一阳将复，天星验数，五福初临。", "汉指才宣，蜀民相贺，百万耄倪犹更生。", "先声布，便胆寒西贼，关塞无尘。", "休嗟往事营营。", "要清献、乖崖相拟伦。", "看作新精采，叶符气运，转旋机括，元在人心。", "奖率三军，扫清万里，从此西南开太平。", "功成后，却归来廊庙，细展经纶。"]'),
('song-ci-621','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','老子家山，近古苏州，有监本呆。',141,'宋词/ci.song.15000.json','["老子家山，近古苏州，有监本呆。", "叹长途荷担，斯宜已矣，急湍鼓枻，岂不危哉。", "我爱陶潜，休官彭泽，为三径荒芜归去来。", "君恩重，奈边戈未偃，阃毂犹推。", "东南休运将回。", "幸天日清明公道开。", "把孤忠自许，我心匪石，一真难灭，人口如碑。", "青眼旧交，黑头新贵。", "快九万里风鹏背培。", "诗筒寄，正多情未已，聊解君颐。"]'),
('song-ci-622','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','我爱临川，簪绂丛林，有宅一区。',142,'宋词/ci.song.15000.json','["我爱临川，簪绂丛林，有宅一区。", "记谢墩名字，百年犹在，平泉孙子，三世重居。", "皂盖新营，青毡旧识，此复古春秋宜大书。", "奇哉事，信当时种子，下到工夫。", "笑渠。", "驷马门闾。", "是几往过之凡几墟。", "喜尚存遗爱，甘棠在在，无穷生意，茂草如如。", "载酒寻盟，论诗结社，想田可秫兮园可蔬。", "应须念，古鄇亭乔木，无恙还无。"]'),
('song-ci-623','兰陵王','李曾伯','宋','宋词','song-ci','兰陵王','[]','甚天色。',159,'宋词/ci.song.15000.json','["甚天色。", "苦问桃红李白。", "伊祈氏，沙际才归，依约春回晓烟湿。", "老寒犹煞忒。", "景物。", "中年惯识。", "天应遣，雨洗风梳，柳睡花眠尚无力。", "名园谩他适。", "任黄四栽培，殷七奇特。", "一年好处须寒食。", "待花畔携酒，酒边索句，春馀太半未须急。", "记旧隐幽寂。", "我亦。", "几时得。", "归检点苔封，评品梅格。", "教看林下休官一。", "与莺花分界，渔樵争席。", "抚松长啸，芳菲事，尽渠惜。"]'),
('song-ci-624','江神子・江城子','李曾伯','宋','宋词','song-ci','江神子・江城子','[]','白妃卷絮逐风颠。',86,'宋词/ci.song.15000.json','["白妃卷絮逐风颠。", "透朱帘。", "向空漫。", "剪出冰花，偏爱腊前看。", "能费化工多少力，千万里，尽同天。", "歌楼清赏记当年。", "玉人占。", "绣衾寒。", "老去孤高，世虑肯咨煎。", "争似小窗梅影下，聊一笑，付无言。"]'),
('song-ci-625','浪淘沙','李曾伯','宋','宋词','song-ci','浪淘沙','[]','昨夜雨兼风。',64,'宋词/ci.song.15000.json','["昨夜雨兼风。", "断送残红。", "老寒犹自著帘栊。", "为问香篝人语道，翠被还重。", "何处有疏锺。", "惊起匆匆。", "惜春休放酒杯空。", "芳草天涯寒食又，归兴尤醲。"]'),
('song-ci-626','哨遍','李曾伯','宋','宋词','song-ci','哨遍','["\u957f\u6c5f"]','天限长江，云扰中原，一局持棋势。',235,'宋词/ci.song.15000.json','["天限长江，云扰中原，一局持棋势。", "汉将谁。", "盍为扫清之。", "彼伎犹、黔驴而止。", "客亦知。", "何材不生斯世。", "丁宁屡费君王旨。", "向马首论诗，灯前观剑，岂无差强人意。", "幸崆峒麦熟且休师。", "又焉用陈琳檄书飞。", "一笛楼头，万柳营间，从容麾帜。", "噫。", "代有戎夷。", "时贤患乏经纶志。", "紫岩公一出，敌当惊见花字。", "谩被发忧邻，汗颜笑斩，客邪终岂婴元气。", "待拜表盏天，移文问隐，老夫行且归矣。", "怕胡雏穴隙尚相窥。", "有淝水儿曹举兵麾。", "看中兴、隽烈堪继。", "随世样多能底。", "卿自为卿计。", "不妨老子，婆娑矍铄，从渠屦盈户外。", "何须岘万勒丰碑。"]'),
('song-ci-627','兰陵王','李曾伯','宋','宋词','song-ci','兰陵王','[]','问梁益。',158,'宋词/ci.song.15000.json','["问梁益。", "天设金城铁壁。", "西风外，依约雁来，还报关山旧秋色。", "三秦听汉檄。", "远恨绵绵脉脉。", "频年事，虚掷桑阴，褘允诸人竟何策。", "彤弓误殊锡。", "怅活国难医，救世须佛。", "平生本藉毛锥力。", "对弧矢初度，满头白发，何堪兵卫叠画戟。", "咄青史陈碛。", "酒石。", "羡王绩。", "任击缶呼天，此乐何极。", "奚须太息惊前席。", "望天阍休待，梦如陶翼。", "柳边春后，放定远，出西域。"]'),
('song-ci-628','八声甘州','李曾伯','宋','宋词','song-ci','八声甘州','[]','问西陵、治比汉河南，若为遽东归。',119,'宋词/ci.song.15000.json','["问西陵、治比汉河南，若为遽东归。", "正峡江衮衮，中流我共，一楫杭之。", "倏听攀辕告语，公去裤襦谁。", "赖有甘棠在，人口如碑。", "百尺楼头徒倚，记绸缪桑土，几对灯棋。", "指鹭洲何处，心事想鸥知。", "向江湖、毋忘魏阙，正吾皇、当馈急贤时。", "经纶事，更须玩易，勿但言诗。"]'),
('song-ci-629','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','序正象古琥，吉叶梦维熊。',114,'宋词/ci.song.15000.json','["序正象古琥，吉叶梦维熊。", "身随金粟出世，香满小山丛。", "铁券丹书家世，朱阁青毡步武，名字在尧聪。", "雕鹗健云翮，聊尔待西风。", "功名事，书剑里，笑谈中。", "江涛衮衮如此，天岂老英雄。", "先我甲庚三日，伴子春秋千岁，何幸举樽同。", "歌以寿南涧，愿学稼轩翁。"]'),
('song-ci-630','临江仙','李曾伯','宋','宋词','song-ci','临江仙','[]','同此三秋端正月，地高先得光辉。',70,'宋词/ci.song.15000.json','["同此三秋端正月，地高先得光辉。", "分明身世玉琉璃。", "不妨人未老，长与月相期。", "我有芳尊共玩事，从渠魏鹊无枝。", "直须饮到五更时。", "大家眠玉界，莫羡宴瑶池。"]'),
('song-ci-631','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','[]','楚乡三载中秋，倚楼辄值萧萧雨。',127,'宋词/ci.song.15000.json','["楚乡三载中秋，倚楼辄值萧萧雨。", "澄空向午，廉纤数点，又疑虚度。", "卷起云鬟，掣开妆鉴，喜瞻眉宇。", "问常娥丰貌，间何阔矣，元不老、只如故。", "见了悄然无语。", "但令人、不堪怀古。", "老蟾应记，旧时人物，孙刘陶庾。", "俯仰皆空，阴晴何恨，芳樽频举。", "问他年，忆取今宵，人如许、月如许。"]'),
('song-ci-632','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','可爱十分月，都无一点云。',114,'宋词/ci.song.15000.json','["可爱十分月，都无一点云。", "清光是处皆有，浑不许人分。", "独是大江深处，一片水晶世界，仿佛有微痕。", "坐到夜深际，万籁寂无闻。", "与诸君，同一笑，举芳樽。", "素娥自有佳约，何必命红裙。", "顷刻参横斗转，归去华胥一觉，玩事任纷纷。", "我袖有玉斧，当为整乾坤。"]'),
('song-ci-633','眼儿媚','李曾伯','宋','宋词','song-ci','眼儿媚','[]','公归东里我西州。',58,'宋词/ci.song.15000.json','["公归东里我西州。", "枫荻楚天秋。", "乌樯转首，暮云江树，落日沙头。", "瞿唐此去风涛恶，宁愿贾胡留。", "明年春晚，松江笠泽，归约追游。"]'),
('song-ci-634','大','李曾伯','宋','宋词','song-ci','大','[]','对剑花凝，笳叶卷，天宇尘清声肃。',163,'宋词/ci.song.15000.json','["对剑花凝，笳叶卷，天宇尘清声肃。", "楼船催解处，正日戈夕照，风旗西矗。", "虎战龙争，人非地是，形势昔雄三国。", "景升今何在，怅婆娑老子，奚堪荆牧。", "岂自古常言，力宁斗智，智宁如福。", "西征非太速。", "奈臣职、难负君王嘱。", "嗟往事、祁山抗表，剑阁刊铭，祗成堕甑并空轴。", "喜听平安信，岂止为、区区一竹。", "蚊蟁类、笑谈逐。", "玉关归老，不愿封侯食肉。", "愿还太平旧蜀。"]'),
('song-ci-635','浪淘沙','李曾伯','宋','宋词','song-ci','浪淘沙','[]','斜日挂汀洲。',64,'宋词/ci.song.15000.json','["斜日挂汀洲。", "帆影悠悠。", "碧云合处是吴头。", "几片寒芦三两雁，人立清秋。", "柳外莫停舟。", "休问闲愁。", "人生江海一萍浮。", "世路相期如此水，万里安流。"]'),
('song-ci-636','八声甘州','李曾伯','宋','宋词','song-ci','八声甘州','[]','上巍楼、指顾剑东西，依然旧江山。',119,'宋词/ci.song.15000.json','["上巍楼、指顾剑东西，依然旧江山。", "怅谁为荆棘，委渠天险，薄我风寒。", "金瓯经营几载，鸿雁尚漂残。", "一片迷棋局，著手良难。", "犹幸红旗破贼，有竹边新报，喜听平安。", "问纷纷遗事，一笑付凭栏。", "愿天驱、五丁壮士，挽岷峨、生意与春还。", "斜阳外，梦回芳草，人老萧关。"]'),
('song-ci-637','满江红','李曾伯','宋','宋词','song-ci','满江红','[]','才过新正，能几日、海棠开了。',115,'宋词/ci.song.15000.json','["才过新正，能几日、海棠开了。", "将谓是、睡犹未足，嫣然何笑。", "一片殷红新锦样，天机知费春多少。", "更芳期、不待燕黄昏，莺清晓。", "花旧说，南昌好。", "花宜占，东风早。", "想香霏地近，融和偏巧。", "佳句流传千古在，石湖不见坡翁老。", "倩何人、寄驿报家山，教知道。"]'),
('song-ci-638','满江红','李曾伯','宋','宋词','song-ci','满江红','[]','自入春来，花信费、几番风了。',115,'宋词/ci.song.15000.json','["自入春来，花信费、几番风了。", "先付与、红妆万点，苍颜一笑。", "旧说沈香亭北似，今虽濯锦江头少。", "最可人、枝上月笼春，烟含晓。", "亨会称，花王好。", "嘉聘惜，梅兄早。", "对芳容细玩，天然新巧。", "羯鼓不须催太甚，霓裳易散梨园老。", "任杜鹃、犹自殿韶华，呼殷道。"]'),
('song-ci-639','谒金门','李曾伯','宋','宋词','song-ci','谒金门','[]','风又雨。',53,'宋词/ci.song.15000.json','["风又雨。", "芳事葱葱如旅。", "借问甚时才百五。", "东君浑弗顾。", "红紫园林几许。", "横笛数声何处。", "桃涨连天归未去。", "客和春且驻。"]'),
('song-ci-640','谒金门','李曾伯','宋','宋词','song-ci','谒金门','[]','春且驻。',53,'宋词/ci.song.15000.json','["春且驻。", "休惜残红无主。", "柳色青青还未絮。", "牡丹犹待雨。", "金鸭沈烟一缕。", "人在纱窗觅句。", "仿佛家山三月暮。", "隔帘闻燕语。"]'),
('song-ci-641','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','今岁渝州热，过似岭南州。',114,'宋词/ci.song.15000.json','["今岁渝州热，过似岭南州。", "火流石铄如傲，尤更炽於秋。", "竟日襟常沾汗，中夕箑无停手，几至欲蕉头。", "世岂乏凉境，老向此山囚。", "赖苍灵，怜赤子，起龙秋。", "刹那顷耳，天瓢倾下足西畴。", "荡涤两间炎酷，苏醒一番枯槁，民瘼庶其廖。", "清入诗脾里，一笑解吾忧。"]'),
('song-ci-642','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','两岁是六帙，万里客他州。',114,'宋词/ci.song.15000.json','["两岁是六帙，万里客他州。", "一眉新月西挂，又报桂花秋。", "想见吴中稚子，已办秫田数顷，更种橘千头。", "堪笑新亭酒，空效楚人囚。", "饭甘粗，衣任恶，卧从湫。", "世缘道眼看破，闻早问先畴。", "这服清凉散子，多在病坊弗悟，美疢甚时瘳。", "膏秣归盘去，无乐亦无忧。"]'),
('song-ci-643','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','雪山有缘，白首重来，信不偶然。',139,'宋词/ci.song.15000.json','["雪山有缘，白首重来，信不偶然。", "怅怆凄未洗，平戎何策，英灵不绝，赖蜀多贤。", "耆旧二三，甲兵百万，力障狂澜回巨川。", "秋声静，共巍楼把酒，自足筹边。", "何人为我盏天。", "焉用此客星留井躔。", "正柴桑栗里，稻肥蟹健，松江笠泽，莼美鲈鲜。", "百计求闲，一归未得，便得归闲能几年。", "持公赋，待后堂新唱，夸语彭宣。"]'),
('song-ci-644','一剪梅・一翦梅','李曾伯','宋','宋词','song-ci','一剪梅・一翦梅','[]','人生能有几中秋。',72,'宋词/ci.song.15000.json','["人生能有几中秋。", "人自多愁。", "月又何愁。", "老娥今夜为谁羞。", "云意悠悠。", "雨意悠悠。", "自怜踪迹等萍浮。", "去岁荆州。", "今岁渝州。", "可人谁与共斯楼。", "归去休休。", "睡去休休。"]'),
('song-ci-645','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','晚出千林，中立三秋，清哉此花。',138,'宋词/ci.song.15000.json','["晚出千林，中立三秋，清哉此花。", "自鹫峰移下，碎成玉屑，蟾宫分到，缀作金葩。", "粟许来微，薰天声价，较楚蕙庾梅还韵些。", "真奇处，但餐沆瀣，不染繁华。", "酒边一笑婆娑。", "疑香醉山中尊者家。", "怅尘埃俗状，强颜羞对，风骚墨客，乐事堪夸。", "月照才清，露浓尤馥，饮待夜深应更佳。", "姑容我，胆瓶斜插，卧看窗纱。"]'),
('song-ci-646','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','一种孤荄，四出清芬，半秋始花。',141,'宋词/ci.song.15000.json','["一种孤荄，四出清芬，半秋始花。", "只些儿肌骨，才逾一芥，许多韵度，迥压群葩。", "得雨相催，随风所到，较七里山樊尤远些。", "纷纷辈，笑渠侬桃李，徒竞春华。", "试容老子婆娑。", "恍身在广寒仙子家。", "任殷勤唤酒，恣从君赏，徘徊待月，剩向人夸。", "我有家林，旧栽岩壑，得归去相延方是佳。", "姑先约，拼共横船玉，教堕巾纱。"]'),
('song-ci-647','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','[]','江头雨过黄花，片帆催向春闱去。',127,'宋词/ci.song.15000.json','["江头雨过黄花，片帆催向春闱去。", "两年共我，风舟问峡，霜砧闻楚。", "定远从军，兹恩策第，岂堪同语。", "谩咨嗟人事，分明天意，广寒阙、待平步。", "健笔凌云如许。", "看新年、榜登龙虎。", "转头却笑，弓刀塞上，粗官何取。", "海阔鹏搏，途穷马老，不胜离绪。", "过旧游、人问征夫，烦为说、戌边苦。"]'),
('song-ci-648','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','[]','天涯舍我先归，还知我以何时去。',127,'宋词/ci.song.15000.json','["天涯舍我先归，还知我以何时去。", "浮生萍梗，南辕北旆，之吴之楚。", "岂偶然哉，祗堪一笑，无庸多语。", "向临歧赋别，丁宁祝望，竿百尺、进一步。", "其奈头颅如许。", "更藩篱、穴犹据虎。", "良机一失，付之谁手，探囊堪取。", "君对天庭，上咨西事，历陈条绪。", "问相如、汉指来宣，果何益、亦何苦。"]'),
('song-ci-649','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','二十年间，黄州竹楼，共酬好春。',140,'宋词/ci.song.15000.json','["二十年间，黄州竹楼，共酬好春。", "记淮堧江表，群贤毕集，清明上巳，二美相并。", "一枕黄粱，满头白发，屈指旧游能几人。", "堪嗟处，怅光阴易老，犹困西尘。", "今朝又值良辰。", "空想像、长安天气新。", "问兰亭癸丑，雪堂壬戌，倏成畴昔，将似来今。", "觞泛流泉，茗烹新火，领略韶华聊啸吟。", "鹦洲去，有故人相问，为语归音。"]'),
('song-ci-650','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','咄咄衰翁，向羽书中，又过一春。',139,'宋词/ci.song.15000.json','["咄咄衰翁，向羽书中，又过一春。", "正老怀梦想，扁舟访剡，壮图惭负，万里城并。", "溟翼之上，冀群空矣，自此阳关无故人。", "岷江路，忆一番风浪，三月烟尘。", "美哉乐事良辰。", "正好趁东门官柳新。", "且舒晴慷慨，何须感旧，转头解后，未必犹今。", "问讯南楼，劳还西戌，君为楚歌侬越吟。", "眉黄近，怕洛涯催出，便有佳音。"]'),
('song-ci-651','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','万里戌边，八载去家，始遂一归。',139,'宋词/ci.song.15000.json','["万里戌边，八载去家，始遂一归。", "怅中年早历，虎头兵幕，平生屡建，豹尾神旗。", "岂得闲身，毋庸多议，感荷九重渊听知。", "当时事，似狂澜欲倒，孰障东之。", "天教狂虏灰飞。", "更莫问儿郎存血衣。", "把雪裘霜帽，绝交楚徼，雨蓑风笠，投老吴矶。", "径与松荒，人同鹤在，交友晓天星样稀。", "从今去，共麴生相约，愿乐清时。"]'),
('song-ci-652','沁园春','李曾伯','宋','宋词','song-ci','沁园春','["\u6d1e\u5ead\u6e56"]','极目江涛，不有人焉，其能国乎。',141,'宋词/ci.song.15000.json','["极目江涛，不有人焉，其能国乎。", "伟故家风烈，激扬手段，平生践履，精密工夫。", "冰漕功成，月卿召入，小却犹当登从涂。", "斯行也，非纪网省闼，定引京都。", "猗欤。", "愿疾其驱。", "弹指顷暑收秋又初。", "向玉阶芳寸，亲承温问，金成十二，细述嘉谟。", "苕霅船边，藕花香里，念人在洞庭青草湖。", "它年事，约携东老酒，附洛英图。"]'),
('song-ci-653','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','天目山房，洪崖老仙，亲授一灯。',139,'宋词/ci.song.15000.json','["天目山房，洪崖老仙，亲授一灯。", "自檄草参筹，宾筵领袖，鼎梅助味，省闼权衡。", "华国文章，立朝风力，犹有老成人典刑。", "如公样，盍夜趋宣室，昼对延英。", "乘轺惠我湘民。", "作翼轸中间一福星。", "正千飕漕玉，张颐西峤，单车把绣，将指南闽。", "过阙留中，历阶而上，方值汉朝更化新。", "南中事，若君王问及，老弗能胜。"]'),
('song-ci-654','满江红','李曾伯','宋','宋词','song-ci','满江红','[]','明日生初，还知否、明年六十。',115,'宋词/ci.song.15000.json','["明日生初，还知否、明年六十。", "嗟老矣、满头都缟，寸心犹赤。", "三十载间尘土债，几千里外风涛役。", "赖君天、许放故山归，恩无极。", "出而作，入而息。", "美可茹，鲜可食。", "任浩书空咄，禹笑人寂。", "断国谋王非我事，抱孙弄子聊吾适。", "且从今、时复一中之，杯中物。"]'),
('song-ci-655','满江红','李曾伯','宋','宋词','song-ci','满江红','[]','今岁潇湘，真个见、嘉平三白。',115,'宋词/ci.song.15000.json','["今岁潇湘，真个见、嘉平三白。", "圜闠里、无非和气，不知寒色。", "宇宙幻成清净境，了无一点红尘入。", "问太空、此瑞自何来，君王德。", "歌笑是，兔园客。", "辛苦是，鹅池役。", "任谢家儿女，赋嘲纷出。", "洗尽腥膻空万里，屏除螟螣深千尺。", "向此时、何以对梅花，呼欢伯。"]'),
('song-ci-656','满江红','李曾伯','宋','宋词','song-ci','满江红','[]','蝶梦惊残，仿佛似、东方才白。',118,'宋词/ci.song.15000.json','["蝶梦惊残，仿佛似、东方才白。", "人报道、城疑不夜，界几无色。", "敲瓦微听冰线响，开窗倏放风花入。", "拥重貂、曾不觉寒侵，将何德。", "呼剡棹，行为客。", "平蔡垒，何能役。", "算争如、穷檐高卧，闭门毋出。", "安得松江江上去，一蓑独钓丝千尺。", "要不持、寸铁和前修，文章伯。"]'),
('song-ci-657','满江红','李曾伯','宋','宋词','song-ci','满江红','[]','立雪寒窗，照肝胆、了然明白。',115,'宋词/ci.song.15000.json','["立雪寒窗，照肝胆、了然明白。", "浑似得、齐宫气象，郢楼颜色。", "天籁无声随物应，阳春有脚从中入。", "与邦人、稽首谢天工，元冥德。", "人正作，潇湘客。", "谁谓有，蓝关役。", "对江天暮景，鹅溪描出。", "银浪卷飞鸥一片，玉枝擎重龙千尺。", "羡联镳、曾作岳峰游，前方伯。"]'),
('song-ci-658','满江红','李曾伯','宋','宋词','song-ci','满江红','[]','把绣成吟，真压倒、古之元白。',115,'宋词/ci.song.15000.json','["把绣成吟，真压倒、古之元白。", "佳句有、雪车冰柱，曾无衿色。", "一点不留烟火气，时脾时有清风入。", "更岭边、多少活人恩，于公德。", "公自是，朝天客。", "应笑我，为人役。", "看时犹多事，公须一出。", "琅腹细披忠抱寸，龙颜密侍天威尺。", "借笔端、从此润皇猷，翰林伯。"]'),
('song-ci-659','满江红','李曾伯','宋','宋词','song-ci','满江红','[]','听彻惊乌，起览镜、顿添头白。',115,'宋词/ci.song.15000.json','["听彻惊乌，起览镜、顿添头白。", "曾不见、江南人寄，一枝春色。", "风卷龙鳞残甲下，山无虎迹新蹄入。", "罄冰天、桂海使同风，修文德。", "三十载，江湖客。", "千万里，关山役。", "且付之杯酒，何愁西出。", "天女花边浑似剪，志公杖上平如尺。", "把富贫、都作一般看，何什伯。"]'),
('song-ci-660','满江红','李曾伯','宋','宋词','song-ci','满江红','[]','草草春盘，那敢赋、丝青玉白。',115,'宋词/ci.song.15000.json','["草草春盘，那敢赋、丝青玉白。", "湘波动、雁怀归思，柳催行色。", "冻逐寒梢残雪解，暖随野烧轻烟入。", "举人间、无物不光辉，东皇德。", "莺燕报，朱门客。", "乌兔老，红尘役。", "羡翠轺多暇，彩花新出。", "捧日东城行应制，去天只隔城南尺。", "趁五更、桦烛向端闱，班常伯。"]'),
('song-ci-661','满江红','李曾伯','宋','宋词','song-ci','满江红','[]','春日何来，深雪里、南枝先白。',118,'宋词/ci.song.15000.json','["春日何来，深雪里、南枝先白。", "伊祈氏、一番陶冶，千林色香。", "弱柳眼回青尚浅，小桃腮晕红将入。", "笑渠侬、剪彩与裁花，夸闺德。", "九十日，春还客。", "数千里，官为役。", "看时来、雁随云去，鱼从冰出。", "一脉流通天造化，三杯扶植身关尺。", "对东皇、太乙续离骚，需词伯。"]'),
('song-ci-662','满江红','李曾伯','宋','宋词','song-ci','满江红','[]','万紫千红，都不似、玉奴一白。',115,'宋词/ci.song.15000.json','["万紫千红，都不似、玉奴一白。", "三数萼、有冰霜操，无脂粉色。", "长共竹君松友伴，岂容蝶使蜂媒人。", "似惠和、伊任与夷清，兼三德。", "能洁已，能娱客。", "成子后，调羹役。", "更岁寒风味，时然后出。", "春浅吹回羌管寸，夜阑吟费花笺尺。", "炯使皇、两两月黄昏，真诗伯。"]'),
('song-ci-663','贺新郎','李曾伯','宋','宋词','song-ci','贺新郎','[]','岭蜀天涯路。',142,'宋词/ci.song.15000.json','["岭蜀天涯路。", "忆前年、担簦西上，旌麾南去。", "谁谓潇湘还解后，重对灯前笑语。", "挺乔木、森森犹故。", "梅外柳边官事了，记牢之、曾著元戎府。", "聊访问，旧游处。", "酒边不用伤南浦。", "为鄇亭、百年门户，正烦宗主。", "见说君王方旰食，借箸哺应为吐。", "这官职、二郎须做。", "若见时贤询小阮，愿早携、襏襫耕春雨。", "嗟矍铄，恐迟暮。"]'),
('song-ci-664','贺新郎','李曾伯','宋','宋词','song-ci','贺新郎','[]','日近长安路。',142,'宋词/ci.song.15000.json','["日近长安路。", "喜骖鸾、带簪游戏，弓旌招去。", "闻道汉朝帷帏里，要问娵隅蛮语。", "嗟时事、尚兹多故。", "办取忠谋宜入告，见石洪、曾在乌公府。", "须细访，风寒处。", "左荆右岭中湘浦。", "愿扶持、东南温厚，老天张主。", "翘馆钦贤人共说，一饭每勤三吐。", "公此去、好官须做。", "从臾泾舟同共济，更绸缪、桑土先阴雨。", "灭此虏，直朝暮。"]'),
('song-ci-665','贺新郎','李曾伯','宋','宋词','song-ci','贺新郎','[]','老作星沙守。',142,'宋词/ci.song.15000.json','["老作星沙守。", "问今年、平头六十，翁还知否。", "暑葛霜砧都历遍，还著回旋舞袖。", "奚所用、皤然一叟。", "欲觅金丹驻颜色，纵铁鞋、踏破终无有。", "空自诧，不龟手。", "西风又近中秋候。", "记相将、桂华开未，月儿圆又。", "弧矢四方男子事，争奈灰心也久。", "何以报、国恩深厚。", "了却宫痴归去好，有竹窗、蓬户生涯旧。", "姑一笑，付杯酒。"]'),
('song-ci-666','贺新郎','李曾伯','宋','宋词','song-ci','贺新郎','[]','问讯南州守。',142,'宋词/ci.song.15000.json','["问讯南州守。", "怅吾生、今非昔比，后犹今否。", "涉尽风涛凭个甚，一瓣心香在袖。", "人竞说、顽哉此叟。", "识破荣途皆幻境，只形骸、已累它何有。", "姑勉尔，应之手。", "休烦太卜勤占候。", "怕漂零、江湖易老，光阴难又。", "兔魄初生人初度，期共婵娟长久。", "赖此月、於人犹厚。", "燕颔封侯非我事，早携书、归卧吾庐旧。", "渝此约，有如酒。"]'),
('song-ci-667','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','宵旰轸先虑，岭海屈真儒。',114,'宋词/ci.song.15000.json','["宵旰轸先虑，岭海屈真儒。", "金城素有奇略，不待至才图。", "春满洲鹦楼鹤，天付簪山带水，驷马驾轻车。", "六月正炎热，吾肯缓吾驱。", "越蓬婆，逾邛筰，彼穹庐。", "其能涉我烟瘴，载籍以来无。", "联络五溪百粤，托柱南方半壁，中外保无虞。", "了此经营事，归去位钧枢。"]'),
('song-ci-668','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','["\u6d1e\u5ead\u6e56"]','洞庭千古月，湘水一天秋。',114,'宋词/ci.song.15000.json','["洞庭千古月，湘水一天秋。", "凉宵将傍三五，玩事若为酬。", "人立梧桐影下，身在桂花香里，疑是玉为州。", "宇宙大圆镜，沆瀣际空浮。", "傍谯城，瞻岳麓，有巍楼。", "不妨举酒，相与一笑作遨头。", "人已星星华发，月只团团素魄，几对老蟾羞。", "回首海天阔，心与水东流。"]'),
('song-ci-669','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','佳月四时有，举世重中秋。',114,'宋词/ci.song.15000.json','["佳月四时有，举世重中秋。", "金明水秀竞爽，互古景难酬。", "爝火繁星退敛，桂海冰天洞照，清影遍神州。", "万象自妍丑，一鉴碧虚浮。", "昔苏张，夸玉界，赋琼楼。", "素娥阅人多矣，不怕雪添头。", "只恐参横斗转，还又酒阑歌散，醉态醒堪羞。", "安得真仙术，兔魄驻西流。"]'),
('song-ci-670','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','敢问辽天月，历几亿春秋。',114,'宋词/ci.song.15000.json','["敢问辽天月，历几亿春秋。", "老娥盍相刮目，无一语相酬。", "似讶经年间阔，类笑衰翁潦倒，岁岁客他州。", "清照五湖阔，倦影一萍浮。", "任渠侬，琴当户，酒当楼。", "人生适意，封君何似橘千头。", "月正圆时固好，人欲闲时须早，毋作陇西羞。", "多谢锦囊句，椽笔富清流。"]'),
('song-ci-671','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','问讯中秋月，瞥见一眉弯。',114,'宋词/ci.song.15000.json','["问讯中秋月，瞥见一眉弯。", "婆娑桂影，今年又向桂林看。", "蓬天桑弧初度，罗带玉簪旧识，俯仰十年间。", "记得老坡语，颓景薄西山。", "碧虚人，应笑我，已苍颜。", "岁寒耿耿，不改惟有寸心丹。", "目断风涛万里，梦绕烟霞一壑，老矣甚时闲。", "不愿酒泉郡，愿入玉门关。"]'),
('song-ci-672','木兰花慢','李曾伯','宋','宋词','song-ci','木兰花慢','[]','渐吾乡秋近，正莼美、更鲈肥。',124,'宋词/ci.song.15000.json','["渐吾乡秋近，正莼美、更鲈肥。", "顾安得相从，征帆衔尾，飞盖追随。", "南中眼前事势，正相持、边腹一枰棋。", "将谓灯明月暗，笑谈共和韩诗。", "谁知。", "催上王畿。", "无计可，挽留之。", "想翠微深处，倚楼日望，天际人归。", "中流江涛衮衮，藉烝徒、共楫属之谁。", "回首西风过雁，料君为我兴思。"]'),
('song-ci-673','沁园春','李曾伯','宋','宋词','song-ci','沁园春','[]','六十衰翁，更加二龄，此何等时。',139,'宋词/ci.song.15000.json','["六十衰翁，更加二龄，此何等时。", "不退寻岩壑，相安耕钓，重来岭峤，犹事驱驰。", "绝类文渊，当年矍铄，上马据鞍奚所为。", "偏怜处，是难堪潦雾，水际鸢飞。", "云台铜柱空题。", "奈床下伊人心素疑。", "自古来如此，只须付酒，风光纵好，勿复言诗。", "莼菜美时，桂花香里，所愿少须臾乐之。", "西风外，喜羽书夜静，即是归期。"]'),
('song-ci-674','满江红','李曾伯','宋','宋词','song-ci','满江红','[]','今岁垂弧，欲自寿、一辞莫措。',115,'宋词/ci.song.15000.json','["今岁垂弧，欲自寿、一辞莫措。", "何可拟、翁头如雪，香山白傅。", "首夏一番罹重病，去秋数月撄狂虏。", "赖天公、肯为保馀生，逢初度。", "今幸释，千钧负。", "尤可喜，归田去。", "但蹒跚勃窣，龙锺如许。", "薇柳诸关成底事，菊松三径犹堪主。", "办篮舆、尚可檄渔樵，盟鸥鹭。"]'),
('song-ci-675','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','[]','西风涤尽炎歊，连朝更值天无雨。',127,'宋词/ci.song.15000.json','["西风涤尽炎歊，连朝更值天无雨。", "笋舆轧轧，经行三日，碧篸无数。", "胜绝江山，余行天下，无如此处。", "任今来昔往，迎新送旧，风景在、只如许。", "谁谓阴山骄虏。", "去年冬、敢侵吾土。", "哀哀鸿雁，一番荡析，幸逢多黍。", "拜表出师，安南定北，岂无忠武。", "嗟病夫、老矣无能，促归棹，舣江渚。"]'),
('song-ci-676','水调歌头','李曾伯','宋','宋词','song-ci','水调歌头','[]','昨夜虽三五，宝鉴未纯全。',114,'宋词/ci.song.15000.json','["昨夜虽三五，宝鉴未纯全。", "今宵既望，兔魄才是十分圆。", "又得平滩系缆，冷浸玻璃千顷，表里一壶天。", "扶惫蓬窗下，拼却夜深眠。", "想嫦娥，应笑我，鬓苍然。", "平生修玩，犹记历历旧山川。", "安得乘槎访斗，问讯广寒宫殿，怅未了尘缘。", "愿赐长生药，换我骨为仙。"]'),
('song-ci-677','八声甘州','李曾伯','宋','宋词','song-ci','八声甘州','[]','数年来、揆度在南州，今年在家山。',118,'宋词/ci.song.15000.json','["数年来、揆度在南州，今年在家山。", "叹平生踪迹，荆淮岭蜀，多少间关。", "幸对园林花竹，一笑且团栾。", "莫忆西风梦，驰志楼兰。", "赢得维摩多病，奈鬓毛剥落，步武蹒跚。", "神仙何处，遗我以金丹。", "愿明时、清平无事，放老翁、长伴白鸥闲。", "聊相与，桂花香里，满酌开颜。"]'),
('song-ci-678','水龙吟','李曾伯','宋','宋词','song-ci','水龙吟','[]','此花迥绝他花，湘中不减吴中盛。',127,'宋词/ci.song.15000.json','["此花迥绝他花，湘中不减吴中盛。", "疑从太华，分来岳麓，根荄玉井。", "炬列千红，盖擎万绿，织成云锦。", "向壶天清暑，风梳露洗，尘不染、香成阵。", "好似一番雨过，似轻鬟、晚临妆镜。", "阿环浴罢，珠横翠乱，芳肌犹润。", "载月同游，隔花共语，酒边清兴。", "问六郎、凝伫多时，公不饮、俗几甚。"]'),
('song-ci-679','八六子','郑熏初','宋','宋词','song-ci','八六子','[]','忆南洲。',105,'宋词/ci.song.15000.json','["忆南洲。", "绀波萦绕，垂杨翠拂朱楼。", "念十载风流梦觉，满身花影人扶，旧曾暗游。", "无言空怆离忧。", "醉袖裛将红泪，吟笺写许清愁。", "试与问、杨琼解怜郎否，也应还是，旧家身价，而今艳质不来眼底，柔情终在心头。", "黯凝眸。", "黄昏月沈半钩。"]'),
('song-ci-680','乌夜啼','郑熏初','宋','宋词','song-ci','乌夜啼','[]','春江一望微茫。',45,'宋词/ci.song.15000.json','["春江一望微茫。", "辨桅樯。", "无限青青麦里、菜花黄。", "今古恨，登临泪，几斜阳。", "不是寄奴住处、也凄凉。"]'),
('song-ci-681','氐州第一','郑熏初','宋','宋词','song-ci','氐州第一','[]','开遍来禽，春事过也，江南倦客心苦。',127,'宋词/ci.song.15000.json','["开遍来禽，春事过也，江南倦客心苦。", "料理花愁，销磨酒病，还是年时意绪。", "寒浅香轻，早一霎、朝来微雨。", "柳曲闻莺，河桥信马，旋题新句。", "漫道而今无贺铸。", "尽肠断、满帘飞絮。", "说似风流，除非小杜，妙绝夸能赋。", "黯相逢，俱有恨，空流落、江山好处。", "猛拍阑干，诉天知、声声杜宇。"]'),
('song-ci-682','一萼红','郑熏初','宋','宋词','song-ci','一萼红','[]','忆燕台。',133,'宋词/ci.song.15000.json','["忆燕台。", "正倚帘吹絮，小立望郎来。", "擫管调丝，涂妆绾髻，密意曾托蜂媒。", "空恁误、湔裙暗约，最无奈、好梦易惊回。", "想见而今，浅颦双翠，沁破妆梅。", "沈带悄然宽尽，恨年时行处，红糁苍苔。", "前事重寻，幽欢难偶，钿合空委鸾钗。", "这一点、相思清泪，做心下、烦恼几时灰。", "数叠蛮笺怨歌，忍对花裁。"]'),
('song-ci-683','瑞鹤仙','余','宋','宋词','song-ci','瑞鹤仙','[]','怪新来瘦损。',127,'宋词/ci.song.15000.json','["怪新来瘦损。", "对镜台、霜华零乱鬓影。", "胸中恨谁省。", "正关山寂寞，暮天风景。", "貂裘渐冷。", "听梧桐、声敲露井。", "可无人、为向楼头，试问塞鸿音信。", "争忍。", "勾引愁绪，半掩金铺，雨欺灯晕。", "家僮困卧，呼不应，自高枕。", "待催他、天际银蟾飞上，唤取嫦娥细问。", "要乾坤，表里光辉，照予醉饮。"]'),
('song-ci-684','如梦令','赵崇嶓','宋','宋词','song-ci','如梦令','[]','日日酒围花阵。',40,'宋词/ci.song.15000.json','["日日酒围花阵。", "画阁红楼相近。", "残月醉归来，长是雨羞云困。", "低问。", "低问。", "独自绣帏睡稳。"]'),
('song-ci-685','如梦令','赵崇嶓','宋','宋词','song-ci','如梦令','[]','窗外燕娇莺妒。',40,'宋词/ci.song.15000.json','["窗外燕娇莺妒。", "窗下梦魂无据。", "梦好却频惊，不到彩云深处。", "无绪。", "无绪。", "红重一帘花雨。"]'),
('song-ci-686','更漏子','赵崇嶓','宋','宋词','song-ci','更漏子','[]','玉搔头，金约臂。',58,'宋词/ci.song.15000.json','["玉搔头，金约臂。", "娇重不胜残醉。", "留粉黛，晕胭脂。", "浅寒生玉肌。", "待归来，浑未准。", "疑杀那回书信。", "春又好，思无穷。", "卷帘花露浓。"]'),
('song-ci-687','谒金门','赵崇嶓','宋','宋词','song-ci','谒金门','[]','春尚浅。',53,'宋词/ci.song.15000.json','["春尚浅。", "江上柳梢风软。", "销尽玉梅春不管。", "冷香和梦远。", "脉脉绿窗新怨。", "花胜无心重翦。", "帘押护香闲不卷。", "卷帘芳事遍。"]'),
('song-ci-688','谒金门','赵崇嶓','宋','宋词','song-ci','谒金门','[]','春意泄。',53,'宋词/ci.song.15000.json','["春意泄。", "香重一枝梅雪。", "寒透玉壶冰暗结。", "玉奴情更劣。", "似语还羞奇绝。", "妒白怜红时节。", "酒力未醒双眼缬。", "一帘风弄月。"]'),
('song-ci-689','谒金门','赵崇嶓','宋','宋词','song-ci','谒金门','[]','晴意早。',53,'宋词/ci.song.15000.json','["晴意早。", "帘外数声啼鸟。", "有约不来春梦杳。", "琐窗微弄晓。", "江上残梅未扫。", "叶底芳桃红小。", "天远断云尘不到。", "过春还草草。"]'),
('song-ci-690','谒金门','赵崇嶓','宋','宋词','song-ci','谒金门','[]','春意薄。',53,'宋词/ci.song.15000.json','["春意薄。", "江上晚来风恶。", "帘外海棠花半落。", "睡深浑未觉。", "梦想当年行乐。", "新恨暗添金鹊。", "写就金笺无处托。", "去鸿天一角。"]'),
('song-ci-691','清平乐','赵崇嶓','宋','宋词','song-ci','清平乐','[]','莺歌蝶舞。',54,'宋词/ci.song.15000.json','["莺歌蝶舞。", "池馆春多处。", "满架花云留不住。", "散作一川香雨。", "相思夜夜情悰。", "青衫泪满啼红。", "料想故园桃李，也应怨月愁风。"]'),
('song-ci-692','清平乐','赵崇嶓','宋','宋词','song-ci','清平乐','[]','妒红欺绿。',54,'宋词/ci.song.15000.json','["妒红欺绿。", "轻浪潮温玉。", "鸾袖卷香金□□。", "娇怯未消寒粟。", "锦衾初罢承欢。", "宿妆微褪香弯。", "醉眼乍松还困，断云犹绕巫山。"]'),
('song-ci-693','南柯子・南歌子','赵崇嶓','宋','宋词','song-ci','南柯子・南歌子','[]','丝发风轻掠，酥胸冷不侵。',62,'宋词/ci.song.15000.json','["丝发风轻掠，酥胸冷不侵。", "背人小立卸瑶簪。", "一缕柔情、系得几人心。", "曲槛花方蓓，荷桥柳未阴。", "红羞绿困不能禁。", "恼乱东风、无计等春深。"]'),
('song-ci-694','南柯子・南歌子','赵崇嶓','宋','宋词','song-ci','南柯子・南歌子','[]','掩笑轻抬袖，慵妆浅画眉。',62,'宋词/ci.song.15000.json','["掩笑轻抬袖，慵妆浅画眉。", "嫩晴帘箔玉梅飞。", "门外寒轻、疏柳趁黄时。", "绾带香罗结，交叉绿玉枝。", "看看又误踏青期。", "倚遍栏干、心事只春知。"]'),
('song-ci-695','望海潮','赵崇嶓','宋','宋词','song-ci','望海潮','[]','轻云过雨，炎晖初减，楼台片片馀霞。',129,'宋词/ci.song.15000.json','["轻云过雨，炎晖初减，楼台片片馀霞。", "曲径通幽，小阑斜护，水天薄暮人家。", "暝色趣归鸦，竹风交立玉，清透窗纱。", "断岸涟漪，乱萍芳苇绕烟沙。", "依稀画艇莲娃。", "掩鲛绡微沁，急桨咿哑。", "香雾霏微，冷光摇曳，娅红深映低花。", "天际玉钩斜。", "矶边菱唱答，惊断鸣蛙。", "满棹白苹归去，幽兴绕天涯。"]'),
('song-ci-696','沁园春','赵崇嶓','宋','宋词','song-ci','沁园春','[]','紫陌芳尘，烟缕收寒，雨丝过云。',139,'宋词/ci.song.15000.json','["紫陌芳尘，烟缕收寒，雨丝过云。", "羡交阴桃叶，窗前曲槛，认巢燕子，柳底朱门。", "回首年时，雾鬟风袖，袅袅娉娉娇上春。", "逢迎处，尽芳华缱绻，玉佩殷勤。", "谁知此际销魂。", "漫隐约人前笑语温。", "记掌中纤细，真成一梦，花时怨忆，应为双文。", "载酒心情，教眉诗句，空悔风流曾误人。", "凭谁去，待寄将恨事，两处平分。"]'),
('song-ci-697','摸鱼儿','赵崇嶓','宋','宋词','song-ci','摸鱼儿','[]','卷珠帘、几番花信。',140,'宋词/ci.song.15000.json','["卷珠帘、几番花信。", "轻寒犹自成阵。", "一年芳事如朝梦，容易绿深红褪。", "寒食近。", "惟自有、断肠垂柳禁春困。", "琐窗深静。", "悄叠损缕衣，凝尘暗掩，金斗熨清润。", "章台恨。", "准拟芳期未稳。", "旧游细把重忖。", "鉴鸾钗凤平分久，留取年时心印。", "谁与问。", "待试写花笺，密寄教郎认。", "妒香怜粉。", "欲写却还羞，轻颦浅叹，字字揽方寸。"]'),
('song-ci-698','过秦楼','赵崇嶓','宋','宋词','song-ci','过秦楼','[]','隐枕轻潮，拂尘疏雨，幽梦似真还断。',138,'宋词/ci.song.15000.json','["隐枕轻潮，拂尘疏雨，幽梦似真还断。", "莺雏燕婉，依约年时，花下试翻歌扇。", "憔悴鬓怯春寒，慢掠轻丝，柳风如箭。", "甚阳台渺邈，行云无准，楚天空远。", "应唤觉、当日琴心，祗今诗思，惆怅客衣尘染。", "钗留股玉，袜袭钩罗，荏苒腻寒香变。", "问讯多情，别后笑巧颦娇，对谁长倩。", "但晚来江上，眼迷心想，越山两点。"]'),
('song-ci-699','归朝欢','赵崇嶓','宋','宋词','song-ci','归朝欢','[]','翠羽低飞帘半揭。',122,'宋词/ci.song.15000.json','["翠羽低飞帘半揭。", "宝簟牙床凉似雪。", "窗虚云母澹无风，隔墙花动黄昏月。", "玉钗鸾坠发。", "盈盈白露侵罗袜。", "记逢迎，鸿惊燕婉，灯影弄明灭。", "蜀雨巫云愁断绝。", "罗带同心留绾结。", "交枝红豆雨中看，为君滴尽相思血。", "染衣香未歇。", "夜阑天净魂飞越。", "正销凝，一庭秋意，烟水浸空阔。"]'),
('song-ci-700','恋绣衾','赵崇嶓','宋','宋词','song-ci','恋绣衾','[]','江烟如雾水满汀。',68,'宋词/ci.song.15000.json','["江烟如雾水满汀。", "早梅花、偏占浅清。", "倚翠竹、寒无力，想潇湘、斜日暮云。", "几回梦断阳春面，问百花、犹隔几尘。", "趁月夜、霜风峭，约彩鸾、同载玉笙。"]'),
('song-ci-701','蝶恋花','赵崇嶓','宋','宋词','song-ci','蝶恋花','[]','一翦微寒禁翠袂。',70,'宋词/ci.song.15000.json','["一翦微寒禁翠袂。", "花下重开，旧燕添新垒。", "风旋落红香币地。", "海棠枝上莺飞起。", "薄雾笼春天欲醉。", "碧草澄波，的的情如水。", "料想红楼挑锦字。", "轻云淡月人憔悴。"]'),
('song-ci-702','菩萨蛮','赵崇嶓','宋','宋词','song-ci','菩萨蛮','[]','桃花相向东风笑。',52,'宋词/ci.song.15000.json','["桃花相向东风笑。", "桃花忍放东风老。", "细草碧如烟。", "薄寒轻暖天。", "折钗鸾作股。", "镜里参差舞。", "破碎玉连环。", "卷帘春睡残。"]'),
('song-ci-703','金明池','赵崇嶓','宋','宋词','song-ci','金明池','[]','桂海云蒸，瘴山雾暖，片雪何曾到地。',148,'宋词/ci.song.15000.json','["桂海云蒸，瘴山雾暖，片雪何曾到地。", "羡长日、岛仙清暑，自学得、剪冰裁□。", "把岁寒、五出工夫，别妆点薰风，尽成清致。", "尽虹雨翻晴，暮霞焦土，一种凄凉如洗。", "酝藉丰标浑无比。", "应似惜、潇湘蕙疏兰弃。", "纵未入、众芳题品，终自倚、一涯风味。", "待等闲、留取遗芬，伴檐匐芳菲，蔷薇清泚。", "看佩贯胡绳，心灰宝燎，到了未输兰蕙。"]'),
('song-ci-704','满江红','方岳','宋','宋词','song-ci','满江红','[]','说与梅花，且莫道、今年无雪。',115,'宋词/ci.song.15000.json','["说与梅花，且莫道、今年无雪。", "君不见、秋崖鬓底，茎茎骚屑。", "笔砚只催人老大，湖山不了诗愁绝。", "问笭箵、何事下矶来，抛云月。", "重省起，西山芴。", "终负却，东山屐。", "把草堂借与，鹭眠鸥歇。", "乌帽久闲苍藓石，青衫今作枯荷叶。", "笑人间、万事竟何如，从吾拙。"]'),
('song-ci-705','满江红','方岳','宋','宋词','song-ci','满江红','[]','且问黄花，陶令后、几番重九。',115,'宋词/ci.song.15000.json','["且问黄花，陶令后、几番重九。", "应解笑、秋崖人老，不堪诗酒。", "宇宙一舟吾倦矣，山河两戒天知否。", "倚西风、无奈剑花寒，虬龙吼。", "江欲釂，谈天口。", "秋何负，持螯手。", "尽石鳞芜没，断烟衰柳。", "故国山围青玉案，何人印佩黄金斗。", "倘只消、江左管夷吾，终须有。"]'),
('song-ci-706','满江红','方岳','宋','宋词','song-ci','满江红','["\u897f\u6e56"]','苍石横筇，松风外、自调龟息。',115,'宋词/ci.song.15000.json','["苍石横筇，松风外、自调龟息。", "浑不记、东皋秋事，西湖春色。", "底处未嫌吾辈在，此心说与何人得。", "向海棠、烂醉过清明，酬佳节。", "君莫道，江鲈忆。", "吾自爱，山泉激。", "尽月明夜半，杜鹃声急。", "人事略如春梦过，年光不啻惊弦发。", "怕醒来、失口问诸公，今何日。"]'),
('song-ci-707','水调歌头','方岳','宋','宋词','song-ci','水调歌头','[]','左手紫螯蟹，右手绿螺杯。',114,'宋词/ci.song.15000.json','["左手紫螯蟹，右手绿螺杯。", "古今多少遗恨，俯仰已尘埃。", "不共青山一笑，不与黄花一醉，怀抱向谁开。", "举酒属吾子，此兴正崔嵬。", "夜何其，秋老矣，盍归来。", "试问先生归否，茅屋欲生苔。", "穷则箪瓢陋巷，达则鼎彝清庙，吾意两悠哉。", "寄语雪溪外，鸥鹭莫惊猜。"]'),
('song-ci-708','水调歌头','方岳','宋','宋词','song-ci','水调歌头','[]','秋雨一何碧，山色倚晴空。',114,'宋词/ci.song.15000.json','["秋雨一何碧，山色倚晴空。", "江南江北愁思，分付酒螺红。", "芦叶蓬舟千重，菰菜莼羹一梦，无语寄归鸿。", "醉眼渺河洛，遗恨夕阳中。", "苹洲外，山欲暝，敛眉峰。", "人间俯仰陈迹，叹息两仙翁。", "不见当时杨柳，只是从前烟雨，磨灭几英雄。", "天地一孤啸，匹马又西风。"]'),
('song-ci-709','水调歌头','方岳','宋','宋词','song-ci','水调歌头','[]','醉我一壶玉，了此十分秋。',114,'宋词/ci.song.15000.json','["醉我一壶玉，了此十分秋。", "江涛还此，当日击楫渡中流。", "问讯重阳烟雨，俯仰人间今古，此意渺沧洲。", "天地几今夕，举白与君浮。", "旧黄花，新白发，笑重游。", "满船明月犹在，何日大刀头。", "谁跨扬州鹤去，已怨故山猿老，借箸欲前筹。", "莫倚阑干北，天际是神州。"]'),
('song-ci-710','满江红','方岳','宋','宋词','song-ci','满江红','[]','甓社有明月，夜半吐光寒。',114,'宋词/ci.song.15000.json','["甓社有明月，夜半吐光寒。", "淮南草木飞动，秀出斗牛间。", "自有秦沙以后，试问少游而下，谁卷入毫端。", "补衮仲山甫，冰雪照云寰。", "霄汉近，绣衣去，锦衣还。", "江南且为梅醉，莫道岁将阑。", "三百六旬欲换，五百岁终才始，月月两循环。", "酌彼金错落，浇此碧琅絜。"]'),
('song-ci-711','水调歌头','方岳','宋','宋词','song-ci','水调歌头','[]','明日又重午，搀借玉蒲香。',114,'宋词/ci.song.15000.json','["明日又重午，搀借玉蒲香。", "劝金且尽杯酒，听我试平章。", "时事艰难甚矣，人物眇然如此，骚意满潇湘。", "醉问屈原子，烟水正微茫。", "溯层峦，浮叠嶂，碧云乡。", "眼中犹有公在，吾意亦差强。", "胸次甲兵百万，笔底天人三策，堪补舜衣裳。", "要及黑头耳，霖雨趁梅黄。"]'),
('song-ci-712','水调歌头','方岳','宋','宋词','song-ci','水调歌头','[]','剡曲一篷月，乘兴到人间。',114,'宋词/ci.song.15000.json','["剡曲一篷月，乘兴到人间。", "蓬莱山在何处，鹤骨不禁寒。", "胸有云门禹穴，笔有禊亭晋帖，风露洗脾肝。", "秋入紫宸殿，磨玉写琅玕。", "问何如，趋琐闼，系狨鞍。", "江涛今已如此，可奈寸心丹。", "我宋与天无极，公寿如春难老，王气自龙蟠。", "勋业付浯石，留与世人看。"]'),
('song-ci-713','水调歌头','方岳','宋','宋词','song-ci','水调歌头','[]','宇宙一杯酒，暝色倚重湖。',114,'宋词/ci.song.15000.json','["宇宙一杯酒，暝色倚重湖。", "青山杳杳何处，烟水泻愁予。", "别岸风涛喷薄，半夜鱼龙悲啸，能撼我诗无。", "李白醉不醒，唤起问何如。", "是耶非，天莽苍，雪模糊。", "苍颜白发如此，空复笑今吾。", "寄语鹭朋鸥侣，好在风餐水宿，底处不烟芜。", "吾亦从此逝，从我者谁欤。"]'),
('song-ci-714','沁园春','方岳','宋','宋词','song-ci','沁园春','[]','尽为春愁，尽劝春归，直恁恨深。',139,'宋词/ci.song.15000.json','["尽为春愁，尽劝春归，直恁恨深。", "况雨急黄昏，寒欺客路，月明夜半，人梦家林。", "店舍无烟，楚乡寒食，一片花飞那可禁。", "小凝伫，黯红蔫翠老，江树阴阴。", "汀洲杜若谁寻。", "想朝鹤怨兮猿夜吟。", "甚连天芳草，凄迷离恨，拂帘香絮，撩乱深心。", "汝亦知乎，吾今倦矣，瓮有馀春可共斟。", "归来也，问渊明而后，谁是知音。"]'),
('song-ci-715','沁园春','方岳','宋','宋词','song-ci','沁园春','[]','岁在永和，癸丑暮春，修禊兰亭。',139,'宋词/ci.song.15000.json','["岁在永和，癸丑暮春，修禊兰亭。", "有崇山峻岭，茂林修竹，清流湍激，映带山阴。", "曲水流觞，群贤毕至，是日风和天气清。", "亦足以，供一觞一咏，畅叙幽情。", "悲夫一世之人。", "或放浪形骸遇所欣。", "虽快然自足，终期於尽，老之将至，后视犹今。", "随事情迁，所之既倦，俯仰之间迹已陈。", "兴怀也，将后之览者，有感斯文。"]'),
('song-ci-716','沁园春','方岳','宋','宋词','song-ci','沁园春','[]','莺带春来，鹃唤春归，春总不知。',139,'宋词/ci.song.15000.json','["莺带春来，鹃唤春归，春总不知。", "恨杨花多事，杏花无赖，半随残梦，半惹晴丝。", "立尽碧云，寒江欲暮，怕过清明燕子时。", "春且住，待新雏熟了，却问行期。", "问春春竟何之。", "看紫态红情难语离。", "想芳韶犹剩，牡丹知处，也须些个，付与荼縻。", "唤取娉婷，劝教春醉，不道五更花漏迟。", "愁一饷，笑车轮生角，早已天涯。"]'),
('song-ci-717','沁园春','方岳','宋','宋词','song-ci','沁园春','[]','蠢彼鼪鼯，嗟尔何为，敢瞰长淮。',140,'宋词/ci.song.15000.json','["蠢彼鼪鼯，嗟尔何为，敢瞰长淮。", "遣诗书元帅，又劳指画，神仙寿日，不放襟怀。", "略已三年，可曾一笑，天岂悭吾老子哉。", "诸人者，且携将雅颂，留待磨崖。", "我姑酌彼金罍。", "便小醉、宁辞鹦鹉杯。", "问今何时也，子其休矣，有如此酒，奚取吾侪。", "帝曰不然，政须卿辈，作我长城惟汝谐。", "凝望处，见红尘飞骑，捷羽东来。"]'),
('song-ci-718','沁园春','方岳','宋','宋词','song-ci','沁园春','[]','有美人兮，铁石心肠，寄春一枝。',140,'宋词/ci.song.15000.json','["有美人兮，铁石心肠，寄春一枝。", "喜藓生龙甲，那因雪瘦，月横鹤膝，不受寒欺。", "云卧空山，梦回孤驿，生怕渠嗔未敢诗。", "江头路，问销魂几许，索笑何时。", "赋成字字明珠。", "君莫倚、家风旧解题。", "叹水曹安在，飘然欲去，逋仙已矣，其与谁归。", "烟雨愁予，江山老我，毕竟岁寒然后知。", "微酸在，尽危谯斜倚，残角孤吹。"]'),
('song-ci-719','沁园春','方岳','宋','宋词','song-ci','沁园春','[]','把酒问花，茧栗梢头，春今几何。',139,'宋词/ci.song.15000.json','["把酒问花，茧栗梢头，春今几何。", "笑身居近侍，阶翻万玉，面丐菩萨，髻拥千螺。", "一一牙签，英英碧字，占定花间甲乙科。", "归来也，傍紫薇吟处，揉作阳和。", "祗今花事无多。", "看几许风烟付与他。", "待围将翡翠，怕蜂粘粉，织成云锦，遣凤衔梭。", "谁翦并刀，赠之燕玉，莫负双娥娇溜波。", "花应道，尽花强人面，底用能歌。"]'),
('song-ci-720','沁园春','方岳','宋','宋词','song-ci','沁园春','[]','子盍规夫，商丘之木，有樗不才。',139,'宋词/ci.song.15000.json','["子盍规夫，商丘之木，有樗不才。", "纵斧斤睥睨，何妨雪立，风烟傲兀，怎问春回。", "老子似之，倦游久矣，归晒渔蓑羹芋魁。", "村锄外，闻韭今有子，芥已生台。", "天於我辈悠哉。", "纵作赋问天天亦猜。", "且醉无何有，酒徒陶陆，与二三子，诗友陈雷。", "正尔眠云，阿谁敲月，不是我曹不肯来。", "君且住，怕口生荆棘，胸有尘埃。"]'),
('song-ci-721','望江南・忆江南','方岳','宋','宋词','song-ci','望江南・忆江南','[]','梅欲老，撑月过南徐。',64,'宋词/ci.song.15000.json','["梅欲老，撑月过南徐。", "家口纵多难减鹤，路程不远易携书。", "只是废春锄。", "霜满袖，茶灶借僧庐。", "湖海甚豪今倦矣，丘山虽寿竟何如。", "一笑荐冰蔬。"]'),
('song-ci-722','蝶恋花','方岳','宋','宋词','song-ci','蝶恋花','[]','雁落寒沙秋恻恻。',70,'宋词/ci.song.15000.json','["雁落寒沙秋恻恻。", "明月芦花，共是江南客。", "骑鹤楼高边羽急。", "柔情不尽淮山碧。", "世路只催双鬓白。", "菰菜莼羹，正自怜人忆。", "归梦不知江水隔。", "烟帆飞过平如席。"]'),
('song-ci-723','蝶恋花','方岳','宋','宋词','song-ci','蝶恋花','[]','山抹修眉横绿净。',70,'宋词/ci.song.15000.json','["山抹修眉横绿净。", "浦溆生寒，立尽梧桐影。", "香灺未消帘幕静。", "醉红如洗风吹醒。", "一夜秋声连玉井。", "梦落孤篷，已尽山阴兴。", "戍角凄凉清漏永。", "江南烟雨何堪省。"]'),
('song-ci-724','蝶恋花','方岳','宋','宋词','song-ci','蝶恋花','[]','秋水涵空如镜净。',70,'宋词/ci.song.15000.json','["秋水涵空如镜净。", "满镜清寒，倒碧摇山影。", "药户谁抨圆玉静。", "碧纱人怯黄昏醒。", "丛桂小山寒井井。", "唤起江南，一叶莼鲈兴。", "先自新愁愁夜永。", "不堪宋□重提省。"]'),
('song-ci-725','木兰花慢','方岳','宋','宋词','song-ci','木兰花慢','[]','慨晴江渺渺，乘风下、倚沧浪。',124,'宋词/ci.song.15000.json','["慨晴江渺渺，乘风下、倚沧浪。", "问许大乾坤，金焦两点，曾几兴亡。", "平章古人安在，但青山、烟水共微茫。", "不道鹭嘲鸥笑，归来鬓已苍苍。", "垂杨。", "舞尽斜阳。", "双燕语、尽渠忙。", "黯柔情不管，花深传漏，羽急飞觞。", "思量人间如梦，放半分、佯醉半佯狂。", "明日海棠犹旧，春风未老秋娘。"]'),
('song-ci-726','如梦令','方岳','宋','宋词','song-ci','如梦令','[]','知是谁家燕子。',40,'宋词/ci.song.15000.json','["知是谁家燕子。", "直恁惺松言语。", "深入绣帘来，无奈落花飞絮。", "春去。", "春去。", "且道干卿何事。"]'),
('song-ci-727','如梦令','方岳','宋','宋词','song-ci','如梦令','[]','雨洗海棠如雪。',40,'宋词/ci.song.15000.json','["雨洗海棠如雪。", "又是清明时节。", "燕子几时来，只了为花愁绝。", "愁绝。", "愁绝。", "枉与春风分说。"]'),
('song-ci-728','贺新凉・贺新郎','方岳','宋','宋词','song-ci','贺新凉・贺新郎','[]','霜月寒如洗。',142,'宋词/ci.song.15000.json','["霜月寒如洗。", "问梅花、经年何事，尚迷烟水。", "梦著翠霞寻好句，新雪阑干独倚。", "见竹外、一枝横蕊。", "已占百花头上了，料诗情、不但江山耳。", "春已逗，有佳思。", "一香吹动人间世。", "奈何地、丛篁低碧，巧相亏蔽。", "尽让春风凡草木，便做云根石底。", "但留取、微酸滋味。", "除却林逋无人识，算岁寒、只是天知己。", "休弄玉，怨迟暮。"]'),
('song-ci-729','贺新凉・贺新郎','方岳','宋','宋词','song-ci','贺新凉・贺新郎','[]','问讯江南客。',142,'宋词/ci.song.15000.json','["问讯江南客。", "怕秋崖、苔荒诗屋，云侵山屐。", "留得钓竿西日手，梦落鸥傍鹭侧。", "倩传语、溪翁将息。", "四十飞腾斜暮景，笑双篷、一懒无他画。", "惟饱饭，散轻策。", "世间万事知何极。", "问乾坤、待谁整顿，岂无豪杰。", "水驿山村还要我，料理松风竹雪。", "也不学、草颠诗白。", "自有春蓑黄犊在，尽诸公、宝马摇金勒。", "容我辈，醉云液。"]'),
('song-ci-730','贺新凉・贺新郎','方岳','宋','宋词','song-ci','贺新凉・贺新郎','[]','雁向愁边落。',142,'宋词/ci.song.15000.json','["雁向愁边落。", "渺汀洲、孤云细雨，暮天寒角。", "有美人兮山翠外，谁共霜桥月壑。", "想朋友、春猿秋鹤。", "竹屋一灯棋未了，问人间、局面如何著。", "风雨夜，更商略。", "六州铁铸从头错。", "笑归来、冰鲈堪脍，雪螯堪嚼。", "莫遣孤舟横浦溆，也怕浪狂风恶。", "且容把、钓纶收却。", "云外空山知何似，料清寒、只与梅花约。", "逋老句，底须作。"]'),
('song-ci-731','贺新凉・贺新郎','方岳','宋','宋词','song-ci','贺新凉・贺新郎','[]','一笑君知否。',142,'宋词/ci.song.15000.json','["一笑君知否。", "笑当年、山阴道士，行歌樵叟。", "五十到头公老矣，只可鹭朋鸥友。", "便富贵、何如杯酒。", "好在归来苍崖底，想月明、不负携锄手。", "谁共酌，翦霜韭。", "乾坤许大山河旧。", "几多人、剑倚西风，笔惊南斗。", "俯仰之间成陈迹，亡是子虚乌有。", "渺烟草、不堪回首。", "隔坞筑亭开野迳，尽一筇、两履山前后。", "春且为，催花柳。"]'),
('song-ci-732','贺新凉・贺新郎','方岳','宋','宋词','song-ci','贺新凉・贺新郎','["\u5e90\u5c71"]','天意然乎否。',142,'宋词/ci.song.15000.json','["天意然乎否。", "待相携、风烟五亩，招邀迂叟。", "屋上青山花木野，尽可两朋三友。", "笑老子、只堪棋酒。", "似恁疏顽何为者，向人前、不解高叉手。", "宁学圃，种菘韭。", "春猿秋鹤皆依旧。", "怪吾今，鬓已成丝，胆还如斗。", "谁与庐山麾之去，尔辈何留之有。", "黯离绪、暮江搔首。", "非我督邮犹束带，这一归、更落渊明后。", "君试问，长亭柳。"]'),
('song-ci-733','西江月','方岳','宋','宋词','song-ci','西江月','[]','茅屋何堪翠袖，芝田自有霓裳。',58,'宋词/ci.song.15000.json','["茅屋何堪翠袖，芝田自有霓裳。", "一双雪舞碧云乡。", "富贵人家以上。", "竹外山童敲臼，梅边溪友传觞。", "青霞道服石炉香。", "便是寿星模样。"]'),
('song-ci-734','西江月','方岳','宋','宋词','song-ci','西江月','[]','燕子催将初度，梨花指定清明。',58,'宋词/ci.song.15000.json','["燕子催将初度，梨花指定清明。", "春风可是太多情。", "乐事良辰一并。", "绛老从头甲子，楚骚几度庚寅。", "晴光不隔凤凰城。", "花底举头天近。"]'),
('song-ci-735','西江月','方岳','宋','宋词','song-ci','西江月','[]','蔬甲初肥雨润，茶枪小摘春明。',58,'宋词/ci.song.15000.json','["蔬甲初肥雨润，茶枪小摘春明。", "野篱是处可诗情。", "打过下湖船并。", "捷报秋来旁午，贤关早晚同寅。", "绿杨连骑带春城。", "不问南山远近。"]'),
('song-ci-736','一落索','方岳','宋','宋词','song-ci','一落索','[]','瘦得黄花能小。',56,'宋词/ci.song.15000.json','["瘦得黄花能小。", "一帘香杳。", "东篱云冷正愁予，犹幸是、西风少。", "叶下亭皋渺渺。", "秋何为者。", "无钱持蟹对黄花，又孤负、重阳也。"]'),
('song-ci-737','汉宫春','方岳','宋','宋词','song-ci','汉宫春','[]','云涧之癯，有诗盟未了，鸥泛江湖。',118,'宋词/ci.song.15000.json','["云涧之癯，有诗盟未了，鸥泛江湖。", "一官直为仙耳，不受尘驱。", "高情逸韵，自兰亭、已后都无。", "准拟画、剡舟夜雪，与君相对成图。", "半竹苔寒如此，问谁欤来者，鹤伴薰炉。", "何如贮之天上，风露冰壶。", "江南春早，想梅花、不肯欺吾。", "疑便是，孤山之北，水乡月影林逋。"]'),
('song-ci-738','汉宫春','方岳','宋','宋词','song-ci','汉宫春','[]','问讯何郎，怎春风未到，却月横枝。',118,'宋词/ci.song.15000.json','["问讯何郎，怎春风未到，却月横枝。", "当年东阁诗兴，夫岂吾欺。", "云寒岁晚，便相逢、已负深期。", "烦说与、秋崖归也，留香更待何时。", "家住江南烟雨，想疏花开遍，野竹巴篱。", "遥怜水边石上，煞欠渠诗。", "月壶雪瓮，肯相从、舍我其谁。", "应自笑，生来孤峭，此心却有天知。"]'),
('song-ci-739','酹江月・念奴娇','方岳','宋','宋词','song-ci','酹江月・念奴娇','[]','问天何事，雪垂垂欲下，又还晴却。',120,'宋词/ci.song.15000.json','["问天何事，雪垂垂欲下，又还晴却。", "春到梅梢香逗也，尽有心情行乐。", "剡曲舟回，灞桥诗在，一笑人如昨。", "此情分付，暮天寒月残角。", "谁道飞梦江南，群山如画，一一琼瑶琢。", "中有玉田三万顷，云是幼舆丘壑。", "招我归来，和春醉去，休跨扬州鹤。", "万花曾约，酒醒当有新作。"]'),
('song-ci-740','酹江月・念奴娇','方岳','宋','宋词','song-ci','酹江月・念奴娇','[]','绿尊翠勺，约秋风、一醉小楼先月。',120,'宋词/ci.song.15000.json','["绿尊翠勺，约秋风、一醉小楼先月。", "谁取宝奁奔帝所，深锁玉华宫阙。", "老桂香寒，疏桐云重，生怕金蛇掣。", "那知天柱，一峰别与天接。", "我欲飞佩重游，置之衣袖，照我襟怀雪。", "玉斧难藏修月手，待做明宵清绝。", "天地无尘，山河有影，了不遗毫发。", "举杯相属，唤谁笺与天说。"]'),
('song-ci-741','酹江月・念奴娇','方岳','宋','宋词','song-ci','酹江月・念奴娇','[]','幅巾云麓。',120,'宋词/ci.song.15000.json','["幅巾云麓。", "笑人生瓮等，何时是足。", "莫道年来无好处，第一秫田新熟。", "孙息乘鸾，大儿荐鹗，翁已恩袍碌。", "笑谭戎幕，尽教岳也碌碌。", "是则江南江北，月明飞梦，认得溪桥屋。", "多少睡乡闲日月，不老柯山棋局。", "唱个曲儿，吃些酒子，检点茅檐竹。", "问梅开未，一枝初破寒玉。"]'),
('song-ci-742','酹江月・念奴娇','方岳','宋','宋词','song-ci','酹江月・念奴娇','[]','且拌春醉。',120,'宋词/ci.song.15000.json','["且拌春醉。", "问人间、谁是十分如意。", "道不好来人又道，也有一分好处。", "管甚长贫，只消长健，切莫眉头聚。", "尽教江路，梅花依旧留住。", "儿辈虽不如人，有何不可，怎敢嫌迟暮。", "但喜吾翁躔度转，唤起烟霞深痼。", "否极而亨，剥馀而复，长至迎初度。", "龟图羲画，直从今日重数。"]'),
('song-ci-743','酹江月・念奴娇','方岳','宋','宋词','song-ci','酹江月・念奴娇','[]','花风初逗，喜边亭依旧，春闲营柳。',120,'宋词/ci.song.15000.json','["花风初逗，喜边亭依旧，春闲营柳。", "烟草隋宫歌舞地，谁遣万红围绣。", "结酒因缘，装春富贵，也要经纶手。", "笙箫声里，一江晴绿吹皱。", "是处羽箭如飞，那知鹤府，花压阑干昼。", "油幕文书谈笑了，馀事尽堪茶酒。", "报答东风，流连西日，绿外沈吟久。", "与春无负，醉归香满襟袖。"]'),
('song-ci-744','酹江月・念奴娇','方岳','宋','宋词','song-ci','酹江月・念奴娇','[]','槎牙诗骨，想生来无分，史闱经幄。',120,'宋词/ci.song.15000.json','["槎牙诗骨，想生来无分，史闱经幄。", "呵护九关多虎豹，谁道去天一握。", "奏赋两都，闻韶三月，雁远书难托。", "一寒如许，蟾枝莫倚高擢。", "空使满壑风烟，半村雪月，孤负梅花约。", "渺渺愁予初度也，山互同云垂幕。", "鹤帐何如，牛衣无恙，麦陇占优渥。", "不如归去，檐花深夜春酌。"]'),
('song-ci-745','酹江月・念奴娇','方岳','宋','宋词','song-ci','酹江月・念奴娇','[]','祈山底处，为二松千竹，肯题崖壁。',120,'宋词/ci.song.15000.json','["祈山底处，为二松千竹，肯题崖壁。", "雪洒谈犀麾雁骛，尔辈何烦涉笔。", "使者知乎，民其劳止，且莫闲耕织。", "片言金石，唤回春意无极。", "虽则王谢人家，一癯仙泽，面作苍烟色。", "茶炷笔床将雨屐，吟到梅花消息。", "贱子何为，老仙如问，莫道头今白。", "寒蓑几梦，研朱看点周易。"]'),
('song-ci-746','水龙吟','方岳','宋','宋词','song-ci','水龙吟','[]','当年睡里闻香，阿谁唤做花间瑞。',126,'宋词/ci.song.15000.json','["当年睡里闻香，阿谁唤做花间瑞。", "巾飘沈水，笼熏古锦，拥青绫被。", "初日酣晴，柔风逗暖，十分情致。", "掩窗绡，待得香融酒醒，尽消受、这春思。", "从把万红排比。", "想较伊、更争些子。", "诗仙老手，春风妙笔，要题教似。", "十里扬州，三生杜牧，可曾知此。", "趁紫唇微绽，芳心半透，与骚人醉。"]'),
('song-ci-747','水龙吟','方岳','宋','宋词','song-ci','水龙吟','[]','昼长庭院深深，春柔一枕流霞醉。',126,'宋词/ci.song.15000.json','["昼长庭院深深，春柔一枕流霞醉。", "蒙松欲醒，娇羞还困，锦屏围翠。", "豆寇初肥，樱桃微绽，玉阑同倚。", "记华清浴起，渭流波暖，红涨腻、弃脂水。", "燕子来时天气。", "尽韶风、与诗为地。", "芳丛雨歇，露痕日酽，英英仙意。", "莫恨无香，最怜有韵，天然情致。", "待问春能几，五更犹是，拌今宵睡。"]'),
('song-ci-748','满庭芳','方岳','宋','宋词','song-ci','满庭芳','[]','半壳含黄，双螯擘紫，风流浑是芦花。',118,'宋词/ci.song.15000.json','["半壳含黄，双螯擘紫，风流浑是芦花。", "江头秋老，谁了酒生涯。", "玉质金相如许，怎消受、明月寒沙。", "橙香也，不闲左手，除是付诗家。", "草泥，行郭索，横戈曾怒，张翰浮夸。", "笑鲈鱼虽好，风味争些。", "醉嚼霜前松雪，江湖梦、不枉归槎。", "停杯问，余其负腹，是腹负余耶。"]'),
('song-ci-749','喜迁莺','方岳','宋','宋词','song-ci','喜迁莺','[]','淮山秋晓。',126,'宋词/ci.song.15000.json','["淮山秋晓。", "问西风几度，雁云蛩草。", "铁色骢骄，金花袍窄，未觉塞垣寒早。", "笳鼓声中晴色，一羽不飞边报。", "君莫道，怎乾坤许大，英雄能少。", "谈笑。", "鸣镝处，生缚胡雏，烽火传音耗。", "漠漠寒沙，荒荒残照，正空不劳深讨。", "但喜欢迎马首，犹是中原遗老。", "关何事，待归来细话，一尊倾倒。"]'),
('song-ci-750','浣溪沙','方岳','宋','宋词','song-ci','浣溪沙','[]','半壳含潮带靥香。',48,'宋词/ci.song.15000.json','["半壳含潮带靥香。", "双螯嚼雪迸脐黄。", "芦花洲渚夜来霜。", "短棹秋江清到底，长头春瓮醉为乡。", "风流不枉与诗尝。"]'),
('song-ci-751','浣溪沙','方岳','宋','宋词','song-ci','浣溪沙','[]','夜醉渊明把菊图。',48,'宋词/ci.song.15000.json','["夜醉渊明把菊图。", "宿酲扶晓又冰壶。", "秋香留得伴双凫。", "并日满浮金馨落，明年初赐玉茱萸。", "更书欲上有除书。"]'),
('song-ci-752','齐天乐','方岳','宋','宋词','song-ci','齐天乐','[]','孤篷夜傍低丛宿，萧萧雨声悲切。',123,'宋词/ci.song.15000.json','["孤篷夜傍低丛宿，萧萧雨声悲切。", "一岸霜痕，半江烟色，愁到沙头枯叶。", "澹云没灭。", "黯西风吹老，满汀新雪。", "天岂无情，离骚点点送归客。", "归去来兮怎得，尽鹭翅鸥倚，乍寒时节。", "秋晚山川，夕阳浦溆，赢得别肠千结。", "涛翻浪叠。", "那得似西来，一筇横绝。", "搔首江南，雁衔千里月。"]'),
('song-ci-753','花心动','方岳','宋','宋词','song-ci','花心动','[]','雪带边寒，渺愁予、雪中谁抱奇节。',127,'宋词/ci.song.15000.json','["雪带边寒，渺愁予、雪中谁抱奇节。", "逊在扬州，逋老孤山，芳信顿成消歇。", "江南茅屋今安在，疏影瘦、祗堪叹息。", "归来未，沙头立尽，暮天云碧。", "自笑梁园赋客。", "倚旧日鞍鞯，春风巾帻。", "问讯横枝，暖热新花，无处访寻诗阁。", "几年不见冰霜面，知谁共、批风支月。", "归来也，鸥盟不妨再结。"]'),
('song-ci-754','风流子','方岳','宋','宋词','song-ci','风流子','[]','小楼帘不卷，花正闹、灯火竞春宵。',136,'宋词/ci.song.15000.json','["小楼帘不卷，花正闹、灯火竞春宵。", "想旧日何郎，飞金叵罗，三生杜牧，醉董娇饶。", "香尘路，云松鸾髻鬌，月衬马蹄骄。", "仿佛神仙，刘安鸡犬，分明富贵，子晋笙箫。", "人生行乐耳，君不见、迷楼春绿迢迢。", "二十四、经行处，旧月今桥。", "但索笑梅花，酒消新雪，纵情诗草，笔卷春潮。", "俯仰人间陈迹，莫惜金貂。"]'),
('song-ci-755','瑞鹤仙','方岳','宋','宋词','song-ci','瑞鹤仙','[]','一年寒尽也。',124,'宋词/ci.song.15000.json','["一年寒尽也。", "问秦沙、梅放未也。", "幽寻者谁也。", "有何郎佳约，岁云除也。", "南枝暖也。", "正同云、商量雪也。", "喜东皇，一转洪钧，依旧春风中也。", "香也。", "骚情酿就，书味熏成，这些情也。", "玉堂深也。", "莫道年华归也。", "是循环、三百六旬六日，生意无穷已也。", "但丁宁，留取微酸，调商鼎也。"]'),
('song-ci-756','瑞鹤仙','方岳','宋','宋词','song-ci','瑞鹤仙','[]','中元才过节。',127,'宋词/ci.song.15000.json','["中元才过节。", "正宇宙澄清，一天寒碧。", "凉飙动秋色。", "算佳辰恰是，下弦当日。", "天生俊杰。", "富文才、瑰奇挺特。", "看葱葱，和气薰城，共庆武夷仙伯。", "难得。", "钓鳌连六，虎傍登名，新题淡墨。", "从容莲幕。", "游花县，无邀隔。", "纵风流别驾，难淹紫诏，行对天颜咫尺。", "更堪夸，萱草长春，红衣交列。"]'),
('song-ci-757','哨遍','方岳','宋','宋词','song-ci','哨遍','[]','月亦老乎，劝尔一杯，听说平生事。',245,'宋词/ci.song.15000.json','["月亦老乎，劝尔一杯，听说平生事。", "吾问汝，开辟自何时。", "有乾坤更应有尔。", "年几许。", "鸿荒邈哉遐已。", "吾今断自唐虞起。", "系帝曰放勋，甲辰践祚，数至今、宋嘉熙。", "凡三千五百二十年馀。", "嗟雨□风□几盈亏。", "老兔奔驰，痴蟆吞吐，定应衰矣。", "噫。", "月岂无悲。", "吾观人寿几期颐。", "炯炯双眸子，明清无过婴儿。", "但才到中年，昏然欲眊，那堪老矣知何似。", "试以此推之。", "吾言有理，不能不自疑耳。", "恐古时月与今时异。", "恨则恨今人不千岁。", "但见今、冰轮如洗。", "阿谁曾自前古，看到隋唐世。", "几时明洁，几时昏暗，毕竟少晴多雨。", "须臾月落夜何其。", "曰先生、审之姑醉。"]'),
('song-ci-758','哨遍','方岳','宋','宋词','song-ci','哨遍','[]','月曰不然，君亦怎知，天上从前事。',236,'宋词/ci.song.15000.json','["月曰不然，君亦怎知，天上从前事。", "吾语汝，月岂有弦时。", "奈人间井观乃尔。", "休浪许。", "历家缪悠而已。", "谁云魄死生明起。", "又明死魄生，循环晦朔，有老兔、自熙熙。", "妄相传、月溯日光馀。", "嗟万古谁知了无亏。", "玉斧修成，银蟾奔去，此言荒矣。", "噫。", "世已堪悲。", "听君歌复解人颐。", "桂魄何曾死，寒光不减些儿。", "但与日相望，对如两镜，山河大地无疑似。", "待既望观之。", "冰轮渐侧，转斜才一钩耳。", "论本来不与中秋异。", "恐天问灵均未知此。", "又底用、咸池重洗。", "乾坤一点英气。", "宁老人问世。", "飞上天来，摩挲月去，才信有晴无雨。", "人生圆缺几何其。"]'),
('song-ci-759','眼儿媚','方岳','宋','宋词','song-ci','眼儿媚','[]','雁带新霜几多愁。',58,'宋词/ci.song.15000.json','["雁带新霜几多愁。", "和月落沧洲。", "桂花如许，菊花如许，怎不悲秋。", "江山例合闲人管，也白几分头。", "去年曾此，今年曾此，烟雨孤舟。"]'),
('song-ci-760','鹊桥仙','方岳','宋','宋词','song-ci','鹊桥仙','[]','银河无浪，琼楼不暑。',68,'宋词/ci.song.15000.json','["银河无浪，琼楼不暑。", "一点柔情如水。", "肯捐兰珮了渠愁，尽闲却、纤纤机杼。", "波心沁雪，鸥边分雨。", "翦得荷花能楚。", "天公煞自解风流，看得我、如何销汝。"]'),
('song-ci-761','鹊桥仙','方岳','宋','宋词','song-ci','鹊桥仙','[]','今朝廿九，明朝初一。',71,'宋词/ci.song.15000.json','["今朝廿九，明朝初一。", "怎欠秋崖个生日。", "客中情绪老天知，道这月、不消三十。", "春盘缕翠，春缸摇碧。", "便泥做、梅花消息。", "雪边试问是耶非，笑今夕、不知何夕。"]'),
('song-ci-762','玉楼春','方岳','宋','宋词','song-ci','玉楼春','[]','木犀过了诗憔悴。',64,'宋词/ci.song.15000.json','["木犀过了诗憔悴。", "只有黄花开又未。", "秋风也不管人愁，到处相寻吹短袂。", "露滴碧觞谁共醉。", "肠断向来携手地。", "夜寒笺与月明看，未必月明知此意。"]'),
('song-ci-763','虞美人','方岳','宋','宋词','song-ci','虞美人','[]','鸥清眠醉晴溪月。',66,'宋词/ci.song.15000.json','["鸥清眠醉晴溪月。", "几梦寒蓑雪。", "断桥篱落带人家。", "枝北枝南初著、两三花。", "曾於春底横孤艇。", "香似诗能冷。", "娟娟玉立载归壶。", "渺渺愁予肯入、楚骚无。"]'),
('song-ci-764','一剪梅・一翦梅','方岳','宋','宋词','song-ci','一剪梅・一翦梅','[]','谁翦轻琼做物华。',72,'宋词/ci.song.15000.json','["谁翦轻琼做物华。", "春绕天涯。", "水绕天涯。", "园林晓树恁横斜。", "道是梅花。", "不是梅花。", "宿鹭联拳倚断槎。", "昨夜寒些。", "今夜寒些。", "孤舟蓑笠钓烟沙。", "待不思家。", "怎不思家。"]'),
('song-ci-765','烛影摇红','方岳','宋','宋词','song-ci','烛影摇红','[]','辇路融晴，宫云逗晓青旗报。',116,'宋词/ci.song.15000.json','["辇路融晴，宫云逗晓青旗报。", "梅边香沁彩鞭寒，初信花风到。", "笑语谁家帘幕，镂冰丝、红粉绿闹。", "髻横玉燕，鬓颤琼幡，不能知掉。", "看见春来，麴尘微涨催兰棹。", "娇横拂略上柔条，等得莺眠觉。", "引出千花万草。", "喜搀先、椒盘竹爆。", "问谁天上，瑶帖初供，玉堂归儤。"]'),
('song-ci-766','最高楼','方岳','宋','宋词','song-ci','最高楼','[]','溪南北，本自一渔舟。',100,'宋词/ci.song.15000.json','["溪南北，本自一渔舟。", "烟雨几盟鸥。", "白鱼不负鸬鹚杓，青蓑不减鹔鹴裘。", "怎无端，贪射策，觅封侯。", "既不似、古人能识字。", "又不似、今人能识事。", "空老去，自宜休。", "帝乡五十六朝暮，人间四十四春秋。", "问何如，茅一把，橘千头。"]'),
('song-ci-767','最高楼','方岳','宋','宋词','song-ci','最高楼','["\u6ed5\u738b\u9601"]','朝元了，万鹤放班回。',100,'宋词/ci.song.15000.json','["朝元了，万鹤放班回。", "携月下天来。", "初平家看青羊石，滕王阁醉绿螺杯。", "试鸣琴，花荡漾，玉崔嵬。", "前十日、鹊桥飞宝镫。", "后一月、兔奁开玉镜。", "秋色净，夜徘徊。", "申从五岳三光出，亥将二首六身排。", "问何其，餐沆瀣，燕蓬莱。"]'),
('song-ci-768','最高楼','方岳','宋','宋词','song-ci','最高楼','[]','秋崖底，云卧欲生苔。',108,'宋词/ci.song.15000.json','["秋崖底，云卧欲生苔。", "无梦到公台。", "有月锄、晓带乌犍去，与烟蓑、夜钓白鱼来。", "问谁能，供酒料，办诗材。", "君莫笑、闲忙棋得势。", "也莫笑、浮湛渔得计。", "胸次老，雪崔嵬。", "付老夫、小小鸬鹚杓，尽诸公、衮衮凤凰台。", "且容侬，多种竹，剩栽梅。"]'),
('song-ci-769','行香子','方岳','宋','宋词','song-ci','行香子','[]','说与樵青。',83,'宋词/ci.song.15000.json','["说与樵青。", "紧闭柴门。", "道先生检校东屯。", "阿戎安在，未扫愁痕。", "且免歌词，休载妓，莫携尊。", "梅自生春。", "雪立前村。", "道此杯、酒也须温。", "无穷身外，付与乾坤。", "谁共耕山，闲钓水、饱窥园。"]'),
('song-ci-770','江神子・江城子','方岳','宋','宋词','song-ci','江神子・江城子','[]','窗绡深隐护芳尘。',86,'宋词/ci.song.15000.json','["窗绡深隐护芳尘。", "翠眉颦。", "越精神。", "几雨几晴，做得这些春。", "切莫近前轻著语，题品错，怕渠嗔。", "碧壶谁贮玉粼粼。", "醉香茵。", "晚风频。", "吹得酒痕，如洗一番新。", "只恨谪仙浑懒却，辜负那，倚阑人。"]'),
('song-ci-771','江神子・江城子','方岳','宋','宋词','song-ci','江神子・江城子','[]','梅花吹梦过溪桥。',86,'宋词/ci.song.15000.json','["梅花吹梦过溪桥。", "路迢迢。", "雪初消。", "似恁天寒，诗瘦想无柳。", "听得草堂人有语，能几日，是生朝。", "乱云深处洗山瓢。", "鬓萧萧。", "酒红朝。", "回首六朝，南北黯魂销。", "纵使锺山青眼在，终不似，侣渔樵。"]'),
('song-ci-772','水调歌头','方岳','宋','宋词','song-ci','水调歌头','[]','世不乏季子，藉甚有休声。',114,'宋词/ci.song.15000.json','["世不乏季子，藉甚有休声。", "芝兰挺秀庭砌，广厦万间新。", "胸次金天爽豁，风骨玉堂清彻，才器更轮囷。", "劲节九秋斡，和气万家春。", "过中元，才两日，是生辰。", "瓣香西上，都向此夕颂殷勤。", "自有阴功天佑，合享人间长寿，不独我知君。", "从此见今日，丹桂伴灵椿。"]'),
('song-ci-773','瑞鹧鸪','方岳','宋','宋词','song-ci','瑞鹧鸪','[]','中元过后恰三朝。',64,'宋词/ci.song.15000.json','["中元过后恰三朝。", "因甚庭闱喜气飘。", "李谪若非当此夕，甲生应是在今宵。", "满斟绿醑歌檀口，慢拍红牙舞柳腰。", "富贵荣华谁得似，祝公千岁乐逍遥。"]'),
('song-ci-774','酹江月・念奴娇','方岳','宋','宋词','song-ci','酹江月・念奴娇','[]','楚天秋早，过中元拈指，蓂飞四荚。',120,'宋词/ci.song.15000.json','["楚天秋早，过中元拈指，蓂飞四荚。", "怪得千门佳气满，恰值生申时节。", "蓬矢当年，椒盘今夕，瑞木金炉艺。", "主人情重，酒红潮上双颊。", "且看戏彩□□，鼎分丹桂，兰玉同班列。", "更喜萱庭南极老，亲授长生秘诀。", "养浩颐然，后昌青紫，天报公阴德。", "年年盛会，祝延椿算千百。"]'),
('song-ci-775','满庭芳','方岳','宋','宋词','song-ci','满庭芳','[]','秋入西郊，律调夷则，韩堂风露清凉。',117,'宋词/ci.song.15000.json','["秋入西郊，律调夷则，韩堂风露清凉。", "洞天昨夜，响动玉玎珰。", "朱户银寰放钥，长庚梦、应诞星郎。", "垂弧旦，蓂飞五荚，簪履共称觞。", "未施经济手，暂参雄府，公论声扬。", "便好趁昌辰，入辅吾皇。", "况是中兴启运，正当宁、梦想循良。", "从兹去，万年佐主，福寿总无疆。"]'),
('song-ci-776','满庭芳','方岳','宋','宋词','song-ci','满庭芳','[]','星昴呈祥，山川锺秀，果然生此真贤。',118,'宋词/ci.song.15000.json','["星昴呈祥，山川锺秀，果然生此真贤。", "精神莹澈，秋水共长天。", "况值西风初起，中元过、七日凉先。", "庭院爽，称觞贺客，车马看骈阗。", "开筵。", "称寿处，红袖歌舞，脆管繁弦。", "愿公与椿松，对阅天年。", "纵使平分风月，不容暂、吟醉苕川。", "龙光近，行看凤诏，促入秉钧权。"]'),
('song-ci-777','百字谣・念奴娇','方岳','宋','宋词','song-ci','百字谣・念奴娇','[]','河南灵地，信从生俊杰，皆由天佑。',120,'宋词/ci.song.15000.json','["河南灵地，信从生俊杰，皆由天佑。", "见说簪缨称世袭，复是青毡还旧。", "学海渊源，笔端锋镝，未逊谁居右。", "使台暂赞，直须黄阁环召。", "欣遇初度良辰，中原节过，九日方称寿。", "好看莱衣□舞处，尽羡一门三秀。", "名过河东，迭居宰职，复见韦平胄。", "祝君遐算，南山松柏长茂。"]'),
('song-ci-778','八六子','方岳','宋','宋词','song-ci','八六子','[]','喜椿庭。',103,'宋词/ci.song.15000.json','["喜椿庭。", "近来强健，团栾雁序欢声。", "正柳絮帘栊清昼，牡丹栏槛新晴，缓飞翠觥。", "阿戎碌碌功名。", "但要无灾无难，何曾著公卿。", "且抖擞斑衣，笑供儿戏，共将乐事，细酬佳景，须知翠袖全盛绿黛，金章不换蓑青。", "松亭。", "中间顿个寿星。"]'),
('song-ci-779','霜天晓角','楼','宋','宋词','song-ci','霜天晓角','[]','月淡风轻。',53,'宋词/ci.song.15000.json','["月淡风轻。", "黄昏未是清。", "吟到十分清处，也不啻、二三更。", "晓钟天未明。", "晓霜人未行。", "只有城头残角，说得尽、我平生。"]'),
('song-ci-780','霜天晓角','楼','宋','宋词','song-ci','霜天晓角','["\u897f\u6e56"]','翦雪裁冰。',53,'宋词/ci.song.15000.json','["翦雪裁冰。", "有人嫌太清。", "又有人嫌太瘦，都不是、我知音。", "谁是我知音。", "孤山人姓林。", "一自西湖别后，辜负我、到如今。"]'),
('song-ci-781','桂枝香','徐宝之','宋','宋词','song-ci','桂枝香','[]','人间秋至。',124,'宋词/ci.song.15000.json','["人间秋至。", "对暮雨满城，沈思如水。", "桐叶惊风，似语怨蛩齐起。", "南楼月冷曾多恨，怕而今、夜深横吹。", "那堪更听，萧萧摵摵，透窗摇睡。", "问楚梦、闲云何地。", "但手约轻绡，省人深意。", "红树池塘，谁见宿妆凝睇。", "旧时裘马行歌事，合都归、汀苹烟芷。", "思王渐老，休为明珰，沈吟洛涘。"]'),
('song-ci-782','沁园春','徐宝之','宋','宋词','song-ci','沁园春','[]','水榭春寒，梅雪漫阶，竹云堕墙。',139,'宋词/ci.song.15000.json','["水榭春寒，梅雪漫阶，竹云堕墙。", "数花时近也，采芳香径，旧情著处，看月西窗。", "十二楼中，玉妃卧冷，懒掬胭脂放海棠。", "层堤外，渺归鸿无数，江树苍苍。", "席藑夜礼东皇。", "剪蕙叶为笺当绿章。", "道杏晴三月，等莺啼晓，草烟万里，待鴂鸣芳。", "九十日春，三千丈发，如此愁来白更长。", "江南岸，正柳边无路，沙雨微茫。"]'),
('song-ci-783','莺啼序','徐宝之','宋','宋词','song-ci','莺啼序','[]','荼䕷一番过雨，洒残花似雪。',296,'宋词/ci.song.15000.json','["荼䕷一番过雨，洒残花似雪。", "向清晓、步入东风，细拾苔砌馀靥。", "有数片、飞沾翠柳，萦回半著双归蝶。", "悄无人、共立幽禽，昵昵能说。", "因念年华，最苦易失，对春愁暗结。", "叹自古、曾有佳人，长门深闭修洁。", "寄么弦、千言万语，闷满眼、欲弹难彻。", "靠珠栊，风雨微收，落花时节。", "春工渐老，绿草连天，别浦共一色。", "但暮霭、朝烟无际，尽日目极，江南江北，杜鹃叫裂。", "此时此意，危魂黯黯，渭城客舍青青树，问何人、把酒来看别。", "思量怎向，迟回独掩青扉，夕阳犹照南陌。", "春应记得，旧日疏狂，等受今磨折。", "便永谢、五湖烟艇，只有吟诗，曲坞煎茶，小窗眠月。", "春还自省，把融和事，长留芳昼人间世，与羁臣、恨妾销离恻。", "自题蕙叶回春，坐听蓬壶，漏声细咽。"]'),
('song-ci-784','水调歌・水调','徐宝之','宋','宋词','song-ci','水调歌・水调','[]','了却意中事，卜筑快幽情。',114,'宋词/ci.song.15000.json','["了却意中事，卜筑快幽情。", "雨帘云栋深窈，歌笑霭春生。", "青嶂碧溪门户，暖翠浮岚衿席，前日展湘屏。", "种竹看霜节，栽菊待秋英。", "九世图，闲居赋，丽人行。", "名碑古画，贴遍东阁与西亭。", "庭下森兰洁玉，天外骧龙舞凤，心迹喜双清。", "频瀹炊茶鼎，听我扣门声。"]'),
('song-ci-785','水龙吟','祖吴','宋','宋词','song-ci','水龙吟','[]','紫貂南北分荣，有人瑞凤池疏秀。',126,'宋词/ci.song.15000.json','["紫貂南北分荣，有人瑞凤池疏秀。", "月斧云斤，斫成三绝，辉华星斗。", "早岁从军，乌戎口伐，奇功立就。", "更题衡忠义，传家清白，人道外甥似舅。", "好看五经说后。", "步蟾宫、桂香盈袖。", "紫橐持荷，清班布武，履声依旧。", "回意刊山，当年垂棒，月明烟袖。", "隐岩清秀，露玉风金，岁岁祝千秋寿。"]'),
('song-ci-786','水调歌头','祖吴','宋','宋词','song-ci','水调歌头','[]','佳丽东阳境，瑞气晓笼晴。',114,'宋词/ci.song.15000.json','["佳丽东阳境，瑞气晓笼晴。", "中元逾了十日，上相喜重生。", "四海文章宗匠，百里弦歌德化，官与水双清。", "恳切劝分意，赈恤活饥甿。", "幸依刘，空颂鲁，阻称觥。", "遥瞻快倚楼上，一点寿星明。", "闻道玺书将下，看取蓬瀛直造，指日秉钧衡。", "大展平戎略，谈笑复神京。"]'),
('song-ci-787','沁园春','周申','宋','宋词','song-ci','沁园春','[]','瑞应柯山，昴宿储祥，嵩岳降神。',139,'宋词/ci.song.15000.json','["瑞应柯山，昴宿储祥，嵩岳降神。", "羡堂堂玉莹，汪汪陂量，一襟风月，满腹经纶。", "试问丹砂，聊乘凫舄，来种锦江桃李春。", "弦歌地，看吏能绰著，荐墨争新。", "从兹大振家声。", "待京国来归专秉钧。", "想宸恩初拜，北门学士，都能尽道，东阁郎君。", "雨细丝轻，梅花金重，两荚宝阶呈瑞蓂。", "称觞庆，愿莱衣衮衮，长照庄椿。"]'),
('song-ci-788','壶中天・念奴娇','周申','宋','宋词','song-ci','壶中天・念奴娇','[]','秋来两日，因个甚、乌鹊侵晨传喜。',120,'宋词/ci.song.15000.json','["秋来两日，因个甚、乌鹊侵晨传喜。", "却是常娥亲姊妹，降作人间佳丽。", "黛柳长青，官梅稳衬，镜里春明媚。", "花颜难老，寿杯频劝浮蚁。", "闻道潇洒才郎，天庭试罢，名挂登科记。", "昨夜凉风新过雁，还有音书来寄。", "千万楼台，三千粉黛，今在谁家醉。", "归来欢笑，一床真个双美。"]'),
('song-ci-789','沁园春','赵汝腾','宋','宋词','song-ci','沁园春','[]','人道耻堂，直声劲气，胜如鹤山。',139,'宋词/ci.song.15000.json','["人道耻堂，直声劲气，胜如鹤山。", "记殿庭叱禹，风生九陛，都亭劾冀，影摄群奸。", "海内英豪，如公有几，此地相逢同左官。", "丹青阁，望烟云缥缈，曾共凭栏。", "忧时空见眉端。", "叹西事何由圣虑宽。", "使蜀居诸葛，兵屯自肃，朝留一范，贼胆须寒。", "天欲兴唐，昴应相汉，立取勋名久远看。", "秋香耐，笑菊潭胡广，污简何颜。"]'),
('song-ci-790','沁园春','赵孟坚','宋','宋词','song-ci','沁园春','[]','许大江山，镇临弹压，岂小任哉。',139,'宋词/ci.song.15000.json','["许大江山，镇临弹压，岂小任哉。", "从潘冢导漾，东倾注海，截然限止，南北天开。", "试向中流，回观铁瓮，万石层棱攒剑堆。", "金焦峙，号紫金浮玉，卷雪轰雷。", "君侯文武兼才。", "天有为生才南国来。", "□历二十年，筹边给饷，上流襟要，几为安排。", "今此雄藩，精明笳鼓，又唤金汤气象回。", "长淮北，望中原非远，更展恢规。"]'),
('song-ci-791','鹊桥仙','赵孟坚','宋','宋词','song-ci','鹊桥仙','[]','明金点染，枝头初见，四出如将刀翦。',68,'宋词/ci.song.15000.json','["明金点染，枝头初见，四出如将刀翦。", "芳心才露一些儿，早以被、西风传遍。", "归来醉也，香凝襟袖，疑向广寒宫殿。", "便须著个胆瓶儿，夜深在、枕屏根畔。"]'),
('song-ci-792','沁园春','赵孟坚','宋','宋词','song-ci','沁园春','[]','晓上画楼，望里笑惊，春到那家。',139,'宋词/ci.song.15000.json','["晓上画楼，望里笑惊，春到那家。", "便从臾闲情，安排醉事，寻芳唤友，行过平沙。", "最是堪怜，花枝清瘦，欲笑还羞寒尚遮。", "浓欢赏，待繁英春透，后会犹赊。", "归时月挂檐牙。", "见花影重重浸宝阶。", "□铜壶摧箭，兽环横钉，浓斟玉醑，芳漱琼芽。", "步绕曲廊，倦回芳帐，梦遍江南山水涯。", "谁知我，有墙头桂影，窗上梅花。"]'),
('song-ci-793','朝中措','赵孟坚','宋','宋词','song-ci','朝中措','[]','担头看尽百花春。',57,'宋词/ci.song.15000.json','["担头看尽百花春。", "春事只三分。", "不似莺莺燕燕，相将红杏芳园。", "名缰易绊，征尘难浣，极目销魂。", "明日清明到也，柳条插向谁门。"]'),
('song-ci-794','好事近','赵孟坚','宋','宋词','song-ci','好事近','[]','春早峭寒天，客里倦怀尤恶。',53,'宋词/ci.song.15000.json','["春早峭寒天，客里倦怀尤恶。", "待起冷清清地，又孤眠不著。", "重温卯酒整瓶花，总待自霍索。", "忽听海棠初卖，买一枝添却。"]'),
('song-ci-795','感皇恩','赵孟坚','宋','宋词','song-ci','感皇恩','[]','官小宦游初，清贫如旧。',81,'宋词/ci.song.15000.json','["官小宦游初，清贫如旧。", "小簇杯盘旋篘酒。", "虽然微禄，不比他们丰厚。", "也知惭愧是，皇恩受。", "富贵千般，享之惟寿。", "心地平时到头有。", "摩挲铜狄，祝望比他长久。", "鼎来荣贵待，通闺后。"]'),
('song-ci-796','感皇恩','赵孟坚','宋','宋词','song-ci','感皇恩','[]','一百二十年，两番甲子。',83,'宋词/ci.song.15000.json','["一百二十年，两番甲子。", "前番风霜饱谙矣。", "今番甲子，一似腊尽春至。", "程程有好在，应惭愧。", "莫道官贫，胜如无底。", "随分杯筵称家计。", "从今数去，尚有五十八生朝里。", "待儿官大，做奢遮会。"]'),
('song-ci-797','风流子','赵孟坚','宋','宋词','song-ci','风流子','[]','望极思悠悠。',134,'宋词/ci.song.15000.json','["望极思悠悠。", "江如练、籁息浪纹收。", "看帆卷帆舒，往来征艇，鹭飞鹭立，远近芳洲。", "逝波不舍山常好，祗白少年头。", "杜若满汀，离骚幽怨，鸱夷去国，烟浪遨游。", "江南知何许，青林晚，山断处、白云浮。", "怀古慨今，谁人似我闲愁。", "叹醉生浪迹，鲈乡蟹舍，殢红怨粉，莲棹菱舟。", "敲遍阑干，默然竟日凝眸。"]'),
('song-ci-798','花心动','赵孟坚','宋','宋词','song-ci','花心动','[]','庭院深深，正花飞零乱，蝶懒蜂稀。',127,'宋词/ci.song.15000.json','["庭院深深，正花飞零乱，蝶懒蜂稀。", "柳絮狂踪，轻入房栊，悄悄可有人知。", "画堂镇日闲晴昼，金炉冷、绣幕低垂。", "梁间燕，双双并翅，对舞高低。", "兰幌玉人睡起，情脉脉、无言暗敛双眉。", "斗帐半褰，六曲屏山，憔悴似不胜衣。", "一声笑语谁家女，秋千映、红粉墙西。", "断肠处，行人马上醉归。"]'),
('song-ci-799','蓦山溪','赵孟坚','宋','宋词','song-ci','蓦山溪','[]','几年修绩，总待荣亲老。',102,'宋词/ci.song.15000.json','["几年修绩，总待荣亲老。", "每羡院南豪，向寿席、花花草草。", "如今惭愧，微胜十年前，聊尔办，杯盘了，一对慈颜笑。", "愿亲强健，绿鬓长长好。", "来岁在琴堂，想凡事、应微热闹。", "契天交道，只办好心肠，官尽大，尽荣亲，待受金花诰。"]'),
('song-ci-800','蓦山溪','赵孟坚','宋','宋词','song-ci','蓦山溪','[]','桃花雨动，测测轻寒小。',102,'宋词/ci.song.15000.json','["桃花雨动，测测轻寒小。", "曲槛面危阑，对东风、伤春怀抱。", "酒边心事，花下旧闲情，流年度，芳尘杳，懊恼人空老。", "粉红题字，寄与分明道。", "消息燕归时，辗柔茵、连天芳草。", "琐窗孤影，夜卜烛花明，清漏断，月朦胧，挂在梅梢袅。"]'),
('song-ci-801','东风第一枝','赵崇霄','宋','宋词','song-ci','东风第一枝','[]','妒雪梅苏，迷烟柳醒，游丝轻扬新霁。',123,'宋词/ci.song.15000.json','["妒雪梅苏，迷烟柳醒，游丝轻扬新霁。", "卷帘看燕初归，步屧为花早起。", "春来犹浅，便做出、十分春意。", "喜凤钗、才卸珠幡，早换巧梳描翠。", "著数点、催花雨腻。", "更一番、递香风细。", "小莺忺暖调声，嫩蝶试晴舞翅。", "清欢易失，怕轻负、年芳流水。", "好趁闲、共整吟鞯，日日访桃寻李。"]'),
('song-ci-802','减字木兰花','马光祖','宋','宋词','song-ci','减字木兰花','[]','多情多爱。',52,'宋词/ci.song.15000.json','["多情多爱。", "还了平生花柳债。", "好个檀郎。", "室女为妻也不妨。", "杰才高作。", "聊赠青蚨三百索。", "烛影摇红。", "记取媒人是马公。"]'),
('song-ci-803','贺新郎','李南金','宋','宋词','song-ci','贺新郎','[]','流落今如许。',141,'宋词/ci.song.15000.json','["流落今如许。", "我亦三生杜牧，为秋娘著句。", "先自多愁多感慨，更值江南春暮。", "君看取、落花飞絮。", "也有吹来穿绣幌，有因风、飘坠随尘土。", "人世事，总无据。", "佳人命薄君休诉。", "若说与、英雄心事，一生更苦。", "且尽樽前今日意，休记绿窗眉妩。", "但春到、儿家庭户。", "幽恨一帘烟月晓，恐明年、雁亦无寻处。", "浑欲倩，莺留住。"]'),
('song-ci-804','朝中措','萧','宋','宋词','song-ci','朝中措','[]','半山社雨欲黄昏。',57,'宋词/ci.song.15000.json','["半山社雨欲黄昏。", "燕子不过门。", "杨柳染深绿意，海棠啼损红痕。", "绮寮妆束，宝钗歌舞，玉枕温存。", "一段旧情有味，十分新恨无言。"]'),
('song-ci-805','恋绣衣','萧','宋','宋词','song-ci','恋绣衣','[]','倚阑闲看燕定巢。',68,'宋词/ci.song.15000.json','["倚阑闲看燕定巢。", "旧弹筝、因病久抛。", "画不尽、残眉黛，被东风、吹在柳梢。", "晓来暗理伤春曲，把金钗、枕畔细敲。", "书寄与、天涯去，并相思、红泪一包。"]'),
('song-ci-806','满江红','萧','宋','宋词','song-ci','满江红','["\u897f\u6e56"]','（和陈漕使仙湖韵）莫是西湖，分一派、残波剩碧。',124,'宋词/ci.song.15000.json','["（和陈漕使仙湖韵）莫是西湖，分一派、残波剩碧。", "闲问著、莺仙丹事，老榕知得。", "荇水带长鸥踏损，柳风絮暖鱼吞入。", "只前山、依旧汉时青，晴还湿。", "亭疏好，何消密。", "花少好，无多植。", "听黄鹂三请，要诗翁出。", "消渴泉斟寒玉液，留题石剥苍苔色。", "叹而今、翻羡□南春，乾坤窄。"]'),
('song-ci-807','霜天晓角','萧泰来','宋','宋词','song-ci','霜天晓角','[]','千霜万雪。',54,'宋词/ci.song.15000.json','["千霜万雪。", "受尽寒磨折。", "赖是生来瘦硬，浑不怕、角吹彻。", "清绝。", "影也别。", "知心惟有月。", "原没春风情性，如何共、海棠说。"]'),
('song-ci-808','满江红','萧泰来','宋','宋词','song-ci','满江红','[]','七十人稀，尝记得、少陵旧语。',115,'宋词/ci.song.15000.json','["七十人稀，尝记得、少陵旧语。", "谁知道、五园庵主，寿今如许。", "书底青瞳如月样，镜中黑鬓无双处。", "与人间、世味不相投，神仙侣。", "文汉史，诗唐句。", "字晋帖，碑周鼓。", "这千年勋业，一年一部。", "晔晔紫芝商隐皓，猗猗绿竹淇瞻武。", "问先生、何处更高歌，凭椿树。"]'),
('song-ci-809','城头月','马天骥','宋','宋词','song-ci','城头月','[]','城头月色明如昼。',57,'宋词/ci.song.15000.json','["城头月色明如昼。", "总是青霞有。", "酒醉茶醒，饥餐困睡，不把双眉皱。", "坎离龙虎勤交媾。", "炼得丹将就。", "借问罗浮鹤侣，还似先生否。"]'),
('song-ci-810','城头月','黎道静','宋','宋词','song-ci','城头月','[]','阳光子夜开清昼。',60,'宋词/ci.song.15000.json','["阳光子夜开清昼。", "照了无何有。", "弱水蓬莱，河车忽动，万顷金波皱。", "红铅墨汞相交媾。", "片饷丹成就。", "把握阴阳，一锺造化，此诀人知否。"]'),
('song-ci-811','满庭芳','黄判院','宋','宋词','song-ci','满庭芳','[]','桃浪翻花，柳风飘絮，翠蓂八叶呈芳。',118,'宋词/ci.song.15000.json','["桃浪翻花，柳风飘絮，翠蓂八叶呈芳。", "奎星初度，箕宿耀祥光。", "元是降神崧岳，生英杰、奇伟非常。", "文章士，青春未老，一鹗快飞黄。", "登瀛，平步上，鳌头独占，头角轩昂。", "主琼林宴席，荣冠绿衣郎。", "归侍彩俱庆，逢生旦、品上椒觞。", "从今去，公侯谈笑，福寿等天长。"]'),
('song-ci-812','青玉案','薛泳','宋','宋词','song-ci','青玉案','[]','一盘消夜江南果。',80,'宋词/ci.song.15000.json','["一盘消夜江南果。", "吃果看书只清坐。", "罪过梅花料理我。", "一年心事，半生牢落，尽向今宵过。", "此身本是山中个。", "才出山来便希差。", "手种青松应是大。", "缚茅深处，抱琴归去，又是明年话。"]'),
('song-ci-813','满江红','徐元杰','宋','宋词','song-ci','满江红','["\u897f\u6e56"]','似玉仙人，三载相见，西湖清客。',115,'宋词/ci.song.15000.json','["似玉仙人，三载相见，西湖清客。", "攧不碎、一团和气，只伊消得。", "雪里水中霜态度，腊前冬后春消息。", "看帘垂、清昼一张琴，中闲著。", "寒谷里，轻回脚。", "魁手段，堪描摸。", "唤东风吹上，兰台芸阁。", "只怕傅岩香不断，摩挲商鼎羹频作。", "管一番滋味一番新，今如昨。"]'),
('song-ci-814','沁园春','国学生','宋','宋词','song-ci','沁园春','[]','三学上书，冤乎天哉，哲人已萎。',140,'宋词/ci.song.15000.json','["三学上书，冤乎天哉，哲人已萎。", "自纲常一疏，为时太息，典刑诸老，尽力扶持。", "方哭南床，继伤右揆，死到先生事可知。", "伤心处，笑寒梅冷落，血泪淋漓。", "人心公论难欺。", "愿君父、明明悟此机。", "昔九龄疏谏，禄山必叛，更生累奏，王氏为危。", "变起范阳，祸成新室，说著当年人噬脐。", "君知否，但皇天祚宋，此事无之。"]'),
('song-ci-815','瑞鹤仙','陆叡','宋','宋词','song-ci','瑞鹤仙','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','湿云黏雁影。',127,'宋词/ci.song.15000.json','["湿云黏雁影。", "望征路愁迷，离绪难整。", "千金买光景。", "但疏钟催晓，乱鸦啼暝。", "花悰暗省。", "许多情、相逢梦境。", "便行云、都不归来，也合寄将音信。", "孤迥。", "盟鸾心在，跨鹤程高，后期无准。", "情丝待翦。", "翻惹得，旧时恨。", "怕天教何处，参差双燕，还染残朱剩粉。", "对菱花、与说相思，看谁瘦损。"]'),
('song-ci-816','八声甘州','陆叡','宋','宋词','song-ci','八声甘州','[]','问缠腰跨鹤，事如何，人生最风流。',119,'宋词/ci.song.15000.json','["问缠腰跨鹤，事如何，人生最风流。", "怕江边潮汐，世间歧路，只是离愁。", "白马青衫往事，赢得鬓先秋。", "目送红桥晚，几番行舟。", "兰珮空馀依黯，便南风吹水，人也难留。", "但从今别后，我亦似浮沤。", "敬亭上、半床琴月，记弹将、寒影落南州。", "秋声里，塞鸿来后，为而登楼。"]'),
('song-ci-817','甘州・八声甘州','陆叡','宋','宋词','song-ci','甘州・八声甘州','["\u897f\u6e56"]','满清平世界庆秋成，看看斗三钱。',118,'宋词/ci.song.15000.json','["满清平世界庆秋成，看看斗三钱。", "论从来活国，论功第一，无过丰年。", "办得闲民一饱，馀事笑谈间。", "若问平戎策，微妙难传。", "玉帝要留公住，把西湖一曲，分入林园。", "有茶炉丹灶，更有钓鱼船。", "觉秋风、未曾吹著，但砌兰、长倚北堂萱。", "千千岁，上天将相，平地神仙。"]'),
('song-ci-818','声声慢','史可堂','宋','宋词','song-ci','声声慢','[]','羞朱妒粉，染雾裁云，淡然苍佩仙裳。',119,'宋词/ci.song.15000.json','["羞朱妒粉，染雾裁云，淡然苍佩仙裳。", "半额蜂妆，莫道梳洗家常。", "碧罗乱萦小带，翠虬寒、一架清香。", "春思苦，倚晴娇无力，如待韩郎。", "密幄笼芳吟夜，任露沾轻袖，月转空梁。", "弱骨柔姿，偏解勾引诗狂。", "遗钿碎金满地，恨无情、风送韶光。", "闲昼永，看青青、垂蔓过墙。"]'),
('song-ci-819','蓦山溪','史可堂','宋','宋词','song-ci','蓦山溪','[]','危阑看月，番做听秋雨。',102,'宋词/ci.song.15000.json','["危阑看月，番做听秋雨。", "一滴一声愁，似相伴，离人悲苦。", "笼香袖冷，独立倚西风，红叶落，菊花残，都是关情处。", "如何排遣，赖有高阳侣。", "长啸酒垆边，且同赋、秋娘词句。", "山翁醉矣，一笛小楼空，思往事，看孤云，目断征鸿去。"]'),
('song-ci-820','眼儿媚','陈诜','宋','宋词','song-ci','眼儿媚','[]','鬓边一点似飞鸦。',58,'宋词/ci.song.15000.json','["鬓边一点似飞鸦。", "休把翠钿遮。", "二年三载，千拦百就，今日天涯。", "杨花又逐东风去，随分入人家。", "要不思量，除非酒醒，休照菱花。"]'),
('song-ci-821','小桃红・连理枝','余桂英','宋','宋词','song-ci','小桃红・连理枝','[]','芳草连天暮。',86,'宋词/ci.song.15000.json','["芳草连天暮。", "斜日明汀渚。", "懊恨东风，恍如春梦，匆匆又去。", "早知人、酒病更诗愁，镇轻随飞絮。", "宝镜空留恨，筝雁浑无据。", "门外当时，薄情流水，如今何处。", "正相思、望断碧山云，又莺啼晚雨。"]'),
('song-ci-822','八声甘州','曾原郕','宋','宋词','song-ci','八声甘州','[]','问岩云朵朵为谁飞，向来读何书。',118,'宋词/ci.song.15000.json','["问岩云朵朵为谁飞，向来读何书。", "道江南名宦，掉头勿顾，彩服归与。", "无限山中风物，今古属潜夫。", "渺渺辽天鹤，应费招呼。", "谩说缁巾缟带，与豸冠犀剑，忧乐如何。", "渐桥横采石，国步已趑趄。", "想归来、顿成憔悴，叹季鹰、闻早忆莼鲈。", "丹泉冷，崖锺绝响，夕照啼乌。"]'),
('song-ci-823','木兰花・玉楼春','曾原郕','宋','宋词','song-ci','木兰花・玉楼春','[]','断崖抛雪瀑，又潜溜、入山跟。',123,'宋词/ci.song.15000.json','["断崖抛雪瀑，又潜溜、入山跟。", "听暗壁潺湲，山中紫雾，山下红云。", "当年七僧甚处，但空馀、老刹靠嶙峋。", "底事神粮不幻，翠窝剩积香尘。", "纷纷。", "结社种莲人。", "名氏已无闻。", "看银书般若，金陵故国，斜敕空存。", "争得十虚销殒，为让皇、冤魄脱沈沦。", "往事犹堪一笑，岩花乱点乌巾。"]'),
('song-ci-824','三台春曲','许棐','宋','宋词','song-ci','三台春曲','[]','昨夜微风细雨，今朝薄霁轻寒。',28,'宋词/ci.song.15000.json','["昨夜微风细雨，今朝薄霁轻寒。", "檐外一声啼鸟，报知花柳平安。"]'),
('song-ci-825','三台春曲','许棐','宋','宋词','song-ci','三台春曲','[]','春是人间过客，花随春不多时。',28,'宋词/ci.song.15000.json','["春是人间过客，花随春不多时。", "人比花尤易老，那堪终日相思。"]'),
('song-ci-826','谒金门','许棐','宋','宋词','song-ci','谒金门','[]','微雨后。',52,'宋词/ci.song.15000.json','["微雨后。", "染得杏腮红透。", "春色好时人却瘦。", "镜寒妆不就。", "柳外一莺啼昼。", "约略情怀中酒。", "困起半弯眉袖。", "髻松簪玉溜。"]'),
('song-ci-827','鹧鸪天','许棐','宋','宋词','song-ci','鹧鸪天','[]','翠凤金鸾绣欲成。',64,'宋词/ci.song.15000.json','["翠凤金鸾绣欲成。", "沈香亭下款新晴。", "绿随杨柳阴边去，红踏桃花片上行。", "莺意绪，蝶心情。", "一时分付小银筝。", "归来玉醉花柔困，月滤窗纱约半更。"]'),
('song-ci-828','柳枝・杨柳枝','许棐','宋','宋词','song-ci','柳枝・杨柳枝','[]','冷迫春宵一半床。',48,'宋词/ci.song.15000.json','["冷迫春宵一半床。", "懒熏香。", "不如屏里画鸳鸯。", "永成双。", "重叠衾罗犹未暖。", "红烛短。", "明朝春雨足池塘。", "落花忙。"]'),
('song-ci-829','小重山','许棐','宋','宋词','song-ci','小重山','[]','正是拈芳采艳时。',70,'宋词/ci.song.15000.json','["正是拈芳采艳时。", "连朝风雨里，掩朱扉。", "强排春恨剪新词。", "词未就，莺唱缕金衣。", "云薄弄晴晖。", "试穿花迳去，拣双枝。", "紫香红腻著罗衣。", "簪不尽，瓶里顿将归。"]'),
('song-ci-830','满宫春','许棐','宋','宋词','song-ci','满宫春','[]','懒抟香，慵弄粉。',60,'宋词/ci.song.15000.json','["懒抟香，慵弄粉。", "犹带浅酲微困。", "金鞍何处掠新欢，偷倩燕寻莺问。", "柳供愁，花献恨。", "衮絮猎红成阵。", "碧楼能有几番春，又是一番春尽。"]'),
('song-ci-831','浣溪沙','许棐','宋','宋词','song-ci','浣溪沙','[]','欲把香缯暖缬裁。',48,'宋词/ci.song.15000.json','["欲把香缯暖缬裁。", "玉箱金锁又慵开。", "一杯茶罢上春台。", "方向柳边揉碧缕，又从花畔并红腮。", "不知凝待阿谁来。"]'),
('song-ci-832','更漏子','许棐','宋','宋词','song-ci','更漏子','[]','泪淹红，腮褪粉。',58,'宋词/ci.song.15000.json','["泪淹红，腮褪粉。", "等得玉销花损。", "羞阮凤，怯筝鸾。", "指寒无好弹。", "一庭雪。", "半窗月。", "又是独眠时节。", "孤枕怨，小屏愁。", "天涯梦里游。"]'),
('song-ci-833','荷叶杯','许棐','宋','宋词','song-ci','荷叶杯','[]','鹊踏画檐双噪。',60,'宋词/ci.song.15000.json','["鹊踏画檐双噪。", "书到。", "和笑拆封看。", "归程能隔几重山。", "远约数宵间。", "准备绣轮雕辔。", "游戏。", "说与百花知。", "莫教枝上一红飞。", "留伴玉东西。"]'),
('song-ci-834','夜行船','许棐','宋','宋词','song-ci','夜行船','[]','一辔东风留不住。',68,'宋词/ci.song.15000.json','["一辔东风留不住。", "离歌断、日斜春暮。", "多事啼莺，妒情飞燕，一路送人归去。", "文君自被琴心误。", "却惆怅、落花飞絮。", "锦字机寒，玉炉烟冷，门外乱山无数。"]'),
('song-ci-835','应天长','许棐','宋','宋词','song-ci','应天长','[]','溅紫飘红风又雨。',60,'宋词/ci.song.15000.json','["溅紫飘红风又雨。", "一刻韶芳留不住。", "燕吞声，莺谇语。", "待得晴来人已去。", "怯新歌，怜旧舞。", "冷落艳腔芳谱。", "要识此时情绪。", "豆梅酸更苦。"]'),
('song-ci-836','喜迁莺','许棐','宋','宋词','song-ci','喜迁莺','[]','鸠雨细，燕风斜。',57,'宋词/ci.song.15000.json','["鸠雨细，燕风斜。", "春悄谢娘家。", "一重帘外即天涯。", "何必暮云遮。", "钏金寒，钗玉冷。", "薄醉欲成还醒。", "一春梳洗不簪花。", "孤负几韶华。"]'),
('song-ci-837','虞美人','许棐','宋','宋词','song-ci','虞美人','[]','杏花窗底人中酒。',68,'宋词/ci.song.15000.json','["杏花窗底人中酒。", "花与人相守。", "帘衣不肯护春寒。", "一声娇嚏两眉攒。", "拥衾眠。", "明朝又有秋千约。", "恐未忺梳掠。", "倩谁传语画楼风。", "略吹丝雨湿春红。", "绊游踪。"]'),
('song-ci-838','清平乐','许棐','宋','宋词','song-ci','清平乐','[]','凤双鸾偶。',54,'宋词/ci.song.15000.json','["凤双鸾偶。", "天上人间有。", "檐玉无声花影瘦。", "夜浅春浓时候。", "别来几度寒宵。", "六桥风月迢迢。", "灯下有谁相伴，一方红湿鲛绡。"]'),
('song-ci-839','山花子','许棐','宋','宋词','song-ci','山花子','[]','挼柳揉花旋染衣。',56,'宋词/ci.song.15000.json','["挼柳揉花旋染衣。", "丝丝红翠扑春辉。", "罗绮丛中无此艳，小西施。", "腰细最便围舞帊，袖寒时复罩香え。", "误点一痕残泪粉，怕人知。"]'),
('song-ci-840','相思引','许棐','宋','宋词','song-ci','相思引','[]','组绣盈箱锦满机。',54,'宋词/ci.song.15000.json','["组绣盈箱锦满机。", "倩谁缝作护花衣。", "恐花飞去，无复上芳枝。", "已恨远山迷望眼，不须更画远山眉。", "正无聊赖，雨外一鸠啼。"]'),
('song-ci-841','画堂春','许棐','宋','宋词','song-ci','画堂春','[]','一绡香暖看灯衣。',55,'宋词/ci.song.15000.json','["一绡香暖看灯衣。", "领珠襟翠争辉。", "金球斜亸雪梅枝。", "著带都宜。", "桃艳妆成醉脸，柳娇移上歌眉。", "一轮蟾玉堕花西。", "携手同归。"]'),
('song-ci-842','相见欢','许棐','宋','宋词','song-ci','相见欢','[]','绣围春水锦笼山。',46,'宋词/ci.song.15000.json','["绣围春水锦笼山。", "冶游天。", "可惜连朝中酒、怯秋千。", "妆楼暖。", "朱帘卷。", "燕斜穿。", "冲落两三花片、镜台边。"]'),
('song-ci-843','后庭花','许棐','宋','宋词','song-ci','后庭花','["\u897f\u6e56"]','一春不识西湖面。',52,'宋词/ci.song.15000.json','["一春不识西湖面。", "翠羞红倦。", "雨窗和泪摇湘管。", "意长笺短。", "知心惟有雕梁燕。", "自来相伴。", "东风不管琵琶怨。", "落花吹遍。"]'),
('song-ci-844','摸鱼儿','陈策','宋','宋词','song-ci','摸鱼儿','[]','倚危梯、酹春怀古，轻寒才转花信。',140,'宋词/ci.song.15000.json','["倚危梯、酹春怀古，轻寒才转花信。", "江城望极多愁思，前事恼人方寸。", "湖海兴。", "算合付元龙，举白浇谈吻。", "凭高试问。", "问旧日王郎，依刘有地，何事赋幽愤。", "沙头路，休记家山远近。", "宾鸿一去无信。", "沧波渺渺空归梦，门外北风凄紧。", "乌帽整。", "便做得功名，难绿星星鬓。", "敲吟为稳。", "又白鹭飞来，垂杨自舞，谁与寄离恨。"]'),
('song-ci-845','满江红','陈策','宋','宋词','song-ci','满江红','[]','倦绣人闲，恨春去、浅颦轻掠。',115,'宋词/ci.song.15000.json','["倦绣人闲，恨春去、浅颦轻掠。", "章台路，雪黏飞燕，带芹穿幕。", "委地身如游子倦，随风命似佳人薄。", "叹此花、飞后更无花，情怀恶。", "心下事，谁堪托。", "怜老大，伤飘泊。", "把前回离恨，暗中描摸。", "又趁扁舟低欲去，可怜世事今非昨。", "看等闲、飞过女墙来，秋千索。"]'),
('song-ci-846','兰陵王','李昴英','宋','宋词','song-ci','兰陵王','[]','燕穿幕。',158,'宋词/ci.song.15000.json','["燕穿幕。", "春在深深院落。", "单衣试，龙沫旋薰，又怕东风晓寒薄。", "别来情绪恶。", "瘦得腰围柳弱。", "清明近，正似海棠，怯雨芳踪任飘泊。", "钗留去年约。", "恨易老娇莺，多误灵鹊。", "碧云杳渺天涯各。", "望不断芳草，更迷香絮，回文强写字屡错。", "泪欲注还阁。", "孤酌。", "住春脚。", "便彩局谁忺，宝轸慵学。", "阶除拾取飞花嚼。", "是多少春恨，等闲吞却。", "阑干猛拍，叹命薄，悔旧诺。"]'),
('song-ci-847','摸鱼儿','李昴英','宋','宋词','song-ci','摸鱼儿','[]','晓风痴、绣帘低舞。',140,'宋词/ci.song.15000.json','["晓风痴、绣帘低舞。", "霏霏香碎红雨。", "燕忙莺懒春无赖，懒为好花遮护。", "浑不顾。", "费多少工夫，做得芳菲聚。", "休颦百五。", "却自恨新年，游疏醉少，光景恁虚度。", "猊烟瘦，困起庭阴正午。", "游丝飞絮无据。", "千林湿翠须臾遍，难绿鬓根霜缕。", "愁绝处。", "怎忍听，声声杜宇深深树。", "东君寄语。", "道去也还来，后期长在，紫陌岁相遇。"]'),
('song-ci-848','摸鱼儿','李昴英','宋','宋词','song-ci','摸鱼儿','[]','敞茅堂、茂林环翠，苔矶低蘸烟浦。',140,'宋词/ci.song.15000.json','["敞茅堂、茂林环翠，苔矶低蘸烟浦。", "青蓑混入渔家社，斜日断桥船聚。", "真乐处。", "坐芳草，瓦樽满酒频频注。", "皋禽自舞。", "惯松迳穿云，梅村踏雪，朗笑自来去。", "车乘坠，争似修筇稳步。", "前尘回首俱误。", "安闲得在中年好，抱瓮尚堪蔬圃。", "高眼觑。", "算不识、人间宠辱除巢许。", "风篁解语。", "应共笑群狙，无端喜怒，三四计朝暮。"]'),
('song-ci-849','摸鱼儿','李昴英','宋','宋词','song-ci','摸鱼儿','[]','绕西园、粉笼千雉，镜池屏石天造。',140,'宋词/ci.song.15000.json','["绕西园、粉笼千雉，镜池屏石天造。", "主人意匠工收拾，华屋落成闻早。", "轮奂巧。", "望缥缈、五云深处移蓬岛。", "油幢羽葆。", "指貔虎长驱，鲸鲲网取，电走捷旗报。", "铙吹发，回庑连屯饮犒。", "海山波静烟扫。", "纶巾萧散环珠履，春满绿杨芳草。", "人境好。", "是握穗五翁，福地无尘到。", "芝书在道。", "便整顿乾坤，经营万宇，栋国要元老。"]'),
('song-ci-850','摸鱼儿','李昴英','宋','宋词','song-ci','摸鱼儿','[]','怪朝来、片红初瘦，半分春事风雨。',140,'宋词/ci.song.15000.json','["怪朝来、片红初瘦，半分春事风雨。", "丹山碧水含离恨，有脚阳春难驻。", "芳草渡。", "似叫住东君，满树黄鹂语。", "无端杜宇。", "报采石矶头，惊涛屋大，寒色要春护。", "阳关唱，画鹢徘徊东渚。", "相逢知又何处。", "摩挲老剑雄心在，对酒细评今古。", "君此去。", "几万里东南，只手擎天柱。", "长生寿母。", "更稳步安舆，三槐堂上，好看彩衣舞。"]'),
('song-ci-851','贺新郎','李昴英','宋','宋词','song-ci','贺新郎','[]','绣谷流明帜。',141,'宋词/ci.song.15000.json','["绣谷流明帜。", "稳飞舆、茵柔草碧，盖欹松翠。", "遨首意行穷绝顶，彩榭千年胜地。", "远峰断、莽苍烟水。", "护日晴云收午暑，飒长风、振叶生秋思。", "笼雾炷，飘霞袂。", "清明官府歌棠芾。", "且萧闲事外，下看玉城珠市。", "山色骄人逢此客，麈尾霏霏露碎。", "一笑又、羊衔新穗。", "田野欢声和气合，唤觥船、猛为鱼占喜。", "谁会得，醉翁意。"]'),
('song-ci-852','贺新郎','李昴英','宋','宋词','song-ci','贺新郎','[]','世羡官高大。',142,'宋词/ci.song.15000.json','["世羡官高大。", "又谁知、几多卿相，身荣名壤。", "我辈相逢无愧色，彼此苍颜健在。", "又荣易、分携越海。", "写出阳关离别恨，看一行、雁字斜飞界。", "天下宝，愿自爱。", "白衣苍狗须臾改。", "久冥心、鸡虫得失，鷃鹏迟快。", "君带貂蝉头上立，老我荷衣草带。", "肯此膝、向人雅拜。", "远饯元非趋炎者，二十年、相与形骸外。", "义金石，更坚耐。"]'),
('song-ci-853','贺新郎','李昴英','宋','宋词','song-ci','贺新郎','[]','谁种蓝田玉。',141,'宋词/ci.song.15000.json','["谁种蓝田玉。", "碧云深、亭亭月上，水明溪曲。", "羞作时妆儿女态，冷淡冰餐露沐。", "出尘外、风标幽独。", "除了留侯无此貌，便何郎、傅粉终粗俗。", "意凝远，韵清淑。", "凉台向晚微风馥。", "讶银杯羽化，折取戏浮醽醁。", "安得梅花如许大，天遣辟除暑溽。", "浑不觉、鹭翘鸥浴。", "可恨妖妃污太液，只东林、社友追游熟。", "宜夜看，灿瑶烛。"]'),
('song-ci-854','贺新郎','李昴英','宋','宋词','song-ci','贺新郎','[]','细与黄花说。',142,'宋词/ci.song.15000.json','["细与黄花说。", "是天教、开遇重阳，玉裁金屑。", "老行要寻松竹伴，雅爱山翁鬓雪。", "任满插、追陪节物。", "惟有渊明吾臭味，傍东篱、盘薄芳丛撷。", "便无酒，也清绝。", "芒寒色正孤标洁。", "惯平生、餐霜饮露，倚风迎月。", "不比芙蓉偏妩媚，不比茱萸太烈。", "似隐者、萧闲岩穴。", "至老枝头犹健在，笑纷纷、红紫尘沙汨。", "香耐久，看晚节。"]'),
('song-ci-855','贺新郎','李昴英','宋','宋词','song-ci','贺新郎','[]','元日除书湿。',141,'宋词/ci.song.15000.json','["元日除书湿。", "到而今、西风老矣，驾轺初入。", "自是龙颜深注想，孤凤翔而后集。", "久父老、攀留原隰。", "庾岭经行梅亦喜，小奚奴、背底惟诗笈。", "冰雪操，又谁及。", "昨来容易风云翕。", "便三台两地，也只等闲如拾。", "天马不鸣凡马喑，百步何如五十。", "况汹汹、波涛方急。", "此去一言回天力，著高高、百尺竿头立。", "浇磊磈，快鲸吸。"]'),
('song-ci-856','贺新郎','李昴英','宋','宋词','song-ci','贺新郎','[]','过雨璇空湿。',141,'宋词/ci.song.15000.json','["过雨璇空湿。", "浩秋香、光浮桂菊，晓风吹入。", "柳系牙樯应小驻，草草还成胜集。", "又追趁、牡车原隰。", "照座玉人风骨耸，想胸蟠、蕊阙琳琅笈。", "真作者，世难及。", "远山云雾工开翕。", "共朱阑徙倚，总好锦囊收拾。", "老我祗今才思涩，知二争如知十。", "戛金缕、檀敲休急。", "访古夷犹行八境，忆朝阳、鸣凤台端立。", "笔也醉，砚池吸。"]'),
('song-ci-857','贺新郎','李昴英','宋','宋词','song-ci','贺新郎','[]','天地中间大。',142,'宋词/ci.song.15000.json','["天地中间大。", "纵遨游、登山临水，散人一个。", "学易已来秋又六，肯趁名缰利锁。", "得日日、安闲笑过。", "金马玉堂也曾到，尽不妨、拍手溪头坐。", "风蒻笠，月兰舸。", "今朝记是初生我。", "近小春、黄菊犹葩，早梅将朵。", "拔宅危巅穷胜践，指点尘寰蚁磨。", "看涧底、飞泉珠颗。", "松柏苍苍俱寿相，更千年、雪鹤鸣相和。", "安期老，举杯贺。"]'),
('song-ci-858','水龙吟','李昴英','宋','宋词','song-ci','水龙吟','[]','唱恭初意如何，朅来五十三年矣。',126,'宋词/ci.song.15000.json','["唱恭初意如何，朅来五十三年矣。", "犁锄颇熟，诗书粗解，簪绅聊耳。", "自信柴愚，真成汲戆，却无刘腻。", "向高秋初度，同时有菊，淡相对、风霜里。", "最癖登山临水。", "又何心、蜗名蝇利。", "俗缘未了，强教肉食，何曾知味。", "无事微吟，会心微笑，逢场微醉。", "把日生、只恁安排，领取百十二岁。"]'),
('song-ci-859','水龙吟','李昴英','宋','宋词','song-ci','水龙吟','[]','驿飞稳驾高秋，迎人满目清新景。',126,'宋词/ci.song.15000.json','["驿飞稳驾高秋，迎人满目清新景。", "秋还有色，芙蓉照水，晨妆对镜。", "雪卷寒芦，字横过雁，渡浮孤艇。", "是骚人行处，腔风调月，香满袖、过梅岭。", "断岸烟收人静。", "雨声乾、桐疏枫冷。", "掀髯独笑，仙翁起舞，卧龙呼醒。", "近小阳春，为梅也合，迟迟鞭影。", "更郁孤、一笑追欢，料得坡翁首肯。"]'),
('song-ci-860','水龙吟','李昴英','宋','宋词','song-ci','水龙吟','[]','碧潭新涨浮花，柳阴稠绿波痕腻。',125,'宋词/ci.song.15000.json','["碧潭新涨浮花，柳阴稠绿波痕腻。", "一声雷鼓，半空雪浪，双龙惊起。", "气压鲸鲵，怒掀鳞鬣，擘开烟水。", "算战争蛮触，雌雄汉楚，总皆一场如此。", "点额许教借一，得头筹、欢呼震地。", "翻嗤浮世，要津搀进，奔波逐利。", "斗了还休，倩渠衔寄，三闾角黍。", "会风云、快出为霖，可但颔明珠睡。"]'),
('song-ci-861','水调歌头','李昴英','宋','宋词','song-ci','水调歌头','[]','郭外足幽胜，潮入涨溪流。',114,'宋词/ci.song.15000.json','["郭外足幽胜，潮入涨溪流。", "舫斋小小一叶，老子日遨游。", "管领白苹红蓼，披戴绿蓑青箬，直钓任沈浮。", "玉楼胞鲈脍，雪阵狎沙鸥。", "个中眠，个中坐，个中讴。", "个中收拾诗料，觞客个中留。", "休羡乘槎博望，且听洞箫赤壁，乐处是瀛洲。", "日月荡双桨，天地一虚舟。"]'),
('song-ci-862','水调歌头','李昴英','宋','宋词','song-ci','水调歌头','[]','万顷黄湾口，千仞白云头。',114,'宋词/ci.song.15000.json','["万顷黄湾口，千仞白云头。", "一亭收拾，便觉炎海豁清秋。", "潮候朝昏来去，山色雨晴浓淡，天末送双眸。", "绝域远烟外，高浪舞连艘。", "风景别，胜滕阁，压黄楼。", "胡床老子，醉挥珠玉落南州。", "稳驾大鹏八极，叱起仙羊五石，飞佩过丹丘。", "一笑人间世，机动早惊鸥。"]'),
('song-ci-863','水调歌头','李昴英','宋','宋词','song-ci','水调歌头','[]','地位到公辅，耆艾过稀年。',114,'宋词/ci.song.15000.json','["地位到公辅，耆艾过稀年。", "几人兼此二美，而况是名贤。", "松柏苍然长健，姜桂老来越辣，劲气九秋天。", "鲠鲠撄鳞语，不改铁心坚。", "说武夷，同此月，瑞三仙。", "公虽居后，瑰奇伟特却光前。", "续得紫阳脉络，了却西山事业，舟楫济商川。", "饮对黄花榭，一酌岁三千。"]'),
('song-ci-864','水调歌头','李昴英','宋','宋词','song-ci','水调歌头','[]','野趣在城市，崛起此台高。',114,'宋词/ci.song.15000.json','["野趣在城市，崛起此台高。", "谁移蓬岛，冯夷夜半策灵鳌。", "十万人家甃碧，四面峰峦涌翠，远岫拍银涛。", "插汉笔双塔，簸两叶轻舠。", "我乘风，时一到，共嬉遨。", "江山无复偃蹇，弹压有诗豪。", "宝剑孤横星动，铁笛一声云裂，寒月冰宫袍。", "沧海一杯酒，世界眇鸿毛。"]'),
('song-ci-865','念奴娇','李昴英','宋','宋词','song-ci','念奴娇','[]','瑶池高会，见云香凤背，风柔鹤膝。',120,'宋词/ci.song.15000.json','["瑶池高会，见云香凤背，风柔鹤膝。", "天遣月卿来拜舞，新拜玺书增秩。", "有母能贤，生儿如此，总是前生佛。", "孙曾戏彩，慈颜一笑闲逸。", "曾向浑尺轩中，共评今古，手写王言绋。", "个里乃翁棠荫在，映得梅仙山碧。", "人爱黄堂，祝萱堂寿，拍拍欢声溢。", "明年宣劝，蟠桃火枣庭实。"]'),
('song-ci-866','念奴娇','李昴英','宋','宋词','song-ci','念奴娇','[]','麦秋时候，薄阴罩炎日，山行乘兴。',120,'宋词/ci.song.15000.json','["麦秋时候，薄阴罩炎日，山行乘兴。", "筇屐追随多胜侣，青佩黄冠方领。", "坐石谈玄，听泉濯暑，直上千山顶。", "倚风长啸，籁鸣林谷相应。", "忽涌云气漫空。", "海吹急雨，觉冰綀微冷。", "洗尽人间名利障，便是蓬莱仙境。", "半日偷闲，一生清福，岂在荣钟鼎。", "青灯深夜，陶然独妙清圣。"]'),
('song-ci-867','瑞鹤仙','李昴英','宋','宋词','song-ci','瑞鹤仙','[]','玉城春不夜。',127,'宋词/ci.song.15000.json','["玉城春不夜。", "映月璧寒流，烛蕖光射。", "鳌山海云驾。", "拥遨头箫鼓，锦旗红亚。", "东风近也。", "趁乐岁、良辰多暇。", "想阳和、早遍南州，暖得柳娇桃冶。", "堪画。", "纱笼夹道，露重花珠，尘吹兰麝。", "歌朋舞社。", "玉梅转，闹蛾耍。", "且茧占先探，芋郎戏巧，又卜紫姑灯下。", "听欢声、犹自未归，钿车宝马。"]'),
('song-ci-868','沁园春','李昴英','宋','宋词','song-ci','沁园春','[]','才到中年，节物浑闲，赏心顿轻。',141,'宋词/ci.song.15000.json','["才到中年，节物浑闲，赏心顿轻。", "据随分东风，瓶簪柳雪，应时灯夜，棚缀莲星。", "自一家春，也三杯酒，巧茧堆香笑语声。", "又何须，听那西楼弦管，南陌箫笙。", "平生。", "黄卷青灯。", "肯珠翠奢华八尺檠。", "欲趁队闲嬉，雕鞍宝马，回头猛忆，破案囊萤。", "邻曲渔歌，庭除鹤舞，尘外冰轮彻骨清。", "人闲处，这炯然方寸，一点长明。"]'),
('song-ci-869','满江红','李昴英','宋','宋词','song-ci','满江红','[]','薄冷催霜，碧空豁、飞鸿斜度。',116,'宋词/ci.song.15000.json','["薄冷催霜，碧空豁、飞鸿斜度。", "□九日、御风绝顶，下看尘宇。", "滕阁芳筵笺笔妙，龙山胜践旌旗驻。", "料山灵、也要可人游，成佳趣。", "吹帽堕，羞千古。", "题饧字，非吾侣。", "却坐间著得，煮茶桑苎。", "万里寒云迷北斗，望远峰夕照频西顾。", "且满浮、大白送黄花，剑休舞。"]'),
('song-ci-870','满江红','李昴英','宋','宋词','song-ci','满江红','[]','人似梅花，峭玉立、岁寒风节。',115,'宋词/ci.song.15000.json','["人似梅花，峭玉立、岁寒风节。", "新圃辟、种梅千树，幻成南雪。", "池碎瀑声荷捧雨，径涵秋影篁筛月。", "唤石君、错落坐庭前，红尘绝。", "嫌聒耳，□筝戛。", "慵著眼，俳优狎。", "但一觞一咏，放怀开阔。", "涌地池亭工掩映，擎天柱石觇施设。", "待枝头、金颗可调羹，休轻折。"]'),
('song-ci-871','菩萨蛮','李昴英','宋','宋词','song-ci','菩萨蛮','[]','云山叠叠双眸短。',52,'宋词/ci.song.15000.json','["云山叠叠双眸短。", "梦魂夜趁行人远。", "千里共襟期。", "吟风饮月时。", "碧溪穿翠峡。", "雪意蓬萧飒。", "安得翅飞来。", "冲寒同访梅。"]'),
('song-ci-872','渔家傲','李昴英','宋','宋词','song-ci','渔家傲','[]','重著夹罗犹怯冷。',72,'宋词/ci.song.15000.json','["重著夹罗犹怯冷。", "隔帘拜祝团圆镜。", "取片龙涎安古鼎。", "香阁静。", "横窗写出梅花影。", "寒鹊颤枝飞不定。", "回纹刺就更筹永。", "小玉欣眠呼不醒。", "霜气紧。", "丽谯吹动梅花引。"]'),
('song-ci-873','西江月','李昴英','宋','宋词','song-ci','西江月','[]','小鹢载池心月，长虹夸水中天。',58,'宋词/ci.song.15000.json','["小鹢载池心月，长虹夸水中天。", "主人情重客留连。", "便欲乘风寒殿。", "霜竹且传秋信，镜蕖不作春妍。", "夜凉正好倒金船。", "朔饮而今再见。"]'),
('song-ci-874','浣溪沙','李昴英','宋','宋词','song-ci','浣溪沙','[]','笋玉纤纤拍扇纨。',48,'宋词/ci.song.15000.json','["笋玉纤纤拍扇纨。", "戏拈荷叶起文鸳。", "水亭初试小龙团。", "拜月深深频祝愿，花枝低压髻云偏。", "倩人解梦语喧喧。"]'),
('song-ci-875','城头月','李昴英','宋','宋词','song-ci','城头月','[]','工夫作用中宵昼。',61,'宋词/ci.song.15000.json','["工夫作用中宵昼。", "点化无中有。", "真气长存，童颜不改，底用呵磨皱。", "一身二五之精媾。", "积得婴儿就。", "试问霞翁，三亩田熟未，还解飞冲否。"]'),
('song-ci-876','琐窗寒','吴文英','宋','宋词','song-ci','琐窗寒','[]','绀缕堆云，清腮润玉，汜人初见。',122,'宋词/ci.song.15000.json','["绀缕堆云，清腮润玉，汜人初见。", "蛮腥未洗，海客一怀凄惋。", "渺征槎、去乘阆风，占香上国幽心展。", "□遗芳掩色，真姿凝澹，返魂骚畹。", "一盼。", "千金换。", "又笑伴鸱夷，共归吴苑。", "离烟恨水，梦杳南天秋晚。", "比来时、瘦肌更销，冷薰沁骨悲乡远。", "最伤情、送客咸阳，佩结西风怨。"]'),
('song-ci-877','尉迟杯','吴文英','宋','宋词','song-ci','尉迟杯','[]','垂杨径。',129,'宋词/ci.song.15000.json','["垂杨径。", "洞钥启，时见流莺迎。", "涓涓暗谷流红，应有缃桃千顷。", "临池笑靥，春色满、铜华弄妆影。", "记年时、试酒湖阴，褪花曾采新杏。", "蛛窗绣网玄经，才石砚开奁，雨润云凝。", "小小蓬莱香一掬，愁不到、朱娇翠靓。", "清尊伴、人闲永日，断琴和、棋声竹露冷。", "笑从前、醉卧红尘，不知仙在人境。"]'),
('song-ci-878','渡江云三犯・渡江云','吴文英','宋','宋词','song-ci','渡江云三犯・渡江云','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','羞红颦浅恨，晚风为落，片绣点重茵。',124,'宋词/ci.song.15000.json','["羞红颦浅恨，晚风为落，片绣点重茵。", "旧堤分燕尾，桂棹轻鸥，宝勒倚残云。", "千丝怨碧，渐路入、仙坞迷津。", "肠漫回，隔花时见，背面楚腰身。", "逡巡。", "题门惆怅，堕履牵萦，数幽期难准。", "还始觉、留情缘眼，宽带因春。", "明朝事与孤烟冷，做满湖、风雨愁人。", "山黛暝，尘波澹绿无痕。"]'),
('song-ci-879','三部乐','吴文英','宋','宋词','song-ci','三部乐','[]','江鶃初飞，荡万里素云，际空如沐。',122,'宋词/ci.song.15000.json','["江鶃初飞，荡万里素云，际空如沐。", "咏情吟思，不在秦筝金屋。", "夜潮上，明月芦花，傍钓蓑梦远，句清敲玉。", "翠罂汲晓，欸乃一声秋曲。", "越装片篷障雨，瘦半竿渭水，鹭汀幽宿。", "那知暖袍挟锦，低帘笼烛。", "鼓春波、载花万斛。", "帆鬣转、银河可掬。", "风定浪息，苍茫外、天浸寒绿。"]'),
('song-ci-880','霜叶飞','吴文英','宋','宋词','song-ci','霜叶飞','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','断烟离绪。',135,'宋词/ci.song.15000.json','["断烟离绪。", "关心事，斜阳红隐霜树。", "半壶秋水荐黄花，香噀西风雨。", "纵玉勒、轻飞迅羽。", "凄凉谁吊荒台古。", "记醉蹋南屏，彩扇咽、寒蝉倦梦，不知蛮素。", "聊对旧节传杯，尘笺蠹管，断阕经岁慵赋。", "小蟾斜影转东篱，夜冷残蛩语。", "早白发、缘愁万缕。", "惊飙从卷乌纱去。", "漫细将、茱萸看，但约明年，翠微高处。"]'),
('song-ci-881','瑞鹤仙','吴文英','宋','宋词','song-ci','瑞鹤仙','[]','泪荷抛碎璧。',127,'宋词/ci.song.15000.json','["泪荷抛碎璧。", "正漏云筛雨，斜捎窗隙。", "林声怨秋色。", "对小山不迭，寸眉愁碧。", "凉欺岸帻。", "暮砧催、银屏翦尺。", "最无聊、燕去堂空，旧幕暗尘罗额。", "行客。", "西园有分，断柳凄花，似曾相识。", "西风破屐。", "林下路，水边石。", "念寒蛩残梦，归鸿心事，那听江村夜笛。", "看雪飞、苹底芦梢，未如鬓白。"]'),
('song-ci-882','瑞鹤仙','吴文英','宋','宋词','song-ci','瑞鹤仙','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','晴丝牵绪乱。',127,'宋词/ci.song.15000.json','["晴丝牵绪乱。", "对沧江斜日，花飞人远。", "垂杨暗吴苑。", "正旗亭烟冷，河桥风暖。", "兰情蕙盼。", "惹相思、春根酒畔。", "又争知、吟骨萦销，渐把旧衫重翦。", "凄断。", "流红千浪，缺月孤楼，总难留燕。", "歌尘凝扇。", "待凭信，拌分钿。", "试挑灯欲写，还依不忍，笺幅偷和泪卷。", "寄残云、剩雨蓬莱，也应梦见。"]'),
('song-ci-883','瑞鹤仙','吴文英','宋','宋词','song-ci','瑞鹤仙','[]','藕心抽莹茧。',127,'宋词/ci.song.15000.json','["藕心抽莹茧。", "引翠针行处，冰花成片。", "金门从回辇。", "两玉凫飞上，绣绒尘软。", "丝絇侍宴。", "曳天香、春风宛转。", "傍星辰、直上无声，缓蹑素云归晚。", "奇践。", "平康得意，醉踏香泥，润红沾线。", "良工诧见。", "吴蚕唾，海沈楦。", "任真珠装缀，春申客屦，今日风流雾散。", "待宣供、禹步宸游，退朝燕殿。"]'),
('song-ci-884','瑞鹤仙','吴文英','宋','宋词','song-ci','瑞鹤仙','[]','乱云生古峤。',127,'宋词/ci.song.15000.json','["乱云生古峤。", "记旧游惟怕，秋光不早。", "人生断肠草。", "叹如今摇落，暗惊怀抱。", "谁临晚眺。", "吹台高、霜歌缥缈。", "想西风、此处留情，肯著故人衰帽。", "闻道。", "萸香西市，酒熟东邻，浣花人老。", "金鞭騕袅。", "追吟赋，倩年少。", "想重来新雁，伤心湖上，销减红深翠窈。", "小楼寒、睡起无聊，半帘晚照。"]'),
('song-ci-885','瑞鹤仙','吴文英','宋','宋词','song-ci','瑞鹤仙','[]','记年时茂苑。',127,'宋词/ci.song.15000.json','["记年时茂苑。", "正画堂凝香，璇奎初焕。", "天边岁华转。", "向九重春近，仙桃传宴。", "银罂翠管。", "宝香飞、蓬莱小殿。", "荷玉皇、恩重千秋，翠麓峻齐云汉。", "须看。", "鸿飞高处，地阔天宽，弋人空羡。", "梅清水暖。", "苕溪上，几吟卷。", "算金门听漏，玉墀班早，赢得风霜满面。", "总不如、绿野身安，镜重未晚。"]'),
('song-ci-886','瑞鹤仙','吴文英','宋','宋词','song-ci','瑞鹤仙','[]','辘轳春又转。',127,'宋词/ci.song.15000.json','["辘轳春又转。", "记旋草新词，江头凭雁。", "乘槎上银汉。", "想车尘才踏，东华红软。", "何时赐见。", "漏声移、深宫夜半。", "问莼鲈、今岁西风，未觉岁华迟晚。", "一片。", "丹心白发，露滴研朱，雅陪清宴。", "班回柳院。", "蒲团底，小禅观。", "望罘罳明月，初圆此夕，应共婵娟茂苑。", "愿年年、玉兔长生，耸秋井乾。"]'),
('song-ci-887','瑞鹤仙','吴文英','宋','宋词','song-ci','瑞鹤仙','[]','夜寒吴馆窄。',126,'宋词/ci.song.15000.json','["夜寒吴馆窄。", "渐酒阑烛暗，犹分香泽。", "轻帆展为翮。", "送高鸿飞过，长安南陌。", "渔矶旧迹。", "有陈蕃、虚床挂壁。", "掩庭扉，蛛网黏花，细草摇春碧。", "还忆。", "洛阳年少，风露秋檠，岁华如昔。", "长吟堕帻。", "暮潮送，富春客。", "算玉堂不染，梅花清梦，宫漏声中夜直。", "正逋仙、清瘦黄昏，几时觅得。"]'),
('song-ci-888','瑞鹤仙','吴文英','宋','宋词','song-ci','瑞鹤仙','[]','彩云栖翡翠。',127,'宋词/ci.song.15000.json','["彩云栖翡翠。", "听凤笙吹下，飞軿天际。", "晴霞翦轻袂。", "澹春姿雪态，寒梅清泚。", "东皇有意。", "旋安排、阑干十二。", "早不知、为雨为云，尽日建章门闭。", "堪比。", "红绡纤素，紫燕轻盈，内家标致。", "游仙旧事。", "星斗下，夜香里。", "□华峰□□，纸屏横幅，春色长供午睡。", "更醉乘、玉井秋风，采花弄水。"]'),
('song-ci-889','满江红','吴文英','宋','宋词','song-ci','满江红','[]','云气楼台，分一派、沧浪翠蓬。',115,'宋词/ci.song.15000.json','["云气楼台，分一派、沧浪翠蓬。", "开小景、玉盆寒浸，巧石盘松。", "风送流花时过岸，浪摇晴练欲飞空。", "算鲛宫、祗隔一红尘，无路通。", "神女驾、凌晓风。", "明月佩，响丁东。", "对两蛾犹锁，怨绿烟中。", "秋色未教飞尽雁，夕阳长是坠疏钟。", "又一声、欸乃过前岩，移钓篷。"]'),
('song-ci-890','满江红','吴文英','宋','宋词','song-ci','满江红','[]','结束萧仙，啸梁鬼、依还未灭。',115,'宋词/ci.song.15000.json','["结束萧仙，啸梁鬼、依还未灭。", "荒城外、无聊闲看，野烟一抹。", "梅子未黄愁夜雨，榴花不见簪秋雪。", "又重罗、红字写香词，年时节。", "帘底事，凭燕说。", "合欢缕，双条脱。", "自香消红臂，旧情都别。", "湘水离魂菰叶怨，扬州无梦铜华阙。", "倩卧箫、吹裂晚天云，看新月。"]'),
('song-ci-891','解连环','吴文英','宋','宋词','song-ci','解连环','[]','暮檐凉薄。',132,'宋词/ci.song.15000.json','["暮檐凉薄。", "疑清风动竹，故人来邈。", "渐夜久、闲引流萤，弄微照素怀，暗呈纤白。", "梦远双成，凤笙杳、玉绳西落。", "掩綀帷倦入，又惹旧愁，汗香阑角。", "银瓶恨沈断索。", "叹梧桐未秋，露井先觉。", "抱素影、明月空闲，早尘损丹青，楚山依约。", "翠冷红衰，怕惊起、西池鱼跃。", "记湘娥、绛绡暗解，褪花坠萼。"]'),
('song-ci-892','解连环','吴文英','宋','宋词','song-ci','解连环','[]','思和云结。',132,'宋词/ci.song.15000.json','["思和云结。", "断江楼望睫，雁飞无极。", "正岸柳、衰不堪攀，忍持赠故人，送秋行色。", "岁晚来时，暗香乱、石桥南北。", "又长亭暮雪，点点泪痕，总成相忆。", "杯前寸阴似掷。", "几酬花唱月，连夜浮白。", "省听风、听雨笙箫，向别枕倦醒，絮扬空碧。", "片叶愁红，趁一舸、西风潮汐。", "叹沧波、路长梦短，甚时到得。"]'),
('song-ci-893','夜飞鹊・夜飞鹊慢','吴文英','宋','宋词','song-ci','夜飞鹊・夜飞鹊慢','[]','金规印遥汉，庭浪无纹。',129,'宋词/ci.song.15000.json','["金规印遥汉，庭浪无纹。", "清雪冷沁花薰。", "天衔曾醉美人畔，凉枝移插乌巾。", "西风骤惊散，念棱悬愁结，蒂翦离恨。", "中郎旧恨，寄横竹、吹裂哀云。", "空剩露华烟彩，人影断幽坊，深闭千门。", "浑似飞仙入梦，袜罗微步，流水青苹。", "轻冰润□，怅今朝、不共清尊。", "怕云槎来晚，流红信杳，萦断秋魂。"]'),
('song-ci-894','一寸金','吴文英','宋','宋词','song-ci','一寸金','[]','秋入中山，臂隼牵卢纵长猎。',133,'宋词/ci.song.15000.json','["秋入中山，臂隼牵卢纵长猎。", "见骇毛飞雪，章台献颖，臞腰束缟，汤沐疏邑。", "筤管刊琼牒。", "苍梧恨、帝娥暗泣。", "陶郎老、憔悴玄香，禁苑犹催夜俱入。", "自叹江湖，雕龙心尽，相携蠹鱼箧。", "念醉魂悠扬，折钗锦字，黠髯掀舞，流觞春帖。", "还倚荆溪楫。", "金刀氏、尚传旧业。", "劳君为、脱帽篷窗，寓情题水叶。"]'),
('song-ci-895','一寸金','吴文英','宋','宋词','song-ci','一寸金','[]','秋压更长，看见姮娥瘦如束。',133,'宋词/ci.song.15000.json','["秋压更长，看见姮娥瘦如束。", "正古花摇落，寒蛩满地，参梅吹老，玉龙横竹。", "霜被芙蓉宿。", "红绵透、尚欺暗烛。", "年年记、一种凄凉，绣幌金圆挂香玉。", "顽老情怀，都无欢事，良宵爱幽独。", "叹画图难仿，橘村砧思，笠蓑有约，莼洲渔屋。", "心景凭谁语，商弦重、袖寒转轴。", "疏篱下、试觅重阳，醉擘青露菊。"]'),
('song-ci-896','绕佛阁','吴文英','宋','宋词','song-ci','绕佛阁','[]','夜空似水，横汉静立，银浪声杳。',123,'宋词/ci.song.15000.json','["夜空似水，横汉静立，银浪声杳。", "瑶镜奁小。", "素娥乍起、楼心弄孤照。", "絮云未巧。", "梧韵露井，偏借秋早。", "晴暗多少。", "怕教彻胆，蟾光见怀抱。", "浪迹尚为客，恨满长安千古道。", "还记暗萤、穿帘街语悄。", "叹步影归来，人鬓花老。", "紫箫天渺。", "又露饮风前，凉堕轻帽。", "酒杯空、数星横晓。"]'),
('song-ci-897','绕佛阁','吴文英','宋','宋词','song-ci','绕佛阁','[]','蒨霞艳锦，星媛夜织，河汉鸣杼。',124,'宋词/ci.song.15000.json','["蒨霞艳锦，星媛夜织，河汉鸣杼。", "红翠万缕。", "送幽梦与、人闲绣芳句。", "怨宫恨羽。", "孤风剑漫倚，无限凄楚。", "□□□□。", "赋情缥缈、东风扬花絮。", "镜里半髯雪，向老春深莺晓处。", "长闭翠阴、幽坊杨柳户。", "看故苑离离，城外禾黍。", "短藜青屦。", "笑寄隐闲追，鸡社歌舞。", "最风流、垫巾沾雨。"]'),
('song-ci-898','拜星月慢','吴文英','宋','宋词','song-ci','拜星月慢','["\u897f\u6e56"]','绛雪生凉，碧霞笼夜，小立中庭芜地。',128,'宋词/ci.song.15000.json','["绛雪生凉，碧霞笼夜，小立中庭芜地。", "昨梦西湖，老扁舟身世。", "叹游荡，暂赏、吟花酌露尊俎，冷玉红香罍洗。", "眼眩魂迷，古陶洲十里。", "翠参差、澹月平芳砌。", "砖花滉、小浪鱼鳞起。", "雾盎浅障青罗，洗湘娥春腻。", "荡兰烟、麝馥浓侵醉。", "吹不散、绣屋重门闭。", "又怕便、绿减西风，泣秋檠烛外。"]'),
('song-ci-899','水龙吟','吴文英','宋','宋词','song-ci','水龙吟','[]','艳阳不到青山，古阴冷翠成秋苑。',126,'宋词/ci.song.15000.json','["艳阳不到青山，古阴冷翠成秋苑。", "吴娃点黛，江妃拥髻，空濛遮断。", "树密藏溪，草深迷市，峭云一片。", "二十年旧梦，轻鸥素约，霜丝乱、朱颜变。", "龙吻春霏玉溅。", "煮银瓶、羊肠车转。", "临泉照影，清寒沁骨，客尘都浣。", "鸿渐重来，夜深华表，露零鹤怨。", "把闲愁换与，楼前晚色，棹沧波远。"]'),
('song-ci-900','水龙吟','吴文英','宋','宋词','song-ci','水龙吟','["\u897f\u6e56"]','夜分溪馆渔灯，巷声乍寂西风定。',126,'宋词/ci.song.15000.json','["夜分溪馆渔灯，巷声乍寂西风定。", "河桥径远，玉箫吹断，霜丝舞影。", "薄絮秋云，澹蛾山色，宦情归兴。", "怕烟江渡后，桃花又泛，宫沟上、春流紧。", "新句欲题还省。", "透香煤、重牒误隐。", "西园已负，林亭移酒，松泉荐茗。", "携手同归处，玉奴唤、绿窗春近。", "想骄骢、又踏西湖，二十四番花信。"]'),
('song-ci-901','水龙吟','吴文英','宋','宋词','song-ci','水龙吟','[]','有人独立空山，翠髯未觉霜颜老。',127,'宋词/ci.song.15000.json','["有人独立空山，翠髯未觉霜颜老。", "新香秀粒，浓光绿浸，千年春小。", "布影参旗，障空云盖，沈沈秋晓。", "驷苍虬万里，笙吹凤女，骖飞乘、天风袅。", "般巧。", "霜斤不到。", "汉游仙、相从最早。", "皴鳞细雨，层阴藏月，朱弦古调。", "问讯东桥，故人南岭，倚天长啸。", "待凌霄谢了，山深岁晚，素心才表。"]'),
('song-ci-902','水龙吟','吴文英','宋','宋词','song-ci','水龙吟','[]','望中璇海波新，泛槎又币银河转。',126,'宋词/ci.song.15000.json','["望中璇海波新，泛槎又币银河转。", "金风细袅，龙枝声奏，钧箫秋远。", "南极飞仙，夜来催驾，祥光重见。", "紫霄承露掌，瑶池荫密，蟠桃秀、螽莲绽。", "新栋晴翬凌汉。", "半凉生、兰檠书卷。", "绣裳五色，昆台十二，香深帘卷。", "花萼楼高处，连清晓、千秋传宴。", "赐长生玉字，鸾回凤舞，下蓬莱殿。"]'),
('song-ci-903','水龙吟','吴文英','宋','宋词','song-ci','水龙吟','[]','望春楼外沧波，旧年照眼青铜镜。',127,'宋词/ci.song.15000.json','["望春楼外沧波，旧年照眼青铜镜。", "炼成宝月，飞来天上，银河流影。", "绀玉钩帘处，横犀尘、天香分鼎。", "记殷云殿锁，裁花翦露，曲江畔、春风劲。", "槐省。", "红尘昼静，午朝回、吟生晚兴。", "春霖绣笔，莺边清晓，金狨旋整。", "阆苑芝仙貌，生绡对、绿窗深景。", "弄琼英数点，宫梅信早，占年光永。"]'),
('song-ci-904','水龙吟','吴文英','宋','宋词','song-ci','水龙吟','[]','几番时事重论，座中共惜斜阳下。',126,'宋词/ci.song.15000.json','["几番时事重论，座中共惜斜阳下。", "今朝翦柳，东风送客，功名近也。", "约住飞花，暂听留燕，更攀情话。", "问千牙过阙，一封入奏，忠孝事、都应写。", "闻道兰台清暇。", "载鸱夷、烟江一舸。", "贞元旧曲，如今谁听，惟公和寡。", "儿骑空迎，舜瞳回盼，玉阶前借。", "便急回暖律，天边海上，正春寒夜。"]'),
('song-ci-905','水龙吟','吴文英','宋','宋词','song-ci','水龙吟','["\u9ec4\u9e64\u697c"]','外湖北岭云多，小园暗碧莺啼处。',126,'宋词/ci.song.15000.json','["外湖北岭云多，小园暗碧莺啼处。", "朝回胜赏，墨池香润，吟船系雨。", "霓节千妃，锦帆一箭，携将春去。", "算归期未卜，青烟散后，春城咏、飞花句。", "黄鹤楼头月午。", "奏玉龙、江梅解舞。", "薰风紫禁，严更清梦，思怀几许。", "秋水生时，赋情还在，南屏别墅。", "看章台走马，长堤种取，柔丝千树。"]'),
('song-ci-906','水龙吟','吴文英','宋','宋词','song-ci','水龙吟','[]','澹云笼月微黄，柳丝浅色东风紧。',126,'宋词/ci.song.15000.json','["澹云笼月微黄，柳丝浅色东风紧。", "夜寒旧事，春期新恨，眉山碧远。", "尘陌飘香，绣帘垂户，趁时妆面。", "钿车催去急，珠囊袖冷，愁如海、情一线。", "犹记初来吴苑。", "未清霜、飞惊双鬓。", "嬉游是处，风光无际，舞葱歌蒨。", "陈迹征衫，老容华镜，欢悰都尽。", "向残灯梦短，梅花晓角，为谁吟怨。"]'),
('song-ci-907','水龙吟','吴文英','宋','宋词','song-ci','水龙吟','["\u897f\u6e56"]','杜陵折柳狂吟，砚波尚湿红衣露。',126,'宋词/ci.song.15000.json','["杜陵折柳狂吟，砚波尚湿红衣露。", "仙桃宴早，江梅春近，还催客句。", "宫漏传鸡，禁门嘶骑，宦情熟处。", "正黄编夜展，天香字暖，春葱翦、红蜜炬。", "宫帽鸾枝醉舞。", "思飘扬、臞仙风举。", "星罗万卷，云驱千阵，飞毫海雨。", "长寿杯深，探春腔稳，江湖同赋。", "又看看、便系金狨莺晓，傍西湖路。"]'),
('song-ci-908','玉烛新','吴文英','宋','宋词','song-ci','玉烛新','[]','花穿帘隙透。',125,'宋词/ci.song.15000.json','["花穿帘隙透。", "向梦里销春，酒中延昼。", "嫩篁细掐，相思字、堕粉轻黏綀袖。", "章台别后，展绣络、红荐香旧。", "□□□，应数归舟，愁凝画阑眉柳。", "移灯夜语西窗，逗晓帐迷香，问何时又。", "素纨乍试，还忆是、绣懒思酸时候。", "兰清蕙秀。", "总为比、蛾眉螓首。", "谁诉与，惟有金笼，春簧细奏。"]'),
('song-ci-909','解语花','吴文英','宋','宋词','song-ci','解语花','[]','门横皱碧，路入苍烟，春近江南岸。',124,'宋词/ci.song.15000.json','["门横皱碧，路入苍烟，春近江南岸。", "暮寒如翦。", "临溪影、一一半斜清浅。", "飞霙弄晚。", "荡千里、暗香平远。", "端正看，琼树三枝，总似兰昌见。", "酥莹云容夜暖。", "伴兰翘清瘦，箫凤柔婉。", "冷云荒翠，幽栖久、无语暗申春怨。", "东风半面。", "料准拟、何郎词卷。", "欢未阑，烟雨青黄，宜昼阴庭馆。"]'),
('song-ci-910','解语花','吴文英','宋','宋词','song-ci','解语花','[]','檐花旧滴，帐烛新啼，香润残冬被。',124,'宋词/ci.song.15000.json','["檐花旧滴，帐烛新啼，香润残冬被。", "澹烟疏绮。", "凌波步、暗阻傍墙挑荠。", "梅痕似洗。", "空点点、年华别泪。", "花鬓愁，钗股笼寒，彩燕沾云腻。", "还斗辛盘葱翠。", "念青丝牵恨，曾试纤指。", "雁回潮尾。", "征帆去、似与东风相避。", "泥云万里。", "应翦断、红情绿意。", "年少时，偏爱轻怜，和酒香宜睡。"]'),
('song-ci-911','庆春宫・高阳台','吴文英','宋','宋词','song-ci','庆春宫・高阳台','[]','春屋围花，秋池沿草，旧家锦藉川原。',126,'宋词/ci.song.15000.json','["春屋围花，秋池沿草，旧家锦藉川原。", "莲花分津，桃边迷路，片红不到人间。", "乱篁苍暗，料惜把、行题共删。", "小晴帘卷，独占西墙，一镜清寒。", "风光未老吟潘。", "嘶骑征尘，祗付凭阑。", "鸣瑟传杯，辟邪翻烬。", "系船香斗春宽。", "晚林青外，乱鸦著、斜阳几山。", "粉消莫染，犹是秦宫，绿扰云鬟。"]'),
('song-ci-912','庆春宫・高阳台','吴文英','宋','宋词','song-ci','庆春宫・高阳台','[]','残叶翻浓，馀香栖苦，障风怨动秋声。',126,'宋词/ci.song.15000.json','["残叶翻浓，馀香栖苦，障风怨动秋声。", "云影摇寒，波尘销腻，翠房人去深扃。", "昼成凄黯，雁飞过、垂杨转青。", "阑干横暮，酥印痕香，玉腕谁凭。", "菱花乍失娉婷。", "别岸围红，千艳倾城。", "重洗清杯，同追深夜，豆花寒落愁灯。", "近欢成梦，断云隔、巫山几层。", "偷相怜处，熏尽金篝，销瘦云英。"]'),
('song-ci-913','塞垣春','吴文英','宋','宋词','song-ci','塞垣春','[]','漏瑟侵琼管。',122,'宋词/ci.song.15000.json','["漏瑟侵琼管。", "润鼓借、烘炉暖。", "藏钩怯冷，画鸡临晓，怜语莺啭。", "殢绿窗、细咒浮梅盏。", "换蜜炬、花心短。", "梦惊回，林鸦起，曲屏春事天远。", "迎路柳丝裙，看争拜东风，盈灞桥岸。", "髻落宝钗寒，恨花胜迟燕。", "渐街帘影转。", "还似新年，过邮亭、一相见。", "南陌又灯火，绣囊尘香浅。"]'),
('song-ci-914','宴清都','吴文英','宋','宋词','song-ci','宴清都','[]','翠羽飞梁苑。',126,'宋词/ci.song.15000.json','["翠羽飞梁苑。", "连催发，暮樯留话江燕。", "尘街堕珥，瑶扉乍钥，彩绳双罥。", "新烟暗叶成阴，效翠妩、西陵送远。", "又趁得、蕊露天香，春留建章花晚。", "归来笑折仙桃，琼楼宴萼，金漏催箭。", "兰亭秀语，乌丝润墨，汉宫传玩。", "红敧醉玉天上，倩凤尾、时题画扇。", "问几时、重驾巫云，蓬莱路浅。"]'),
('song-ci-915','宴清都','吴文英','宋','宋词','song-ci','宴清都','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','绣幄鸳鸯柱。',126,'宋词/ci.song.15000.json','["绣幄鸳鸯柱。", "红情密，腻云低护秦树。", "芳根兼倚，花梢钿合，锦屏人妒。", "东风睡足交枝，正梦花、瑶钗燕股。", "障滟蜡、满照欢丛，嫠蟾冷落羞度。", "人间万感幽单，华清惯浴，春盎风露。", "连鬟并暖，同心共结，向承恩处。", "凭谁为歌长恨，暗殿锁、秋灯夜语。", "叙旧期、不负春盟，红朝翠暮。"]'),
('song-ci-916','宴清都','吴文英','宋','宋词','song-ci','宴清都','[]','万壑蓬莱路。',126,'宋词/ci.song.15000.json','["万壑蓬莱路。", "非烟霁，五云城阙深处。", "璇源媲凤，瑶池种玉，练颜金姥。", "长虹梦入仙怀，便洗日、铜华翠渚。", "向瑞世、独占长春，蟠桃正饱风露。", "殷勤汉殿传卮，隔江云起，暗飞青羽。", "南山寿石，东周宝鼎，千秋巩固。", "何时地拂龙衣，待迎入、玉京阆圃。", "看□□、剩拥湖船，三千彩御。"]'),
('song-ci-917','宴清都','吴文英','宋','宋词','song-ci','宴清都','[]','翠匝西门柳。',126,'宋词/ci.song.15000.json','["翠匝西门柳。", "荆州昔，未来时正春瘦。", "如今剩舞，西风旧色，胜东风秀。", "黄粱露湿秋江，转万里、云樯蔽昼。", "正虎落、马静晨嘶，连营夜沈刁斗。", "含章换几桐阴，千官邃幄，韶凤还奏。", "席前夜久，天低宴密，御香盈袖。", "星槎信约长在，醉兴渺、银河赋就。", "对小弦、月挂南楼，凉浮桂酒。"]'),
('song-ci-918','宴清都','吴文英','宋','宋词','song-ci','宴清都','[]','柳色春阴重。',126,'宋词/ci.song.15000.json','["柳色春阴重。", "东风力，快将云雁高送。", "书檠细雨，吟窗乱雪，井寒笔冻。", "家林秀橘霜老，笑分得、蟾边桂种。", "应茂苑、斗转苍龙，唯潮献奇吴凤。", "玉眉暗隐华年，凌云气压，千载云梦。", "名笺澹墨，恩袍翠草，紫骝青鞚。", "飞香杏园新句，眩醉眼、春游乍纵。", "弄喜音、鹊绕庭花，红帘影动。"]'),
('song-ci-919','宴清都','吴文英','宋','宋词','song-ci','宴清都','[]','万里关河眼。',125,'宋词/ci.song.15000.json','["万里关河眼。", "愁凝处，渺渺残照红敛。", "天低远树，潮分断港，路回淮甸。", "吟鞭又指孤店。", "对玉露金风送晚。", "恨自古、才子佳人，此景此情多感。", "吴王故苑。", "别来良朋雅集，空叹蓬转。", "挥毫记烛，飞觞赶月，梦销香断。", "区区去程何限。", "倩片纸、丁宁过雁。", "寄相思，寒雨灯窗，芙蓉旧院。"]'),
('song-ci-920','齐天乐','吴文英','宋','宋词','song-ci','齐天乐','[]','三千年事残鸦外，无言倦凭秋树。',123,'宋词/ci.song.15000.json','["三千年事残鸦外，无言倦凭秋树。", "逝水移川，高陵变谷，那识当时神禹。", "幽云怪雨。", "翠萍湿空梁，夜深飞去。", "雁起青天，数行书似旧藏处。", "寂寥西窗久坐，故人悭会遇，同翦灯语。", "积藓残碑，零圭断璧，重拂人间尘土。", "霜红罢舞。", "漫山色青青，雾朝烟暮。", "岸锁春船，画旗喧赛鼓。"]'),
('song-ci-921','齐天乐','吴文英','宋','宋词','song-ci','齐天乐','[]','芙蓉心上三更露，茸香漱泉玉井。',123,'宋词/ci.song.15000.json','["芙蓉心上三更露，茸香漱泉玉井。", "自洗银舟，徐开素酌，月落空杯无影。", "庭阴未暝。", "度一曲新蝉，韵秋堪听。", "瘦骨侵冰，怕惊纹簟夜深冷。", "当时湖上载酒，翠云开处共，雪面波镜。", "万感琼浆，千茎鬓雪，烟锁蓝桥花径。", "留连暮景。", "但偷觅孤欢，强宽秋兴。", "醉倚修篁，晚风吹半醒。"]'),
('song-ci-922','齐天乐','吴文英','宋','宋词','song-ci','齐天乐','[]','凌朝一片阳台影，飞来太空不去。',123,'宋词/ci.song.15000.json','["凌朝一片阳台影，飞来太空不去。", "栋与参横，帘钩斗曲，西北城高几许。", "天声似语。", "便阊阖轻排，虹河平溯。", "问几阴晴，霸吴平地漫今古。", "西山横黛瞰碧，眼明应不到，烟际沈鹭。", "卧笛长吟，层霾乍裂，寒月溟濛千里。", "凭虚醉舞。", "梦凝白阑干，化为飞雾。", "净洗青红，骤飞沧海雨。"]'),
('song-ci-923','齐天乐','吴文英','宋','宋词','song-ci','齐天乐','[]','新烟初试花如梦，疑收楚峰残雨。',123,'宋词/ci.song.15000.json','["新烟初试花如梦，疑收楚峰残雨。", "茂苑人归，秦楼燕宿，同惜天涯为旅。", "游情最苦。", "早柔绿迷津，乱莎荒圃。", "数树梨花，晚风吹堕半汀鹭。", "流红江上去远，翠尊曾共醉，云外别墅。", "澹月秋千，幽香巷陌，愁结伤春深处。", "听歌看舞。", "驻不得当时，柳蛮樱素。", "睡起恹恹，洞箫谁院宇。"]'),
('song-ci-924','齐天乐','吴文英','宋','宋词','song-ci','齐天乐','[]','竹深不放斜阳度，横披澹墨林沼。',123,'宋词/ci.song.15000.json','["竹深不放斜阳度，横披澹墨林沼。", "断莽平烟，残莎剩水，宜得秋深才好。", "荒亭旋扫。", "正著酒寒轻，弄花春小。", "障锦西风，半围歌袖半吟草。", "独游清兴易懒，景饶人未胜，乐事长少。", "柳下交车，尊前岸帻，同抚云根一笑。", "秋香未老。", "渐风雨西城，暗敧客帽。", "背月移舟，乱鸦溪树晓。"]'),
('song-ci-925','齐天乐','吴文英','宋','宋词','song-ci','齐天乐','[]','曲尘犹沁伤心水，歌蝉暗惊春换。',123,'宋词/ci.song.15000.json','["曲尘犹沁伤心水，歌蝉暗惊春换。", "露藻清啼，烟萝澹碧，先结湖山秋怨。", "波帘翠卷。", "叹霞薄轻绡，泛人重见。", "傍柳追凉，暂疏怀袖负纨扇。", "南花清斗素靥，画船应不载，坡静诗卷。", "泛酒芳筒，题名蠹壁，重集湘鸿江燕。", "平芜未翦。", "怕一夕西风，镜心红变。", "望极愁生，暮天菱唱远。"]'),
('song-ci-926','齐天乐','吴文英','宋','宋词','song-ci','齐天乐','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','烟波桃叶西陵路，十年断魂潮尾。',123,'宋词/ci.song.15000.json','["烟波桃叶西陵路，十年断魂潮尾。", "古柳重攀，轻鸥聚别，陈迹危亭独倚。", "凉飔乍起。", "渺烟碛飞帆，暮山横翠。", "但有江花，共临秋镜照憔悴。", "华堂烛暗送客，眼波回盼处，芳艳流水。", "素骨凝冰，柔葱蘸雪，犹忆分瓜深意。", "清尊未洗。", "梦不湿行云，漫沾残泪。", "可惜秋宵，乱蛩疏雨里。"]'),
('song-ci-927','齐天乐','吴文英','宋','宋词','song-ci','齐天乐','[]','玉皇重赐瑶池宴，琼筵第二十四。',123,'宋词/ci.song.15000.json','["玉皇重赐瑶池宴，琼筵第二十四。", "万象澄秋，群裾曳玉，清澈冰壶人世。", "鳌峰对起。", "许分得钧天，凤丝龙吹。", "翠羽飞来，舞鸾曾赋曼桃字。", "鹤胎曾梦电绕，桂根看骤长，玉干金蕊。", "少海波新，芳茅露滴，凉入堂阶彩戏。", "香霖乍洗。", "拥莲媛三千，羽裳风佩。", "圣姥朝元，炼颜银汉水。"]'),
('song-ci-928','齐天乐','吴文英','宋','宋词','song-ci','齐天乐','[]','馀香才润鸾绡汗，秋风夜来先起。',123,'宋词/ci.song.15000.json','["馀香才润鸾绡汗，秋风夜来先起。", "雾锁林深，蓝浮野阔，一笛渔蓑鸥外。", "红尘万里。", "就中决银河，冷涵空翠。", "岸觜沙平，水杨阴下晚初舣。", "桃溪人住最久，浪吟谁得到，兰蕙疏绮。", "砚色寒云，签声乱叶，蕲竹纱纹如水。", "笙歌醉里。", "步明月丁东，静传环佩。", "更展芳塘，种花招燕子。"]'),
('song-ci-929','丹凤吟','吴文英','宋','宋词','song-ci','丹凤吟','[]','丽景长安人海，避影繁华，结庐深寂。',137,'宋词/ci.song.15000.json','["丽景长安人海，避影繁华，结庐深寂。", "灯窗雪户，光映夜寒东壁。", "心凋鬓改，镂冰刻水，缥简离离，风签索索。", "怕遣花虫蠹粉，自采秋芸熏架，香泛纤碧。", "更上新梯窈窕，暮山澹著城外色。", "旧雨江湖远，问桐阴门巷，燕曾相识。", "吟壶天小，不觉翠蓬云隔。", "桂斧月宫三万手，计元和通籍。", "软红满路，谁聘幽素客。"]'),
('song-ci-930','扫花游・扫地游','吴文英','宋','宋词','song-ci','扫花游・扫地游','[]','冷空澹碧，带翳柳轻云，护花深雾。',117,'宋词/ci.song.15000.json','["冷空澹碧，带翳柳轻云，护花深雾。", "艳晨易午。", "正笙箫竞渡，绮罗争路。", "骤卷风埃，半掩长蛾翠妩。", "散红缕。", "渐红湿杏泥，愁燕无语。", "乘盖争避处。", "就解佩旗亭，故人相遇。", "恨春太妒。", "溅行裙更惜，凤钩尘污。", "酹入梅根，万点啼痕暗树。", "峭寒暮。", "更萧萧、陇头人去。"]'),
('song-ci-931','扫花游・扫地游','吴文英','宋','宋词','song-ci','扫花游・扫地游','[]','水云共色，渐断岸飞花，雨声初峭。',117,'宋词/ci.song.15000.json','["水云共色，渐断岸飞花，雨声初峭。", "步帷素袅。", "想玉人误惜，章台春老。", "岫敛愁蛾，半洗铅华未晓。", "舣轻棹。", "似山阴夜晴，乘兴初到。", "心事春缥缈。", "记遍地梨花，弄月斜照。", "旧时斗草。", "恨凌波路钥，小庭深窈。", "冻涩琼箫，渐入东风郢调。", "暖回早。", "醉西园、乱红休扫。"]'),
('song-ci-932','扫花游・扫地游','吴文英','宋','宋词','song-ci','扫花游・扫地游','[]','草生梦碧，正燕子帘帏，影迟春午。',117,'宋词/ci.song.15000.json','["草生梦碧，正燕子帘帏，影迟春午。", "倦茶荐乳。", "看风签乱叶，老沙昏雨。", "古简蟫篇，种得云根疗蠹。", "最清楚。", "带明月自锄，花外幽圃。", "醒眼看醉舞。", "到应事无心，与闲同趣。", "小山有语。", "恨逋仙占却，暗香吟赋。", "暖通书床，带草春摇翠露。", "未归去。", "正长安、软红如雾。"]'),
('song-ci-933','扫花游・扫地游','吴文英','宋','宋词','song-ci','扫花游・扫地游','[]','水园沁碧，骤夜雨飘红，竟空林岛。',117,'宋词/ci.song.15000.json','["水园沁碧，骤夜雨飘红，竟空林岛。", "艳春过了。", "有尘香坠钿，尚遗芳草。", "步绕新阴，渐觉交枝径小。", "醉深窈。", "爱绿叶翠圆，胜看花好。", "芳架雪未扫。", "怪翠被佳人，困迷清晓。", "柳丝系棹。", "问阊门自古，送春多少。", "倦蝶慵飞，故扑簪花破帽。", "酹残照。", "掩重城、暮钟不到。"]'),
('song-ci-934','扫花游・扫地游','吴文英','宋','宋词','song-ci','扫花游・扫地游','["\u897f\u6e56"]','暖波印日，倒秀影秦山，晓鬟梳洗。',117,'宋词/ci.song.15000.json','["暖波印日，倒秀影秦山，晓鬟梳洗。", "步帷艳绮。", "正梁园未雪，海棠犹睡。", "藉绿盛红，怕委天香到地。", "画船系。", "舞西湖暗黄，虹卧新霁。", "天梦春枕被。", "和凤筑东风，宴歌曲水。", "海宫对起。", "灿骊光乍湿，杏梁云气。", "夜色瑶台，禁蜡初传翡翠。", "唤春醉。", "问人间、几番桃李。"]'),
('song-ci-935','应天长','吴文英','宋','宋词','song-ci','应天长','[]','丽花斗靥，清麝溅尘，春声遍满芳陌。',122,'宋词/ci.song.15000.json','["丽花斗靥，清麝溅尘，春声遍满芳陌。", "竟路障空云幕，冰壶浸霞色。", "芙蓉镜，词赋客。", "竞绣笔、醉嫌天窄。", "素娥下，小驻轻镳，眼乱红碧。", "前事顿非昔，故苑年光，浑与世相隔。", "向暮巷空人绝，残灯耿尘壁。", "凌波恨，帘户寂。", "听怨写、堕梅哀笛。", "伫立久，雨暗河桥，谯漏疏滴。"]'),
('song-ci-936','风流子','吴文英','宋','宋词','song-ci','风流子','[]','金谷已空尘。',133,'宋词/ci.song.15000.json','["金谷已空尘。", "薰风转、国色返春魂。", "半敧雪醉霜，舞低鸾翅，绛笼蜜炬，绿映龙盆。", "窈窕绣窗人睡起，临砌脉无言。", "慵整堕鬟，怨时迟暮，可怜憔悴，啼雨黄昏。", "轻桡移花市，秋娘渡、飞浪溅湿行裙。", "二十四桥南北，罗荐香分。", "念碎劈芳心，萦思千缕，赠将幽素，偷翦重云。", "终待凤池归去，催咏红翻。"]'),
('song-ci-937','风流子','吴文英','宋','宋词','song-ci','风流子','[]','温柔酣紫曲，扬州路、梦绕翠盘龙。',133,'宋词/ci.song.15000.json','["温柔酣紫曲，扬州路、梦绕翠盘龙。", "似日长傍枕，堕妆偏髻，露浓如酒，微醉敧红。", "自别楚娇天正远，倾国见吴宫。", "银烛夜阑，暗闻香泽，翠阴秋寂，重返春风。", "芳期嗟轻误，花君去、肠断妾若为容。", "惆怅舞衣叠损，露绮千重。", "料绣窗曲理，红牙拍碎，禁阶敲遍，白玉盂空。", "犹记弄花相谑，十二阑东。"]'),
('song-ci-938','过秦楼','吴文英','宋','宋词','song-ci','过秦楼','[]','藻国凄迷，曲澜澄映，怨入粉烟蓝雾。',135,'宋词/ci.song.15000.json','["藻国凄迷，曲澜澄映，怨入粉烟蓝雾。", "香笼麝水，腻涨红波，一镜万妆争妒。", "湘女归魂，佩环玉冷无声，凝情谁诉。", "又江空月堕，凌波尘起，彩鸳愁舞。", "还暗忆、钿合兰桡，丝牵琼腕，见的更怜心苦。", "玲珑翠屋，轻薄冰绡，稳称锦云留住。", "生怕哀蝉，暗惊秋被红衰，啼珠零露。", "能西风老尽，羞趁东风嫁与。"]'),
('song-ci-939','法曲献仙音','吴文英','宋','宋词','song-ci','法曲献仙音','[]','风拍波惊，露零秋觉，断绿衰红江上。',113,'宋词/ci.song.15000.json','["风拍波惊，露零秋觉，断绿衰红江上。", "艳拂潮妆，澹凝冰靥，别翻翠池花浪。", "过数点斜阳雨，啼绡粉痕冷。", "宛相向。", "指汀洲、素云飞过，清麝洗、玉井晓霞佩响。", "寸藕折长丝，笑何郎、心似春荡。", "半掬微凉，听娇蝉、声度菱唱。", "伴鸳鸯秋梦，酒醒月斜轻帐。"]'),
('song-ci-940','法曲献仙音','吴文英','宋','宋词','song-ci','法曲献仙音','[]','落叶霞翻，败窗风咽，暮色凄凉深院。',113,'宋词/ci.song.15000.json','["落叶霞翻，败窗风咽，暮色凄凉深院。", "瘦不关秋，泪缘轻别，情消鬓霜千点。", "怅翠冷搔头燕，那能语恩怨。", "紫箫远。", "记桃根、向随春渡，愁未洗、铅水又将恨染。", "粉缟涩离箱，忍重拈、灯夜裁翦。", "望极蓝桥，彩云飞、罗扇歌断。", "料莺笼玉锁，梦里隔花时见。"]'),
('song-ci-941','还京乐','吴文英','宋','宋词','song-ci','还京乐','[]','宴兰溆，促奏丝萦管裂飞繁响。',125,'宋词/ci.song.15000.json','["宴兰溆，促奏丝萦管裂飞繁响。", "似汉宫人去，夜深独语，胡沙凄哽。", "对雁斜玫柱，琼琼弄月临秋影。", "凤吹远，河汉去杳，天风飘冷。", "泛清商竟。", "转铜壶敲漏，瑶床二八青娥，环佩再整。", "菱歌四碧无声，变须臾、翠翳红暝。", "叹梨园、今调绝音希，愁深未醒。", "桂楫轻如翼，归霞时点清镜。"]'),
('song-ci-942','塞翁吟','吴文英','宋','宋词','song-ci','塞翁吟','[]','草色新宫绶，还跨紫陌骄骢。',115,'宋词/ci.song.15000.json','["草色新宫绶，还跨紫陌骄骢。", "好花是，晚开红。", "冷菊最香浓。", "黄帘绿幕萧萧梦，灯外换几秋风。", "叙往约，桂花宫。", "为别翦珍丛。", "雕栊。", "行人去、秦腰褪玉，心事称、吴妆晕浓。", "向春夜、闰情赋就，想初寄、上国书时，唱入眉峰。", "归来共酒，窈窕纹窗，莲卸新蓬。"]'),
('song-ci-943','塞翁吟','吴文英','宋','宋词','song-ci','塞翁吟','["\u897f\u6e56"]','有约西湖去，移棹晓折芙蓉。',115,'宋词/ci.song.15000.json','["有约西湖去，移棹晓折芙蓉。", "算才是，称心红。", "染不尽薰风。", "千桃过眼春如梦，还认锦叠云重。", "弄晚色，旧香中。", "旋撑入深丛。", "从容。", "情犹赋、冰车健笔，人未老、南屏翠峰。", "转河影、浮槎信早，素妃叫、海月归来，太液池东。", "红衣卸了，结子成莲，天劲秋浓。"]'),
('song-ci-944','丁香结','吴文英','宋','宋词','song-ci','丁香结','[]','香袅红霏，影高银烛，曾纵夜游浓醉。',120,'宋词/ci.song.15000.json','["香袅红霏，影高银烛，曾纵夜游浓醉。", "正锦温琼腻。", "被燕踏、暖雪惊翻庭砌。", "马嘶人散后，秋风换、故园梦里。", "吴霜融晓，陡觉暗动偷春花意。", "还似。", "海雾冷仙山，唤觉环儿半睡。", "浅薄朱唇，娇羞艳色，自伤时背。", "帘外寒挂澹月，向日秋千地。", "怀春情不断，犹带相思旧子。"]'),
('song-ci-945','六么令','吴文英','宋','宋词','song-ci','六么令','[]','露蛩初响，机杼还催织。',112,'宋词/ci.song.15000.json','["露蛩初响，机杼还催织。", "婺星为情慵懒，伫立明河侧。", "不见津头艇子，望绝南飞翼。", "云梁千尺。", "尘缘一点，回首西风又陈迹。", "那知天上计拙，乞巧楼南北。", "瓜果几度凄凉，寂寞罗池客。", "人事回廊缥缈，谁见金钗擘。", "今夕何夕。", "杯残月堕，但耿银河漫天碧。"]'),
('song-ci-946','蕙兰芳引','吴文英','宋','宋词','song-ci','蕙兰芳引','[]','空翠染云，楚山迥、故人南北。',103,'宋词/ci.song.15000.json','["空翠染云，楚山迥、故人南北。", "秀骨冷盈盈，清洗九秋涧绿。", "奉车旧畹，料未许、千金轻价。", "浅笑还不语，蔓草罗裙一幅。", "素女情多，阿真娇重，唤起空谷。", "弄野色烟姿，宜扫怨蛾澹墨。", "光风入户，媚香倾国。", "湘佩寒、幽梦小窗春足。"]'),
('song-ci-947','隔浦莲近・隔浦莲近拍','吴文英','宋','宋词','song-ci','隔浦莲近・隔浦莲近拍','[]','榴花依旧照眼。',88,'宋词/ci.song.15000.json','["榴花依旧照眼。", "愁褪红丝腕。", "梦绕烟江路，汀菰绿薰风晚。", "年少惊送远。", "吴蚕老、恨绪萦抽茧。", "旅情懒。", "扁舟系处，青帘浊酒须换。", "一番重午，旋买香蒲浮盏。", "新月湖光荡素练。", "人散。", "红衣香在南岸。"]'),
('song-ci-948','垂丝钓近・垂丝钓','吴文英','宋','宋词','song-ci','垂丝钓近・垂丝钓','[]','听风听雨，春残花落门掩。',81,'宋词/ci.song.15000.json','["听风听雨，春残花落门掩。", "乍倚玉阑，旋翦夭艳。", "携醉靥。", "放溯溪游缆。", "波光撼。", "映烛花黯澹。", "碎霞澄水，吴宫初试菱鉴。", "旧情顿减。", "孤负深杯滟。", "衣露天香染。", "通夜饮。", "问漏移几点。"]'),
('song-ci-949','荔枝香近・荔枝香','吴文英','宋','宋词','song-ci','荔枝香近・荔枝香','[]','锦带吴钩，征思横雁水。',92,'宋词/ci.song.15000.json','["锦带吴钩，征思横雁水。", "夜吟敲落霜红，船傍枫桥系。", "相思不管年华，唤酒吴娃市。", "因话、驻马新堤步秋绮。", "淮楚尾。", "暮云送、人千里。", "细雨南楼，香密锦温曾醉。", "花谷依然，秀靥偷春小桃李。", "为语梦窗憔悴。"]'),
('song-ci-950','荔枝香近・荔枝香','吴文英','宋','宋词','song-ci','荔枝香近・荔枝香','[]','睡轻时闻，晚鹊噪庭树。',92,'宋词/ci.song.15000.json','["睡轻时闻，晚鹊噪庭树。", "又说今夕天津，西畔重欢遇。", "蛛丝暗锁红楼，燕子穿帘处。", "天上、未比人间更情苦。", "秋鬓改，妒月姊、长眉妩。", "过雨西风，数叶井梧愁舞。", "梦入蓝桥，几点疏星映朱户。", "泪湿沙边凝伫。"]'),
('song-ci-951','西河','吴文英','宋','宋词','song-ci','西河','["\u897f\u6e56"]','春乍霁。',125,'宋词/ci.song.15000.json','["春乍霁。", "清涟画舫融泄。", "螺云万叠暗凝愁，黛蛾照水。", "漫将西子比西湖，溪边人更多丽。", "步危径、攀艳蕊。", "掬霞到手红碎。", "青蛇细折小回廊，去天半咫。", "画阑日暮起东风，棋声吹下人世。", "海棠藉雨半绣地。", "正残寒、初御罗绮。", "除酒销春何计。", "向沙头更续，残阳一醉。", "双玉杯和流花洗。"]'),
('song-ci-952','浪淘沙慢','吴文英','宋','宋词','song-ci','浪淘沙慢','[]','梦仙到、吹笙路杳，度巘云滑。',163,'宋词/ci.song.15000.json','["梦仙到、吹笙路杳，度巘云滑。", "溪谷冰绡未裂。", "金铺昼锁乍掣。", "见竹静、梅深春海阔。", "有新燕、帘底低说。", "念汉履无声跨鲸远，年年谢桥月。", "曲折。", "折画阑尽日凭热。", "半蜃起玲珑楼阁畔，缥缈鸿去绝。", "飞絮扬东风，天外歌阕。", "睡红醉缬。", "还是催、寒食看花时节。", "花下苍苔盛罗袜。", "银烛短、漏壶易竭。", "料池柳、不攀春送别。", "倩玉兔、别捣秋香，更醉蹋、千山冷翠飞晴雪。"]'),
('song-ci-953','西平乐慢・西平乐','吴文英','宋','宋词','song-ci','西平乐慢・西平乐','[]','岸压邮亭，路敧华表，堤树旧色依依。',164,'宋词/ci.song.15000.json','["岸压邮亭，路敧华表，堤树旧色依依。", "红索新晴，翠阴寒食，天涯倦客重归。", "叹废绿平烟带苑，幽渚尘香荡晚，当时燕子，无言对立斜晖。", "追念吟风赏月，十载事，梦惹绿杨丝。", "画船为市，夭妆艳水，日落云沈，人换春移。", "谁更与、苔根洗石，菊井招魂，漫省连车载酒，立马临花，犹认荐红傍路枝。", "歌断宴阑，荣华露草，冷落山丘，到此徘徊，细雨西城，羊昙醉后花飞。"]'),
('song-ci-954','瑞龙吟','吴文英','宋','宋词','song-ci','瑞龙吟','[]','堕虹际。',163,'宋词/ci.song.15000.json','["堕虹际。", "层观翠冷玲珑，五云飞起。", "玉虬萦结城根，澹烟半野，斜阳半市。", "瞰危睇。", "门巷去来车马，梦游宫蚁。", "秦鬟古色凝愁，镜中暗换，明眸皓齿。", "东海青桑生处，劲风吹浅，瀛洲清泚。", "山影泛出琼壶，碧树人世。", "枪芽焙绿，曾试云根味。", "岩流溅、涎香惯搅，娇龙春睡。", "露草啼清泪。", "酒香断到，文丘废隧。", "今古秋声里。", "情漫黯、寒鸦孤村流水。", "半空画角，落梅花地。"]'),
('song-ci-955','瑞龙吟','吴文英','宋','宋词','song-ci','瑞龙吟','["\u897f\u6e56"]','黯分袖。',163,'宋词/ci.song.15000.json','["黯分袖。", "肠断去水流萍，住船系柳。", "吴宫娇月娆花，醉题恨倚，蛮江豆蔻。", "吐春绣。", "笔底丽情多少，眼波眉岫。", "新园锁却愁阴，露黄漫委，寒香半亩。", "还背垂虹秋去，四桥烟雨，一宵歌酒。", "犹忆翠微携壶，乌帽风骤。", "西湖到日，重见梅钿皱。", "谁家听、琵琶未了，朝骢嘶漏。", "印剖黄金籀。", "待来共凭，齐云话旧。", "莫唱朱樱口。", "生怕遣、楼前行云知后。", "泪鸿怨角，空教人瘦。"]'),
('song-ci-956','瑞龙吟','吴文英','宋','宋词','song-ci','瑞龙吟','[]','大溪面。',163,'宋词/ci.song.15000.json','["大溪面。", "遥望绣羽冲烟，锦棱飞练。", "桃花三十六陂，鲛宫睡起，娇雷乍转。", "去如箭。", "催趁戏旗游鼓，素澜雪溅。", "东风冷湿蛟腥，澹阴送昼，轻霏弄晚。", "洲上青苹生处，斗春不管，怀沙人远。", "残日半开一川，花影零乱。", "山屏醉缬，连棹东西岸。", "阑干倒、千红妆靥，铅香不断。", "傍暝疏帘卷。", "翠涟皱净，笙歌未散。", "簪柳门归懒。", "犹自有、玉龙黄昏吹怨。", "重云暗阁，春霖一片。"]'),
('song-ci-957','大','吴文英','宋','宋词','song-ci','大','[]','峭石帆收，归期差，林沼年销红碧。',163,'宋词/ci.song.15000.json','["峭石帆收，归期差，林沼年销红碧。", "渔蓑樵笠畔，买佳邻翻盖，浣花新宅。", "地凿桃阴，天澄藻镜，聊与渔郎分席。", "沧波耕不碎，似蓝田初种，翠烟生璧。", "料情属新莲，梦惊春草，断桥相识。", "平生江海客。", "秀怀抱、云锦当秋织。", "任岁晚、陶篱菊暗，逋冢梅荒，总输玉井尝甘液。", "忍弃红香叶。", "集楚裳、西风催著。", "正明月、秋无极。", "归隐何处，门外垂杨天窄。", "放船五湖夜色。"]'),
('song-ci-958','解蹀躞','吴文英','宋','宋词','song-ci','解蹀躞','[]','醉云又兼醒雨，楚梦时来往。',90,'宋词/ci.song.15000.json','["醉云又兼醒雨，楚梦时来往。", "倦蜂刚著梨花、惹游荡。", "还作一段相思，冷波叶舞愁红，送人双桨。", "暗凝想。", "情共天涯秋黯，朱桥锁深巷。", "会稀投得轻分、顿惆怅。", "此去幽曲谁来，可怜残照西风，半妆楼上。"]'),
('song-ci-959','江神子・江城子','吴文英','宋','宋词','song-ci','江神子・江城子','[]','天街如水翠尘空。',86,'宋词/ci.song.15000.json','["天街如水翠尘空。", "建章宫。", "月明中。", "人未归来，玉树起秋风。", "宝栗万钉花露重，催赐带，过垂虹。", "夜凉沈水绣帘栊。", "酒香浓。", "雾濛濛。", "钗列吴娃，騕袅带金虫。", "三十六宫蟾观冷，留不住，佩丁东。"]'),
('song-ci-960','江神子・江城子','吴文英','宋','宋词','song-ci','江神子・江城子','[]','西风来晚桂开迟。',86,'宋词/ci.song.15000.json','["西风来晚桂开迟。", "月宫移。", "到东篱。", "簌簌惊尘，吹下半冰规。", "拟唤阿娇来小隐，金屋低，乱香飞。", "重阳还是隔年期。", "蝶相思。", "客情知。", "吴水吴烟，愁里更多诗。", "一夜看承应未别，秋好处，雁来时。"]'),
('song-ci-961','江神子・江城子','吴文英','宋','宋词','song-ci','江神子・江城子','[]','西风一叶送行舟。',86,'宋词/ci.song.15000.json','["西风一叶送行舟。", "浅迟留。", "舣汀洲。", "新浴红衣，绿水带香流。", "应是离宫城外晚，人伫立，小帘钩。", "新归重省别来愁。", "黛眉头。", "半痕秋。", "天上人间，斜月绣针楼。", "湘浪莫迷花蝶梦，江上约，负轻鸥。"]'),
('song-ci-962','沁园春','吴文英','宋','宋词','song-ci','沁园春','["\u897f\u6e56"]','澄碧西湖，软红南陌，银河地穿。',139,'宋词/ci.song.15000.json','["澄碧西湖，软红南陌，银河地穿。", "见华星影里，仙棋局静，清风行处，瑞玉圭寒。", "斜谷山深，望春楼远，无此峥嵘小渭川。", "一泓地，解新波不涸，独障狂澜。", "老苏而后坡仙。", "继菊井嘉名相与传。", "试摩挲劲石，无令角折，丁宁明月，莫涴规圆。", "漫结鸥盟，那知鱼乐，心止中流别有天。", "无尘夜，听吾伊正在，秋水阑干。"]'),
('song-ci-963','江神子・江城子','吴文英','宋','宋词','song-ci','江神子・江城子','[]','情如之何，暮涂为客，忍堪送君。',139,'宋词/ci.song.15000.json','["情如之何，暮涂为客，忍堪送君。", "便江湖天远，中宵同月，关河秋近，何日清尘。", "玉尘生风，貂裘明雪，幕府英雄今几人。", "行须早，料刚肠肯殢，泪眼离颦。", "平生秀句清尊。", "到帐东风开自有神。", "听夜鸣黄鹤，楼高百尺，朝驰白马，笔扫千军。", "贾傅才高，岳家军在，好勒燕然石上文。", "松江上，念故人老矣，甘卧闲云。"]'),
('song-ci-964','珍珠帘・真珠帘','吴文英','宋','宋词','song-ci','珍珠帘・真珠帘','[]','蜜沈烬暖萸烟袅。',123,'宋词/ci.song.15000.json','["蜜沈烬暖萸烟袅。", "层帘卷、伫立行人官道。", "麟带压愁香，听舞箫云渺。", "恨缕情丝春絮远，怅梦隔、银屏难到。", "寒峭。", "有东风嫩柳，学得腰小。", "还近绿水清明，叹孤身如燕，将花平绕。", "细雨湿黄昏，半醉归怀抱。", "蠹损歌纨人去久，漫泪沾、香兰如笑。", "书杳。", "念客枕幽单，看看春老。"]'),
('song-ci-965','风入松','吴文英','宋','宋词','song-ci','风入松','[]','春风吴柳几番黄。',90,'宋词/ci.song.15000.json','["春风吴柳几番黄。", "欢事小蛮窗。", "梅花正结双头梦，被玉龙、吹散幽香。", "昨夜灯前歌黛，今朝陌上啼妆。", "最怜无侣伴雏莺。", "桃叶已春江。", "曲屏先暖鸳衾惯，夜寒深、都是思量。", "莫道蓝桥路远，行云只隔幽坊。"]'),
('song-ci-966','风入松','吴文英','宋','宋词','song-ci','风入松','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','听风听雨过清明。',90,'宋词/ci.song.15000.json','["听风听雨过清明。", "愁草瘗花铭。", "楼前绿暗分携路，一丝柳、一寸柔情。", "料峭春寒中酒，交加晓梦啼莺。", "西园日日扫林亭。", "依旧赏新晴。", "黄蜂频扑秋千索，有当时、纤手香凝。", "惆怅双鸳不到，幽阶一夜苔生。"]'),
('song-ci-967','风入松','吴文英','宋','宋词','song-ci','风入松','["\u897f\u6e56"]','兰舟高荡涨波凉。',90,'宋词/ci.song.15000.json','["兰舟高荡涨波凉。", "愁被矮桥妨。", "暮烟疏雨西园路，误秋娘、浅约宫黄。", "还泊邮亭唤酒，旧曾送客斜阳。", "蝉声空曳别枝长。", "似曲不成商。", "御罗屏底翻歌扇，忆西湖、临水开窗。", "和醉重寻幽梦，残衾已断熏香。"]'),
('song-ci-968','风入松','吴文英','宋','宋词','song-ci','风入松','[]','一番疏雨洗芙蓉。',90,'宋词/ci.song.15000.json','["一番疏雨洗芙蓉。", "玉冷佩丁东。", "辘轳听带秋声转，早凉生、傍井梧桐。", "欢宴良宵好月，佳人修竹清风。", "临池飞阁乍青红。", "移酒小垂虹。", "贞元供奉梨园曲，称十香、深蘸琼锺。", "醉梦孤云晓色，笙歌一派秋空。"]'),
('song-ci-969','风入松','吴文英','宋','宋词','song-ci','风入松','[]','画船帘密不藏香。',90,'宋词/ci.song.15000.json','["画船帘密不藏香。", "飞作楚云狂。", "傍怀半卷金炉烬，怕暖销、春日朝阳。", "清馥晴熏残醉，断烟无限思量。", "凭阑心事隔垂杨。", "楼燕锁幽妆。", "梅花偏恼多情月，慰溪桥、流水昏黄。", "哀曲霜鸿凄断，梦魂寒蝶幽扬。"]'),
('song-ci-970','莺啼序','吴文英','宋','宋词','song-ci','莺啼序','[]','天吴驾云阆海，凝春空灿绮。',295,'宋词/ci.song.15000.json','["天吴驾云阆海，凝春空灿绮。", "倒银海、蘸影西城，四碧天镜无际。", "彩翼曳、扶摇宛转，雩龙降尾交新霁。", "近玉虚高处，天风笑语吹坠。", "清濯缁尘，快展旷眼，傍危阑醉倚。", "面屏障、一一莺花，薛萝浮动金翠。", "惯朝昏、晴光雨色，燕泥动、红香流水。", "步新梯，藐视年华，顿非尘世。", "麟翁衮舄，领客登临，座有诵鱼美。", "翁笑起、离席而语，敢诧京兆，以役为功，落成奇事。", "明良庆会，赓歌熙载，隆都观国多闲暇，遣丹青、雅饰繁华地。", "平瞻太极，天街润纳璇题，露床夜沈秋纬。", "清风观阙，丽日罘罳，正午长漏迟。", "为洗尽、脂痕茸唾，净卷曲尘，永昼低垂，绣帘十二。", "高轩驷马，峨冠鸣佩，班回花底修禊饮，御炉香、分惹朝衣袂。", "碧桃数点飞花，涌出宫沟，溯春万里。"]'),
('song-ci-971','莺啼序','吴文英','宋','宋词','song-ci','莺啼序','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u897f\u6e56"]','残寒正欺病酒，掩沈香绣户。',295,'宋词/ci.song.15000.json','["残寒正欺病酒，掩沈香绣户。", "燕来晚、飞入西城，似说春事迟暮。", "画船载、清明过却，晴烟冉冉吴宫树。", "念羁情游荡，随风化为轻絮。", "十载西湖，傍柳系马，趁娇尘软雾。", "溯红渐、招入仙溪，锦儿偷寄幽素。", "倚银屏、春宽梦窄，断红湿、歌纨金缕。", "暝堤空，轻把斜阳，总还鸥鹭。", "幽兰旋老，杜若还生，水乡尚寄旅。", "别后访、六桥无信，事往花委，瘗玉埋香，几番风雨。", "长波妒盼，遥山羞黛，渔灯分影春江宿，记当时、短楫桃根渡。", "青楼彷佛，临分败壁题诗，泪墨惨澹尘土。", "危亭望极，草色天涯，吹鬓侵半苎。", "暗点检、离痕欢唾，尚染鲛绡，亸凤迷归，破鸾慵舞。", "殷勤待写，书中长恨，蓝霞辽海沈过雁，漫相思、弹入哀筝柱。", "伤心千里江南，怨曲重招，断魂在否。"]'),
('song-ci-972','莺啼序','吴文英','宋','宋词','song-ci','莺啼序','["\u897f\u6e56"]','横塘棹穿艳锦，引鸳鸯弄水。',295,'宋词/ci.song.15000.json','["横塘棹穿艳锦，引鸳鸯弄水。", "断霞晚、笑折花归，绀纱低护灯蕊。", "润玉瘦、冰轻倦浴，斜拖凤股盘云坠。", "听银床声细。", "梧桐渐搅凉思。", "窗隙流光，冉冉迅羽，诉空粱燕子。", "误惊起、风竹敲门，故人还又不至。", "记琅玕、新诗细掐，早陈迹、香痕纤指。", "怕因循，罗扇恩疏，又生秋意。", "西湖旧日，画舸频移，叹几萦梦寐。", "霞佩冷，叠澜不定，麝霭飞雨，乍湿鲛绡，暗盛红泪。", "綀单夜共，波心宿处，琼箫吹月霓裳舞，向明朝、未觉花容悴。", "嫣香易落，回头澹碧销烟，镜空画罗屏裹。", "残蝉度曲，唱彻西园，也感红怨翠。", "念省惯、吴宫幽憩。", "暗柳追凉，晓岸参斜，露零沤起。", "丝索寸藕，留连欢事。", "桃笙平展湘浪影，有昭华、秾李冰相倚。", "如今鬓点凄霜，半箧秋词，恨盈蠹纸。"]'),
('song-ci-973','天香','吴文英','宋','宋词','song-ci','天香','[]','珠络玲珑，罗囊闲斗，酥怀暖麝相倚。',117,'宋词/ci.song.15000.json','["珠络玲珑，罗囊闲斗，酥怀暖麝相倚。", "百和花须，十分风韵，半袭凤箱重绮。", "茜垂四角，慵未揭、流苏春睡。", "熏度红薇院落，烟销画屏沈水。", "温泉降绡乍试。", "露华侵、透肌兰泚。", "漫省浅溪月夜，暗浮花气。", "荀令如今老矣。", "但未减、韩郎旧风味。", "远寄相思，馀熏梦里。"]'),
('song-ci-974','天香','吴文英','宋','宋词','song-ci','天香','[]','蟫叶黏霜，蝇苞缀冻，生香远带风峭。',117,'宋词/ci.song.15000.json','["蟫叶黏霜，蝇苞缀冻，生香远带风峭。", "岭上寒多，溪头月冷，北枝瘦、南枝小。", "玉奴有姊，先占立、墙阴春早。", "初试宫黄澹薄，偷分寿阳纤巧。", "银烛泪深未晓。", "酒锺悭、贮愁多少。", "记得短亭归马，暮衙蜂闹。", "豆蔻钗梁恨袅。", "但怅望、天涯岁华老。", "远信难，吴云雁杳。"]'),
('song-ci-975','玉漏迟','吴文英','宋','宋词','song-ci','玉漏迟','[]','雁边风讯小，飞琼望杳，碧云先晚。',115,'宋词/ci.song.15000.json','["雁边风讯小，飞琼望杳，碧云先晚。", "露冷阑干，定怯藕丝冰腕。", "净洗浮空片玉，胜花影、春灯相乱。", "秦镜满。", "素娥未肯，分秋一半。", "每圆处既良宵，甚此夕偏饶，对歌临怨。", "万里蝉娟，几许雾屏云幔。", "孤免凄凉照水，晓风起、银河西转。", "摩泪眼。", "瑶台梦回人远。"]'),
('song-ci-976','金盏子','吴文英','宋','宋词','song-ci','金盏子','["\u897f\u6e56"]','卜筑西湖，种翠萝犹傍，软红尘裹。',125,'宋词/ci.song.15000.json','["卜筑西湖，种翠萝犹傍，软红尘裹。", "来往载清吟，为偏爱吾庐，画船频繁。", "笑携雨色晴光，入春明朝市。", "石桥锁，烟霞五百名仙，第一人是。", "临酒论深意。", "流光转、莺花任乱委。", "冷然九秋肺腑，应多梦、岩扃冷云空翠。", "漱流枕石幽情，写猗兰绿绮。", "专城处，他山小队登临，待西风起。"]'),
('song-ci-977','金盏子','吴文英','宋','宋词','song-ci','金盏子','[]','赏月梧园，恨广寒宫树，晓风摇落。',126,'宋词/ci.song.15000.json','["赏月梧园，恨广寒宫树，晓风摇落。", "莓砌扫珠尘，空肠断、熏炉烬销残萼。", "殿秋尚有馀花，锁烟窗云幄。", "新雁又、无端送人江上，短亭初泊。", "篱角。", "梦依约。", "人一笑、惺忪翠袖薄。", "悠然醉魂唤醒，幽丛畔、凄香雾雨漠漠。", "晚吹乍颤秋声，早屏空金雀。", "明朝想，犹有数点蜂黄，伴我斟酌。"]'),
('song-ci-978','永遇乐','吴文英','宋','宋词','song-ci','永遇乐','[]','春酌沈沈，晚妆的的，仙梦游惯。',128,'宋词/ci.song.15000.json','["春酌沈沈，晚妆的的，仙梦游惯。", "锦溆维舟，青门倚盖，还被笼莺唤。", "裴郎归后，崔娘沈恨，漫客请传芳卷。", "联题在，频经翠袖，胜隔绀纱尘幔。", "桃根杏叶，胶黏缃缥，几回凭阑人换。", "峨髻愁云，兰香腻粉，都为多情褪。", "离巾拭泪，征袍染醉，强作酒朋花伴。", "留连怕，风姨浪妒，又吹雨断。"]'),
('song-ci-979','永遇乐','吴文英','宋','宋词','song-ci','永遇乐','[]','风拂尘徽，雨侵凉榻，才动秋思。',128,'宋词/ci.song.15000.json','["风拂尘徽，雨侵凉榻，才动秋思。", "缓酒销更，移灯傍影，净洗芭蕉耳。", "铜华沧海，愁霾重嶂，燕北雁南天外。", "算阴晴，浑似几番，渭城故人离会。", "青楼旧日，高歌取醉，唤出玉人梳洗。", "红叶流光，苹花两鬓，心事成秋水。", "白凝虚晓，香吹轻烬，倚窗小瓶疏桂。", "问深宫，姮娥正在，妒云第几。"]'),
('song-ci-980','永遇乐','吴文英','宋','宋词','song-ci','永遇乐','["\u897f\u6e56"]','阁雪云低，卷沙风急，惊雁失序。',128,'宋词/ci.song.15000.json','["阁雪云低，卷沙风急，惊雁失序。", "户掩寒宵，屏闲冷梦，灯飐唇似语。", "堪怜窗景，都闲刺绣，但续旧愁一缕。", "邻歌散，罗襟印粉，袖湿茜桃红露。", "西湖旧日，留连清夜，爱酒几将花误。", "遣袜尘销，题裙墨黯，天远吹笙路。", "吴台直下，缃梅无限，未放野桥香度。", "重谋醉，揉香弄影，水清浅处。"]'),
('song-ci-981','玉胡蝶・玉蝴蝶','吴文英','宋','宋词','song-ci','玉胡蝶・玉蝴蝶','[]','角断竿鸣疏点，倦萤透隙，低弄书光。',124,'宋词/ci.song.15000.json','["角断竿鸣疏点，倦萤透隙，低弄书光。", "一寸悲秋，生动万种凄凉。", "旧衫染、唾凝花碧，别泪想、妆洗蜂黄。", "楚魂伤。", "雁汀沙冷，来信微茫。", "都忘。", "孤山旧赏，水沈熨露，岸锦宜霜。", "败叶题诗，御沟应不到流湘。", "数客路、又随淮月，羡故人、还买吴航。", "两凝望。", "满城风雨，催送重阳。"]'),
('song-ci-982','绛都春','吴文英','宋','宋词','song-ci','绛都春','[]','香深雾暖。',122,'宋词/ci.song.15000.json','["香深雾暖。", "正人在、锦瑟华年深院。", "旧日汉宫，分得红兰滋吴苑。", "临池羞落梅花片。", "弄水月、初匀妆面。", "紫烟笼处，双鸾共跨，洞箫低按。", "歌管。", "红围翠袖，冻云外，似觉东风先转。", "绣畔昼迟，花底天宽春无限。", "仙郎骄马琼林宴。", "待卷上、珠帘教看。", "更传莺入新年，宝钗梦燕。"]'),
('song-ci-983','绛都春','吴文英','宋','宋词','song-ci','绛都春','[]','羁云旅雁。',122,'宋词/ci.song.15000.json','["羁云旅雁。", "敛倦羽、寄楼墙阴年晚。", "问字翠尊，刻烛红笺悭曾展。", "冰滩鸣佩舟如箭。", "笑乌帻、临风重岸。", "傍邻垂柳，清霜万缕，送将人远。", "吴苑。", "千金未惜，买新赋、共赏文园词翰。", "流水翠微，明月清风平分半。", "梅深驿路香不断。", "万玉舞、罘罳东畔。", "料应花底春多，软红雾暖。"]'),
('song-ci-984','绛都春','吴文英','宋','宋词','song-ci','绛都春','[]','螺屏暖翠。',122,'宋词/ci.song.15000.json','["螺屏暖翠。", "正雾卷暮色，星河浮霁。", "路幕递香，街马冲尘东风细。", "梅槎凌海横鳌背。", "倩稳载、蓬莱云气。", "宝阶斜转，冰峨素影，夜清如水。", "应记。", "千秋化鹤，旧华表、认得山川犹是。", "暗解绣囊，争掷金钱游人醉。", "笙歌晓度晴霞外。", "又上苑、春生一苇。", "便教接宴莺花，万红镜裹。"]'),
('song-ci-985','绛都春','吴文英','宋','宋词','song-ci','绛都春','[]','情黏舞线。',122,'宋词/ci.song.15000.json','["情黏舞线。", "怅驻马灞桥，天寒人远。", "旋翦露痕，移得春娇栽琼苑。", "流莺常语烟中怨。", "恨三月、飞花零乱。", "艳阳归后，红藏翠掩，小坊幽院。", "谁见。", "新腔按彻，背灯暗、共倚篔屏葱茜。", "绣被梦轻，金屋妆深沈香换。", "梅花重洗春风面。", "正溪上、参横月转。", "并禽飞上金沙，瑞香雾暖。"]'),
('song-ci-986','绛都春','吴文英','宋','宋词','song-ci','绛都春','[]','南楼坠燕。',122,'宋词/ci.song.15000.json','["南楼坠燕。", "又灯晕夜凉，疏帘空卷。", "叶吹暮喧，花露晨晞秋光短。", "当时明月娉婷伴。", "怅客路、幽扃俱远。", "雾鬟依约，除非照影，镜空不见。", "别馆。", "秋娘乍识，似人处、最在双波凝盼。", "旧色旧香，闲雨闲云情终浅。", "丹青谁画真真面。", "便只作、梅花频看。", "更愁花变梨霙，又随梦散。"]'),
('song-ci-987','绛都春','吴文英','宋','宋词','song-ci','绛都春','[]','春来雁渚。',122,'宋词/ci.song.15000.json','["春来雁渚。", "弄艳冶、又入垂杨如许。", "困舞瘦腰，啼湿宫黄池塘雨。", "碧沿苍藓云根路。", "尚追想、凌波微步。", "小楼重上，凭谁为唱，旧时金缕。", "凝伫。", "烟萝翠竹，欠罗袖、为倚天寒日暮。", "强醉梅边，招得花奴来尊俎。", "东风须惹春云住。", "□莫把、飞琼吹去。", "便教移取熏笼，夜温绣户。"]'),
('song-ci-988','惜秋华','吴文英','宋','宋词','song-ci','惜秋华','["\u897f\u6e56"]','细响残蛩，傍灯前、似说深秋怀抱。',116,'宋词/ci.song.15000.json','["细响残蛩，傍灯前、似说深秋怀抱。", "怕上翠微，伤心乱烟残照。", "西湖镜掩尘沙，翳晓影、秦鬟云扰。", "新鸿，唤凄凉、渐入红萸乌帽。", "江上故人老。", "视东篱秀色，依然娟好。", "晚梦趁、邻杵断，乍将愁到。", "秋娘泪湿黄昏，又满城、雨轻风小。", "闲了。", "看芙蓉、画船多少。"]'),
('song-ci-989','惜秋华','吴文英','宋','宋词','song-ci','惜秋华','[]','思渺西风，怅行踪、浪逐南飞高雁。',115,'宋词/ci.song.15000.json','["思渺西风，怅行踪、浪逐南飞高雁。", "怯上翠微，危楼更堪凭晚。", "蓬莱对起幽云，澹野色山容愁卷。", "清浅。", "瞰沧波、静衔秋痕一线。", "十载寄吴苑。", "惯东篱深把，露黄偷翦。", "移暮影、照越镜，意销香断。", "秋娥赋得闲情，倚翠尊、小眉初展。", "深劝。", "待明朝、醉巾重岸。"]'),
('song-ci-990','惜秋华','吴文英','宋','宋词','song-ci','惜秋华','[]','露罥蛛丝，小楼阴堕月，秋惊华鬓。',116,'宋词/ci.song.15000.json','["露罥蛛丝，小楼阴堕月，秋惊华鬓。", "宫漏未央，当时钿钗遗恨。", "人间梦隔西风，算天上、年华一瞬。", "相逢，纵相疏、胜却巫阳无准。", "和处动凉讯。", "听露井梧桐，楚骚成韵。", "彩云断、翠羽散，此情难问。", "银河万古秋声，但望中、婺星清润。", "轻俊。", "度金针、漫牵方寸。"]'),
('song-ci-991','惜秋华','吴文英','宋','宋词','song-ci','惜秋华','[]','数日西风，打秋林枣熟，还催人去。',114,'宋词/ci.song.15000.json','["数日西风，打秋林枣熟，还催人去。", "瓜果夜深，斜河拟看星度。", "葱葱便倒离尊，怅遇合、云销萍聚。", "留连，有残蝉韵晚，时歌金缕。", "绿水暂如许。", "奈南墙冷落，竹烟槐雨。", "此去杜曲，已近紫霄尺五。", "扁舟夜宿吴江，正水佩霓裳无数。", "眉妩。", "问别来、解相思否。"]'),
('song-ci-992','惜秋华','吴文英','宋','宋词','song-ci','惜秋华','[]','路远仙城，自王郎去后，芳卿憔悴。',115,'宋词/ci.song.15000.json','["路远仙城，自王郎去后，芳卿憔悴。", "锦段镜空，重铺步障新绮。", "凡花瘦不禁秋，幻腻玉、腴红鲜丽。", "相携。", "试新妆乍毕，交扶轻醉。", "长记断桥外。", "骤玉骢过处，千娇凝睇。", "昨梦顿醒，依约旧时眉翠。", "愁边暮合碧云，倩唱入、六幺声里。", "风起。", "舞斜阳、阑干十二。"]'),
('song-ci-993','惜黄花慢','吴文英','宋','宋词','song-ci','惜黄花慢','[]','粉靥金裳。',133,'宋词/ci.song.15000.json','["粉靥金裳。", "映绣屏认得，旧日萧娘。", "翠微高处，故人帽底，一年最好，偏是重阳。", "避春祗怕春不远，望幽径、偷理秋妆。", "殢醉乡。", "寸心似翦，飘荡愁觞。", "潮腮笑入清霜。", "斗万花样巧，深染蜂黄。", "露痕千点，自怜旧色，寒泉半掬，百感幽香。", "雁声不到东篱畔，满城但、风雨凄凉。", "最断肠。", "夜深怨蝶飞狂。"]'),
('song-ci-994','惜黄花慢','吴文英','宋','宋词','song-ci','惜黄花慢','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','送客吴皋。',133,'宋词/ci.song.15000.json','["送客吴皋。", "正试霜夜冷，枫落长桥。", "望天不尽，背城渐杳，离亭黯黯，恨水迢迢。", "翠香零落红衣老，暮愁锁、残柳眉梢。", "念瘦腰。", "沈郎旧日，曾系兰桡。", "仙人凤咽琼箫。", "怅断魂送远，九辨难招。", "醉鬟留盼，小窗翦烛，歌云载恨，飞上银霄。", "素秋不解随船去，败红趁、一叶寒涛。", "梦翠翘。", "怨鸿料过南谯。"]'),
('song-ci-995','十二郎・二郎神','吴文英','宋','宋词','song-ci','十二郎・二郎神','[]','素天际水，浪拍碎、冻云不凝。',129,'宋词/ci.song.15000.json','["素天际水，浪拍碎、冻云不凝。", "记晓叶题霜，秋灯吟雨，曾系长桥过艇。", "又是宾鸿重来后，猛赋得、归期才定。", "嗟绣鸭解言，香鲈堪钓，尚庐人境。", "幽兴。", "争如共载，越娥妆镜。", "念倦客依前，貂裘茸帽，重向淞江照影。", "酹酒苍茫，倚歌平远，亭上玉虹腰冷。", "迎醉面，暮雪飞花，几点黛愁山暝。"]'),
('song-ci-996','醉蓬莱','吴文英','宋','宋词','song-ci','醉蓬莱','[]','望碧天书断，宝枕香留，泪痕盈袖。',120,'宋词/ci.song.15000.json','["望碧天书断，宝枕香留，泪痕盈袖。", "谁识秋娘，比行云纤瘦。", "象尺熏炉，翠针金缕，记倚床同绣。", "月亸琼梳，冰销粉汗，南花熏透。", "尽是当时，少年清梦，臂约痕深，帕绡红皱。", "凭鹊传音，恨语多轻漏。", "润玉留情，沈郎无奈，向柳阴期候。", "数曲催阑，双铺深掩，风环鸣兽。"]'),
('song-ci-997','烛影摇红','吴文英','宋','宋词','song-ci','烛影摇红','["\u897f\u6e56"]','西子西湖，赋情合载鸱夷棹。',116,'宋词/ci.song.15000.json','["西子西湖，赋情合载鸱夷棹。", "断桥直去是孤山，应为梅花到。", "几度吟昏醉晓。", "背东风、偷闲斗草。", "乱鸦啼后，解佩归来，春怀多少。", "千里蝉娟，茂园今夜同清照。", "樱脂茸唾听吟诗，争似还家好。", "昵昵西窗语笑。", "凤云深、琼箫缥缈。", "顾春如旧，柳带同心，花枝压帽。"]'),
('song-ci-998','烛影摇红','吴文英','宋','宋词','song-ci','烛影摇红','["\u897f\u6e56"]','新月侵阶，彩云林外笙箫透。',117,'宋词/ci.song.15000.json','["新月侵阶，彩云林外笙箫透。", "银台双引绕花行，红坠香沾袖。", "不管签声转漏。", "更明朝、棋消永昼。", "静中闲看，倦羽飞还，游云出岫。", "随处春光，翠阴那只西湖柳。", "去年溪上牡丹时，还试长安酒。", "都把愁怀抖擞。", "笑流莺、啼春漫漫瘦。", "晓风恶尽，妒雪寒销，青梅如豆。"]'),
('song-ci-999','烛影摇红','吴文英','宋','宋词','song-ci','烛影摇红','[]','飞尽西园，晚秋却胜春天气。',116,'宋词/ci.song.15000.json','["飞尽西园，晚秋却胜春天气。", "霜花开尽锦屏空，红叶新装缀。", "时放清杯泛水。", "暗凄凉、东风旧事。", "夜吟不绝，松影阑干，月笼寒翠。", "莫唱阳关，但凭彩袖歌千岁。", "秋星入梦隔明朝，十载吴宫会。", "一棹回潮度苇。", "正西窗、灯花报喜。", "柳蛮樱素，试酒争怜，不教不醉。"]'),
('song-ci-0','烛影摇红','吴文英','宋','宋词','song-ci','烛影摇红','[]','碧澹山姿，暮寒愁沁歌眉浅。',116,'宋词/ci.song.16000.json','["碧澹山姿，暮寒愁沁歌眉浅。", "障泥南陌润轻酥，灯火深深院。", "入夜笙歌渐暖。", "彩旗翻、宜男舞遍。", "恣游不怕，素袜尘生，行裙红溅。", "银烛笼纱，翠屏不照残梅怨。", "洗妆清靥湿春风，宜带啼痕看。", "楚梦留情未散。", "素娥愁、天深信远。", "晓窗移枕，酒困香残，春阴帘卷。"]'),
('song-ci-1','烛影摇红','吴文英','宋','宋词','song-ci','烛影摇红','[]','天桂飞香，御花簇座千秋宴。',116,'宋词/ci.song.16000.json','["天桂飞香，御花簇座千秋宴。", "笑从王母摘仙桃，琼醴双金盏。", "掌上龙珠照眼。", "映萝图、星晖海润。", "浮槎远到，水浅蓬莱，秋明河汉。", "宝月将弦，晚钩斜挂西帘卷。", "未须十日便中秋，争看清光满。", "净洗红尘障面。", "贺朝霖、催班正殿。", "喜回天上，紫府开筵，瑶池宣劝。"]'),
('song-ci-2','烛影摇红','吴文英','宋','宋词','song-ci','烛影摇红','[]','莓锁虹梁，稽山祠下当时见。',116,'宋词/ci.song.16000.json','["莓锁虹梁，稽山祠下当时见。", "横斜无分照溪光，珠网空凝遍。", "姑射青春对面。", "驾飞虬、罗浮路远。", "千年春在，新月苔池，黄昏山馆。", "花满河阳，为君羞褪晨妆茜。", "云根直下是银河，客老秋槎变。", "雨外红铅洗断。", "又晴匣、惊飞暮管。", "倚阑祗怕，弄水鳞生，乘东风便。"]'),
('song-ci-3','烛影摇红','吴文英','宋','宋词','song-ci','烛影摇红','[]','秋入灯花，夜深檐影琵琶语。',116,'宋词/ci.song.16000.json','["秋入灯花，夜深檐影琵琶语。", "越娥青镜洗红埃，山斗秦眉妩。", "相问金茸翠亩。", "认城阴、春耕旧处。", "晚春相应，新稻炊香，疏烟林莽。", "清磬风前，海沈宿袅芙蓉炷。", "阿香秋梦起娇啼，玉女传幽素。", "人驾梅槎未渡。", "试梧桐、聊分宴俎。", "采菱别调，留取蓬莱，霎时云住。"]'),
('song-ci-4','丑奴儿慢・采桑子慢','吴文英','宋','宋词','song-ci','丑奴儿慢・采桑子慢','[]','东风未起，花上纤尘无影。',110,'宋词/ci.song.16000.json','["东风未起，花上纤尘无影。", "峭云湿，凝酥深，乍洗梅清。", "钓卷愁丝，冷浮虹气海空明。", "若耶门闭，扁舟去懒，客思鸥轻。", "几度问春，倡红冶翠，空媚阴晴。", "看真色、千岩一素，天澹无情。", "醒眼重开，玉钩帘外晓峰青。", "相扶轻醉，越王台上，更最高层。"]'),
('song-ci-5','丑奴儿慢・采桑子慢','吴文英','宋','宋词','song-ci','丑奴儿慢・采桑子慢','[]','空濛乍敛，波影帘花晴乱。',106,'宋词/ci.song.16000.json','["空濛乍敛，波影帘花晴乱。", "正西子、梳妆楼上，镜舞青鸾。", "润逼风襟，满湖山色入阑干。", "天虚鸣籁，云多易雨，长带秋寒。", "遥望翠凹，隔江时见，越女低鬟。", "算堪羡、烟沙白鹭，暮往朝远。", "歌管重城，醉花春梦半香残。", "乘杯对影，云海人闲。"]'),
('song-ci-6','木兰花慢','吴文英','宋','宋词','song-ci','木兰花慢','[]','紫骝嘶冻草，晓云锁、岫眉颦。',124,'宋词/ci.song.16000.json','["紫骝嘶冻草，晓云锁、岫眉颦。", "正蕙雪初销，松腰玉瘦，憔悴真真。", "轻藜渐穿险磴，步荒苔、犹认瘗花痕。", "千古兴亡旧恨，半丘残日孤云。", "开尊。", "重吊吴魂。", "岚翠冷、洗微醺。", "问几曾夜宿，月明起看，剑水星纹。", "登临总成去客，更软红、先有探芳人。", "回首沧波故苑，落梅烟雨黄昏。"]'),
('song-ci-7','木兰花慢','吴文英','宋','宋词','song-ci','木兰花慢','[]','步层丘翠莽，□□处、更春寒。',126,'宋词/ci.song.16000.json','["步层丘翠莽，□□处、更春寒。", "渐晚色催阴，风花弄雨，愁起阑干。", "惊翰。", "带云去杳，任红尘、一片落人间。", "青冢麒麟有恨，卧听箫鼓游山。", "年年。", "叶外花前。", "腰艳楚、鬓成潘。", "叹宝奁瘗久，青萍共化，裂石空磐。", "尘缘。", "酒沾粉污，问何人、从此濯清泉。", "一笑掀髯付与，寒松瘦倚苍峦。"]'),
('song-ci-8','木兰花慢','吴文英','宋','宋词','song-ci','木兰花慢','[]','送秋云万里，算舒卷、总何心。',126,'宋词/ci.song.16000.json','["送秋云万里，算舒卷、总何心。", "叹路转羊肠，人营燕垒，霜满蓬簪。", "愁侵。", "庾尘满袖，便封侯、那羡汉淮阴。", "一醉莼丝脍玉，忍教菊老松深。", "离音。", "又听西风，金井树、动秋吟。", "向暮江目断，鸿飞渺渺，天色沈沈。", "沾襟。", "四弦夜语，问杨琼、往事到寒砧。", "争似湖山岁晚，静梅香底同斟。"]'),
('song-ci-9','木兰花慢','吴文英','宋','宋词','song-ci','木兰花慢','[]','酹清杯问水，惯曾见、几逢迎。',126,'宋词/ci.song.16000.json','["酹清杯问水，惯曾见、几逢迎。", "自越棹轻飞，秋莼归后，杞菊荒荆。", "孤鸣。", "舞鸥惯下，又渔歌、忽断晚烟生。", "雪浪闲销钓石，冷枫频落江汀。", "长亭。", "春恨何穷，目易尽、酒微醒。", "怅断魂西子，凌波去杳，环佩无声。", "阴晴。", "最无定处，被浮云、多翳镜华明。", "向晓东风霁色，绿杨楼外山青。"]'),
('song-ci-10','木兰花慢','吴文英','宋','宋词','song-ci','木兰花慢','[]','润寒梅细雨，卷灯火、暗尘香。',126,'宋词/ci.song.16000.json','["润寒梅细雨，卷灯火、暗尘香。", "正万里胥涛，流花涨腻，春共东江。", "云樯。", "未传燕语，过罘罳、垂柳舞鹅黄。", "留取行人系马，软红深处闻莺。", "悠扬。", "霁月清风，凝望久、鄮山苍。", "又紫箫一曲，还吹别调，楚际吴旁。", "仙方。", "袖中秘宝，遣蓬莱、弱水变飞霜。", "寒食春城秀句，趁花飞入宫墙。"]'),
('song-ci-11','木兰花慢','吴文英','宋','宋词','song-ci','木兰花慢','[]','指罘罳晓月，动凉信、又催归。',126,'宋词/ci.song.16000.json','["指罘罳晓月，动凉信、又催归。", "正玉涨松波，花穿画舫，无限红衣。", "青丝。", "傍桥浅系，问笛中、谁奏鹤南飞。", "西子冰销冷处，素娥宝镜圆时。", "清奇。", "好借秋光，临水色、写瑶卮。", "向醉中织就，天孙云锦，一杼新诗。", "依稀。", "数声禁漏，又东华、尘染帽檐缁。", "争似西风小队，便乘鲈脍秋肥。"]'),
('song-ci-12','木兰花慢','吴文英','宋','宋词','song-ci','木兰花慢','[]','几临流送远，渐荒落、旧邮亭。',126,'宋词/ci.song.16000.json','["几临流送远，渐荒落、旧邮亭。", "念西子初来，当时望眼，啼雨难晴。", "娉婷。", "素亭共载，到越吟、翻调倚吴声。", "得意东风去棹，怎怜会重离轻。", "云零。", "梦绕浮觞，流水畔、叙幽情。", "恨赋笔分携，江山委秀，桃李荒荆。", "经行。", "问春在否，过汀洲、暗忆百花名。", "莺缕争堪细折，御黄堤上重盟。"]'),
('song-ci-13','喜迁莺','吴文英','宋','宋词','song-ci','喜迁莺','[]','凡尘流水。',126,'宋词/ci.song.16000.json','["凡尘流水。", "正春在、绛阙瑶阶十二。", "暖日明霞，天香盘锦，低映晓光梳洗。", "故苑浣花沈恨，化作妖红斜紫。", "困无力，倚阑干，还倩东风扶起。", "公子。", "留意处，罗盖牙签，一一花名字。", "小扇翻歌，密围留客，云叶翠温罗绮。", "艳波紫金杯重，人倚妆台微醉。", "夜和露，翦残枝，点点花心清泪。"]'),
('song-ci-14','喜迁莺','吴文英','宋','宋词','song-ci','喜迁莺','[]','烟空白鹭。',126,'宋词/ci.song.16000.json','["烟空白鹭。", "乍飞下、似呼行人相语。", "细縠春波，微痕秋月，曾认片帆来去。", "万顷素云遮断，十二红帘钩处。", "黯愁远，向虹腰，时送斜阳凝伫。", "轻许。", "孤梦到，海上玑宫，玉冷深窗户。", "遥指人间，隔江烟火，漠漠水葓摇暮。", "看葺断矶残钓，替却珠歌雪舞。", "吟未了，去匆匆，清晓一阑烟雨。"]'),
('song-ci-15','喜迁莺','吴文英','宋','宋词','song-ci','喜迁莺','[]','江亭年暮。',127,'宋词/ci.song.16000.json','["江亭年暮。", "趁飞雁、又听，数声柔橹。", "蓝尾杯单，胶牙饧澹，重省旧时羁旅。", "雪舞野梅篱落，寒拥渔家门户。", "晚风峭，作初番花讯，春还知否。", "何处。", "围艳冶、红烛画堂，博簺良宵午。", "谁念行人，愁先芳草，轻送年华如羽。", "自剔短檠不睡，空索彩桃新句。", "便归好，料鹅黄，已染西池千缕。"]'),
('song-ci-16','喜迁莺','吴文英','宋','宋词','song-ci','喜迁莺','[]','冬分人别。',125,'宋词/ci.song.16000.json','["冬分人别。", "渡倦客晚潮，伤头俱雪。", "雁影秋空，蝶情春荡，几处路穷车绝。", "把酒共温寒夜，倚绣添慵时节。", "又底事，对愁云江国，离心还折。", "吴越。", "重会面，点检旧吟，同看灯花结。", "儿女相思，年华轻送，邻户断声噎。", "待移杖藜雪后，犹怯蓬莱寒阔。", "最起晚，任鸦林催晓，梅窗沈月。"]'),
('song-ci-17','探芳信','吴文英','宋','宋词','song-ci','探芳信','[]','夜寒重。',110,'宋词/ci.song.16000.json','["夜寒重。", "见羽葆将迎，飞琼入梦。", "整素妆归处，中宵按瑶凤。", "舞春歌夜棠梨岸，月冷和云冻。", "画船中、太白仙人，锦袍初拥。", "应过语溪否，试笑挹中郎，还叩清弄。", "粉黛湖山，欠携酒、共飞鞚。", "洗杯时换铜觚水，待作梅花供。", "问何时、带雨锄烟自种。"]'),
('song-ci-18','探芳信','吴文英','宋','宋词','song-ci','探芳信','[]','暖风定。',108,'宋词/ci.song.16000.json','["暖风定。", "正卖花吟春，去年曾听。", "旋自洗幽兰，银瓶钓金井。", "斗窗香暖悭留客，街鼓还催暝。", "调雏莺、试遣深杯，唤将愁醒。", "灯市又重整。", "待醉勒游缰，缓穿斜径。", "暗忆芳盟，绡帕泪犹凝。", "吴宫十里吹笙路，桃李都羞靓。", "绣帘人、怕惹飞梅翳镜。"]'),
('song-ci-19','探芳信','吴文英','宋','宋词','song-ci','探芳信','[]','为春瘦。',108,'宋词/ci.song.16000.json','["为春瘦。", "更瘦如梅花，花应知否。", "任枕函云坠，离怀半中酒。", "雨声楼阁春寒里，寂寞收灯后。", "甚年年、斗草心期，探花时候。", "娇懒强拈绣。", "暗背里相思，闲供晴昼。", "玉合罗囊，兰膏渍红豆。", "舞衣叠损金泥凤，妒折阑干柳。", "几多愁、两点天涯远岫。"]'),
('song-ci-20','探芳信','吴文英','宋','宋词','song-ci','探芳信','[]','转芳径。',109,'宋词/ci.song.16000.json','["转芳径。", "见雾卷晴漪，鱼弄游影。", "旋解缨濯翠，临流抚菱镜。", "半林竹色香处，意足多新咏。", "试衣单、雁欲来时，旧寒才定。", "门巷对深静。", "但酒敌春浓，棋消日永。", "旧曲猗兰，待留向、月中听。", "藻池不通宫沟水，任泛流红冷。", "小阑干、笑拍东风醉醒。"]'),
('song-ci-21','探芳信','吴文英','宋','宋词','song-ci','探芳信','[]','探春到。',110,'宋词/ci.song.16000.json','["探春到。", "见彩花钗头，玉燕来早。", "正紫龙眠重，明月弄清晓。", "夜尘不浸银河水，金盎供新澡。", "镇帷犀、护紧东风，秀藏芝草。", "星斗粲怀抱。", "问雾暖蓝田，玉长多少。", "禁苑传香，柳边语、听莺报。", "片云飞趁春潮去，红软长安道。", "试回头、一点蓬莱翠小。"]'),
('song-ci-22','声声慢','吴文英','宋','宋词','song-ci','声声慢','[]','蓝云笼晓，玉树悬秋，交加金钏霞枝。',119,'宋词/ci.song.16000.json','["蓝云笼晓，玉树悬秋，交加金钏霞枝。", "人起昭阳，禁寒粉栗生肌。", "浓香最无著处，渐冷香、风露成霏。", "绣茵展，怕空阶惊坠，化作萤飞。", "三十六宫愁重，问谁持金锸，和月都移。", "掣锁西厢，清尊素手重携。", "秋来鬓华多少，任乌纱、醉压花低。", "正摇落，叹淹留、客又未归。"]'),
('song-ci-23','声声慢','吴文英','宋','宋词','song-ci','声声慢','[]','云深山坞，烟冷江皋，人生未易相逢。',119,'宋词/ci.song.16000.json','["云深山坞，烟冷江皋，人生未易相逢。", "一笑灯前，钗行两两春容。", "清芳夜争真态，引生香、撩乱东风。", "探花手，与安排金屋，懊恼司空。", "憔悴敧翘委佩，恨玉奴销瘦，飞趁轻鸿。", "试问知心，尊前谁最情浓。", "连呼紫云伴醉，小丁香、才吐微红。", "还解语，待携归、行雨梦中。"]'),
('song-ci-24','声声慢','吴文英','宋','宋词','song-ci','声声慢','[]','檀栾金碧，婀娜蓬莱，游云不蘸芳洲。',119,'宋词/ci.song.16000.json','["檀栾金碧，婀娜蓬莱，游云不蘸芳洲。", "露柳霜莲，十分点缀成秋。", "新弯画眉未稳，似含羞、低护墙头。", "愁送远，驻西台车马，共惜临流。", "知道池亭多宴，掩庭花、长是惊落秦讴。", "腻粉阑干，犹闻凭袖香留。", "输他翠涟拍甃，瞰新妆、时浸明眸。", "帘半卷，带黄花、人在小楼。"]'),
('song-ci-25','声声慢','吴文英','宋','宋词','song-ci','声声慢','[]','春星当户，眉月分心，罗屏绣幕围香。',119,'宋词/ci.song.16000.json','["春星当户，眉月分心，罗屏绣幕围香。", "歌缓□□，轻尘暗簌文梁。", "秋桐泛商丝雨，恨未回、飘雪垂杨。", "连宝镜，更一家姊妹，曾入昭阳。", "莺燕堂深谁到，为殷勤、须放醉客疏狂。", "量减离怀，孤负蘸甲清觞。", "曲中倚娇佯误，算只图、一顾周郎。", "花镇好，驻年华、长在琐窗。"]'),
('song-ci-26','声声慢','吴文英','宋','宋词','song-ci','声声慢','[]','寒筲惊坠，香豆初收，银妆一夜霜深。',119,'宋词/ci.song.16000.json','["寒筲惊坠，香豆初收，银妆一夜霜深。", "乱泻明珠，金盘来荐清斟。", "绿窗细剥檀皱，料水晶、微损春簪。", "风韵处，惹手香酥润，樱口脂侵。", "重省追凉前事，正风吟莎井，月碎苔阴。", "颗颗相思，无情漫搅秋心。", "银台翦花杯散，梦阿娇、金屋沈沈。", "甚时见，露十香、钗燕坠金。"]'),
('song-ci-27','声声慢','吴文英','宋','宋词','song-ci','声声慢','[]','清漪衔苑，御水分流，阿阶西北青红。',119,'宋词/ci.song.16000.json','["清漪衔苑，御水分流，阿阶西北青红。", "朱栱浮云，碧窗宿雾濛濛。", "璇题净横秋影，笑南飞、不过新鸿。", "延桂影，见素娥梳洗，微步琼空。", "城外湖山十里，想无时长敞，罨画帘栊。", "暗柳回堤，何须系马金狨。", "莺花翰林千首，彩毫飞、海雨天风。", "凤池上，又相思、春夜梦中。"]'),
('song-ci-28','声声慢','吴文英','宋','宋词','song-ci','声声慢','[]','六铢衣细，一叶舟轻，黄芦堪笑浮槎。',119,'宋词/ci.song.16000.json','["六铢衣细，一叶舟轻，黄芦堪笑浮槎。", "何处汀洲，云澜锦浪无涯。", "秋姿澹凝水色，艳真香、不染春华。", "笑归去，傍金波开户，翠屋为家。", "回施红妆青镜，与一川平绿，五月晴霞。", "赪玉杯中，西风不到窗纱。", "端的旧莲深薏，料采菱、新曲羞夸。", "秋潋滟，对年年、人胜似花。"]'),
('song-ci-29','声声慢','吴文英','宋','宋词','song-ci','声声慢','[]','莺围橙径，鲈跃莼波，重来雨过中秋。',119,'宋词/ci.song.16000.json','["莺围橙径，鲈跃莼波，重来雨过中秋。", "酒市渔乡，西风胜似春柔。", "宿舂去年村墅，看黄云、还委西畴。", "凤池去，信吴人有分，借与迟留。", "应是香山续梦，又凝香追咏，重到苏州。", "青鬓江山，足成千岁风流。", "围腰御仙花底，衬月中、金粟香浮。", "夜宴久，揽秋云、平倚画楼。"]'),
('song-ci-30','声声慢','吴文英','宋','宋词','song-ci','声声慢','[]','旋移轻鹢，浅傍垂虹，还因送客迟留。',119,'宋词/ci.song.16000.json','["旋移轻鹢，浅傍垂虹，还因送客迟留。", "泪雨横波，遥山眉上新愁。", "行人倚阑心事，问谁知、只有沙鸥。", "念聚散，几枫丹霜渚，莼绿春洲。", "渐近香菰炊黍，想红丝织字，未远青楼。", "寂寞渔乡，争如连醉温柔。", "西窗夜深翦烛，梦频生、不放云收。", "共怅望，认孤烟、起处是州。"]'),
('song-ci-31','高阳台','吴文英','宋','宋词','song-ci','高阳台','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u897f\u6e56"]','修竹凝妆，垂杨驻马，凭阑浅画成图。',122,'宋词/ci.song.16000.json','["修竹凝妆，垂杨驻马，凭阑浅画成图。", "山色谁题，楼前有雁斜书。", "东风紧送斜阳下，弄旧寒、晚酒醒馀。", "自销凝，能几花前，顿老相如。", "伤春不在高楼上，在灯前敧枕，雨外熏炉。", "怕舣游船，临流可奈清臞。", "飞红若到西湖底，搅翠澜、总是愁鱼。", "莫重来，吹尽香绵，泪满平芜。"]'),
('song-ci-32','高阳台','吴文英','宋','宋词','song-ci','高阳台','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','宫粉雕痕，仙云堕影，无人野水荒湾。',121,'宋词/ci.song.16000.json','["宫粉雕痕，仙云堕影，无人野水荒湾。", "古石埋香，金沙锁骨连环。", "南楼不恨吹横笛，恨晓风、千里关山。", "半飘零，庭上黄昏，月冷阑干。", "寿阳空理愁鸾。", "问谁调玉髓，暗补香瘢。", "细雨归鸿，孤山无限春寒。", "离魂难倩招清些，梦缟衣、解佩溪边。", "最愁人，啼鸟晴明，叶底青圆。"]'),
('song-ci-33','高阳台','吴文英','宋','宋词','song-ci','高阳台','[]','淝水秋寒，淮堤柳色，别来几换年光。',120,'宋词/ci.song.16000.json','["淝水秋寒，淮堤柳色，别来几换年光。", "紫马行迟，才生梦草池塘。", "便乘丹凤天边去，禁漏催、春殿称觞。", "过松江，雪弄飞花，冰解鸣珰。", "芳洲酒社词场。", "赋高台陈迹，曾醉吴王。", "重上逋山，诗清月瘦昏黄。", "春风侍女篝畔，早鹊袍、已暖天香。", "到东园，应费新题，千树苔苍。"]'),
('song-ci-34','高阳台','吴文英','宋','宋词','song-ci','高阳台','[]','风袅垂杨，雪销蕙草，何如清润潘郎。',122,'宋词/ci.song.16000.json','["风袅垂杨，雪销蕙草，何如清润潘郎。", "风月襟怀，挥豪倚马成章。", "仙都观里桃千树，映曲尘、十里荷塘。", "未归来，应恋花洲，醉玉吟香。", "东风晴昼浓如酒，正十分皓月，一半春光。", "燕子重来，明朝传梦西窗。", "朝寒几暖金炉烬，料洞天、日月偏长。", "杏园诗，应待先题，嘶马平康。"]'),
('song-ci-35','高阳台','吴文英','宋','宋词','song-ci','高阳台','[]','帆落回潮，人归故国，山椒感慨重游。',122,'宋词/ci.song.16000.json','["帆落回潮，人归故国，山椒感慨重游。", "弓折霜寒，机心已堕沙鸥。", "灯前宝剑清风断，正五湖、雨笠扁舟。", "最无情，岩上闲花，腥染春愁。", "当时白石苍松路，解勒回玉辇，雾掩山羞。", "木客歌阑，青春一梦荒丘。", "年年古苑西风到，雁怨啼、绿水葓秋。", "莫登临，几树残烟，西北高楼。"]'),
('song-ci-36','倦寻芳','吴文英','宋','宋词','song-ci','倦寻芳','[]','坠瓶恨井，分镜迷楼，空闲孤燕。',118,'宋词/ci.song.16000.json','["坠瓶恨井，分镜迷楼，空闲孤燕。", "寄别崔徽，清瘦画图春面。", "不约舟移杨柳系，有缘人映桃花见。", "叙分携，悔香瘢漫爇，绿鬟轻翦。", "听细语、琵琶幽怨。", "客鬓苍华，衫袖湿遍。", "渐老芙蓉，犹自带霜宜看。", "一缕情深朱户掩，两痕愁起青山远。", "被西风，又惊吹、梦云分散。"]'),
('song-ci-37','倦寻芳','吴文英','宋','宋词','song-ci','倦寻芳','[]','海霞倒影，空雾飞香，天市催晚。',118,'宋词/ci.song.16000.json','["海霞倒影，空雾飞香，天市催晚。", "暮靥宫梅，相对画楼帘卷。", "罗袜轻尘花笑语，宝钗争艳春心眼。", "乱箫声，正风柔柳弱，舞肩交燕。", "念窈窕、东邻深巷，灯外歌沈，月上花浅。", "梦雨离云，点点漏壶清怨。", "珠络香销空念往，纱窗人老羞相见。", "渐铜壶，闭春阴、晓寒人倦。"]'),
('song-ci-38','倦寻芳','吴文英','宋','宋词','song-ci','倦寻芳','[]','暮帆挂雨，冰岸飞梅，春思零乱。',118,'宋词/ci.song.16000.json','["暮帆挂雨，冰岸飞梅，春思零乱。", "送客将归，偏是故宫离苑。", "醉酒曾同凉月舞，寻芳还隔江尘面。", "去难留，怅芙蓉路窄，绿杨天远。", "便系马、莺边清晓，烟草晴花，沙润香软。", "烂锦年华，谁念故人游倦。", "寒食相思堤上路，行云应在孤山畔。", "寄新吟，莫空回、五湖春雁。"]'),
('song-ci-39','三姝媚','吴文英','宋','宋词','song-ci','三姝媚','[]','吹笙池上道。',122,'宋词/ci.song.16000.json','["吹笙池上道。", "为王孙重来，旋生芳草。", "水石清寒，过半春犹自，燕沈莺悄。", "樨柳阑干，晴荡漾、禁烟残照。", "往事依然，争忍重听，怨红凄调。", "曲榭方亭初扫。", "印藓迹双鸳，记穿林窈。", "顿隔年华，似梦回花上，露晞平晓。", "恨遂孤鸿，客又去、清明还到。", "便鞚墙头归骑，青梅已老。"]'),
('song-ci-40','三姝媚','吴文英','宋','宋词','song-ci','三姝媚','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','湖山经醉惯。',122,'宋词/ci.song.16000.json','["湖山经醉惯。", "溃春衫、啼痕酒痕无限。", "又客长安，叹断襟零袂，涴尘谁浣。", "紫曲门荒，沿败井、风摇青蔓。", "对语东邻，犹是曾巢，谢堂双燕。", "春梦人间须断。", "但怪得、当年梦缘能短。", "绣屋秦筝，傍海棠偏爱，夜深开宴。", "舞歇歌沈，花未减、红颜先变。", "伫久河桥欲去，斜阳泪满。"]'),
('song-ci-41','三姝媚','吴文英','宋','宋词','song-ci','三姝媚','[]','酣春青镜里。',122,'宋词/ci.song.16000.json','["酣春青镜里。", "照晴波明眸，暮云愁髻。", "半绿垂丝，正楚腰纤瘦，舞衣初试。", "燕客飘零，烟树冷、青骢曾系。", "画馆朱楼，还把清尊，慰春憔悴。", "离苑幽芳深闭。", "恨浅薄东风，褪花销腻。", "彩箑翻歌，最赋情、偏在笑红颦翠。", "暗拍阑干，看散尽、斜阳船市。", "付与金衣清晓，花深未起。"]'),
('song-ci-42','昼锦堂','吴文英','宋','宋词','song-ci','昼锦堂','[]','舞影灯前，箫声酒外，独鹤华表重归。',123,'宋词/ci.song.16000.json','["舞影灯前，箫声酒外，独鹤华表重归。", "旧雨残云仍在，门巷都非。", "愁结春情迷醉眼，老怜秋鬓倚蛾眉。", "难忘处，犹恨绣笼，无端误放莺飞。", "当时。", "征路远，欢事差，十年轻负心期。", "楚梦秦楼相遇，共叹相违。", "泪香沾湿孤山雨，瘦腰折损六桥丝。", "何时向，窗下翦残红烛，夜杪参移。"]'),
('song-ci-43','汉宫春','吴文英','宋','宋词','song-ci','汉宫春','[]','花姥来时，带天香国艳，羞掩名姝。',118,'宋词/ci.song.16000.json','["花姥来时，带天香国艳，羞掩名姝。", "日长半娇半困，宿酒微苏。", "沈香槛北，比人间、风异烟殊。", "春恨重，盘云坠髻，碧花翻吐琼盂。", "洛苑旧移仙谱，向吴娃深馆，曾奉君娱。", "猩唇露红未洗，客鬓霜铺。", "兰词沁壁，过西园、重载双壶。", "休漫道，花扶人醉，醉花却要人扶。"]'),
('song-ci-44','汉宫春','吴文英','宋','宋词','song-ci','汉宫春','[]','名压年芳，倚竹根新影，独照清漪。',118,'宋词/ci.song.16000.json','["名压年芳，倚竹根新影，独照清漪。", "千年禹梁藓碧，重发南枝。", "冰凝素质，遣凡桃、羞濯尘姿。", "寒正峭，东风似海，香浮夜雪春霏。", "练鹊锦袍仙使，有青娥传梦，月转参移。", "逋山傍莺系马，玉翦新辞。", "宫妆镜裹，笑人间、花信都迟。", "春未了，红盐荐鼎，江南烟雨黄时。"]'),
('song-ci-45','汉宫春','吴文英','宋','宋词','song-ci','汉宫春','[]','怀得银符，卷朝衣归袖，犹惹天香。',118,'宋词/ci.song.16000.json','["怀得银符，卷朝衣归袖，犹惹天香。", "星移太微几度，飞出西江。", "吴城驻马，趁鲈肥、腊蚁初尝。", "红雾底，金门候晓，争如小队春行。", "何用倚楼看镜，算橘中深趣，日月偏长。", "江山待吟秀句，梅靥催妆。", "东风水暖，弄烟娇、语燕飞墙。", "来岁醉，鹊楼胜处，轰围舞袖歌裳。"]'),
('song-ci-46','秋霁','吴文英','宋','宋词','song-ci','秋霁','["\u6d1e\u5ead\u6e56"]','一水盈盈，汉影隔游尘，净洗寒绿。',128,'宋词/ci.song.16000.json','["一水盈盈，汉影隔游尘，净洗寒绿。", "秋沐平烟，日回西照，乍惊饮虹天北。", "彩阑翠馥。", "锦云直下花成屋。", "试纵目。", "空际、醉乘风露跨黄鹄。", "追想缥缈，钓雪松江，恍然烟蓑，秋梦重续。", "问何如、临池脍玉，扁舟空舣洞庭宿。", "也胜饮湘然楚竹。", "夜久人悄，玉妃唤月归来，桂笙声裹，水宫六六。"]'),
('song-ci-47','花心动','吴文英','宋','宋词','song-ci','花心动','[]','入眼青红，小玲珑、飞檐度云微湿。',127,'宋词/ci.song.16000.json','["入眼青红，小玲珑、飞檐度云微湿。", "绣槛展春，金屋宽花，谁管采菱波狭。", "翠深知是深多少，不都放、夕阳红入。", "待装缀，新漪涨翠，小圜荷叶。", "此去春风满箧。", "应时锁蛛丝，浅虚尘榻。", "夜雨试灯，晴雪吹梅，趁取玳簪重盍。", "卷帘不解招新燕，春须笑、酒悭歌涩。", "半窗掩，日长困生翠睫。"]'),
('song-ci-48','花心动','吴文英','宋','宋词','song-ci','花心动','[]','十里东风，袅垂杨、长似舞时腰瘦。',127,'宋词/ci.song.16000.json','["十里东风，袅垂杨、长似舞时腰瘦。", "翠馆朱楼，紫陌青门，处处燕莺晴昼。", "乍看摇曳金丝细，春浅映、鹅黄如酒。", "嫩阴裹，烟滋露染，翠娇红溜。", "此际雕鞍去久。", "空追念邮亭，短枝盈首。", "海角天涯，寒食清明，泪点絮花沾袖。", "去年折赠行人远，今年恨、依然纤手。", "断肠也，羞眉画应未就。"]'),
('song-ci-49','龙山会','吴文英','宋','宋词','song-ci','龙山会','[]','石径幽云冷，步障深深，艳锦青红亚。',126,'宋词/ci.song.16000.json','["石径幽云冷，步障深深，艳锦青红亚。", "小桥和梦过，仙佩杳、烟水茫茫城下。", "何处不秋阴，问谁借、东风艳冶。", "最娇娆，愁侵醉颊，泪销红洒。", "摇落翠莽平沙，竞挽斜阳，驻短亭车马。", "晓妆羞未堕。", "沈恨起、金谷魂飞深夜。", "惊雁落清歌，酹花倩、觥船快泻。", "去未舍。", "待月向井梧梢上挂。"]'),
('song-ci-50','八声甘州','吴文英','宋','宋词','song-ci','八声甘州','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','渺空烟四远，是何年、青天坠长星。',119,'宋词/ci.song.16000.json','["渺空烟四远，是何年、青天坠长星。", "幻苍崖云树，名娃金屋，残霸宫城。", "箭径酸风射眼，腻水染花腥。", "时靸双鸳响，廊叶秋声。", "宫里吴王沈醉，倩五湖倦客，独钓醒醒。", "问苍波无语，华发奈山青。", "水涵空、阑干高处，送乱鸦、斜日落渔汀。", "连呼酒，上琴台去，秋与云平。"]'),
('song-ci-51','八声甘州','吴文英','宋','宋词','song-ci','八声甘州','[]','步晴霞倒影，洗闲愁、深杯滟风漪。',119,'宋词/ci.song.16000.json','["步晴霞倒影，洗闲愁、深杯滟风漪。", "望越来清浅，吴歈杳霭，江雁初飞。", "辇路凌空九险，粉冷濯妆池。", "歌舞烟霄顶，乐景沈晖。", "别是青红阑槛，对女墙山色，碧澹宫眉。", "问当时游鹿，应笑古台非。", "有谁招、扁舟渔隐，但寄情、西子却题诗。", "闲风月，暗销磨尽，浪打鸥矶。"]'),
('song-ci-52','八声甘州','吴文英','宋','宋词','song-ci','八声甘州','[]','记行云梦影，步凌波、仙衣翦芙蓉。',119,'宋词/ci.song.16000.json','["记行云梦影，步凌波、仙衣翦芙蓉。", "念杯前烛下，十香搵袖，玉暖屏风。", "分种寒花旧盎，藓土蚀吴蛩。", "人远云槎渺，烟海沈蓬。", "重访樊姬邻里，怕等闲易别，那忍相逢。", "试潜行幽曲，心荡□匆匆。", "井梧凋、铜铺低亚，映小眉、瞥见立惊鸿。", "空惆怅，醉秋香畔，往事朦胧。"]'),
('song-ci-53','新雁过妆楼','吴文英','宋','宋词','song-ci','新雁过妆楼','[]','梦醒芙蓉。',119,'宋词/ci.song.16000.json','["梦醒芙蓉。", "风檐近、挥疑佩玉丁东。", "翠微流水，都是惜别行踪。", "宋玉秋花相比瘦，赋情更苦似秋浓。", "小黄昏，绀云暮合，不见征鸿。", "宜城当时放客，认燕泥旧迹，返照楼空。", "夜阑心事，灯外败壁哀蛩。", "江寒夜枫怨落，怕流作题情肠断红。", "行云远，料澹蛾人在，秋香月中。"]'),
('song-ci-54','新雁过妆楼','吴文英','宋','宋词','song-ci','新雁过妆楼','[]','阆苑高寒。',119,'宋词/ci.song.16000.json','["阆苑高寒。", "金枢动、冰宫桂树年年。", "翦秋一半，难破万户连环。", "织锦相思楼影下，细钗暗约小帘间。", "共无眠。", "素娥惯得，西坠阑干。", "谁知壶中自乐，正醉围夜玉，浅斗婵娟。", "雁风自劲，云气不上凉天。", "红牙润沾素手，听一曲清歌双雾鬟。", "徐郎老，恨断肠声在，离镜孤鸾。"]'),
('song-ci-55','凄凉犯','吴文英','宋','宋词','song-ci','凄凉犯','[]','空江浪阔。',116,'宋词/ci.song.16000.json','["空江浪阔。", "清尘凝、层层刻碎冰叶。", "水边照影，华裾曳翠，露搔泪湿。", "湘烟暮合。", "□尘袜、凌波半涉。", "怕临风、□欺瘦骨，护冷素衣叠。", "樊姊玉奴恨，小细疏唇，洗妆轻怯。", "汜人最苦，粉痕深、几重愁靥。", "花隘香浓，猛熏透、霜绡细摺。", "倚瑶台，十二金钱晕半掐。"]'),
('song-ci-56','尾犯','吴文英','宋','宋词','song-ci','尾犯','[]','翠被落红妆，流水腻香，犹共吴越。',118,'宋词/ci.song.16000.json','["翠被落红妆，流水腻香，犹共吴越。", "十载江枫，冷霜波成缬。", "灯院静、凉花乍翦，桂园深、幽香旋折。", "醉云吹散，晚树细蝉，时替离歌咽。", "长亭曾送客，为偷赋、锦雁留别。", "泪接孤城，渺平芜烟阔。", "半菱镜、青门重售，采香堤、秋兰共结。", "故人憔悴，远梦越来溪畔月。"]'),
('song-ci-57','尾犯','吴文英','宋','宋词','song-ci','尾犯','[]','绀海掣微云，金井暮凉，梧韵风急。',118,'宋词/ci.song.16000.json','["绀海掣微云，金井暮凉，梧韵风急。", "何处楼高，想清光先得。", "江汜冷、冰绡乍洗，素娥忺，菱花再拭。", "影留人去，忍向夜深，帘户照陈迹。", "竹房苔径小，对日暮、数尽烟碧。", "露蓼香泾，记年时相识。", "二十五、声声秋点，梦不认、屏山路窄。", "醉魂幽扬，满地桂阴无人惜。"]'),
('song-ci-58','东风第一枝','吴文英','宋','宋词','song-ci','东风第一枝','[]','倾国倾城，非花非雾，春风十里独步。',123,'宋词/ci.song.16000.json','["倾国倾城，非花非雾，春风十里独步。", "胜如西子妖娆，更比太真澹泞。", "铅华不御。", "漫道有、巫山洛浦。", "似恁地、标格无双，镇锁画楼深处。", "曾被风、容易送去。", "曾被月、等闲留住。", "似花翻使花羞，似柳任从柳妒。", "不教歌舞。", "恐化作、彩云轻举。", "信下蔡、阳城俱迷，看取宋玉词赋。"]'),
('song-ci-59','夜合花','吴文英','宋','宋词','song-ci','夜合花','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u897f\u6e56"]','柳暝河桥，莺晴台苑，短策频惹春香。',123,'宋词/ci.song.16000.json','["柳暝河桥，莺晴台苑，短策频惹春香。", "当时夜泊，温柔便入深乡。", "词韵窄，酒杯长。", "翦蜡花、壶箭催忙。", "共追游处，凌波翠陌，连棹横塘。", "十年一梦凄凉。", "似西湖燕去，吴馆巢荒。", "重来万感，依前唤酒银罂。", "溪雨急，岸花狂。", "趁残鸦、飞过苍茫。", "故人楼上，凭谁指与，芳草斜阳。"]'),
('song-ci-60','探春慢','吴文英','宋','宋词','song-ci','探春慢','["\u897f\u6e56"]','径苔深，念断无故人，轻敲幽户。',116,'宋词/ci.song.16000.json','["径苔深，念断无故人，轻敲幽户。", "细草春回，目送流光一羽。", "重云冷，哀雁断，翠微空，愁蝶舞。", "荡鸣澌，游蓬小，梦枕残云惊寤。", "还识西湖醉路。", "向柳下并鞍，银袍吹絮。", "事影难追，那负灯床闻雨。", "冰溪凭谁照影，有明月、乘兴去。", "暗相思，梅孤瘦、共江亭暮。"]'),
('song-ci-61','柳梢青','吴文英','宋','宋词','song-ci','柳梢青','[]','断梦游轮。',61,'宋词/ci.song.16000.json','["断梦游轮。", "孤山路杳，越树阴新。", "流水凝酥，征衫沾泪，都是离痕。", "玉屏风冷愁人。", "醉烂漫、梅花翠云。", "傍夜船回，惜春门掩，一镜香尘。"]'),
('song-ci-62','生查子','吴文英','宋','宋词','song-ci','生查子','[]','暮云千万重，寒梦家乡远。',48,'宋词/ci.song.16000.json','["暮云千万重，寒梦家乡远。", "愁见越溪娘，镜里梅花面。", "醉情啼枕冰，往事分钗燕。", "三月灞陵桥，心翦东风乱。"]'),
('song-ci-63','一翦梅','吴文英','宋','宋词','song-ci','一翦梅','[]','远目伤心楼上山。',72,'宋词/ci.song.16000.json','["远目伤心楼上山。", "愁里长眉，别后峨鬟。", "暮云低压小阑干。", "教问孤鸿，因甚先还。", "瘦倚溪桥梅夜寒。", "雪欲消时，泪不禁弹。", "翦成钗胜待归看。", "春在西窗，灯火更阑。"]'),
('song-ci-64','点绛唇','吴文英','宋','宋词','song-ci','点绛唇','[]','春未来时，酒携不到千岩路。',50,'宋词/ci.song.16000.json','["春未来时，酒携不到千岩路。", "瘦还如许。", "晚色天寒处。", "无限新愁，难对风前语。", "行人去。", "暗消春素。", "横笛空山暮。"]'),
('song-ci-65','西江月','吴文英','宋','宋词','song-ci','西江月','[]','枝袅一痕雪在，叶藏几豆春浓。',58,'宋词/ci.song.16000.json','["枝袅一痕雪在，叶藏几豆春浓。", "玉奴最晚嫁东风。", "来结梨花幽梦。", "香力添熏罗被，瘦肌犹怯冰绡。", "绿阴青子老溪桥。", "羞见东邻娇小。"]'),
('song-ci-66','桃源忆故人','吴文英','宋','宋词','song-ci','桃源忆故人','[]','越山青断西陵浦。',56,'宋词/ci.song.16000.json','["越山青断西陵浦。", "一片密阴疏雨。", "潮带旧愁生暮。", "曾折垂杨处。", "桃根桃叶当时渡。", "呜咽风前柔橹。", "燕子不留春住。", "空寄离樯语。"]'),
('song-ci-67','木兰花慢','吴文英','宋','宋词','song-ci','木兰花慢','[]','记琼林宴起，软红路、几西风。',126,'宋词/ci.song.16000.json','["记琼林宴起，软红路、几西风。", "想汉影千年，荆江万顷，槎信长通。", "金狨。", "锦韀赐马，又霜横、汉节枣仍红。", "细柳春阴喜色，四郊秋事年丰。", "从容。", "岁晚玉关，长不闭、静边鸿。", "访五昌旧垒，山川相缪，日费诗筒。", "兰宫。", "系书翠羽，带天香、飞下玉芙蓉。", "明月瑶笙奏彻，倚楼黄鹤声中。"]'),
('song-ci-68','夜行船','吴文英','宋','宋词','song-ci','夜行船','[]','碧甃清漪方镜小。',68,'宋词/ci.song.16000.json','["碧甃清漪方镜小。", "绮疏净、半尘不到。", "古鬲香深，宫壶花换，留取四时春好。", "楼上眉山云窈窕。", "香衾梦、镇疏清晓。", "并蒂莲开，合欢屏暖，玉漏又催朝早。"]'),
('song-ci-69','朝中措','吴文英','宋','宋词','song-ci','朝中措','[]','吴山相对越山青。',57,'宋词/ci.song.16000.json','["吴山相对越山青。", "湘水一春平。", "粉字情深题叶，红波香染浮萍。", "朝云暮雨，玉壶尘世，金屋瑶京。", "晚雨西陵潮讯，沙鸥不似身轻。"]'),
('song-ci-70','风入松','吴文英','宋','宋词','song-ci','风入松','[]','一帆江上暮潮平。',90,'宋词/ci.song.16000.json','["一帆江上暮潮平。", "骑鹤过瑶京。", "湘波山色青天外，红香荡、玉佩东丁。", "西圃仍圆夜月，南风微弄秋声。", "阿咸才俊玉壶冰。", "王母最怜生。", "万年枝上千年叶，垂杨鬓、春共青青。", "连唤碧筒传酒，云回一曲双成。"]'),
('song-ci-71','西江月','吴文英','宋','宋词','song-ci','西江月','[]','清梦重游天上，古香吹下云头。',58,'宋词/ci.song.16000.json','["清梦重游天上，古香吹下云头。", "箫声三十六宫愁。", "高处花惊风骤。", "客路羁情不断，阑干晚色先收。", "千山浓绿未成秋。", "谁见月中人瘦。"]'),
('song-ci-72','朝中措','吴文英','宋','宋词','song-ci','朝中措','[]','殷云凋叶晚晴初。',57,'宋词/ci.song.16000.json','["殷云凋叶晚晴初。", "篱落认奚奴。", "才近西窗灯火，旋收残夜琴书。", "秋深露重，天空海阔，玉界香浮。", "木落秦山清瘦，西风几许工夫。"]'),
('song-ci-73','声声慢','吴文英','宋','宋词','song-ci','声声慢','[]','凭高入梦，摇落关情，寒香吹尽空岩。',119,'宋词/ci.song.16000.json','["凭高入梦，摇落关情，寒香吹尽空岩。", "坠叶消红，欲题秋讯难缄。", "重阳正隔残照，趁西风、不响云尖。", "乘半暝、看残山濯翠，剩水开奁。", "暗省长安年少，几传杯吊甫，把菊招潜。", "身老江湖，心随飞雁天南。", "乌纱倩谁重整，映风林、钓玉纤纤。", "漏声起，乱星河、入影画檐。"]'),
('song-ci-74','点绛唇','吴文英','宋','宋词','song-ci','点绛唇','[]','金井空阴，枕痕历尽秋声闹。',50,'宋词/ci.song.16000.json','["金井空阴，枕痕历尽秋声闹。", "梦长难晓。", "月树愁鸦悄。", "梅压檐梢，寒蝶寻香到。", "窗黏了。", "翠池春小。", "波冷鸳鸯觉。"]'),
('song-ci-75','点绛唇','吴文英','宋','宋词','song-ci','点绛唇','[]','明月茫茫，夜来应照南桥路。',50,'宋词/ci.song.16000.json','["明月茫茫，夜来应照南桥路。", "梦游熟处。", "一枕啼秋雨。", "可惜人生，不向吴城住。", "心期误。", "雁将秋去。", "天远青山暮。"]'),
('song-ci-76','玉楼春','吴文英','宋','宋词','song-ci','玉楼春','[]','阑干独倚天涯客。',64,'宋词/ci.song.16000.json','["阑干独倚天涯客。", "心影暗雕风叶寂。", "千山秋入雨中青，一雁暮随云去急。", "霜花强弄春颜色。", "相吊年光浇大白。", "海烟沈处倒残霞，一杼鲛绡和泪织。"]'),
('song-ci-77','柳梢青','吴文英','宋','宋词','song-ci','柳梢青','[]','翠嶂围屏。',61,'宋词/ci.song.16000.json','["翠嶂围屏。", "留连讯景，花外油亭。", "澹色烟昏，浓光清晓，一幅闲情。", "辋川落日渔罾。", "写不尽、人间四并。", "亭上秋声，莺笼春语，难入丹青。"]'),
('song-ci-78','浣溪沙','吴文英','宋','宋词','song-ci','浣溪沙','[]','秦黛横愁送暮云。',48,'宋词/ci.song.16000.json','["秦黛横愁送暮云。", "越波秋浅暗啼昏。", "空庭春草绿如裙。", "彩扇不歌原上酒，青门频返月中魂。", "花开空忆倚阑人。"]'),
('song-ci-79','浣溪沙','吴文英','宋','宋词','song-ci','浣溪沙','[]','一曲鸾箫别彩云。',48,'宋词/ci.song.16000.json','["一曲鸾箫别彩云。", "燕钗尘涩镜华昏。", "灞桥舞色褪蓝裙。", "湖上醉迷西子梦，江头春断倩离魂。", "旋缄红泪寄行人。"]'),
('song-ci-80','一翦梅','吴文英','宋','宋词','song-ci','一翦梅','[]','老色频生玉镜尘。',72,'宋词/ci.song.16000.json','["老色频生玉镜尘。", "雪澹春姿，越看精神。", "溪桥人去几黄昏。", "流水泠泠，都是啼痕。", "烟雨轻寒暮掩门。", "萼绿灯前，酒带香温。", "风情谁道不因春。", "春到一分，花瘦一分。"]'),
('song-ci-81','燕归梁','吴文英','宋','宋词','song-ci','燕归梁','[]','一片游尘拂镜湾。',62,'宋词/ci.song.16000.json','["一片游尘拂镜湾。", "素影护梅残。", "行人无语看春山。", "背东风、两苍颜。", "梦飞不到梨花外，孤馆闭、五更寒。", "谁怜消渴老文园。", "听溪声、泻冰泉。"]'),
('song-ci-82','乌夜啼','吴文英','宋','宋词','song-ci','乌夜啼','[]','醉痕深晕潮红。',45,'宋词/ci.song.16000.json','["醉痕深晕潮红。", "睡初浓。", "寒食来时池馆，旧东风。", "银烛换。", "月西转。", "梦魂中。", "明日春和人去，绣屏空。"]'),
('song-ci-83','浪淘沙','吴文英','宋','宋词','song-ci','浪淘沙','[]','绿树越溪湾。',64,'宋词/ci.song.16000.json','["绿树越溪湾。", "过雨云殷。", "西陵人去暮潮还。", "铅泪结成红粟颗，封寄长安。", "别味带生酸。", "愁忆眉山。", "小楼灯外栋花寒。", "衫袖醉痕花睡在，犹染微丹。"]'),
('song-ci-84','蹋莎行・踏莎行','吴文英','宋','宋词','song-ci','蹋莎行・踏莎行','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','润玉笼绡，檀樱倚扇。',68,'宋词/ci.song.16000.json','["润玉笼绡，檀樱倚扇。", "绣圈犹带脂香浅。", "榴心空叠舞裙红，艾枝应压愁鬟乱。", "午梦千山，窗阴一箭。", "香瘢新褪红丝腕。", "隔江人在雨声中，晚风菰叶生秋怨。"]'),
('song-ci-85','浪淘沙','吴文英','宋','宋词','song-ci','浪淘沙','[]','山远翠眉长。',64,'宋词/ci.song.16000.json','["山远翠眉长。", "高处凄凉。", "菊花清瘦杜秋娘。", "净洗绿杯牵露井，聊荐幽香。", "乌帽压吴霜。", "风力偏狂。", "一年佳节过西厢。", "秋色雁声愁几许，都在斜阳。"]'),
('song-ci-86','思佳客','吴文英','宋','宋词','song-ci','思佳客','[]','钗燕拢云睡起时。',64,'宋词/ci.song.16000.json','["钗燕拢云睡起时。", "隔墙折得杏花枝。", "青春半面妆如画，细雨三更花又飞。", "轻爱别，旧相知。", "断肠青冢几斜晖。", "断红一任风吹起，结习空时不点衣。"]'),
('song-ci-87','满江红','吴文英','宋','宋词','song-ci','满江红','[]','竹下门敲，又呼起、胡蝶梦清。',115,'宋词/ci.song.16000.json','["竹下门敲，又呼起、胡蝶梦清。", "闲里看、邻墙梅子，几度仁生。", "灯外江湖多夜雨，月边河汉独晨星。", "向草堂、清晓卷琴书，猿鹤惊。", "宫漏静，朝马鸣。", "西风起，已关情。", "料希音不在，女瑟娲笙。", "莲荡折花香未晚，野舟横渡水初晴。", "看高鸿、飞上碧云中，秋一声。"]'),
('song-ci-88','极相思','吴文英','宋','宋词','song-ci','极相思','[]','玉纤风透秋痕。',60,'宋词/ci.song.16000.json','["玉纤风透秋痕。", "凉与素怀分。", "乘鸾归后，生绡净翦，一片冰云。", "心事孤山春梦在，到思量、犹断诗魂。", "水清月冷，香消影瘦，人立黄昏。"]'),
('song-ci-89','思佳客','吴文英','宋','宋词','song-ci','思佳客','[]','丹桂花开第二番。',64,'宋词/ci.song.16000.json','["丹桂花开第二番。", "东篱展却宴期宽。", "人间宝镜离仍合，海上仙槎去复还。", "分不尽，半凉天。", "可怜闲剩此婵娟。", "素娥未隔三秋梦，赢得今宵又倚阑。"]'),
('song-ci-90','醉落魄・一斛珠','吴文英','宋','宋词','song-ci','醉落魄・一斛珠','[]','春温红玉。',67,'宋词/ci.song.16000.json','["春温红玉。", "纤衣学翦娇鸦绿。", "夜香烧短银屏烛。", "偷掷金钱，重把寸心卜。", "翠深不碍鸳鸯宿。", "采菱谁记当时曲。", "青山南畔红云北。", "一叶波心，明灭澹妆束。"]'),
('song-ci-91','朝中措','吴文英','宋','宋词','song-ci','朝中措','[]','楚皋相遇笑盈盈。',57,'宋词/ci.song.16000.json','["楚皋相遇笑盈盈。", "江碧远山青。", "露重寒香有恨，月明秋佩无声。", "银灯炙了，金炉烬暖，真色罗屏。", "病起十分清瘦，梦阑一寸春情。"]'),
('song-ci-92','杏花天','吴文英','宋','宋词','song-ci','杏花天','[]','蛮姜豆蔻相思味。',65,'宋词/ci.song.16000.json','["蛮姜豆蔻相思味。", "算却在、春风舌底。", "江清爱与消残醉。", "悴憔文园病起。", "停嘶骑、歌眉送意。", "记晓色、东城梦里。", "紫檀晕浅香波细。", "肠断垂杨小市。"]'),
('song-ci-93','满江红','吴文英','宋','宋词','song-ci','满江红','[]','露浥初英，早遗恨、参差九日。',115,'宋词/ci.song.16000.json','["露浥初英，早遗恨、参差九日。", "还却笑、萸随节过，桂凋无色。", "杯面寒香蜂共泛，篱根秋讯蛩催织。", "爱玲珑、筛月水屏风，千枝结。", "芳井韵，寒泉咽。", "霜著处，微红湿。", "共评花索句，看谁先得。", "好漉乌巾连夜醉，莫愁金细无人拾。", "算遗踪、犹有枕囊留，相思物。"]'),
('song-ci-94','朝中措','吴文英','宋','宋词','song-ci','朝中措','[]','海东明月锁云阴。',57,'宋词/ci.song.16000.json','["海东明月锁云阴。", "花在月中心。", "天外幽香轻漏，人间仙影难寻。", "并刀翦叶，一枝晓露，绿鬓曾簪。", "惟有别时难忘，冷烟疏雨秋深。"]'),
('song-ci-95','梦行云','吴文英','宋','宋词','song-ci','梦行云','[]','簟波皱纤縠。',82,'宋词/ci.song.16000.json','["簟波皱纤縠。", "朝炊熟。", "眠未足。", "青奴细腻，未拌真珠斛。", "素莲幽怨风前影，搔头斜坠玉。", "画阑枕水，垂杨疏雨，青丝乱、如乍沐。", "娇笙微韵，晚蝉理秋曲。", "翠阴明月胜花夜，那愁春去速。"]'),
('song-ci-96','天香','吴文英','宋','宋词','song-ci','天香','[]','碧藕藏丝，红莲并蒂，荷塘水暖香斗。',117,'宋词/ci.song.16000.json','["碧藕藏丝，红莲并蒂，荷塘水暖香斗。", "窈窕文窗，深沈书幔，锦瑟岁华依旧。", "洞箫韵里，同跨鹤、青田碧岫。", "菱镜妆台挂玉，芙蓉艳褥铺绣。", "西邻障蓬澡手。", "共华朝、梦兰分秀。", "未冷绮帘犹卷，浅冬时候。", "秋到霜黄半亩。", "便准拟、携花就君酒。", "花酒年华，天长地久。"]'),
('song-ci-97','谒金门','吴文英','宋','宋词','song-ci','谒金门','[]','鸡唱晚。',53,'宋词/ci.song.16000.json','["鸡唱晚。", "斜照西窗白暖。", "一沈午酲幽梦远。", "素衾春絮软。", "紫燕红楼歌断。", "锦瑟华年一箭。", "偷果风流输曼倩。", "昼际生绣线。"]'),
('song-ci-98','点绛唇','吴文英','宋','宋词','song-ci','点绛唇','[]','香泛罗屏，夜寒著酒宜偎倚。',50,'宋词/ci.song.16000.json','["香泛罗屏，夜寒著酒宜偎倚。", "翠偏红坠。", "唤起芙蓉睡。", "一曲伊州，秋色芭蕉里。", "娇和醉。", "眼情心事。", "愁隔湘江水。"]'),
('song-ci-99','夜游宫','吴文英','宋','宋词','song-ci','夜游宫','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','人去西楼雁杳。',71,'宋词/ci.song.16000.json','["人去西楼雁杳。", "叙别梦、扬州一觉。", "云澹星疏楚山晓。", "听啼乌，立河桥，话未了。", "雨外蛩声早。", "细织就、霜丝多少。", "说与萧娘未知道。", "向长安，对秋灯，几人老。"]'),
('song-ci-100','瑶华','吴文英','宋','宋词','song-ci','瑶华','[]','秋风采石，羽扇挥兵，认紫骝飞跃。',126,'宋词/ci.song.16000.json','["秋风采石，羽扇挥兵，认紫骝飞跃。", "江蓠塞草，应笑春、空锁凌烟高阁。", "胡歌奏陇，问铙鼓、新词谁作。", "有秀荪、来染吴香，瘦马青刍南陌。", "冰澌细响长桥，荡波底蛟腥，不涴霜锷。", "乌丝醉墨，红袖暖、十里湖山行乐。", "老仙何处，算洞府、光阴如昨。", "想地宽、多种桃花，艳锦东风成幄。"]'),
('song-ci-101','思佳客','吴文英','宋','宋词','song-ci','思佳客','[]','自唱新词送岁华。',64,'宋词/ci.song.16000.json','["自唱新词送岁华。", "鬓丝添得老生涯。", "十年旧梦无寻处，几度新春不在家。", "衣懒换，酒难赊。", "可怜此夕看梅花。", "隔年昨夜青灯在，无限妆楼尽醉哗。"]'),
('song-ci-102','六丑','吴文英','宋','宋词','song-ci','六丑','[]','渐新鹅映柳，茂苑锁、东风初掣。',172,'宋词/ci.song.16000.json','["渐新鹅映柳，茂苑锁、东风初掣。", "馆娃旧游，罗襦香未灭。", "玉夜花节。", "记向留连处，看街临晚，放小帘低揭。", "星河潋艳春云热。", "笑靥敧梅，仙衣舞缬。", "澄澄素娥宫阙。", "醉西楼十二，铜漏催彻。", "红消翠歇。", "叹霜簪练发。", "过眼年光，旧情尽别。", "泥深厌听啼鴂。", "恨愁霏润沁，陌头尘袜。", "青鸾杳、细车音绝。", "却因甚、不把欢期，付与少年华月。", "残梅瘦、飞趁风雪。", "向夜永，更说长安梦，灯花正结。"]'),
('song-ci-103','青玉案','吴文英','宋','宋词','song-ci','青玉案','[]','东风客雁溪边道。',80,'宋词/ci.song.16000.json','["东风客雁溪边道。", "带春去、随春到。", "认得踏青香径小。", "伤高怀远，乱云深处，目断湖山杳。", "梅花似惜行人老。", "不忍轻飞送残照。", "一曲秦娥春态少。", "幽香谁采，旧寒犹在，归梦啼莺晓。"]'),
('song-ci-104','采桑子','吴文英','宋','宋词','song-ci','采桑子','[]','茜罗结就丁香颗，颗颗相思。',52,'宋词/ci.song.16000.json','["茜罗结就丁香颗，颗颗相思。", "犹记年时。", "一曲春风酒一卮。", "彩鸾依旧乘云到，不负心期。", "清睡浓时。", "香趁银屏胡蝶飞。"]'),
('song-ci-105','水龙吟','吴文英','宋','宋词','song-ci','水龙吟','["\u897f\u6e56"]','好山都在西湖，斗城转北多流水。',126,'宋词/ci.song.16000.json','["好山都在西湖，斗城转北多流水。", "屋边五亩，桥通双沼，平烟蘸翠。", "旋叠云根，半开竹径，鸥来须避。", "四时长把酒，临花傍月，无一日、不春意。", "独乐当时高致。", "醉吟篇、如今还继。", "举头见日，葵心倾□，□□归计。", "浮碧亭□，泛红波迥，桃源人世。", "待天香□□，开时又胜，翠阴青子。"]'),
('song-ci-106','望江南・忆江南','吴文英','宋','宋词','song-ci','望江南・忆江南','[]','三月暮，花落更情浓。',64,'宋词/ci.song.16000.json','["三月暮，花落更情浓。", "人去秋千闲挂月，马停杨柳倦嘶风。", "堤畔画船空。", "恹恹醉，长日小帘栊。", "宿燕夜归银烛外，啼莺声在绿阴中。", "无处觅残红。"]'),
('song-ci-107','采桑子','吴文英','宋','宋词','song-ci','采桑子','[]','水亭花上三更月，扇与人闲。',52,'宋词/ci.song.16000.json','["水亭花上三更月，扇与人闲。", "弄影阑干。", "玉燕重抽拢坠簪。", "心期偷卜新莲子，秋入眉山。", "翠破红残。", "半簟湘波生晓寒。"]'),
('song-ci-108','清平乐','吴文英','宋','宋词','song-ci','清平乐','[]','柔柯翦翠。',54,'宋词/ci.song.16000.json','["柔柯翦翠。", "胡蝶双飞起。", "谁堕玉细花径里。", "香带熏风临水。", "露红滴□秋枝。", "金泥不染禅衣。", "结得同心成了，任教春去多时。"]'),
('song-ci-109','燕归梁','吴文英','宋','宋词','song-ci','燕归梁','[]','白玉搔头坠髻松。',62,'宋词/ci.song.16000.json','["白玉搔头坠髻松。", "怯冷翠裙重。", "当时离佩解丁东。", "澹云低、暮江空。", "青丝结带鸳鸯盏，岁华晚、又相逢。", "绿尘湘水避春风。", "步归来、月宫中。"]'),
('song-ci-110','西江月','吴文英','宋','宋词','song-ci','西江月','[]','江上桃花流水，天涯芳草青山。',57,'宋词/ci.song.16000.json','["江上桃花流水，天涯芳草青山。", "楼台春锁碧湾。", "都入行人望眼。", "一镜波平鸥去，千林日落鸦还。", "天风袅袅送轻帆。", "蓦过星槎银汉。"]'),
('song-ci-111','满江红','吴文英','宋','宋词','song-ci','满江红','[]','翠暮深庭，露红晚、闲花自发。',115,'宋词/ci.song.16000.json','["翠暮深庭，露红晚、闲花自发。", "春不断、亭台成趣，翠阴蒙密。", "紫燕雏飞帘额静，金鳞影转池心阔。", "有花香、竹色赋闲情，供吟笔。", "闲问字，评风月。", "时载酒，调冰雪。", "似初秋入夜，浅凉欺葛。", "人境不教车马近，醉乡莫放笙歌歇。", "倩双成、一曲紫云回，红莲折。"]'),
('song-ci-112','夜行船','吴文英','宋','宋词','song-ci','夜行船','[]','鸦带斜阳归远树。',68,'宋词/ci.song.16000.json','["鸦带斜阳归远树。", "无人听、数声钟暮。", "日与愁长，心灰香断，月冷竹房扃户。", "画扇青山吴苑路。", "傍怀袖、梦飞不去。", "忆别西池，红绡盛泪，肠断粉莲啼路。"]'),
('song-ci-113','好事近','吴文英','宋','宋词','song-ci','好事近','[]','翠冷石床云，海上偷传新曲。',53,'宋词/ci.song.16000.json','["翠冷石床云，海上偷传新曲。", "弹作一檐风雨，碎芭蕉寒绿。", "冰泉轻泻翠筒香，林果荐红玉。", "早是一分秋意，到临窗修竹。"]'),
('song-ci-114','鹧鸪天','吴文英','宋','宋词','song-ci','鹧鸪天','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','池上红衣伴倚阑。',64,'宋词/ci.song.16000.json','["池上红衣伴倚阑。", "栖鸦常带夕阳还。", "殷云度雨疏桐落，明月生凉宝扇闲。", "乡梦窄，水天宽。", "小窗愁黛澹秋山。", "吴鸿好为传归信，杨柳阊门屋数间。"]'),
('song-ci-115','虞美人影・桃源忆故人','吴文英','宋','宋词','song-ci','虞美人影・桃源忆故人','["\u6d1e\u5ead\u6e56"]','黄包先著风霜劲。',56,'宋词/ci.song.16000.json','["黄包先著风霜劲。", "独占一年佳景。", "点点吴盐雪凝。", "玉脍和齑冷。", "洋园谁识黄金径。", "一棹洞庭秋兴。", "香荐兰皋汤鼎。", "残酒西窗醒。"]'),
('song-ci-116','花上月令','吴文英','宋','宋词','song-ci','花上月令','[]','文园消渴爱江清。',72,'宋词/ci.song.16000.json','["文园消渴爱江清。", "酒肠怯，怕深觥。", "玉舟曾洗芙蓉水，泻清冰。", "秋梦浅，醉云轻。", "庭竹不收帘影去，人睡起，月空明。", "瓦瓶汲井和秋叶，荐吟醒。", "夜深重，怨遥更。"]'),
('song-ci-117','卜算子','吴文英','宋','宋词','song-ci','卜算子','[]','凉挂晓云轻，声度西风小。',52,'宋词/ci.song.16000.json','["凉挂晓云轻，声度西风小。", "井上梧桐应未知，一叶云鬟袅。", "来雁带书迟，别燕归程早。", "频探秋香开未开，恰似春来了。"]'),
('song-ci-118','凤栖梧・蝶恋花','吴文英','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','开过南枝花满院。',70,'宋词/ci.song.16000.json','["开过南枝花满院。", "新月西楼，相约同针线。", "高树数声蝉送晚。", "归家梦向斜阳断。", "夜色银河情一片。", "轻账偷欢，银烛罗屏怨。", "陈迹晓风吹雾散。", "帘钩空带蛛丝卷。"]'),
('song-ci-119','霜天晓角','吴文英','宋','宋词','song-ci','霜天晓角','[]','烟林褪叶。',54,'宋词/ci.song.16000.json','["烟林褪叶。", "红藉游人屧。", "十里秋声松路，岚云重、翠涛涉。", "伫立。", "闲素箑。", "画屏萝嶂叠。", "明月双成归去，天风里、凤笙浃。"]'),
('song-ci-120','乌夜啼','吴文英','宋','宋词','song-ci','乌夜啼','[]','西风先到岩扃。',45,'宋词/ci.song.16000.json','["西风先到岩扃。", "月笼明。", "金露啼珠滴翠，小银屏。", "一颗颗，一星星。", "是秋情。", "香裂碧窗烟破，醉魂醒。"]'),
('song-ci-121','夜行船','吴文英','宋','宋词','song-ci','夜行船','[]','逗晓阑干沾露水。',68,'宋词/ci.song.16000.json','["逗晓阑干沾露水。", "归期杳、画檐鹊喜。", "粉汗馀香，伤秋中酒，月落桂花影里。", "屏曲巫山和梦倚。", "行云重、梦飞不起。", "红叶中庭，绿尘斜□，应是宝筝慵理。"]'),
('song-ci-122','凤栖梧・蝶恋花','吴文英','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','湘水烟中相见早。',70,'宋词/ci.song.16000.json','["湘水烟中相见早。", "罗盖低笼，红拂犹娇小。", "妆镜明星争晚照。", "西风日送凌波杳。", "惆怅来迟羞窈窕。", "一霎留连，相伴阑干悄。", "今夜西池明月到。", "馀香翠被空秋晓。"]'),
('song-ci-123','生查子','吴文英','宋','宋词','song-ci','生查子','[]','当楼月半奁，曾买菱花处。',48,'宋词/ci.song.16000.json','["当楼月半奁，曾买菱花处。", "愁影背阑干，素发残风露。", "神前鸡酒盟，歌断秋香户。", "泥落画梁空，梦想青春语。"]'),
('song-ci-124','霜天晓角','吴文英','宋','宋词','song-ci','霜天晓角','[]','香莓幽径滑。',55,'宋词/ci.song.16000.json','["香莓幽径滑。", "索绕秋曲折。", "帘额红摇波影，鱼惊坠、暗吹沫。", "浪阔。", "轻棹拨。", "武陵曾话别。", "一点烟红春小，桃花梦、半林月。"]'),
('song-ci-125','西江月','吴文英','宋','宋词','song-ci','西江月','[]','添线绣床人倦，翻香罗暮烟斜。',58,'宋词/ci.song.16000.json','["添线绣床人倦，翻香罗暮烟斜。", "五更箫鼓贵人家。", "门外晓寒嘶马。", "帽压半檐朝雪，镜开千靥春霞。", "小帘沽酒看梅花。", "梦到林逋山下。"]'),
('song-ci-126','恋绣衾','吴文英','宋','宋词','song-ci','恋绣衾','[]','频摩书眼怯细文。',68,'宋词/ci.song.16000.json','["频摩书眼怯细文。", "小窗阴、天气似昏。", "兽炉暖、慵添困，带茶烟、微润宝薰。", "少年娇马西风冷，旧春衫、犹涴酒痕。", "梦不到、梨花路，断长桥、无限暮云。"]'),
('song-ci-127','杏花天','吴文英','宋','宋词','song-ci','杏花天','[]','鬓棱初翦玉纤弱。',65,'宋词/ci.song.16000.json','["鬓棱初翦玉纤弱。", "早春入、屏山四角。", "少年买困成欢谑。", "人在浓香绣幄。", "霜丝换、梅残梦觉。", "夜寒重、长安紫陌。", "东风入户先情薄。", "吹老灯花半萼。"]'),
('song-ci-128','醉桃源・阮郎归','吴文英','宋','宋词','song-ci','醉桃源・阮郎归','[]','五更枥马静无声。',56,'宋词/ci.song.16000.json','["五更枥马静无声。", "邻鸡犹怕惊。", "日华平晓弄春明。", "暮寒愁翳生。", "新岁梦，去年情。", "残宵半酒醒。", "春风无定落梅轻。", "断鸿长短亭。"]'),
('song-ci-129','唐多令','吴文英','宋','宋词','song-ci','唐多令','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','何处合成愁。',75,'宋词/ci.song.16000.json','["何处合成愁。", "离人心上秋。", "纵芭蕉、不雨也飕飕。", "都道晚凉天气好，有明月、怕登楼。", "年事梦中休。", "花空烟水流。", "燕辞归、客尚淹留。", "垂柳不萦裙带住，漫长是、系行舟。"]'),
('song-ci-130','好事近','吴文英','宋','宋词','song-ci','好事近','[]','雁外雨丝丝，将恨和愁都织。',53,'宋词/ci.song.16000.json','["雁外雨丝丝，将恨和愁都织。", "玉骨西风添瘦，减尊前歌力。", "袖香曾枕醉红腮，依约唾痕碧。", "花下凌波入梦，引春雏双鶒。"]'),
('song-ci-131','忆旧游','吴文英','宋','宋词','song-ci','忆旧游','["\u897f\u6e56"]','送人犹未苦，苦送春、随人去天涯。',123,'宋词/ci.song.16000.json','["送人犹未苦，苦送春、随人去天涯。", "片红都飞尽，正阴阴润绿，暗裹啼鸦。", "赋情顿雪双鬓，飞梦逐尘沙。", "叹病渴凄凉，分香瘦减，两地看花。", "西湖断桥路，想系马垂杨，依旧敧斜。", "葵麦迷烟处，问离巢孤燕，飞过谁家。", "故人为写深怨，空壁扫秋蛇。", "但醉上吴台，残阳草色归思赊。"]'),
('song-ci-132','宴清都','吴文英','宋','宋词','song-ci','宴清都','["\u897f\u6e56"]','病渴文园久。',126,'宋词/ci.song.16000.json','["病渴文园久。", "梨花月，梦残春故人旧。", "愁弹枕雨，衰翻帽雪，为情僝僽。", "千金醉跃骄骢，试问取、朱桥翠柳。", "痛恨不、买断斜阳，西湖酝入春酒。", "吴宫乱水斜烟，留连倦客，慵更回首。", "幽蛩韵苦，哀鸿叫绝，断音难偶。", "题红泛叶零乱，想夜冷、江枫暗瘦。", "付与谁、一半悲秋，行云在否。"]'),
('song-ci-133','金缕歌・贺新郎','吴文英','宋','宋词','song-ci','金缕歌・贺新郎','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','乔木生云气。',141,'宋词/ci.song.16000.json','["乔木生云气。", "访中兴、英雄陈迹，暗追前事。", "战舰东风悭借便，梦断神州故里。", "旋小筑、吴宫闲地。", "华表月明归夜鹤，叹当时、花竹今如此。", "枝上露，溅清泪。", "遨头小簇行春队。", "步苍苔、寻幽别坞，问梅开未。", "重唱梅边吸度曲，催发寒梢冻蕊。", "此心与、东君同意。", "后不如今非昔，两无言、相对沧浪水。", "怀此恨，寄残醉。"]'),
('song-ci-134','醉落魄・一斛珠','吴文英','宋','宋词','song-ci','醉落魄・一斛珠','[]','柔怀难托。',67,'宋词/ci.song.16000.json','["柔怀难托。", "老天如水人情薄。", "烛痕犹刻西窗约。", "歌断梨云，留梦绕罗幕。", "寒更唱遍吹梅角。", "香消臂趁弓弰削。", "主家衣在羞重著。", "独掩营门，春尽柳花落。"]'),
('song-ci-135','朝中措','吴文英','宋','宋词','song-ci','朝中措','[]','晚妆慵理瑞云盘。',57,'宋词/ci.song.16000.json','["晚妆慵理瑞云盘。", "针线傍灯前。", "燕子不归帘卷，海棠一夜孤眠。", "踏青人散，遗细满路，雨打秋千。", "尚有落花寒在，绿杨未褪春绵。"]'),
('song-ci-136','青玉案','吴文英','宋','宋词','song-ci','青玉案','[]','短亭芳草长亭柳。',80,'宋词/ci.song.16000.json','["短亭芳草长亭柳。", "记桃叶，烟江口。", "今日江村重载酒。", "残杯不到，乱红青冢，满地闲春绣。", "翠阴曾摘梅枝嗅。", "还忆秋千玉葱手。", "红索倦将春去后。", "蔷薇花落，故园胡蝶，粉薄残香瘦。"]'),
('song-ci-137','青玉案','吴文英','宋','宋词','song-ci','青玉案','[]','新腔一唱双金斗。',80,'宋词/ci.song.16000.json','["新腔一唱双金斗。", "正霜落、分甘手。", "已是红窗人倦绣。", "春词裁烛，夜香温被，怕减银壶漏。", "吴天雁晓云飞后。", "百感情怀顿疏酒。", "彩扇何时翻翠袖。", "歌边拌取，醉魂和梦，化作梅边瘦。"]'),
('song-ci-138','好事近','吴文英','宋','宋词','song-ci','好事近','[]','飞露洒银床，叶叶怨梧啼碧。',53,'宋词/ci.song.16000.json','["飞露洒银床，叶叶怨梧啼碧。", "蕲竹粉连香汗，是秋来陈迹。", "藕丝空缆宿湖船，梦阔水云窄。", "还系鸳鸯不在，老红香月白。"]'),
('song-ci-139','杏花天','吴文英','宋','宋词','song-ci','杏花天','[]','幽欢一梦成炊黍。',65,'宋词/ci.song.16000.json','["幽欢一梦成炊黍。", "知绿暗、汀菰几度。", "竹西歌断芳尘去。", "宽尽经年臂缕。", "梅黄后、林梢更雨。", "小池面、啼红怨暮。", "当时明月重生处。", "楼上宫眉在否。"]'),
('song-ci-140','浪淘沙','吴文英','宋','宋词','song-ci','浪淘沙','[]','灯火雨中船。',64,'宋词/ci.song.16000.json','["灯火雨中船。", "客思绵绵。", "离亭春草又秋烟。", "似与轻鸥盟未了，来去年年。", "往事一潸然。", "莫过西园。", "凌波香断绿苔钱。", "燕子不知春事改，时立秋千。"]'),
('song-ci-141','思佳客','吴文英','宋','宋词','song-ci','思佳客','[]','迷蝶无踪晓梦沈。',64,'宋词/ci.song.16000.json','["迷蝶无踪晓梦沈。", "寒香深闭小庭心。", "欲知湖上春多少，但看楼前柳浅深。", "愁自遣，酒孤斟。", "一帘芳景燕同吟。", "杏花宜带斜阳看，几阵东风晚又阴。"]'),
('song-ci-142','采桑子慢','吴文英','宋','宋词','song-ci','采桑子慢','[]','桐敲露井，残照西窗人起。',111,'宋词/ci.song.16000.json','["桐敲露井，残照西窗人起。", "怅玉手、曾携乌纱，笑整风敧。", "水叶沈红，翠微云冷雁慵飞。", "楼高莫上，魂消正在，摇落江蓠。", "走马断桥，玉台妆榭，罗帕香遗。", "叹人老、长安灯外，愁换秋衣。", "醉把茱萸，细看清泪湿芳枝。", "重阳重处，寒花怨蝶，新月东篱。"]'),
('song-ci-143','古香慢','吴文英','宋','宋词','song-ci','古香慢','[]','怨娥坠柳，离佩摇荭，霜讯南圃。',117,'宋词/ci.song.16000.json','["怨娥坠柳，离佩摇荭，霜讯南圃。", "漫忆桥扉，倚竹袖寒日暮。", "还问月中游，梦飞过、金风翠羽。", "把残云、剩水万顷，暗熏冷麝凄苦。", "渐浩渺、凌山高处。", "秋澹无光，残照谁主。", "露粟侵肌，夜约羽林轻误。", "翦碎惜秋心，更肠断、珠尘藓路。", "怕重阳，又催近、满城细雨。"]'),
('song-ci-144','蹋莎行・踏莎行','吴文英','宋','宋词','song-ci','蹋莎行・踏莎行','["\u897f\u6e56"]','杨柳风流，蕙花清润。',68,'宋词/ci.song.16000.json','["杨柳风流，蕙花清润。", "苹□未数张三影。", "沈香倚醉调清平，新辞□□□□□。", "鲛室裁绡，□□□□。", "□□白雪争歌郢。", "西湖同结杏花盟，东风休赋丁香恨。"]'),
('song-ci-145','失调名','吴文英','宋','宋词','song-ci','失调名','[]','霜杵敲寒，风灯摇梦。',10,'宋词/ci.song.16000.json','["霜杵敲寒，风灯摇梦。"]'),
('song-ci-146','烛影摇红','翁元龙','宋','宋词','song-ci','烛影摇红','[]','蜀锦华堂，宝筝频送花前酒。',116,'宋词/ci.song.16000.json','["蜀锦华堂，宝筝频送花前酒。", "妖娆全在半开时，人试单衣后。", "花面围春竞秀。", "如红潮、玉腮微透。", "欲苏还坠，浅醉扶头，朦胧晴昼。", "金屋名姝，眼情空伫闲眉岫。", "世间还有此娉婷，拼尽珠量斗。", "真艳可令消受。", "倩莺催、天香共袖。", "冷烟庭院，淡月梨花，空教春瘦。"]'),
('song-ci-147','齐天乐','翁元龙','宋','宋词','song-ci','齐天乐','[]','曲廊连苑吹笙道，重来暗尘都满。',123,'宋词/ci.song.16000.json','["曲廊连苑吹笙道，重来暗尘都满。", "种石生云，移花带月，犹欠藏春庭院。", "年华过眼。", "便梅谢兰销，舞沈歌断。", "露井寒蛩，为谁清夜诉幽怨。", "人生乐事最少，有时得意处，光阴偏短。", "树色凝红，山眉弄碧，不与朱颜相恋。", "临风念远。", "叹蝶梦难追，鹭盟重换。", "一片斜阳，送人归骑晚。"]'),
('song-ci-148','菩萨蛮','翁元龙','宋','宋词','song-ci','菩萨蛮','[]','春心莫共花争发。',52,'宋词/ci.song.16000.json','["春心莫共花争发。", "花开不管连环缺。", "梦断小楼空。", "杜鹃啼晓红。", "眼看连理树。", "纤手移筝柱。", "调遍错成声。", "无人知此情。"]'),
('song-ci-149','菩萨蛮','翁元龙','宋','宋词','song-ci','菩萨蛮','[]','玉纤闲捻花间集。',52,'宋词/ci.song.16000.json','["玉纤闲捻花间集。", "赤阑干对芭蕉立。", "薤叶晚生凉。", "竹阴移小床。", "拗莲牵藕线。", "藕断丝难断。", "弹水没鸳鸯。", "教寻波底香。"]'),
('song-ci-150','倦寻芳','翁元龙','宋','宋词','song-ci','倦寻芳','[]','燕帘挂晚。',118,'宋词/ci.song.16000.json','["燕帘挂晚。", "莺槛迷晴，花思零乱。", "试觅娉婷，日日傍湖亭苑。", "掷果墙阴窥驻马，采香深迳抛春扇。", "醉归来，任钗云半落，绣帘慵卷。", "念灿锦、年华如旧，飞絮游丝，萦恨难翦。", "蜀羽无情，早带怨红啼断，厚约轻辞寒食夜，行云空梦梨花院。", "莫凭阑，正斜阳、淡烟平远。"]'),
('song-ci-151','瑞龙吟','翁元龙','宋','宋词','song-ci','瑞龙吟','[]','清明近。',161,'宋词/ci.song.16000.json','["清明近。", "还是递趱东风，做成花讯。", "芳时一刻千金，半晴半雨、酬春未准。", "雁归尽。", "离字向人欲写，暗云难认。", "西园猛忆逢迎，翠纨障面，花间笑隐。", "曲径池莲平砌，绛裙曾与，濯香湔粉。", "无奈燕幕莺帘，轻负娇俊。", "青榆巷陌，蹋马红成寸。", "十年梦、秋千吊影，袜罗尘褪。", "事往凭谁问。", "昼长病酒添新恨。", "烟冷斜阳紧。", "山黛远、曲曲阑干凭损。", "柳丝万尺，不如轻鬓。"]'),
('song-ci-152','隔浦莲近・隔浦莲近拍','翁元龙','宋','宋词','song-ci','隔浦莲近・隔浦莲近拍','[]','街檐插缀翠柳。',88,'宋词/ci.song.16000.json','["街檐插缀翠柳。", "憔悴清明后。", "泪蜡堆香径，一夜海棠中酒。", "枝上酸似豆。", "莺声骤。", "恨软弹筝手。", "搵眉袖。", "嘶骢过尽平芜，绿衬飞绣。", "沈红入水，渐做小莲离藕。", "亭冷沈香梦似旧。", "花瘦。", "欲留春住时候。"]'),
('song-ci-153','玲珑四犯','翁元龙','宋','宋词','song-ci','玲珑四犯','[]','窗外啼莺，报数日西园，花事都空。',121,'宋词/ci.song.16000.json','["窗外啼莺，报数日西园，花事都空。", "绣屋专房，姚魏渐邀新宠。", "葱翠试剪春畦，羞对酒、夜寒犹重。", "误暗期、绿架香洞。", "月黯小阶云冻。", "算春将揽邮亭鞚。", "柳成圈、记人迎送。", "蜀魂怨染岩花色，泥径红成陇。", "楼上半揭画帘，料看雨、玉笙寒拥。", "怕骤晴，无事消遣，日长清梦。"]'),
('song-ci-154','风流子','翁元龙','宋','宋词','song-ci','风流子','["\u897f\u6e56"]','天阔玉屏空。',135,'宋词/ci.song.16000.json','["天阔玉屏空。", "轻阴弄、淡墨画秋容。", "正凉挂半蟾，酒醒窗下，露催新雁，人在山中。", "又一片，好秋花占了，香换却西风。", "箫女夜归，帐栖青凤，镜娥妆冷，钗坠金虫。", "西湖花深窈，闲庭砌、曾占席地歌钟。", "载取断云归去，几处房栊。", "恨小帘灯暗，粟肌消瘦，薰炉烟减，珠袖玲珑。", "三十六宫清梦，还与谁同。"]'),
('song-ci-155','西江月','翁元龙','宋','宋词','song-ci','西江月','[]','山色低衔小苑，春云暗宿空庭。',58,'宋词/ci.song.16000.json','["山色低衔小苑，春云暗宿空庭。", "秋千无月冷双绳。", "闲却画栏人静。", "一夜海棠如梦，半窗银烛多情。", "好花留不到清明。", "日日阴晴无定。"]'),
('song-ci-156','忆秦娥','翁元龙','宋','宋词','song-ci','忆秦娥','[]','三月时。',56,'宋词/ci.song.16000.json','["三月时。", "杨花飞尽无花飞。", "无花飞。", "不教春去，争得春归。", "高楼望断黄金羁。", "绿窗眉黛伤新离。", "伤新离。", "好将别后，长做归时。"]'),
('song-ci-157','恋绣衾','翁元龙','宋','宋词','song-ci','恋绣衾','[]','兽炉烟重火半焦。',68,'宋词/ci.song.16000.json','["兽炉烟重火半焦。", "卷帘时、雪意又销。", "过数点、残鸦外，想梅花、寒在灞桥。", "谢娘春恨深如柳，未东风、先遣絮飘。", "且莫把、冰丝剪，有灯球、红绣未描。"]'),
('song-ci-158','水龙吟','翁元龙','宋','宋词','song-ci','水龙吟','[]','画楼红湿斜阳，素妆褪出山眉翠。',127,'宋词/ci.song.16000.json','["画楼红湿斜阳，素妆褪出山眉翠。", "街声暮起，尘侵灯户，月来舞地。", "宫柳招莺，水荭飘雁，隔年春意。", "黯梨云，散作人间好梦，琼箫在、锦屏底。", "乐事轻随流水。", "暗兰消、作花心计。", "情丝万轴，因春织就，愁罗恨绮。", "昵沈迷香，占帘看夜，旧游轻醉。", "任孤山、剩雪残梅，渐懒跨、东风骑。"]'),
('song-ci-159','醉桃源・阮郎归','翁元龙','宋','宋词','song-ci','醉桃源・阮郎归','[]','千丝风雨万丝晴。',56,'宋词/ci.song.16000.json','["千丝风雨万丝晴。", "年年长短亭。", "暗黄看到绿成阴。", "春由他送迎。", "莺思重，燕愁轻。", "如人离别情。", "绕湖烟冷罩波明。", "画船移玉笙。"]'),
('song-ci-160','谒金门','翁元龙','宋','宋词','song-ci','谒金门','[]','莺树暖。',53,'宋词/ci.song.16000.json','["莺树暖。", "弱絮欲成芳茧。", "流水惜花流不远。", "小桥红欲满。", "原上草迷离苑。", "金勒晚风嘶断。", "等得日长春又短。", "愁深山翠浅。"]'),
('song-ci-161','绛都春','翁元龙','宋','宋词','song-ci','绛都春','[]','花娇半面。',122,'宋词/ci.song.16000.json','["花娇半面。", "记蜜烛夜阑，同醉深院。", "衣袖粉香，犹未经年如年远。", "玉颜不趁秋容换。", "但换却、春游同伴。", "梦回前度，邮亭倦客，又拈笺管。", "慵按。", "梁州旧曲，怕离柱断弦，惊破金雁。", "霜被睡浓，不比花前良宵短。", "秋娘羞占东篱畔。", "待说与、深宫幽怨。", "恨他情淡陶郎，旧缘较浅。"]'),
('song-ci-162','江城子','翁元龙','宋','宋词','song-ci','江城子','[]','一年箫鼓又疏钟。',86,'宋词/ci.song.16000.json','["一年箫鼓又疏钟。", "爱东风。", "恨东风。", "吹落灯花，移在杏梢红。", "玉靥翠钿无半点，空湿透，绣罗弓。", "燕魂莺梦渐惺松。", "月帘栊。", "影迷濛。", "催趁年华，都在艳歌中。", "明日柳边春意思，便不与，夜来同。"]'),
('song-ci-163','西江月','翁元龙','宋','宋词','song-ci','西江月','[]','画阁换黏春贴，宝筝抛学银钩。',58,'宋词/ci.song.16000.json','["画阁换黏春贴，宝筝抛学银钩。", "东风轻滑玉钗流。", "织就燕纹莺绣。", "隔帐灯花微笑，倚窗云叶低收。", "双鸳刺罢底尖头。", "剔雪闲寻豆蔻。"]'),
('song-ci-164','朝中措','翁元龙','宋','宋词','song-ci','朝中措','[]','花情偏与夜相投。',57,'宋词/ci.song.16000.json','["花情偏与夜相投。", "心事鬓边羞。", "薰醒半床凉梦，能消几个开头。", "风轮慢卷，冰壶低架，香雾飕飕。", "更著月华相恼，木犀淡了中秋。"]'),
('song-ci-165','鹊桥仙','翁元龙','宋','宋词','song-ci','鹊桥仙','[]','天长地久，风流云散，惟有离情无算。',68,'宋词/ci.song.16000.json','["天长地久，风流云散，惟有离情无算。", "从分金镜不成圆，到此夜、年年一半。", "轻罗暗网，蛛丝得意，多似妆楼针线。", "晓看玉砌淡无痕，但吹落、梧桐几片。"]'),
('song-ci-166','烛影摇红','翁孟寅','宋','宋词','song-ci','烛影摇红','[]','楼倚春城，锁窗曾共巢春燕。',116,'宋词/ci.song.16000.json','["楼倚春城，锁窗曾共巢春燕。", "人生好梦比春风，不似杨花健。", "旧事如天渐远。", "奈情缘、素丝未断。", "镜尘埋恨，带粉栖香，曲屏寒浅。", "环佩空归，故园羞见桃花面。", "轻烟残照下阑干，独自疏帘卷。", "一信狂风又晚。", "海棠花、随风满院。", "乱鸦归后，杜宇啼时，一声声怨。"]'),
('song-ci-167','阮郎归','翁孟寅','宋','宋词','song-ci','阮郎归','[]','月高楼外柳花明。',56,'宋词/ci.song.16000.json','["月高楼外柳花明。", "单衣怯露零。", "小桥灯影落残星。", "寒烟蘸水萍。", "歌袖窄，舞鬟轻。", "梨花梦满城。", "落红啼鸟两无情。", "春愁添晓酲。"]'),
('song-ci-168','齐天乐','翁孟寅','宋','宋词','song-ci','齐天乐','[]','幽香不受春料理，青青尚馀秋鬓。',123,'宋词/ci.song.16000.json','["幽香不受春料理，青青尚馀秋鬓。", "磵曲岩隈，烟梳露浴，甘与菰蒲共隐。", "芳标瘦迥。", "看缨结丁香，带萦晴荇。", "恨水东流，楚江憔悴乱云暝。", "凄凉梦游故苑，纵妒花风暴，吹梦难醒。", "艳李妖桃，纡青佩紫，争似广文官冷。", "尘波万顷。", "算谁是同心，自怜孤影。", "收敛风流，素弦清夜永。"]'),
('song-ci-169','齐天乐','翁孟寅','宋','宋词','song-ci','齐天乐','[]','红香十里铜驼梦，如今旧游重省。',123,'宋词/ci.song.16000.json','["红香十里铜驼梦，如今旧游重省。", "节序飘零，欢娱老大，慵立灯光蟾影。", "伤心对景。", "怕回首东风，雨晴难准。", "曲巷幽坊，管弦一片笑声近。", "飞棚浮动翠葆，看金钗半溜，春妒红粉。", "凤辇鳌山，云收雾敛，迤逦铜壶漏迥。", "霜风渐紧。", "展一幅青绡，净悬孤镜。", "带醉扶归，晓酲春梦稳。"]'),
('song-ci-170','摸鱼儿','翁孟寅','宋','宋词','song-ci','摸鱼儿','[]','卷西风、方肥塞草，带钩何事东去。',140,'宋词/ci.song.16000.json','["卷西风、方肥塞草，带钩何事东去。", "月明万里关河梦，吴楚几番风雨。", "江上路。", "二十载头颅，凋落今如许。", "凉生弄尘。", "叹江左夷吾，隆中诸葛，谈笑已尘土。", "寒汀外，还见来时鸥鹭。", "重来应是春暮。", "轻裘岘首陪登眺，马上落花飞絮。", "拼醉舞。", "谁解道，断肠贺老江南句。", "沙津少驻。", "举目送飞鸿，幅巾老子，楼上正凝伫。"]'),
('song-ci-171','蝶恋花','万俟绍之','宋','宋词','song-ci','蝶恋花','[]','啼鴂一声云榭晚。',70,'宋词/ci.song.16000.json','["啼鴂一声云榭晚。", "好梦惊回，蓬岛疑行遍。", "无绪东风帘自卷。", "香苞云压荼䕷院。", "似有还无烟色展。", "絮暖鱼肥，时复吹池面。", "扇影著花蜂蝶见。", "药栏春静红尘远。"]');
